const GameLoop = function (frameCallback) {

  /*
   * Class GameLoop
   * Wrapper for the game loop with configurable FPS cap (30, 60, 120)
   *
   * API:
   *
   * GameLoop.isRunning() - returns true if the game loop is running
   * GameLoop.init() - initializes the game loop
   * GameLoop.abort() - aborts the game loop
   * GameLoop.setFPSLimit(limit) - sets the FPS cap (30, 60, or 120)
   *
   */

  // Callback fired every frame
  this.__frameCallback = frameCallback;

  // State
  this.__frame = 0;
  this.__running = false;
  this.__aborted = false;
  this.__initialized = null;

  // FPS control — subtract 1ms tolerance to prevent rAF timing jitter from skipping frames
  this.__targetFPS = 60;
  this.__lastFrameTime = 0;
  this.__frameInterval = (1000 / 60) - 1;

  // Handle of the currently-scheduled animation frame. CRITICAL: abort() must
  // cancel it. abort() used to only set __aborted=true, but the still-pending
  // rAF is what carries the loop forward — and handleAcceptLogin does
  // abort() then init() synchronously, so init() reset __aborted=false BEFORE
  // that pending frame fired, reviving the old loop. Every reconnect/re-login
  // then stacked ANOTHER rAF chain (10-20 of them), so the FPS counter read
  // 700-1200 "fps", the device overheated, and iOS throttled it to ~5 FPS / a
  // frozen first frame (refresh cleared the stacked loops). Cancelling the
  // pending frame on abort()/init() guarantees exactly one rAF chain.
  this.__rafId = null;

  // Cache bound loop function to avoid per-frame allocation
  this.__boundLoop = this.__loop.bind(this);

}

GameLoop.prototype.getCurrentFrame = function () {

  return this.__frame;

}

GameLoop.prototype.isRunning = function () {

  /*
   * Function GameLoop.isRunning
   * Returns true if the game loop is running
   */

  return this.__running;

}

GameLoop.prototype.setFPSMode = function (targetFPS) {

  /*
   * Function GameLoop.setFPSMode
   * Legacy alias for setFPSLimit
   */

  this.setFPSLimit(targetFPS);

}

GameLoop.prototype.setFPSLimit = function (limit) {

  /*
   * Function GameLoop.setFPSLimit
   * Sets the FPS cap (30, 60, 120, or 0 for VSync / unlimited)
   */

  this.__targetFPS = parseInt(limit) || 0;
  this.__frameInterval = this.__targetFPS > 0 ? (1000 / this.__targetFPS) - 1 : 0;

}

GameLoop.prototype.getFPSMode = function () {

  /*
   * Function GameLoop.getFPSMode
   * Returns the current FPS target
   */

  return this.__targetFPS;

}

GameLoop.prototype.init = function () {

  /*
   * Function GameLoop.init
   * Initializes the game loop
   */

  // Already running
  if (this.isRunning()) {
    return;
  }

  // Defensive: kill any frame still pending from a previous (aborted) loop so
  // we never run two rAF chains at once — see __rafId note in the constructor.
  if (this.__rafId !== null) {
    cancelAnimationFrame(this.__rafId);
    this.__rafId = null;
  }

  this.__initialized = performance.now();
  this.__lastFrameTime = performance.now();

  // Set state and begin the loop
  this.__aborted = false;
  this.__running = true;

  this.__loop();

}

GameLoop.prototype.abort = function () {

  /*
   * Function GameLoop.abort
   * Aborts the currently running gameloop
   */

  this.__aborted = true;
  this.__running = false;

  // Cancel the pending frame so this loop truly stops — without this a
  // following init() (handleAcceptLogin does abort()+init()) revives it and
  // stacks a second rAF chain. See __rafId note in the constructor.
  if (this.__rafId !== null) {
    cancelAnimationFrame(this.__rafId);
    this.__rafId = null;
  }

}

GameLoop.prototype.__loop = function () {

  /*
   * Function GameLoop.__loop
   * Main body of the internal game loop — uses rAF with frame skipping for FPS cap
   */

  // The internal loop was aborted: stop running
  if (this.__aborted) {
    return;
  }

  // Always schedule via rAF for smooth timing and battery efficiency. Store the
  // handle so abort()/init() can cancel it (prevents stacked rAF chains).
  this.__rafId = requestAnimationFrame(this.__boundLoop);

  // Effective frame interval — driven solely by the user's FPS-limit choice.
  // 0 = render every rAF callback (VSync / uncapped).
  let interval = this.__frameInterval;

  // Uncapped (VSync): render every rAF callback.
  if (interval === 0) {
    this.__frame++;
    this.__frameCallback();
    // Render-liveness stamp: proves the render loop actually completed a
    // frame. A hung / throwing frameCallback or a stalled rAF stops updating
    // this, which the heartbeat tick reports to the server (render-freeze
    // shield). Set AFTER the callback so a per-frame throw leaves it stale.
    window.__lastRenderAt = Date.now();
    return;
  }

  let now = performance.now();
  let elapsed = now - this.__lastFrameTime;

  // Only render when enough time has passed for the (effective) target FPS
  if (elapsed < interval) {
    return;
  }

  // Adjust for drift so we don't accumulate timing errors
  this.__lastFrameTime = now - (elapsed % interval);
  this.__frame++;
  this.__frameCallback();
  // Render-liveness stamp (see VSync branch above).
  window.__lastRenderAt = Date.now();

}


