const CLIENT_VERSION = "0.0.1";
const SERVER_VERSION = "760";

// Bump this number whenever Tibia.dat or Tibia.spr files are updated on the server.
// Clients with a cached version mismatch will automatically re-download.
const ASSET_VERSION = 57;

// Bump this number whenever client/data/<version>/minimap.bin.gz is
// regenerated. Independent of ASSET_VERSION so a minimap-only update
// doesn't force clients to re-validate the (much larger) Tibia.dat /
// Tibia.spr binaries. Compared as a string against the value stored
// in localStorage under "minimap-asset-version".
const MINIMAP_VERSION = 13;

// Lightweight boot logger — sends diagnostics to server before WebSocket connects
// Rate-limited: max 20 messages per page load, deduplicated. Local dev only.
window.__bootLog = (function() {
  var host = location.hostname;
  if (host !== "localhost" && host !== "127.0.0.1") return function() {};
  var count = 0;
  var sent = {};
  return function(step) {
    if (count >= 20 || sent[step]) return;
    count++;
    sent[step] = true;
    try { new Image().src = "/api/bootlog?s=" + encodeURIComponent(step); } catch(e) {}
  };
})();

