  this.pathfinder.__pathfindCache = new Array();
  this.pathfinder.__finalDestination = null;
  this.pathfinder.__minimapWaypoints = null;
  this.pathfinder.__recentMinimapStarts = [];
  this.pathfinder.__hybridPath = null;

