Player.prototype.getContainer = function (id) {
  /*
   * Function Player.getContainer
   * Returns the container based on the identifier
   */

  // Container identifier 0 refers to the players own equipment
  if (id === 0x00) {
    return this.equipment;
  }

  // Linear direct search for the correct container
  let containers = Array.from(this.__openedContainers);

  for (let i = 0; i < containers.length; i++) {
    if (containers[i].__containerId === id) {
      return containers[i];
    }
  }

  return null;
};

Player.prototype.closeAllContainers = function () {
  /*
   * Function Player.closeAllContainers
   * Cleanup function to close all containers
   */

  // Mobile: clear the tabbed panel(s) in one go
  if (gameClient.touch && gameClient.touch.isMobileMode && gameClient.touch.mobileContainerPanel) {
    gameClient.touch.mobileContainerPanel.clear();
    if (gameClient.touch.mobileContainerPanel2) {
      gameClient.touch.mobileContainerPanel2.clear();
    }
  }

  this.__openedContainers.forEach(function (container) {
    this.removeContainer(container);
  }, this);
};

Player.prototype.removeContainer = function (container) {
  /*
   * Function Player.removeContainer
   * Removes a container from the DOM
   */

  // Remove the reference from the player
  this.__openedContainers.delete(container);

  // Mobile: remove from tabbed panel. Depot routes to mobileDepotPanel
  // via getContainerPanelFor's "already tracked" branch.
  if (gameClient.touch && gameClient.touch.isMobileMode && gameClient.touch.mobileContainerPanel) {
    let panel = gameClient.touch.getContainerPanelFor(container.__containerId);
    if (panel) {
      panel.removeContainer(container.__containerId);
    }
    return;
  }

  // If this container had been replaced by a child (same-window-mode: parent
  // was hidden, child is the visible window), DON'T cascade-close the child.
  // The user is looking at the child right now; closing it is jarring,
  // especially when the parent's removal was triggered by an unrelated toggle
  // (e.g. clicking the main backpack in the equipment slot to re-open it).
  // Instead, promote the child to standalone: clear its parent reference and
  // hide the now-meaningless "back" arrow. The child window stays visible.
  this.__openedContainers.forEach(function (c) {
    if (c.__replacedParent === container) {
      c.__replacedParent = null;
      if (c.window && c.window.__element) {
        let upBtn = c.window.__element.querySelector(".container-up-btn");
        if (upBtn) upBtn.style.display = "none";
      }
    }
  });

  // If this container replaced a parent, show the parent window again
  if (container.__replacedParent && container.__replacedParent.window) {
    container.__replacedParent.window.__element.style.display = "flex";
  }

  // Desktop: remove InteractiveWindow
  container.window.remove();
};

Player.prototype.closeContainer = function (container) {
  /*
   * Function Player.closeContainer
   * Closes the container and removes it from the graphical user interface
   */

  gameClient.send(new ContainerClosePacket(container.__containerId));
};

