Touch.prototype.__cleanup = function () {

    /*
     * Function Touch.__cleanup
     * Clean up mobile controls when switching to desktop mode
     */

    this.joystick.active = false;
    this.joystick.direction = null;
    this.actionMode = null;
    this.__clearActionButtonHighlights();

    // Reset tab state
    this.__visiblePanels = null;
    this.__panelRefs = null;
    this.tabPosition = 'right';

    // Clean up mobile chat
    if (this.mobileChat) {
        this.mobileChat.dismiss();
        this.mobileChat = null;
    }

    // Clean up mobile container panel
    if (this.mobileContainerPanel) {
        this.mobileContainerPanel.clear();
        this.mobileContainerPanel = null;
    }
    if (this.mobileContainerPanel2) {
        this.mobileContainerPanel2.clear();
        this.mobileContainerPanel2 = null;
    }
    if (this.mobileDepotPanel) {
        this.mobileDepotPanel.clear();
        this.mobileDepotPanel = null;
    }
    if (this.mobileFloatPanel) {
        this.mobileFloatPanel.clear();
        this.mobileFloatPanel = null;
    }

}

Touch.prototype.getContainerPanelFor = function (containerId) {

    /*
     * Function Touch.getContainerPanelFor
     * Returns the MobileContainerPanel that should host this container.
     *
     * Routing order:
     * 1. Already tracked → the panel that owns it (depot, primary, secondary).
     * 2. Container is the depot (CONST.CONTAINER.DEPOT) → depot panel.
     * 3. Depot-context flag set (the player tapped a slot inside the depot
     *    or a depot-child to trigger this open) → depot panel.
     * 4. Tablet + primary already has a backpack → secondary panel.
     * 5. Otherwise → primary panel.
     */

    if (!this.mobileContainerPanel) return null;

    // Lazy-instantiate the tablet second panel on first use. The force-tablet
    // class is only set after __initialize runs, so we can't create the panel
    // in the constructor — but by the time any container opens, the class is
    // definitely on <body>. Also handles runtime display-mode switches.
    if (!this.mobileContainerPanel2 &&
        document.body.classList.contains("force-tablet") &&
        document.getElementById("mobile-container-panel-2")) {
        this.mobileContainerPanel2 = new MobileContainerPanel("mobile-container-panel-2", "container2");
    }

    // Already tracked — return the owning panel
    if (this.mobileDepotPanel && this.mobileDepotPanel.__containers.has(containerId)) {
        return this.mobileDepotPanel;
    }
    if (this.mobileContainerPanel.__containers.has(containerId)) {
        return this.mobileContainerPanel;
    }
    if (this.mobileContainerPanel2 && this.mobileContainerPanel2.__containers.has(containerId)) {
        return this.mobileContainerPanel2;
    }
    if (this.mobileFloatPanel && this.mobileFloatPanel.__containers.has(containerId)) {
        return this.mobileFloatPanel;
    }

    // Explicit "Open in Window" from the long-press menu: route this open
    // into the floating centered panel (depot-style — shares its CSS and
    // drag/center/close wiring). One-shot flag stamped by ContainerMenu,
    // consumed here; lazy-instantiate the panel on first use.
    if (gameClient.__nextOpenInFloatPanel === true) {
        gameClient.__nextOpenInFloatPanel = false;
        if (gameClient.__nextOpenInFloatPanelTimeout) {
            clearTimeout(gameClient.__nextOpenInFloatPanelTimeout);
            gameClient.__nextOpenInFloatPanelTimeout = null;
        }
        if (!this.mobileFloatPanel && document.getElementById("mobile-float-panel")) {
            this.mobileFloatPanel = new MobileContainerPanel("mobile-float-panel", "floatcontainer");
            // Close → reopen re-centers, exactly like the depot panel.
            this.mobileFloatPanel.__resetPositionOnHide = true;
            this.__enablePanelDragAndCenter("mobile-float-panel", ".float-panel-close", "float-center", function () {
                return gameClient.touch ? gameClient.touch.mobileFloatPanel : null;
            });
        }
        if (this.mobileFloatPanel) {
            return this.mobileFloatPanel;
        }
    }

    // Depot itself OR a sub-container opened from depot-context → depot panel
    // (the Star Fishisland depot is a depot too — route it the same way)
    let isDepot = (containerId === CONST.CONTAINER.DEPOT || containerId === CONST.CONTAINER.STARFISH_DEPOT);
    let depotContext = (gameClient.__nextOpenIsDepot === true);
    if (this.mobileDepotPanel && (isDepot || depotContext)) {
        // Consume the one-shot flag
        gameClient.__nextOpenIsDepot = false;
        if (gameClient.__nextOpenIsDepotTimeout) {
            clearTimeout(gameClient.__nextOpenIsDepotTimeout);
            gameClient.__nextOpenIsDepotTimeout = null;
        }
        return this.mobileDepotPanel;
    }

    if (!this.mobileContainerPanel2) return this.mobileContainerPanel;

    // Panel 1 is the "backpack slot" — first container that opens claims it.
    // When it's released (backpack swap / logout), the next open claims it.
    if (this.mobileContainerPanel.__containers.size === 0) {
        return this.mobileContainerPanel;
    }

    return this.mobileContainerPanel2;

}

Touch.prototype.__bindCanvasTouchEvents = function () {

    /*
     * Function Touch.__bindCanvasTouchEvents
     * Bind touch events to the game canvas for interaction
     */

    let canvas = document.getElementById('screen');
    if (!canvas) return;

    canvas.addEventListener('touchstart', this.__handleCanvasTouchStart.bind(this), { passive: false });
    canvas.addEventListener('touchend', this.__handleCanvasTouchEnd.bind(this), { passive: false });
    canvas.addEventListener('touchmove', this.__handleCanvasTouchMove.bind(this), { passive: false });
    // Clear pending long-press timers if the OS cancels the touch (system
    // gesture, notification, etc.) so the long-press context menu cannot fire
    // after the finger is already gone.
    canvas.addEventListener('touchcancel', this.__cancelLongPress.bind(this), { passive: false });

}

Touch.prototype.__handleCanvasTouchStart = function (event) {

    /*
     * Function Touch.__handleCanvasTouchStart
     * Handle touch start on game canvas.
     * Two-finger tap opens the context menu.
     * Single-finger long press starts dragging the top ground item.
     * Single-finger short tap walks or performs action mode.
     */

    if (!gameClient || !gameClient.networkManager.isConnected()) return;
    if (gameClient.player && gameClient.player.isDead) return;
    if (this.__layoutEditActive) return;

    // Ignore canvas taps during keyboard customize mode
    if (this.mobileChat && this.mobileChat.__keyboard && this.mobileChat.__keyboard.__editingScale) return;

    event.preventDefault();

    // Close any open context menu when tapping the canvas
    if (gameClient.interface && gameClient.interface.menuManager.isOpened()) {
        gameClient.interface.menuManager.close();
        this.__suppressTapWalk = true;
        return;
    }

    // Close open modal (e.g. friend list add name) — canvas tap dismisses it
    // Call handleCancel() first so modals can clean up (e.g. hide virtual
    // keyboard). If handleCancel() returns false (CaptchaModal refuses),
    // do NOT close — and return early so the canvas tap doesn't fall
    // through to walk/attack handling either (player tapped on backdrop,
    // not the game world).
    if (gameClient.interface && gameClient.interface.modalManager.isOpened()) {
        let modal = gameClient.interface.modalManager.__openedModal;
        this.__suppressTapWalk = true;
        if (modal && modal.handleCancel && modal.handleCancel() === false) return;
        gameClient.interface.modalManager.close();
        return;
    }

    // Exit hotbar edit mode when tapping outside the hotbar
    if (this.__hotbarEditMode) {
        this.__toggleHotbarEditMode();
        this.__suppressTapWalk = true;
        return;
    }

    // Close mobile chat if open — canvas tap dismisses everything
    if (this.mobileChat && this.mobileChat.__state !== "closed") {
        this.mobileChat.dismiss();
        this.__suppressTapWalk = true;
        return;
    }

    // Two-finger tap detection — next single tap opens context menu
    // Require two simultaneous touches that are spread apart (> 60px)
    // to avoid false triggers from rapid single-finger double/triple taps
    if (event.touches.length >= 2) {
        let t0 = event.touches[0];
        let t1 = event.touches[1];
        let dx = t0.clientX - t1.clientX;
        let dy = t0.clientY - t1.clientY;
        let dist = Math.sqrt(dx * dx + dy * dy);
        if (dist > 60) {
            this.__cancelLongPress();
            // Require the two fingers to be HELD together briefly before arming
            // "Tap for menu". A fast single-finger double-tap (or two thumbs
            // tapping to walk) can momentarily report 2 contacts >60px apart and
            // used to trip context mode INSTANTLY — players kept entering the menu
            // by accident (report 2026-06-13). Now it's a deliberate two-finger
            // PRESS: any finger lifting / moving before the confirm cancels it
            // (__cancelLongPress, called from touchend / touchcancel / move).
            this.__twoFingerPending = true;
            this.__twoFingerPendingAt = Date.now();
            if (this.__twoFingerTimer) clearTimeout(this.__twoFingerTimer);
            let self = this;
            // HOLD path: if the two fingers stay down this long, arm the menu even
            // before they lift (immediate feedback). The TAP path — a quick lift
            // before this fires — is handled in __handleCanvasTouchEnd so a genuine
            // two-finger TAP works again, not only a hold (report 2026-07-01).
            this.__twoFingerTimer = setTimeout(function () {
                self.__twoFingerTimer = null;
                if (!self.__twoFingerPending) return;   // a finger already lifted/moved
                self.__triggerTwoFingerContext();
            }, 120);
            return;
        }
    }

    let touch = event.touches[0];
    this.touchStartTime = Date.now();
    this.touchStartX = touch.clientX;
    this.touchStartY = touch.clientY;
    this.longPressTriggered = false;

    // Start long press timer for dragging ground items
    this.longPressTimer = setTimeout(() => {
        this.longPressTriggered = true;
        this.__startCanvasItemDrag(touch);
    }, this.LONG_PRESS_DURATION);

    // Opt-in: a long, stationary single-finger hold opens the screen context
    // menu. It coexists with the item drag above (which arms much earlier) —
    // any finger movement cancels this timer, and if a drag was lifted it is
    // torn down (without moving the item) when the menu opens.
    if (gameClient.interface.settings
        && gameClient.interface.settings.isLongPressMenuEnabled
        && gameClient.interface.settings.isLongPressMenuEnabled()) {
        this.__contextLongPressTimer = setTimeout(() => {
            this.__contextLongPressTimer = null;
            this.__triggerLongPressContextMenu(touch);
        }, this.LONG_PRESS_CONTEXT_DURATION);
    }

}

Touch.prototype.__handleCanvasTouchMove = function (event) {

    /*
     * Function Touch.__handleCanvasTouchMove
     * Handle touch move on canvas.
     * If a drag is active, update the floating element position and highlight targets.
     * Otherwise, cancel long press if finger moved too much.
     */

    event.preventDefault();

    let touch = event.touches[0];

    // Cancel the long-press context-menu timer as soon as the finger moves —
    // the hold must stay put to count. Checked before the drag-active branch so
    // that moving a just-lifted item also cancels the pending menu.
    if (this.__contextLongPressTimer
        && (Math.abs(touch.clientX - this.touchStartX) > this.LONG_PRESS_CONTEXT_MOVE_TOLERANCE
         || Math.abs(touch.clientY - this.touchStartY) > this.LONG_PRESS_CONTEXT_MOVE_TOLERANCE)) {
        clearTimeout(this.__contextLongPressTimer);
        this.__contextLongPressTimer = null;
    }

    // If canvas drag is active, update floating element and highlight drop targets
    if (this.__dragState.active) {
        let fakeEvent = { clientX: touch.clientX, clientY: touch.clientY };
        if (this.__dragState.isPush) {
            // Push drag: update orange tile highlight on canvas
            let tileObj = gameClient.renderer.screen.getWorldCoordinates(fakeEvent);
            gameClient.renderer.__pushHighlightTile = tileObj || null;
        } else {
            // Item drag: offset floating element above finger for visibility
            if (this.__dragState.floatingElement) {
                this.__dragState.floatingElement.style.left = (touch.clientX - 20) + "px";
                this.__dragState.floatingElement.style.top = (touch.clientY - 66) + "px";
            }
            // Update tile highlight on canvas during item drag
            let tileObj = gameClient.renderer.screen.getWorldCoordinates(fakeEvent);
            // Reset contrast color when target tile changes
            if (tileObj !== gameClient.renderer.__dragHighlightTile) {
                gameClient.renderer.__dragHighlightColor = null;
            }
            gameClient.renderer.__dragHighlightTile = tileObj || null;
        }
        this.__updateDragHighlight(touch);
        return;
    }

    let dx = Math.abs(touch.clientX - this.touchStartX);
    let dy = Math.abs(touch.clientY - this.touchStartY);

    // If moved more than threshold, cancel long press
    if (dx > this.DRAG_MOVE_THRESHOLD || dy > this.DRAG_MOVE_THRESHOLD) {
        this.__cancelLongPress();
    }

}

Touch.prototype.__handleCanvasTouchEnd = function (event) {

    /*
     * Function Touch.__handleCanvasTouchEnd
     * Handle touch end on game canvas.
     * Uses a delayed single-tap approach: the first tap sets a short timer
     * before triggering walk. If a second tap arrives within the window,
     * the timer is cancelled and double-tap fires instead.
     */

    event.preventDefault();

    // Two-finger TAP: fingers lifted before the 120ms hold-confirm timer fired.
    // As long as they were down for a real tap (>= TWO_FINGER_TAP_MIN_MS — filters
    // the sub-frame accidental 2-contact flickers the hold timer was added for) and
    // didn't move (movement disarms __twoFingerPending via touchmove), open the menu
    // now. Restores TAP, not just HOLD (report 2026-07-01). Runs BEFORE the cancel
    // below, which would otherwise disarm the pending gesture.
    if (this.__twoFingerPending && !this.__twoFingerTapTriggered
        && (Date.now() - (this.__twoFingerPendingAt || 0)) >= this.TWO_FINGER_TAP_MIN_MS) {
        this.__triggerTwoFingerContext();
    }

    this.__cancelLongPress();

    // If two-finger tap was triggered, don't do any tap action
    // Only clear the flag once all fingers are lifted
    if (this.__twoFingerTapTriggered) {
        if (event.touches.length === 0) {
            this.__twoFingerTapTriggered = false;
        }
        return;
    }

    // If canvas drag is active, complete the drag
    if (this.__dragState.active) {
        let touch = event.changedTouches[0];
        this.__endItemDrag(touch);
        return;
    }

    // If long press was triggered (drag started but no item found), don't do tap action
    if (this.longPressTriggered) {
        this.longPressTriggered = false;
        return;
    }
    this.__cancelLongPress();

    // This tap was consumed on touchstart to dismiss UI (chat / modal / menu /
    // hotbar edit) — do NOT also walk to the tapped tile on release. Clears so
    // the next genuine tap walks normally.
    if (this.__suppressTapWalk) {
        this.__suppressTapWalk = false;
        return;
    }

    let touchDuration = Date.now() - this.touchStartTime;

    // Only process short taps (< 400ms)
    if (touchDuration >= 400) return;

    // Double tap detection on game canvas (400ms window, 50px distance for mobile fingers)
    let now = Date.now();
    let isDoubleTap = (now - this.__lastCanvasTapTime < 400) &&
        Math.abs(this.touchStartX - this.__lastCanvasTapX) < 50 &&
        Math.abs(this.touchStartY - this.__lastCanvasTapY) < 50;

    this.__lastCanvasTapTime = now;
    this.__lastCanvasTapX = this.touchStartX;
    this.__lastCanvasTapY = this.touchStartY;

    if (isDoubleTap) {
        // Cancel the pending single-tap timer so walk doesn't fire
        if (this.__singleTapTimer) {
            clearTimeout(this.__singleTapTimer);
            this.__singleTapTimer = null;
        }
        // Clear canvas hover highlight
        gameClient.mouse.__currentMouseTile = null;
        this.__handleCanvasDoubleTap();
        this.__lastCanvasTapTime = 0; // Prevent triple-tap
        return;
    }

    // Set canvas hover highlight on first tap so the renderer draws the overlay
    let fakeEvent = { clientX: this.touchStartX, clientY: this.touchStartY };
    gameClient.mouse.__currentMouseTile = gameClient.renderer.screen.getWorldCoordinates(fakeEvent);

    // In targeting mode (crosshair from hotbar/multiuse), execute immediately —
    // no reason to wait for double-tap detection when selecting a target
    let isTargeting = gameClient.mouse.__multiUseObject !== null
                   || gameClient.mouse.__hotbarCrosshairItem !== null
                   || gameClient.mouse.__hotbarUseCrosshair
                   || gameClient.mouse.__hotbarLookCrosshair
                   || gameClient.mouse.__tradeSourceObject !== null;

    if (isTargeting) {
        gameClient.mouse.__currentMouseTile = null;
        this.__performTapAction();
        return;
    }

    // Delay single-tap action to allow double-tap detection
    // If a second tap arrives within 250ms, this timer is cancelled above
    // Exception: if tap-to-walk is enabled and no monster nearby, walk immediately
    // to match desktop responsiveness (double-tap is for item use, not walking)
    if (this.__singleTapTimer) {
        clearTimeout(this.__singleTapTimer);
    }

    let self = this;
    let savedX = this.touchStartX;
    let savedY = this.touchStartY;

    // Check if this tap would trigger walking — if so, skip the 250ms delay
    let canWalkImmediately = false;
    if (gameClient.interface.settings.isTapToWalkEnabled() && this.actionMode === null) {
        let checkEvent = { clientX: savedX, clientY: savedY };
        let checkTile = gameClient.renderer.screen.getWorldCoordinates(checkEvent);
        if (checkTile && checkTile.which && checkTile.which.constructor.name === "Tile") {
            let monster = this.__findNearbyMonster(checkTile.which);
            if (!monster) canWalkImmediately = true;
        }
    }

    if (canWalkImmediately) {
        gameClient.mouse.__currentMouseTile = null;
        this.__performTapAction();
    } else {
        this.__singleTapTimer = setTimeout(function () {
            self.__singleTapTimer = null;
            // Clear canvas hover highlight
            gameClient.mouse.__currentMouseTile = null;
            // Restore touch coordinates (they may have changed if another touch started)
            self.touchStartX = savedX;
            self.touchStartY = savedY;
            self.__performTapAction();
        }, 250);
    }

}

Touch.prototype.__cancelLongPress = function () {

    if (this.longPressTimer) {
        clearTimeout(this.longPressTimer);
        this.longPressTimer = null;
    }

    if (this.__contextLongPressTimer) {
        clearTimeout(this.__contextLongPressTimer);
        this.__contextLongPressTimer = null;
    }

    // Reached via touchMOVE / touchcancel (finger moved = not a clean tap) → disarm
    // the pending menu. A clean two-finger TAP is caught in __handleCanvasTouchEnd
    // BEFORE it calls this, so on touchend the pending is already consumed (or it
    // was a sub-TWO_FINGER_TAP_MIN_MS flicker we correctly drop here).
    if (this.__twoFingerPending) {
        this.__twoFingerPending = false;
        if (this.__twoFingerTimer) {
            clearTimeout(this.__twoFingerTimer);
            this.__twoFingerTimer = null;
        }
    }

}

Touch.prototype.__triggerTwoFingerContext = function () {

    /*
     * Function Touch.__triggerTwoFingerContext
     * Arms "Tap for menu" context mode from a two-finger gesture. Shared by the
     * hold-confirm timer (fingers held 120ms) and the quick-tap path in
     * __handleCanvasTouchEnd (fingers lifted after a real tap) so TAP and HOLD
     * both open the menu.
     */

    this.__twoFingerPending = false;
    if (this.__twoFingerTimer) { clearTimeout(this.__twoFingerTimer); this.__twoFingerTimer = null; }
    this.__twoFingerTapTriggered = true;
    this.actionMode = 'context';
    let indicator = document.getElementById("mobile-use-indicator");
    if (indicator) {
        indicator.textContent = "📋 Tap for menu";
        indicator.classList.add("active");
    }
    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__triggerLongPressContextMenu = function (touch) {

    /*
     * Function Touch.__triggerLongPressContextMenu
     * Fires when the opt-in long-press hold completes (LONG_PRESS_CONTEXT_DURATION)
     * without the finger moving. Tears down any ground drag that the shorter
     * drag long-press may have lifted — WITHOUT moving the item — then opens the
     * screen context menu at the press point.
     */

    this.__cancelLongPress();

    // A ground drag may have been lifted at LONG_PRESS_DURATION. Abort it
    // cleanly — the item was never dropped, so nothing moves on the server.
    if (this.__dragState.active) {
        this.__cancelCanvasDrag();
    }

    // Suppress the tap-to-walk that touchend would otherwise fire on release.
    this.longPressTriggered = true;

    if (navigator.vibrate) {
        try { navigator.vibrate(40); } catch (e) {}
    }

    this.__openContextMenuAtTouch({ clientX: touch.clientX, clientY: touch.clientY });

}

Touch.prototype.__cancelCanvasDrag = function () {

    /*
     * Function Touch.__cancelCanvasDrag
     * Aborts an in-progress ground drag WITHOUT dropping/moving the item —
     * mirrors the cleanup tail of __endItemDrag but performs no server move.
     * Used when a long-press hold escalates to the context menu.
     */

    if (this.__dragState.dragTimer) {
        clearTimeout(this.__dragState.dragTimer);
        this.__dragState.dragTimer = null;
    }
    if (this.__dragState.sourceSlot) {
        this.__dragState.sourceSlot.style.opacity = "";
    }
    this.__removeAllDragFloats();
    let highlighted = document.querySelector(".mobile-drag-target");
    if (highlighted) highlighted.classList.remove("mobile-drag-target");
    gameClient.renderer.__dragHighlightTile = null;
    gameClient.renderer.__dragHighlightColor = null;
    gameClient.renderer.__pushHighlightTile = null;
    this.__dragState.active = false;
    this.__dragState.isPush = false;
    this.__dragState.sourceSlot = null;
    this.__dragState.sourceContainer = null;
    this.__dragState.sourceIndex = -1;

}

Touch.prototype.__startCanvasItemDrag = function (touch) {

    /*
     * Function Touch.__startCanvasItemDrag
     * Starts dragging the top item from a ground tile on long press.
     * If a pickupable item exists on the tile, it takes priority (e.g. corpse/loot).
     * Otherwise, if a creature is on the tile, starts a push drag.
     * Uses the shared __dragState so the existing __endItemDrag handles the drop.
     */

    let fakeEvent = { clientX: touch.clientX, clientY: touch.clientY };
    let tileObject = gameClient.mouse.getWorldObject(fakeEvent);

    if (!tileObject || !tileObject.which) return;

    // Get top item on the tile
    let topItem = (typeof tileObject.which.peekItem === "function")
        ? tileObject.which.peekItem(0xFF)
        : null;

    // Priority 1: Draggable item — pickupable, container, or moveable (chairs, tables, etc.)
    // Corpses have DatFlagContainer but NOT DatFlagPickupable, so also check isContainer()
    // Moveable items (chairs/tables) need isMoveable() to be draggable on mobile.
    // ALSO allow any non-ground top item (the `!isGround` clause): house furniture
    // placed from a kit (astro clock, old clock, wardrobes, etc.) is NON-MOVEABLE
    // per DAT, so it failed the old gate and mobile players could not rearrange
    // their own furniture — while DESKTOP could, because mouse.js sends tile moves
    // to the server regardless. This is the long-press drag path (a deliberate
    // gesture, NOT tap-to-walk), and the server is authoritative: it permits
    // furniture rearrange ONLY for the house owner/guests within the same house and
    // rejects every other move (walls, fixed decoration), so widening the client
    // gate cannot bypass any rule. Ground is excluded so long-pressing the bare
    // floor still falls through to walk/creature-push.
    let __isGroundTop = topItem !== null && typeof topItem.hasFlag === "function"
        && topItem.hasFlag(PropBitFlag.prototype.flags.DatFlagGround);
    if (topItem !== null && (topItem.isPickupable() || topItem.isContainer()
            || topItem.isMoveable() || !__isGroundTop)) {
        this.__beginDragState(tileObject);
        this.__createItemDragFloat(touch, topItem);
        return;
    }

    // Priority 2: Creature on tile — start push drag (no floating element)
    if (tileObject.which.monsters && tileObject.which.monsters.size > 0) {
        this.__beginDragState(tileObject);
        this.__dragState.isPush = true;
        if (navigator.vibrate) navigator.vibrate(40);
        return;
    }

}

Touch.prototype.__beginDragState = function (tileObject) {

    /*
     * Function Touch.__beginDragState
     * Sets up the shared drag state for a ground tile drag (item or push)
     */

    this.__dragState.active = true;
    this.__dragState.sourceSlot = null;
    this.__dragState.sourceContainer = tileObject.which;
    this.__dragState.sourceIndex = 0xFF;
    this.__dragState.dragTimer = null;

}

Touch.prototype.__removeAllDragFloats = function () {

    /*
     * Function Touch.__removeAllDragFloats
     * Removes EVERY drag-float element by class, not just the tracked
     * reference. Player report 2026-07-18 (tablet): stacked item ghosts
     * stuck on screen until reload — a second touch starting a new drag
     * overwrote __dragState.floatingElement while the old node was still
     * in the DOM, orphaning it forever. The class sweep guarantees no
     * path can strand a floater, whatever the touch sequence was.
     */

    document.querySelectorAll(".mobile-drag-float").forEach(function (el) { el.remove(); });
    this.__dragState.floatingElement = null;

}

Touch.prototype.__createItemDragFloat = function (touch, item) {

    /*
     * Function Touch.__createItemDragFloat
     * Creates a floating element with the dragged item sprite
     */

    this.__removeAllDragFloats();

    let floater = document.createElement("div");
    floater.className = "mobile-drag-float mobile-push-float";
    floater.style.cssText = "position:fixed;z-index:10000;pointer-events:none;width:40px;height:40px;opacity:0.85;";
    floater.style.left = (touch.clientX - 20) + "px";
    floater.style.top = (touch.clientY - 66) + "px";

    let canvas = document.createElement("canvas");
    canvas.width = 32;
    canvas.height = 32;
    canvas.style.cssText = "width:40px;height:40px;image-rendering:pixelated;";
    floater.appendChild(canvas);

    // Draw the item sprite on the floating canvas
    let drawCanvas = new Canvas(canvas, 32, 32);
    drawCanvas.drawSprite(item, Position.prototype.NULL, 32);

    document.body.appendChild(floater);
    this.__dragState.floatingElement = floater;

    if (navigator.vibrate) navigator.vibrate(40);

}

Touch.prototype.__createPushDragFloat = function (touch) {

    /*
     * Function Touch.__createPushDragFloat
     * Creates a floating push indicator for creature push drag
     */

    this.__removeAllDragFloats();

    let floater = document.createElement("div");
    floater.className = "mobile-drag-float mobile-push-float";
    floater.style.cssText = "position:fixed;z-index:10000;pointer-events:none;width:32px;height:32px;";
    floater.style.left = (touch.clientX - 16) + "px";
    floater.style.top = (touch.clientY - 16) + "px";

    document.body.appendChild(floater);
    this.__dragState.floatingElement = floater;

    if (navigator.vibrate) navigator.vibrate(40);

}

Touch.prototype.__handleFullscreenButton = function (event) {

    /*
     * Function Touch.__handleFullscreenButton
     * Toggles fullscreen mode and locks orientation to landscape.
     * Works like a YouTube fullscreen button.
     */

    event.preventDefault();
    event.stopPropagation();

    // Block entering fullscreen while keyboard is open to avoid layout issues
    let chatInput = document.getElementById('chat-input');
    if (chatInput && chatInput === document.activeElement) return;

    let isFullscreen = document.fullscreenElement
        || document.webkitFullscreenElement
        || document.mozFullScreenElement
        || document.msFullscreenElement;

    if (isFullscreen) {
        // Exit fullscreen
        let exitMethod = document.exitFullscreen
            || document.webkitExitFullscreen
            || document.mozCancelFullScreen
            || document.msExitFullscreen;

        if (exitMethod) {
            exitMethod.call(document);
        }

        // Update button icon
        if (this.fullscreenBtn) {
            this.fullscreenBtn.textContent = "⛶";
        }
    } else {
        // Enter fullscreen
        let element = document.documentElement;
        let requestMethod = element.requestFullscreen
            || element.webkitRequestFullscreen
            || element.mozRequestFullScreen
            || element.msRequestFullscreen;

        if (!requestMethod) {
            // iOS doesn't support Fullscreen API — show hint to add to home screen
            if (!navigator.standalone && !window.matchMedia('(display-mode: standalone)').matches) {
                gameClient.interface.setCancelMessage("For fullscreen, tap Share then \"Add to Home Screen\"");
            }
            return;
        }

        let self = this;
        let promise = requestMethod.call(element);

        if (promise && promise.then) {
            promise.then(function () {
                // Update button icon
                if (self.fullscreenBtn) {
                    self.fullscreenBtn.textContent = "✕";
                }
            }).catch(function () {});
        }
    }

    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__performTapAction = function () {

    /*
     * Function Touch.__performTapAction
     * Perform action based on current mode (look, use, or walk)
     */

    // Get tile at touch position
    let fakeEvent = {
        clientX: this.touchStartX,
        clientY: this.touchStartY
    };

    let tileObject = gameClient.mouse.getWorldObject(fakeEvent);

    if (!tileObject || !tileObject.which) {
        // Cancel any active targeting if tap resolved to nothing
        if (gameClient.mouse.__multiUseObject !== null || gameClient.mouse.__hotbarCrosshairItem !== null) {
            gameClient.mouse.cancelTargeting();
        }
        if (gameClient.mouse.__hotbarUseCrosshair || gameClient.mouse.__hotbarLookCrosshair) {
            gameClient.mouse.__hotbarUseCrosshair = false;
            gameClient.mouse.__hotbarLookCrosshair = false;
            gameClient.mouse.setCursor("auto");
        }
        if (this.actionMode) {
            this.__clearActionMode();
        }
        return;
    }

    // Brief white flash on the tapped tile (for all actions: walk, attack, use-with)
    gameClient.renderer.setTapHighlight(tileObject.which, 750);

    // Hotbar "Use on Crosshair" action — fire USE on the target
    if (gameClient.mouse.__hotbarUseCrosshair) {
        gameClient.mouse.__handleHotbarUseCrosshairClick(tileObject);
        return;
    }

    // Hotbar "Look at Crosshair" action — fire LOOK on the target
    if (gameClient.mouse.__hotbarLookCrosshair) {
        gameClient.mouse.__handleHotbarLookCrosshairClick(tileObject);
        return;
    }

    // Hotbar crosshair mode (closed backpack): send HotbarUsePacket with target position
    if (gameClient.mouse.__hotbarCrosshairItem !== null) {
        gameClient.mouse.__handleHotbarCrosshairUse(tileObject);
        return;
    }

    // Crosshair mode: if a multi-use item is pending, use it on the tapped tile
    if (gameClient.mouse.__multiUseObject !== null) {
        gameClient.mouse.__handleItemUseWith(gameClient.mouse.__multiUseObject, tileObject);
        gameClient.mouse.__multiUseObject = null;
        gameClient.mouse.setCursor("auto");
        return;
    }

    // Trade target selection mode: tap on a player to send trade request
    if (gameClient.mouse.__tradeSourceObject !== null) {
        gameClient.mouse.__handleTradeTargetSelect(tileObject);
        return;
    }

    switch (this.actionMode) {
        case 'context':
            this.__openContextMenuAtTouch({ clientX: this.touchStartX, clientY: this.touchStartY });
            this.__clearActionMode();
            break;

        case 'look':
            gameClient.mouse.look(tileObject);
            this.__clearActionMode();
            break;

        case 'use':
            gameClient.mouse.use(tileObject);
            this.__clearActionMode();
            break;

        default:
            // Check if tapping on or near a monster — toggle attack.
            // "Mobile precise click" (Optimization setting, owner 2026-07-15):
            // resolve the tap against creatures' DRAWN sprites via the desktop
            // OTCv8-style resolver (fakeEvent carries the clientX/clientY it
            // needs) — a hit attacks exactly that creature; a miss deliberately
            // SKIPS the fuzzy scan and falls through to walk. That strictness
            // is the point: tap the sprite to attack, tap anywhere else to
            // walk. Off (default) = forgiving 3x3 tile scan.
            let monster;
            if (gameClient.interface.settings.isMobilePreciseClickEnabled
                && gameClient.interface.settings.isMobilePreciseClickEnabled()) {
                monster = gameClient.mouse.__pickCreatureAtClick(fakeEvent, tileObject.which) || null;
            } else {
                monster = this.__findNearbyMonster(tileObject.which);
            }
            if (monster !== null) {
                // Skip attack logic in protection zones — open context menu instead
                if (gameClient.player.isInProtectionZone()) {
                    this.__openContextMenuAtTouch({ clientX: this.touchStartX, clientY: this.touchStartY });
                    return;
                }
                if (gameClient.player.isCreatureTarget(monster)) {
                    gameClient.player.setTarget(null);
                    return gameClient.send(new TargetPacket(0));
                }
                gameClient.player.setTarget(monster);
                return gameClient.send(new TargetPacket(monster.id));
            }
            // Tap-to-walk: if enabled, walk to tapped tile using pathfinder
            // Allow redirect while autowalking (matching desktop behavior)
            if (gameClient.interface.settings.isTapToWalkEnabled()) {
                let tilePos = tileObject.which.getPosition();
                if (tilePos && (!gameClient.player.isMoving() || gameClient.world.pathfinder.__isAutoWalking)) {
                    // If the tapped tile isn't walkable, redirect to the nearest
                    // walkable tile within 4 (matches the desktop map-click rule).
                    if (tileObject.which.isWalkable && !tileObject.which.isWalkable()) {
                        let near = gameClient.world.pathfinder.__findNearbyWalkable(tilePos, gameClient.player.__position, 4);
                        if (near !== null) {
                            tilePos = near;
                        }
                    }
                    gameClient.world.pathfinder.findPath(gameClient.player.__position, tilePos);
                }
            }
            break;
    }

}

Touch.prototype.__findNearbyMonster = function (tile) {

    /*
     * Function Touch.__findNearbyMonster
     * Finds an attackable creature on the tapped tile or adjacent tiles.
     * Provides forgiving touch targeting for mobile by checking a 3x3 area.
     * Excludes the player from results.
     *
     * The fuzzy 3x3 sweep is MONSTER-ONLY. Players require an exact-tile
     * tap. Without this filter, a tap on a food / container / ladder
     * tile next to a player would pick up the player from an adjacent
     * tile and PvP-target them instead of using the tapped item — exactly
     * the "tapped food next to a player, attacked the player" report
     * (Ombilke 2026-05-08, mobile). Exact-tile tap still allows player
     * targeting so intentional PvP keeps working.
     */

    // First check the tapped tile itself — players allowed here
    let monster = gameClient.mouse.__getFirstAttackableCreature(tile);
    if (monster !== null) return monster;

    // Check adjacent tiles for fuzzy mobile targeting — monsters only
    let tilePos = tile.getPosition();
    if (!tilePos) return null;

    for (let ox = -1; ox <= 1; ox++) {
        for (let oy = -1; oy <= 1; oy++) {
            if (ox === 0 && oy === 0) continue;
            let neighborPos = new Position(tilePos.x + ox, tilePos.y + oy, tilePos.z);
            let neighbor = gameClient.world.getTileFromWorldPosition(neighborPos);
            if (neighbor === null || !neighbor.monsters) continue;
            // Inline monster-only scan instead of __getFirstAttackableCreature
            // (which includes players). type === CONST.TYPES.MONSTER filters
            // both self (player) and other players.
            let found = null;
            neighbor.monsters.forEach(function (creature) {
                if (found === null && creature !== gameClient.player
                    && creature.type === CONST.TYPES.MONSTER) {
                    found = creature;
                }
            });
            if (found !== null) return found;
        }
    }

    return null;

}

Touch.prototype.__handleCanvasDoubleTap = function () {

    /*
     * Function Touch.__handleCanvasDoubleTap
     * Handles double tap on the game canvas with smart behavior:
     * - Container/corpse: opens it (use)
     * - Multi-use item (rune, rope): uses it (use-with mode)
     * - Non-pickupable world object (sewer, ladder, lever, door): uses it
     * - Pickupable regular item: picks it up into first open backpack
     */

    let fakeEvent = {
        clientX: this.touchStartX,
        clientY: this.touchStartY
    };

    let tileObject = gameClient.mouse.getWorldObject(fakeEvent);

    if (!tileObject || !tileObject.which) return;

    // Longer white flash on double-tapped tile for use-action feedback
    gameClient.renderer.setTapHighlight(tileObject.which, 1000);

    // NPC on tile — interact directly (greet + open trade if available)
    if (tileObject.which.monsters && tileObject.which.monsters.size > 0) {
        for (let creature of tileObject.which.monsters) {
            if (creature.type === CONST.TYPES.NPC) {
                gameClient.send(new NPCInteractPacket(creature.id));
                if (navigator.vibrate) navigator.vibrate(30);
                return;
            }
        }
    }

    let topItem = (typeof tileObject.which.peekItem === "function")
        ? tileObject.which.peekItem(0xFF)
        : null;

    // PRIORITY OVERRIDE: if the topmost item is pickupable but there's a
    // non-pickupable use-target (ladder, sewer, hole, door, lever) deeper
    // in the stack, prefer using the use-target. Without this, a stray
    // ring left lying on a ladder tile causes double-tap to pick up the
    // ring instead of climbing the ladder. We skip index 0 (ground tile —
    // always non-pickupable, but not what the player wants to "use").
    if (topItem !== null && topItem.isPickupable() && tileObject.which.items) {
        let stack = tileObject.which.items;
        for (let __i = stack.length - 1; __i >= 1; __i--) {
            let __it = stack[__i];
            if (!__it || __it === topItem) continue;
            if (!__it.isPickupable()) {
                gameClient.mouse.use({ which: tileObject.which, index: __i });
                if (navigator.vibrate) navigator.vibrate(30);
                return;
            }
        }
    }

    // Container/corpse — open it
    if (topItem !== null && topItem.isContainer()) {
        gameClient.mouse.use(tileObject);
        if (navigator.vibrate) navigator.vibrate(30);
        return;
    }

    // Multi-use item on the ground — pick up if pickupable, otherwise use (rope holes, etc.)
    if (topItem !== null && topItem.isMultiUse()) {
        if (topItem.isPickupable()) {
            // Pickupable multiuse items (weapons, runes): pick up to backpack
            let equipment = gameClient.player.equipment;
            if (equipment) {
                let source = { "which": tileObject.which, "index": tileObject.index };
                let target = { "which": equipment, "index": CONST.EQUIPMENT.BACKPACK };
                let count = topItem.isStackable() ? topItem.getCount() : 1;
                gameClient.mouse.sendItemMove(source, target, count);
                if (navigator.vibrate) navigator.vibrate(30);
            }
        } else {
            // Non-pickupable multiuse items (rope spots, etc.): use directly
            gameClient.mouse.use(tileObject);
            if (navigator.vibrate) navigator.vibrate(30);
        }
        return;
    }

    // Non-pickupable world object (sewer grate, ladder, lever, door, etc.) — use it
    if (topItem !== null && !topItem.isPickupable()) {
        gameClient.mouse.use(tileObject);
        if (navigator.vibrate) navigator.vibrate(30);
        return;
    }

    // Own character — open outfit selection (lowest priority, only if no usable item on tile)
    if (typeof tileObject.which.getPosition === "function") {
        let tilePos = tileObject.which.getPosition();
        let playerPos = gameClient.player.getPosition();
        if (tilePos.equals(playerPos)) {
            gameClient.interface.modalManager.open("outfit-modal");
            if (navigator.vibrate) navigator.vibrate(30);
            return;
        }
    }

    if (topItem === null) return;

    // Pickupable regular item — pick up to backpack via equipment slot
    let equipment = gameClient.player.equipment;

    if (!equipment) {
        gameClient.interface.setCancelMessage("No equipment available.");
        return;
    }

    let source = { "which": tileObject.which, "index": tileObject.index };
    let target = { "which": equipment, "index": CONST.EQUIPMENT.BACKPACK };
    let count = topItem.isStackable() ? topItem.getCount() : 1;
    gameClient.mouse.sendItemMove(source, target, count);

    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__openSlotContextMenu = function (slotObject, touch) {

    /*
     * Function Touch.__openSlotContextMenu
     * Opens the container context menu for an equipment or container slot item
     */

    let menu = gameClient.interface.menuManager.getMenu("container-menu");
    if (!menu) return;

    // Update button text based on item type
    let item = slotObject.which.peekItem(slotObject.index);
    if (item !== null) {
        if (item.isContainer()) {
            menu.element.querySelector("button[action=use]").innerHTML = "Open";
        } else if (item.isMultiUse()) {
            menu.element.querySelector("button[action=use]").innerHTML = "Use With";
        } else {
            menu.element.querySelector("button[action=use]").innerHTML = "Use";
        }
    }

    // Show "Trade with..." for pickupable items
    let tradeBtn = menu.element.querySelector("button[action=trade]");
    if (tradeBtn) {
        tradeBtn.style.display = "none";
        if (item !== null && item.isPickupable()) {
            tradeBtn.style.display = "";
        }
    }

    // Mobile-only "Open in Window": route the container into the floating
    // centered panel (depot-style) instead of the corner tab panel.
    let openWindowBtn = menu.element.querySelector("button[action=open-window]");
    if (openWindowBtn) {
        openWindowBtn.style.display = (item !== null && item.isContainer()) ? "" : "none";
    }

    // Loot router Set/Clear Name — mirror desktop Mouse.__handleContextMenu:
    // container items in windows the server marked nameable (equipment tree).
    let setNameBtn = menu.element.querySelector("button[action=set-name]");
    let clearNameBtn = menu.element.querySelector("button[action=clear-name]");
    if (setNameBtn) setNameBtn.style.display = "none";
    if (clearNameBtn) clearNameBtn.style.display = "none";
    if (item !== null && item.isContainer() && setNameBtn) {
        let parentCid = slotObject.which ? slotObject.which.__containerId : undefined;
        let ok = gameClient.__bagNameable && gameClient.__bagNameable[parentCid] === true;
        if (ok) {
            setNameBtn.style.display = "";
            let known = gameClient.__bagNames && gameClient.__bagNames[parentCid];
            if (clearNameBtn && known && known[slotObject.index]) {
                clearNameBtn.style.display = "";
            }
        }
    }

    // Show "Cook" for cookable food items — mirror desktop Mouse.__handleContextMenu
    let cookBtn = menu.element.querySelector("button[action=cook]");
    if (cookBtn) {
        cookBtn.style.display = "none";
        if (item !== null && item.sid && Mouse.COOKABLE_SIDS[item.sid]) {
            cookBtn.style.display = "";
        }
    }

    // "Add to Loot List" — mirror the desktop container menu toggle
    let lootAddBtn = menu.element.querySelector("button[action=lootlist-add]");
    if (lootAddBtn) {
        lootAddBtn.style.display = "none";
        if (item !== null && item.isPickupable() && item.sid) {
            lootAddBtn.style.display = "";
        }
    }

    // Open the menu at touch position
    let fakeEvent = { clientX: touch.clientX, clientY: touch.clientY };
    menu.open(fakeEvent, slotObject);
    gameClient.interface.menuManager.__activeMenu = menu;

}

Touch.prototype.__triggerSlotLongPressMenu = function (slotElement, x, y) {

    /*
     * Function Touch.__triggerSlotLongPressMenu
     * Fires when the opt-in long-press hold completes over a container/equipment
     * slot. Aborts any drag the 200ms slot-drag timer may have lifted (without
     * moving the item), then opens the item context menu for that slot.
     */

    if (this.__dragState && this.__dragState.active) {
        this.__cancelItemDrag();
    }

    let slotObject = this.__getSlotObject(slotElement);
    if (!slotObject || !slotObject.which) {
        return;
    }

    // Suppress the tap the slot-tap handler would otherwise fire on release.
    this.__slotLongPressFired = true;

    if (navigator.vibrate) {
        try { navigator.vibrate(40); } catch (e) {}
    }

    this.__openSlotContextMenu(slotObject, { clientX: x, clientY: y });

}

Touch.prototype.__openContextMenuAtTouch = function (touch) {

    /*
     * Function Touch.__openContextMenuAtTouch
     * Opens the screen context menu at touch position (long press)
     * Replicates the menu setup logic from Mouse.__handleContextMenu
     */

    let fakeEvent = {
        clientX: touch.clientX,
        clientY: touch.clientY
    };

    let tile = gameClient.mouse.getWorldObject(fakeEvent);

    if (!tile) return;

    let menu = gameClient.interface.menuManager.getMenu("screen-menu");
    menu.__tile = tile;

    // Configure Use button label
    menu.element.querySelector("button[action=use]").innerHTML = "Use";
    let repackBtn = menu.element.querySelector("button[action=repackage]");
    if (repackBtn) repackBtn.style.display = "none";
    if (tile.which.items && tile.which.items.length > 0) {
        let topItem = tile.which.peekItem(0xFF);
        if (topItem && topItem.isRotateable()) {
            menu.element.querySelector("button[action=use]").innerHTML = "Rotate";
        } else if (topItem && topItem.isMultiUse()) {
            menu.element.querySelector("button[action=use]").innerHTML = "Use With";
        }
        // Repackage: placed shop-furniture (CID has a kit). Server enforces
        // house ownership; this only decides whether the entry shows.
        if (repackBtn && topItem && gameClient.repackageableCids
            && gameClient.repackageableCids.has(topItem.id)) {
            repackBtn.style.display = "";
        }
    }

    // Capture the first creature on the tile at menu-open time
    let tileCreature = null;
    if (tile.which.monsters && tile.which.monsters.size > 0) {
        tileCreature = tile.which.monsters.values().next().value;
    }
    menu.__targetCreature = tileCreature;

    // Show/hide Attack button based on monsters on tile
    let attackButton = menu.element.querySelector("button[action=attack]");
    if (attackButton) {
        if (tileCreature) {
            attackButton.style.display = "";
            attackButton.innerHTML = gameClient.player.isCreatureTarget(tileCreature) ? "Stop Attack" : "Attack";
        } else {
            attackButton.style.display = "none";
        }
    }

    // Show/hide Follow button the same way as desktop (mouse.js).
    let followButton = menu.element.querySelector("button[action=follow]");
    if (followButton) {
        if (tileCreature) {
            followButton.style.display = "";
            followButton.innerHTML = gameClient.player.isCreatureFollowTarget(tileCreature) ? "Stop Follow" : "Follow";
        } else {
            followButton.style.display = "none";
        }
    }

    // Show/hide party buttons
    let inviteBtn = menu.element.querySelector("button[action=party-invite]");
    let joinBtn = menu.element.querySelector("button[action=party-join]");
    let leaveBtn = menu.element.querySelector("button[action=party-leave]");
    let kickBtn = menu.element.querySelector("button[action=party-kick]");
    let sharedXpBtn = menu.element.querySelector("button[action=party-shared-xp]");

    if (inviteBtn) inviteBtn.style.display = "none";
    if (joinBtn) joinBtn.style.display = "none";
    if (leaveBtn) leaveBtn.style.display = "none";
    if (kickBtn) kickBtn.style.display = "none";
    if (sharedXpBtn) sharedXpBtn.style.display = "none";

    // Find any other player on the tile
    let targetPlayer = null;
    if (tile.which.monsters && tile.which.monsters.size > 0) {
        tile.which.monsters.forEach(function (creature) {
            if (creature.type === CONST.TYPES.PLAYER && creature !== gameClient.player) {
                targetPlayer = creature;
            }
        });

        if (targetPlayer !== null) {
            menu.__targetCreatureId = targetPlayer.id;
            let myShield = gameClient.player.shield;
            let isInParty = myShield !== CONST.SHIELD.NONE;
            let isLeader = myShield === CONST.SHIELD.LEADER;

            if (!isInParty || isLeader) {
                if (inviteBtn) inviteBtn.style.display = "";
            }
            if (gameClient.player.__pendingPartyInvite === targetPlayer.id) {
                if (joinBtn) joinBtn.style.display = "";
            }
            if (isLeader && targetPlayer.shield === CONST.SHIELD.MEMBER) {
                if (kickBtn) kickBtn.style.display = "";
            }
        }
    }

    if (gameClient.player.shield !== CONST.SHIELD.NONE) {
        if (leaveBtn) leaveBtn.style.display = "";
        if (gameClient.player.shield === CONST.SHIELD.LEADER && sharedXpBtn) {
            sharedXpBtn.style.display = "";
            sharedXpBtn.innerHTML = gameClient.player.__sharedExperienceEnabled ? "Disable Shared XP" : "Enable Shared XP";
        }
    }

    // Show "Message" button when a player is on the tile
    let messageBtn = menu.element.querySelector("button[action=message]");
    if (messageBtn) {
        messageBtn.style.display = "none";
        if (targetPlayer !== null) {
            menu.__targetPlayerName = targetPlayer.name;
            messageBtn.style.display = "";
        }
    }

    // Show "Report Player" with the same target rule as Message — mirror
    // desktop (mouse.js). Sends the /report command; everything else is
    // server-side.
    let reportBtn = menu.element.querySelector("button[action=report]");
    if (reportBtn) {
        reportBtn.style.display = "none";
        if (targetPlayer !== null) {
            menu.__targetPlayerName = targetPlayer.name;
            reportBtn.style.display = "";
        }
    }

    // Show "Trade with..." for pickupable items
    let tradeBtn = menu.element.querySelector("button[action=trade]");
    if (tradeBtn) {
        tradeBtn.style.display = "none";
        if (tile.which.items && tile.which.items.length > 0) {
            let topItem = tile.which.peekItem(0xFF);
            if (topItem && topItem.isPickupable()) {
                tradeBtn.style.display = "";
            }
        }
    }

    // Show "Cook" for cookable items on the ground — mirror desktop
    let cookBtn = menu.element.querySelector("button[action=cook]");
    if (cookBtn) {
        cookBtn.style.display = "none";
        if (tile.which.items && tile.which.items.length > 0) {
            let topItem = tile.which.peekItem(0xFF);
            if (topItem && topItem.sid && Mouse.COOKABLE_SIDS[topItem.sid]) {
                cookBtn.style.display = "";
            }
        }
    }

    // Show "Set Outfit" when the tapped tile contains the player themselves
    let outfitBtn = menu.element.querySelector("button[action=change-outfit]");
    if (outfitBtn) {
        outfitBtn.style.display = "none";
        if (tile.which.monsters && tile.which.monsters.has(gameClient.player)) {
            outfitBtn.style.display = "";
        }
    }

    // Open the context menu at the touch position
    gameClient.interface.menuManager.open("screen-menu", fakeEvent);

    // Visual feedback
    if (navigator.vibrate) {
        navigator.vibrate(50);
    }

}

Touch.prototype.__handleJoystickStart = function (event) {

    /*
     * Function Touch.__handleJoystickStart
     * Handle joystick touch start
     */

    event.preventDefault();

    // Ignore if joystick is already active with another finger
    if (this.joystick.active) {
      return;
    }

    let touch = event.changedTouches[0];

    let rect = this.joystickZone.getBoundingClientRect();

    this.joystick.active = true;
    this.joystick.touchId = touch.identifier;
    this.joystick.activeSince = performance.now();
    this.joystick.__turnDir = null;
    this.joystick.startX = rect.left + rect.width / 2;
    this.joystick.startY = rect.top + rect.height / 2;
    this.joystick.currentX = touch.clientX;
    this.joystick.currentY = touch.clientY;

    this.__updateJoystickVisual();

}

Touch.prototype.__handleJoystickMove = function (event) {

    /*
     * Function Touch.__handleJoystickMove
     * Handle joystick touch move
     */

    if (!this.joystick.active) return;

    event.preventDefault();

    let touch = this.__findTouchById(event.touches, this.joystick.touchId);
    if (!touch) return;

    this.joystick.currentX = touch.clientX;
    this.joystick.currentY = touch.clientY;

    this.__updateJoystickVisual();
    this.__processJoystickInput();

}

Touch.prototype.__handleJoystickEnd = function (event) {

    /*
     * Function Touch.__handleJoystickEnd
     * Handle joystick touch end
     */

    event.preventDefault();

    // Only end if the correct touch was lifted
    if (!this.__findTouchById(event.changedTouches, this.joystick.touchId)) return;

    this.joystick.active = false;
    this.joystick.touchId = null;
    this.joystick.direction = null;
    this.joystick.__turnDir = null;


    // Clear the movement buffer on release to prevent taps from double-stepping
    if (gameClient.player) {
        gameClient.player.__movementBuffer = null;
    }

    // Reset joystick visual
    if (this.joystickKnob) {
        this.joystickKnob.style.transform = 'translate(0, 0)';
    }

}

/* ======================================
   Movement Input Routing (Joystick / D-Pad)
   ====================================== */

Touch.prototype.__handleMovementStart = function (event) {

    /*
     * Function Touch.__handleMovementStart
     * Routes touch start to joystick or d-pad handler
     */

    if (this.__layoutEditActive) return;

    if (this.__isDpadStyle()) {
        this.__handleDpadStart(event);
    } else {
        this.__handleJoystickStart(event);
    }

}

Touch.prototype.__handleMovementMove = function (event) {

    /*
     * Function Touch.__handleMovementMove
     * Routes touch move to joystick or d-pad handler
     */

    if (this.__isDpadStyle()) {
        this.__handleDpadMove(event);
    } else {
        this.__handleJoystickMove(event);
    }

}

Touch.prototype.__handleMovementEnd = function (event) {

    /*
     * Function Touch.__handleMovementEnd
     * Routes touch end to joystick or d-pad handler
     */

    if (this.__isDpadStyle()) {
        this.__handleDpadEnd(event);
    } else {
        this.__handleJoystickEnd(event);
    }

}

/* ======================================
   D-Pad Handlers
   ====================================== */

Touch.prototype.__handleDpadStart = function (event) {

    /*
     * Function Touch.__handleDpadStart
     * Handle d-pad touch start — snap to 8-zone direction immediately.
     * If the touch starts in the center deadzone, activate turn mode:
     * the player can then swipe to a direction to turn without walking.
     */

    event.preventDefault();

    let touch = event.changedTouches[0];

    let rect = this.joystickZone.getBoundingClientRect();
    let centerX = rect.left + rect.width / 2;
    let centerY = rect.top + rect.height / 2;

    // Check if this touch starts in the center deadzone → turn mode
    let dx = touch.clientX - centerX;
    let dy = touch.clientY - centerY;
    let distance = Math.sqrt(dx * dx + dy * dy);

    if (distance < this.JOYSTICK_DEADZONE) {
        if (!this.__dpadTurnMode) {
            this.__dpadTurnMode = true;
            this.__dpadTurnTouchId = touch.identifier;
            this.__dpadLastTurnDirection = null;
            this.joystick.startX = centerX;
            this.joystick.startY = centerY;
            if (this.virtualDpad) {
                let center = this.virtualDpad.querySelector(".dpad-center");
                if (center) center.classList.add("turn-active");
            }
        }
        return;
    }

    // Normal d-pad activation — walk immediately
    this.joystick.active = true;
    this.joystick.touchId = touch.identifier;
    this.joystick.activeSince = performance.now();
    this.joystick.startX = centerX;
    this.joystick.startY = centerY;

    this.__updateDpadFromTouch(touch.clientX, touch.clientY, centerX, centerY);

}

Touch.prototype.__handleDpadMove = function (event) {

    /*
     * Function Touch.__handleDpadMove
     * Handle d-pad touch move — update zone if finger slides.
     * In turn mode, swipe from center to a direction sends a turn packet.
     */

    event.preventDefault();

    // Turn mode: single finger swipe from center to direction
    if (this.__dpadTurnMode) {
        let touch = null;
        for (let i = 0; i < event.touches.length; i++) {
            if (event.touches[i].identifier === this.__dpadTurnTouchId) {
                touch = event.touches[i];
                break;
            }
        }
        if (!touch) return;

        let dx = touch.clientX - this.joystick.startX;
        let dy = touch.clientY - this.joystick.startY;
        let distance = Math.sqrt(dx * dx + dy * dy);

        // Cancel turn mode if finger leaves the d-pad zone
        let rect = this.joystickZone.getBoundingClientRect();
        if (touch.clientX < rect.left || touch.clientX > rect.right ||
            touch.clientY < rect.top || touch.clientY > rect.bottom) {
            this.__dpadTurnMode = false;
            this.__dpadTurnTouchId = null;
            this.__dpadLastTurnDirection = null;
            if (this.virtualDpad) {
                let center = this.virtualDpad.querySelector(".dpad-center");
                if (center) center.classList.remove("turn-active");
            }
            this.__clearDpadHighlights();
            return;
        }

        if (distance < this.JOYSTICK_DEADZONE) {
            // Still in center — clear any arrow highlight
            this.__dpadLastTurnDirection = null;
            this.__clearDpadHighlights();
            return;
        }

        // Compute the turn direction from the SAME zone snap the walk uses
        // (cardinal-biased in dpad8), so turning can't pick a diagonal the walk
        // wouldn't — the highlighted arrow and the turn always agree.
        let angle = Math.atan2(dy, dx) * 180 / Math.PI;
        let zone = this.__dpadZoneFromAngle(angle);
        let zd = Touch.prototype.DPAD_ZONE_DXDY[zone];
        let direction = this.__getCardinalDirection(zd.dx, zd.dy);

        // Highlight the arrow being turned to
        this.__updateDpadHighlights(zone);

        if (direction !== this.__dpadLastTurnDirection) {
            this.__dpadLastTurnDirection = direction;
            if (gameClient && gameClient.player && !gameClient.player.isDead && gameClient.networkManager.isConnected()) {
                gameClient.keyboard.__setTurn(direction);
            }
        }
        return;
    }

    // Normal d-pad movement
    if (!this.joystick.active) return;

    let touch = this.__findTouchById(event.touches, this.joystick.touchId);
    if (!touch) return;

    this.__updateDpadFromTouch(touch.clientX, touch.clientY, this.joystick.startX, this.joystick.startY);

}

Touch.prototype.__handleDpadEnd = function (event) {

    /*
     * Function Touch.__handleDpadEnd
     * Handle d-pad touch end — deactivate turn mode or stop movement
     */

    event.preventDefault();

    // Check if the turn-mode touch ended
    if (this.__dpadTurnMode) {
        for (let i = 0; i < event.changedTouches.length; i++) {
            if (event.changedTouches[i].identifier === this.__dpadTurnTouchId) {
                this.__dpadTurnMode = false;
                this.__dpadTurnTouchId = null;
                this.__dpadLastTurnDirection = null;
                if (this.virtualDpad) {
                    let center = this.virtualDpad.querySelector(".dpad-center");
                    if (center) center.classList.remove("turn-active");
                }
                this.__clearDpadHighlights();
                return;
            }
        }
    }

    // Only end movement if the correct touch was lifted
    if (!this.__findTouchById(event.changedTouches, this.joystick.touchId)) return;

    this.joystick.active = false;
    this.joystick.touchId = null;
    this.joystick.direction = null;
    this.joystick.__turnDir = null;

    // Re-arm the one-step-per-press diagonal gate (dpad8): lifting the finger
    // means the next corner tap walks one diagonal step again.
    this.__dpad8DiagSteppedZone = undefined;

    // Clear the movement buffer on release to prevent taps from double-stepping
    // (mirrors keyboard keyUp behavior)
    if (gameClient.player) {
        gameClient.player.__movementBuffer = null;
    }

    // Clear active arrow highlights
    this.__clearDpadHighlights();

}

Touch.prototype.__updateDpadFromTouch = function (touchX, touchY, centerX, centerY) {

    /*
     * Function Touch.__updateDpadFromTouch
     * Calculates 8-zone direction from touch position and sets joystick dx/dy
     */

    let dx = touchX - centerX;
    let dy = touchY - centerY;
    let distance = Math.sqrt(dx * dx + dy * dy);

    // Deadzone check
    if (distance < this.JOYSTICK_DEADZONE) {
        this.joystick.direction = null;
        this.__dpadCurrentZone = -1;
        this.__clearDpadHighlights();
        return;
    }

    // Calculate angle and snap to a zone. Classic dpad = uniform 45° zones;
    // dpad8 = cardinal-biased (diagonals need a deliberate corner tap) — see
    // __dpadZoneFromAngle.
    let angle = Math.atan2(dy, dx) * 180 / Math.PI; // -180 to 180
    let zone = this.__dpadZoneFromAngle(angle);

    let zoneData = Touch.prototype.DPAD_ZONE_DXDY[zone];
    this.joystick.dx = zoneData.dx;
    this.joystick.dy = zoneData.dy;
    this.joystick.direction = this.__getCardinalDirection(zoneData.dx, zoneData.dy);

    // Track zone changes for stabilization (prevents side-steps at high speed)
    if (zone !== this.__dpadCurrentZone) {
        this.__dpadZoneChangedTime = performance.now();
    }
    this.__dpadCurrentZone = zone;

    // Highlight the active arrow(s)
    this.__updateDpadHighlights(zone);

}

Touch.prototype.__updateDpadHighlights = function (zone) {

    /*
     * Function Touch.__updateDpadHighlights
     * Highlights the active d-pad arrow(s) based on zone
     */

    if (!this.virtualDpad) return;

    let arrows = this.virtualDpad.querySelectorAll(".dpad-arrow");
    arrows.forEach(function(a) { a.classList.remove("active"); });

    // Zone to arrow mapping: highlight relevant arrows
    // Cardinal zones light one arrow, diagonal zones light two
    let up = this.virtualDpad.querySelector(".dpad-up");
    let right = this.virtualDpad.querySelector(".dpad-right");
    let down = this.virtualDpad.querySelector(".dpad-down");
    let left = this.virtualDpad.querySelector(".dpad-left");

    // During a layout swap (tablet ↔ phone reflow, fullscreen toggle,
    // rotation) virtualDpad may still be the old DOM node whose children
    // were already removed. Reported 2026-05-25 (Dam Wang) "null is not
    // an object (evaluating 'down.classList'/'right.classList')." Bail
    // out if any arrow is missing — the next highlight tick after the
    // DOM rebuild will paint correctly.
    if (!up || !right || !down || !left) return;

    // 8-way mode: a diagonal zone lights its dedicated corner arrow instead of
    // the two cardinals. Null-guarded (stale cached markup without the corners
    // falls back to the classic two-cardinal highlight).
    let dpad8 = this.virtualDpad.classList.contains("dpad8");
    let corner = function (sel) { return dpad8 ? this.virtualDpad.querySelector(sel) : null; }.bind(this);

    switch (zone) {
        case 0: right.classList.add("active"); break;           // E
        case 1: {                                               // SE
            let c = corner(".dpad-downright");
            if (c) c.classList.add("active");
            else { right.classList.add("active"); down.classList.add("active"); }
            break;
        }
        case 2: down.classList.add("active"); break;            // S
        case 3: {                                               // SW
            let c = corner(".dpad-downleft");
            if (c) c.classList.add("active");
            else { left.classList.add("active"); down.classList.add("active"); }
            break;
        }
        case 4: left.classList.add("active"); break;            // W
        case 5: {                                               // NW
            let c = corner(".dpad-upleft");
            if (c) c.classList.add("active");
            else { left.classList.add("active"); up.classList.add("active"); }
            break;
        }
        case 6: up.classList.add("active"); break;              // N
        case 7: {                                               // NE
            let c = corner(".dpad-upright");
            if (c) c.classList.add("active");
            else { right.classList.add("active"); up.classList.add("active"); }
            break;
        }
    }

}

Touch.prototype.__clearDpadHighlights = function () {

    /*
     * Function Touch.__clearDpadHighlights
     * Removes active state from all d-pad arrows
     */

    if (!this.virtualDpad) return;

    let arrows = this.virtualDpad.querySelectorAll(".dpad-arrow");
    arrows.forEach(function(a) { a.classList.remove("active"); });

}

/* ======================================
   Movement Style Toggle
   ====================================== */

Touch.prototype.setScreenProtectorMode = function (enabled) {

    /*
     * Function Touch.setScreenProtectorMode
     * Adjusts touch sensitivity for users with screen protectors.
     * Reduces long-press duration and increases move threshold to
     * compensate for extra friction and jitter from screen protectors.
     */

    this.__screenProtectorMode = enabled;
    this.LONG_PRESS_DURATION = enabled ? 50 : 100;
    this.DRAG_MOVE_THRESHOLD = enabled ? 40 : 20;

}

Touch.prototype.setMovementStyle = function (style) {

    /*
     * Function Touch.setMovementStyle
     * Switches between analog stick and d-pad
     */

    this.movementStyle = style;
    this.__applyMovementStyle();

}

Touch.prototype.__isDpadStyle = function () {

    /*
     * Function Touch.__isDpadStyle
     * True for BOTH d-pad movement styles: classic 4-arrow "dpad" and the
     * 8-way "dpad8" (same zone/angle handling; dpad8 only adds the visible
     * diagonal corner arrows). Anything else = analog stick.
     */

    return this.movementStyle === "dpad" || this.movementStyle === "dpad8";

}

Touch.prototype.__dpadZoneFromAngle = function (angle) {

    /*
     * Function Touch.__dpadZoneFromAngle
     * Maps a touch angle (degrees, any range) to a d-pad zone 0-7 (0=E … 7=NE).
     *
     * Classic "dpad": uniform 45° zones (unchanged shipped behaviour).
     * "dpad8": CARDINAL-BIASED — each cardinal owns ±DPAD8_CARDINAL_HALF_ARC°
     * around its axis and the diagonals only get the remaining corner gap, so a
     * press that overlaps a cardinal and a diagonal always resolves to the
     * CARDINAL; walking diagonally takes a deliberate tap near the corner
     * (owner 2026-07-02).
     */

    let a = ((angle % 360) + 360) % 360;   // normalize to 0..360

    if (this.movementStyle !== "dpad8") {
        let zone = Math.round(a / 45);
        return (zone >= 8) ? 0 : zone;
    }

    let half = Touch.prototype.DPAD8_CARDINAL_HALF_ARC;
    let nearestCardinal = Math.round(a / 90) * 90;          // 0, 90, 180, 270, 360
    if (Math.abs(a - nearestCardinal) <= half) {
        return ((nearestCardinal / 90) * 2) % 8;            // 0, 2, 4, 6
    }
    return (Math.floor(a / 90) * 2 + 1) % 8;                // 1, 3, 5, 7 (the corner gap)

}

Touch.prototype.__applyMovementStyle = function () {

    /*
     * Function Touch.__applyMovementStyle
     * Shows/hides the correct movement control element
     */

    let isDpad = this.__isDpadStyle();

    if (this.virtualJoystick) {
        this.virtualJoystick.style.display = isDpad ? "none" : "";
    }
    if (this.virtualDpad) {
        this.virtualDpad.style.display = isDpad ? "" : "none";
        // 8-way variant: reveals the diagonal corner arrows (CSS .dpad8 .dpad-diag)
        this.virtualDpad.classList.toggle("dpad8", this.movementStyle === "dpad8");
    }
    if (this.joystickZone) {
        this.joystickZone.classList.toggle("dpad-active", isDpad);
        this.joystickZone.style.visibility = "";
        this.joystickZone.style.pointerEvents = "";
    }

}

Touch.prototype.__updateJoystickVisual = function () {

    /*
     * Function Touch.__updateJoystickVisual
     * Update the visual position of the joystick knob
     */

    if (!this.joystickKnob) return;

    let dx = this.joystick.currentX - this.joystick.startX;
    let dy = this.joystick.currentY - this.joystick.startY;

    // Limit to joystick bounds
    let maxOffset = 30;
    let distance = Math.sqrt(dx * dx + dy * dy);

    if (distance > maxOffset) {
        dx = (dx / distance) * maxOffset;
        dy = (dy / distance) * maxOffset;
    }

    this.joystickKnob.style.transform = `translate(${dx}px, ${dy}px)`;

}

Touch.prototype.__processJoystickInput = function () {

    /*
     * Function Touch.__processJoystickInput
     * Process joystick position and update direction.
     * Actual movement is handled per-frame by handleInput().
     */

    let dx = this.joystick.currentX - this.joystick.startX;
    let dy = this.joystick.currentY - this.joystick.startY;
    let distance = Math.sqrt(dx * dx + dy * dy);

    // Deadzone check
    if (distance < this.JOYSTICK_DEADZONE) {
        this.joystick.direction = null;
        this.joystick.__turnDir = null;
        return;
    }

    // Turn zone (optional, "Joystick turn zone" setting): a light nudge between
    // the deadzone and JOYSTICK_WALK_THRESHOLD only TURNS the player to face the
    // direction — no walking. handleInput() bails when joystick.direction is
    // null, so leaving it null here suppresses movement. A turn packet is sent
    // only when the faced direction changes (no per-frame spam). Push past the
    // threshold to walk.
    let settings = gameClient.interface && gameClient.interface.settings;
    let turnZoneOn = settings && typeof settings.isJoystickTurnZoneEnabled === "function"
        && settings.isJoystickTurnZoneEnabled();

    if (turnZoneOn && distance < this.JOYSTICK_WALK_THRESHOLD) {
        let turnDir = this.__getCardinalDirection(dx, dy);
        if (turnDir !== this.joystick.__turnDir) {
            this.joystick.__turnDir = turnDir;
            if (gameClient && gameClient.player && !gameClient.player.isDead
                && gameClient.networkManager.isConnected() && gameClient.keyboard
                && typeof gameClient.keyboard.__setTurn === "function") {
                gameClient.keyboard.__setTurn(turnDir);
            }
        }
        this.joystick.direction = null; // suppress walking while only turning
        return;
    }

    // Walk zone — clear the turn latch and feed the per-frame mover as before.
    this.joystick.__turnDir = null;

    // Store raw deltas for smart direction computation in handleInput
    this.joystick.dx = dx;
    this.joystick.dy = dy;

    // Compute the raw cardinal direction for immediate visual feedback
    this.joystick.direction = this.__getCardinalDirection(dx, dy);

}

Touch.prototype.__findTouchById = function (touchList, id) {

    /*
     * Function Touch.__findTouchById
     * Finds a touch in a TouchList by its identifier, returns null if not found
     */

    if (id === null) return null;

    for (let i = 0; i < touchList.length; i++) {
        if (touchList[i].identifier === id) {
            return touchList[i];
        }
    }

    return null;

}

Touch.prototype.__getCardinalDirection = function (dx, dy) {

    /*
     * Function Touch.__getCardinalDirection
     * Returns the nearest cardinal direction (4-way) from joystick deltas
     */

    if (Math.abs(dx) >= Math.abs(dy)) {
        return dx > 0 ? CONST.DIRECTION.EAST : CONST.DIRECTION.WEST;
    }
    return dy > 0 ? CONST.DIRECTION.SOUTH : CONST.DIRECTION.NORTH;

}

Touch.prototype.__getSmartDirection = function () {

    /*
     * Function Touch.__getSmartDirection
     * Computes a movement direction that prefers cardinal movement.
     * Only moves diagonally when the primary cardinal direction is blocked
     * and the joystick has enough secondary-axis deflection.
     * This prevents accidental diagonal movement on open terrain.
     */

    let dx = this.joystick.dx;
    let dy = this.joystick.dy;
    let absDx = Math.abs(dx);
    let absDy = Math.abs(dy);

    // Cardinal directions from each axis
    let horizontalDir = dx > 0 ? CONST.DIRECTION.EAST : CONST.DIRECTION.WEST;
    let verticalDir = dy > 0 ? CONST.DIRECTION.SOUTH : CONST.DIRECTION.NORTH;

    // 8-Way D-Pad: a diagonal zone is a DELIBERATE corner tap — the dpad8 zone
    // snap already biases cardinals (diagonals only fire in the narrow ~29°
    // corner gap), so honour the diagonal directly. The cardinal-preference
    // logic below exists to stop ACCIDENTAL diagonals from imprecise presses
    // on the classic pad / analog stick, which can't happen here — with it, a
    // corner tap walked the primary cardinal on open ground (owner report
    // 2026-07-02: "tapping a diagonal doesn't walk diagonal").
    if (this.movementStyle === "dpad8" && dx !== 0 && dy !== 0) {
        return this.__composeDiagonal(horizontalDir, verticalDir);
    }

    // Primary is the axis with larger deflection
    let primaryDir = (absDx >= absDy) ? horizontalDir : verticalDir;

    // Check if secondary axis has enough deflection for diagonal intent (~22° off primary axis)
    let minorAxis = Math.min(absDx, absDy);
    let majorAxis = Math.max(absDx, absDy);
    let hasDiagonalIntent = majorAxis > 0 && (minorAxis / majorAxis) > 0.4;

    if (!hasDiagonalIntent) {
        return primaryDir;
    }

    // There is diagonal intent — check if primary cardinal is blocked
    let position = gameClient.player.getPosition();
    let primaryPos = this.__getPositionForDirection(position, primaryDir);

    if (primaryPos === null) {
        return primaryDir;
    }

    // Check if tile exists and is blocked (null tile = unknown, treat as walkable)
    let primaryTile = gameClient.world.getTileFromWorldPosition(primaryPos);

    if (primaryTile === null || !primaryTile.isOccupied()) {
        // Primary cardinal is walkable — use it
        return primaryDir;
    }

    // Primary blocked — check secondary cardinal before resorting to diagonal
    let secondaryDir = (absDx >= absDy) ? verticalDir : horizontalDir;
    let secondaryPos = this.__getPositionForDirection(position, secondaryDir);

    if (secondaryPos !== null) {
        let secondaryTile = gameClient.world.getTileFromWorldPosition(secondaryPos);
        if (secondaryTile === null || !secondaryTile.isOccupied()) {
            // Secondary cardinal is walkable — use it instead of diagonal
            return secondaryDir;
        }
    }

    // Both cardinals blocked — diagonal is the only way
    return this.__composeDiagonal(horizontalDir, verticalDir);

}

Touch.prototype.__getPositionForDirection = function (position, direction) {

    /*
     * Function Touch.__getPositionForDirection
     * Returns the adjacent position for a given direction
     */

    switch (direction) {
        case CONST.DIRECTION.NORTH: return position.north();
        case CONST.DIRECTION.SOUTH: return position.south();
        case CONST.DIRECTION.EAST: return position.east();
        case CONST.DIRECTION.WEST: return position.west();
        case CONST.DIRECTION.NORTHEAST: return position.northeast();
        case CONST.DIRECTION.NORTHWEST: return position.northwest();
        case CONST.DIRECTION.SOUTHEAST: return position.southeast();
        case CONST.DIRECTION.SOUTHWEST: return position.southwest();
        default: return null;
    }

}

Touch.prototype.__composeDiagonal = function (horizontalDir, verticalDir) {

    /*
     * Function Touch.__composeDiagonal
     * Combines a horizontal and vertical cardinal into a diagonal direction
     */

    if (verticalDir === CONST.DIRECTION.NORTH) {
        return horizontalDir === CONST.DIRECTION.EAST ? CONST.DIRECTION.NORTHEAST : CONST.DIRECTION.NORTHWEST;
    }
    return horizontalDir === CONST.DIRECTION.EAST ? CONST.DIRECTION.SOUTHEAST : CONST.DIRECTION.SOUTHWEST;

}

Touch.prototype.DIRECTION_TO_KEY = {
    0: 38,  // NORTH → UP_ARROW
    1: 39,  // EAST → RIGHT_ARROW
    2: 40,  // SOUTH → DOWN_ARROW
    3: 37,  // WEST → LEFT_ARROW
    4: 34,  // SOUTHEAST → KEYPAD_3
    5: 35,  // SOUTHWEST → KEYPAD_1
    6: 33,  // NORTHEAST → KEYPAD_9
    7: 36   // NORTHWEST → KEYPAD_7
};

Touch.prototype.handleInput = function () {

    /*
     * Function Touch.handleInput
     * Called every frame from the game loop. Handles joystick movement
     * using the same frame-based approach as the keyboard for smooth walking.
     * Uses the movement buffer for seamless step chaining.
     */


    if (!this.joystick.active || this.joystick.direction === null) return;
    if (!gameClient || !gameClient.networkManager.isConnected()) return;
    if (gameClient.player && gameClient.player.isDead) return;

    // Self-heal a prediction queue gone stale (lost server confirm/cancel
    // after a mobile reconnect) before the walk gate reads its length.
    if (gameClient.player) {
      gameClient.player.prunePreWalks();
    }

    // Predict-ahead bounded by MAX_PREDICT_AHEAD (see Player.MAX_PREDICT_AHEAD).
    // Bypassed under Burst Walk or Semi-Burst Walk — see
    // Settings.getBurstWalkCap() for the active cap (3 / 2 / 0).
    // Earlier this gate only checked isBurstWalkEnabled() and ignored
    // Semi-Burst, so the touch d-pad / joystick path forced Semi-Burst
    // (the new default!) into Legacy cap=1 behavior. Aligned now.
    let __burstCap = gameClient.interface && gameClient.interface.settings
      && gameClient.interface.settings.getBurstWalkCap
      ? gameClient.interface.settings.getBurstWalkCap()
      : (gameClient.interface && gameClient.interface.settings
         && gameClient.interface.settings.isBurstWalkEnabled
         && gameClient.interface.settings.isBurstWalkEnabled() ? 3 : 0);
    let __queueOK = gameClient.player &&
      gameClient.player.__preWalks &&
      __burstCap > 0 &&
      gameClient.player.__preWalks.length < __burstCap &&
      !gameClient.player.__predictionFrozen;
    // Post-teleport burst suspend — see handleSelfTeleport.
    let __burstSuspended = gameClient.player &&
      gameClient.player.__burstSuspendedUntil > Date.now();
    let __burstWalk = __burstCap > 0 &&
      gameClient.isConnected && gameClient.isConnected() &&
      __queueOK &&
      !__burstSuspended;
    if (!__burstWalk && gameClient.player.__preWalks.length >= gameClient.player.MAX_PREDICT_AHEAD) return;

    // Cancel pathfinding on any d-pad input so map-click walks are interrupted
    gameClient.world.pathfinder.setPathfindCache(null);

    // Compute smart direction (cardinal preferred, diagonal only when blocked;
    // dpad8 diagonal zones walk their true diagonal — see __getSmartDirection)
    let direction = this.__getSmartDirection();

    // 8-Way D-Pad: a DIAGONAL responds to a single TAP only — one step per
    // press, never hold-to-repeat (owner 2026-07-02; diagonal steps cost ~3x,
    // so a held corner racing off diagonally is never what the thumb meant).
    // Re-arms when the finger lifts (__handleDpadEnd) or slides to another
    // zone. Cardinals keep normal hold-to-walk.
    if (this.__dpad8DiagSteppedZone !== undefined
        && this.__dpad8DiagSteppedZone !== this.__dpadCurrentZone) {
        this.__dpad8DiagSteppedZone = undefined;   // left the stepped corner — re-arm
    }
    if (this.movementStyle === "dpad8" && this.joystick.dx !== 0 && this.joystick.dy !== 0) {
        if (this.__dpad8DiagSteppedZone === this.__dpadCurrentZone) {
            return;   // already stepped this press — wait for lift / zone change
        }
        this.__dpad8DiagSteppedZone = this.__dpadCurrentZone;
    }

    // Map direction to a keycode for the movement buffer
    let key = this.DIRECTION_TO_KEY[direction];

    // If currently moving, buffer the next step. Zone must be stable for
    // 20ms to prevent side-steps from quick zone flickers — was 50ms,
    // which made the chain-step gate too strict on touch (any micro-jitter
    // of the thumb resets the timer, leaving visible pauses between steps
    // while holding the joystick). 20ms still filters real flicker but
    // lets steady holds chain smoothly.
    if (gameClient.player.isMoving()) {
        let zoneStable = (performance.now() - this.__dpadZoneChangedTime) > 20;
        if (key !== undefined && zoneStable) {
            gameClient.player.extendMovementBuffer(key);
        }
        return;
    }

    // Execute the move
    gameClient.keyboard.handleMoveKey(direction);

}

Touch.prototype.__handleLookButton = function (event) {

    /*
     * Function Touch.__handleLookButton
     * Toggle Look mode
     */

    event.preventDefault();

    if (this.actionMode === 'look') {
        this.__clearActionMode();
    } else {
        this.actionMode = 'look';
        this.__updateActionButtonHighlights();
    }

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__handleUseButton = function (event) {

    /*
     * Function Touch.__handleUseButton
     * Toggle Use mode
     */

    event.preventDefault();

    if (this.actionMode === 'use') {
        this.__clearActionMode();
    } else {
        this.actionMode = 'use';
        this.__updateActionButtonHighlights();
    }

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.toggleContextMode = function () {

    /*
     * Function Touch.toggleContextMode
     * Toggles context-menu mode. While armed, the next tap on a tile,
     * creature or item opens the on-screen context menu — the same path
     * the two-finger-tap shortcut uses. Invoked by the "Context Menu"
     * hotbar action (which replaced the removed floating button).
     */

    if (this.actionMode === 'context') {
        this.__clearActionMode();
    } else {
        this.actionMode = 'context';
        // Mirror the two-finger-tap path: show the "tap a target" hint.
        let indicator = document.getElementById("mobile-use-indicator");
        if (indicator) {
            indicator.textContent = "📋 Tap for menu";
            indicator.classList.add("active");
        }
    }

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__handleAttackButton = function (event) {

    /*
     * Function Touch.__handleAttackButton
     * Attack current target
     */

    event.preventDefault();

    if (!gameClient || !gameClient.player) return;

    let target = gameClient.player.getTarget();

    if (target) {
        // Already have a target - attack it
        gameClient.send(new TargetPacket(target.getId()));
    } else {
        // No target — open the People panel directly on the Battle sub-tab
        // so the user can pick a creature from the nearby-list instead of
        // chasing a fast-moving sprite with their finger.
        this.__openSocialTab('battle');
    }

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(50);

}

Touch.prototype.__handleMenuButton = function (event) {

    /*
     * Function Touch.__handleMenuButton
     * Open mobile menu / settings
     */

    event.preventDefault();

    // Check if modal is already open, close it if so — but respect
    // handleCancel refusal (CaptchaModal must not be dismissed by
    // tapping the settings gear).
    if (gameClient.interface.modalManager.isOpened()) {
        let modal = gameClient.interface.modalManager.__openedModal;
        if (modal && modal.handleCancel && modal.handleCancel() === false) return;
        gameClient.interface.modalManager.close();
    } else {
        // Open settings modal
        gameClient.interface.modalManager.open("settings-modal");
    }

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__clearActionMode = function () {

    this.actionMode = null;
    this.__clearActionButtonHighlights();

    // Hide mobile look/targeting indicator
    let indicator = document.getElementById("mobile-use-indicator");
    if (indicator) {
        indicator.classList.remove("active");
    }

}

Touch.prototype.__updateActionButtonHighlights = function () {

    /*
     * Function Touch.__updateActionButtonHighlights
     * Update button visual state based on current mode
     */

    this.__clearActionButtonHighlights();

    if (this.actionMode === 'look' && this.lookBtn) {
        this.lookBtn.style.boxShadow = '0 0 10px 3px #4444ff';
    } else if (this.actionMode === 'use' && this.useBtn) {
        this.useBtn.style.boxShadow = '0 0 10px 3px #44ff44';
    }

}

Touch.prototype.__clearActionButtonHighlights = function () {

    if (this.lookBtn) this.lookBtn.style.boxShadow = '';
    if (this.useBtn) this.useBtn.style.boxShadow = '';

}

Touch.prototype.updateStatusBars = function (health, healthMax, mana, manaMax) {

    /*
     * Function Touch.updateStatusBars
     * Update mobile status bars with current HP/MP values
     */

    if (!this.isMobileMode) return;

    let healthPercent = healthMax > 0 ? Math.min(100, (health / healthMax) * 100) : 0;
    let manaPercent = manaMax > 0 ? Math.min(100, (mana / manaMax) * 100) : 0;
    let healthStr = health + ' / ' + healthMax;
    let manaStr = mana + ' / ' + manaMax;

    if (this.healthBar) this.healthBar.style.width = healthPercent + '%';
    if (this.healthText) this.healthText.textContent = healthStr;
    if (this.manaBar) this.manaBar.style.width = manaPercent + '%';
    if (this.manaText) this.manaText.textContent = manaStr;

    // Portrait bars (below canvas)
    if (this.portraitHealthBar) this.portraitHealthBar.style.width = healthPercent + '%';
    if (this.portraitHealthText) this.portraitHealthText.textContent = healthStr;
    if (this.portraitManaBar) this.portraitManaBar.style.width = manaPercent + '%';
    if (this.portraitManaText) this.portraitManaText.textContent = manaStr;

}

Touch.prototype.__handleInventoryButton = function (event) {

    /*
     * Function Touch.__handleInventoryButton
     * Open inventory / equipment window
     */

    event.preventDefault();

    if (!gameClient || !gameClient.player) return;

    // Try to open the first container (backpack) or equipment window
    let containers = Array.from(gameClient.player.__openedContainers || []);

    if (containers.length > 0) {
        // Toggle visibility of existing containers
        containers.forEach(container => {
            if (container.window) {
                let display = container.window.style.display;
                container.window.style.display = (display === 'none') ? 'block' : 'none';
            }
        });
    } else {
        // Show a message that no containers are open
        gameClient.interface.setCancelMessage("No backpack open. Use a backpack first.");
    }

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__handleEquipmentButton = function (event) {

    /*
     * Function Touch.__handleEquipmentButton
     * Toggle equipment panel via tab system
     */

    event.preventDefault();

    this.__switchTab('equipment');

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__bindTabBar = function () {

    /*
     * Function Touch.__bindTabBar
     * Bind touch events to mobile tab bar buttons
     */

    let tabBar = document.getElementById('mobile-tab-bar');
    if (!tabBar) return;

    tabBar.addEventListener('touchstart', this.__handleTabBarTouch.bind(this), { passive: false });
    tabBar.addEventListener('click', this.__handleTabBarTouch.bind(this));

    // Bind swap button
    let swapBtn = tabBar.querySelector('[data-action="swap"]');
    if (swapBtn) {
        swapBtn.addEventListener('touchstart', this.__handleTabSwap.bind(this), { passive: false });
        swapBtn.addEventListener('click', this.__handleTabSwap.bind(this));
    }

}

Touch.prototype.__getTabPanels = function () {

    /*
     * Function Touch.__getTabPanels
     * Lazily resolve references to the four tab panel elements
     */

    if (this.__panelRefs) return this.__panelRefs;

    this.__panelRefs = {
        equipment: document.querySelector('.equipment.wrapper'),
        minimap: document.querySelector('.minimap-container'),
        stats: document.getElementById('skill-window'),
        friends: document.getElementById('friend-window')
    };

    return this.__panelRefs;

}

Touch.prototype.__handleTabBarTouch = function (event) {

    /*
     * Function Touch.__handleTabBarTouch
     * Handle touch on a tab bar button — switch active panel
     */

    event.preventDefault();

    let button = event.target.closest('.mobile-tab');
    if (!button) return;

    // Menu button opens the general menu modal directly (was the quest/trophy
    // button; the Quest Log is now one entry inside the menu).
    if (button.getAttribute('data-action') === 'menu') {
      if (gameClient && gameClient.interface && gameClient.interface.modalManager) {
        gameClient.interface.modalManager.open("menu-modal");
      }
      if (navigator.vibrate) navigator.vibrate(30);
      return;
    }

    let tabName = button.getAttribute('data-tab');
    if (!tabName) return;

    this.__switchTab(tabName);

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__handleTabSwap = function (event) {

    /*
     * Function Touch.__handleTabSwap
     * Toggle tab bar position between left and right
     */

    event.preventDefault();
    event.stopPropagation();

    this.tabPosition = (this.tabPosition === 'right') ? 'left' : 'right';
    localStorage.setItem('mobile-tab-position', this.tabPosition);
    this.__applyTabPosition();

    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__applyTabPosition = function () {

    /*
     * Function Touch.__applyTabPosition
     * Apply the current tab position (left/right) to all relevant elements
     */

    let isLeft = (this.tabPosition === 'left');
    let tabBar = document.getElementById('mobile-tab-bar');
    let panels = this.__getTabPanels();

    // Toggle on body for global CSS rules (e.g. container positioning)
    document.body.classList.toggle('mobile-tab-left', isLeft);

    // Toggle on tab bar
    if (tabBar) {
        tabBar.classList.toggle('mobile-tab-left', isLeft);
    }

    // Toggle on equipment wrapper
    if (panels.equipment) {
        panels.equipment.classList.toggle('mobile-tab-left', isLeft);
    }

    // Toggle on any currently visible tab panels
    let activePanels = document.querySelectorAll('.mobile-tab-panel');
    activePanels.forEach(function (panel) {
        panel.classList.toggle('mobile-tab-left', isLeft);
    });

    // Reposition any open container windows to the opposite side
    let containers = document.querySelectorAll('.window[containerIndex]');
    containers.forEach(function (container) {
        if (isLeft) {
            container.style.setProperty('left', 'auto', 'important');
            container.style.setProperty('right', '5px', 'important');
            container.style.setProperty('transform-origin', 'top right', 'important');
        } else {
            container.style.setProperty('left', '5px', 'important');
            container.style.setProperty('right', 'auto', 'important');
            container.style.setProperty('transform-origin', 'top left', 'important');
        }
    });

    // Reposition mobile container panel to the opposite side of equipment
    // (skip if user has a custom layout — layout editor manages positioning)
    if (!document.body.classList.contains('layout-custom')) {
        let containerPanel = document.getElementById('mobile-container-panel');
        if (containerPanel) {
            if (isLeft) {
                containerPanel.style.setProperty('left', 'auto', 'important');
                containerPanel.style.setProperty('right', '5px', 'important');
                containerPanel.style.setProperty('transform-origin', 'top right', 'important');
            } else {
                containerPanel.style.setProperty('left', '5px', 'important');
                containerPanel.style.setProperty('right', 'auto', 'important');
                containerPanel.style.setProperty('transform-origin', 'top left', 'important');
            }
        }
    }

    // Re-stack panels after position change
    if (this.__visiblePanels) {
        this.__stackPanels();
    }

}

Touch.prototype.__switchTab = function (tabName) {

    /*
     * Function Touch.__switchTab
     * Toggle a tab panel on or off independently.
     * Centered panels (minimap, stats, friends) are mutually exclusive —
     * opening one closes the others to prevent overlapping.
     */

    // Guard: __visiblePanels is null after __cleanup() tears down mobile
    // mode — a tab tap arriving after teardown must not crash.
    if (!this.__visiblePanels) {
        return;
    }

    if (this.__visiblePanels.has(tabName)) {
        this.__hidePanel(tabName);
        this.__visiblePanels.delete(tabName);
    } else {
        // Only one panel can be open at a time — close all others first
        let self = this;
        this.__visiblePanels.forEach(function (other) {
            if (other !== tabName) {
                self.__hidePanel(other);
            }
        });
        this.__visiblePanels.clear();
        this.__showPanel(tabName);
        this.__visiblePanels.add(tabName);
    }

    this.__updateTabButtons();
    this.__stackPanels();

}

Touch.prototype.__showPanel = function (tabName) {

    /*
     * Function Touch.__showPanel
     * Show the panel for the given tab name
     */

    // The 'friends' tab is actually a combined People panel with two sub-tabs
    // (Friends + Battle). Show whichever sub-tab was last selected.
    if (tabName === 'friends') {
        this.__showSocialSubTab(this.__socialSubTab);
        return;
    }

    let panels = this.__getTabPanels();
    let panel = panels[tabName];

    if (!panel) return;

    // Re-apply any custom position saved via LayoutEditor BEFORE we make
    // the panel visible. The hide path clears the `top: auto` override
    // from the saved layout, so when the display: none is removed the
    // element briefly inherits its CSS default `top: 37px` — which
    // conflicts with the saved `bottom: Xpx` and visually stretches /
    // displaces the panel for one frame. Applying the saved position
    // first means when display flips on, `top: auto` is already back in
    // place and there's no conflict.
    if (this.layoutEditor) {
        let cfgId = null;
        if (tabName === 'stats') cfgId = 'skillWindow';
        else if (tabName === 'minimap') cfgId = 'minimap';
        else if (tabName === 'equipment') cfgId = 'equipment';
        if (cfgId) this.layoutEditor.reapplyElement(cfgId);
    }

    if (tabName === 'equipment') {
        // Remove inline display override so CSS rules take effect
        panel.style.removeProperty('display');
    } else {
        panel.classList.add('mobile-tab-panel');
        if (this.tabPosition === 'left') {
            panel.classList.add('mobile-tab-left');
        }
    }

}

Touch.prototype.__showSocialSubTab = function (subTab) {

    /*
     * Function Touch.__showSocialSubTab
     * Show the Friends or Battle sub-tab of the merged People panel.
     * On mobile, WindowManager merges both into #friend-window with two
     * body panels (.friends-body / .battle-body). This just toggles which
     * body is visible and ensures the window has the mobile-tab-panel class.
     */

    let peopleWindow = document.getElementById('friend-window');
    if (!peopleWindow) return;

    peopleWindow.classList.add('mobile-tab-panel');
    if (this.tabPosition === 'left') {
        peopleWindow.classList.add('mobile-tab-left');
    }

    if (gameClient && gameClient.interface && typeof gameClient.interface.setPeopleSubTab === 'function') {
        gameClient.interface.setPeopleSubTab(subTab);
    }

    if (this.layoutEditor) {
        this.layoutEditor.reapplyElement('friendWindow');
    }

}

Touch.prototype.__openSocialTab = function (subTab) {

    /*
     * Function Touch.__openSocialTab
     * Programmatically open the People panel on the given sub-tab. Used by
     * callers that want to jump the user straight to the Battle list (e.g.
     * the "attack target" hotbar action when no target is set).
     */

    if (subTab !== 'friends' && subTab !== 'battle') subTab = 'friends';

    this.__socialSubTab = subTab;
    try { localStorage.setItem('mobile-social-subtab', subTab); } catch (e) {}

    // Close any other visible mutually-exclusive panel first.
    let self = this;
    this.__visiblePanels.forEach(function (other) {
        if (other !== 'friends') self.__hidePanel(other);
    });
    this.__visiblePanels.clear();

    this.__showSocialSubTab(subTab);
    this.__visiblePanels.add('friends');
    this.__updateTabButtons();
    this.__stackPanels();

}

Touch.prototype.__bindPeopleSubtabs = function () {

    /*
     * Function Touch.__bindPeopleSubtabs
     * Wire clicks on the Friends / Battle sub-tab buttons (present inside
     * both friend-window and battle-window) to switch which window is shown.
     */

    let self = this;
    document.querySelectorAll('.people-subtab').forEach(function (btn) {
        let handler = function (event) {
            event.preventDefault();
            event.stopPropagation();
            let sub = btn.getAttribute('data-people-subtab');
            if (!sub) return;
            self.__socialSubTab = sub;
            try { localStorage.setItem('mobile-social-subtab', sub); } catch (e) {}
            self.__showSocialSubTab(sub);
            if (navigator.vibrate) navigator.vibrate(20);
        };
        btn.addEventListener('click', handler);
        btn.addEventListener('touchstart', handler, { passive: false });
    });

}

Touch.prototype.__hidePanel = function (tabName) {

    /*
     * Function Touch.__hidePanel
     * Hide the panel for the given tab name
     */

    // On mobile the People tab is a single #friend-window with two body
    // panels — normal hide flow applies. battle-window was hidden by the
    // WindowManager merge so nothing extra to clean up here.

    let panels = this.__getTabPanels();
    let panel = panels[tabName];

    if (!panel) return;

    // Remove minimized state when hiding
    panel.classList.remove('mobile-minimized');
    let minBtn = panel.querySelector('.mobile-panel-minimize');
    if (minBtn) minBtn.textContent = '\u2212';

    // Clear inline top set by stacking
    panel.style.removeProperty('top');

    if (tabName === 'equipment') {
        // Use !important to override tablet CSS (body.force-tablet .equipment.wrapper { display: grid !important })
        panel.style.setProperty('display', 'none', 'important');
    } else {
        panel.classList.remove('mobile-tab-panel');
        panel.classList.remove('mobile-tab-left');
        panel.style.display = '';
    }

}

Touch.prototype.__updateTabButtons = function () {

    /*
     * Function Touch.__updateTabButtons
     * Update tab button visual state to reflect all active tabs
     */

    let self = this;
    let buttons = document.querySelectorAll('#mobile-tab-bar .mobile-tab');

    buttons.forEach(function (btn) {
        let tab = btn.getAttribute('data-tab');
        if (self.__visiblePanels && self.__visiblePanels.has(tab)) {
            btn.classList.add('active');
        } else {
            btn.classList.remove('active');
        }
    });

}

Touch.prototype.notifyNewMessage = function (channel, isConsole) {

    /*
     * Function Touch.notifyNewMessage
     * Delegates to MobileChat for unread badge and live message updates
     */

    if (this.mobileChat) {
        this.mobileChat.onNewMessage(channel, isConsole);
    }

}

Touch.prototype.notifyNewDM = function () {

    /*
     * Function Touch.notifyNewDM
     * Delegates to MobileChat for DM badge
     */

    if (this.mobileChat) {
        this.mobileChat.onNewDM();
    }

}

Touch.prototype.__bindHotbarSlots = function () {

    /*
     * Function Touch.__bindHotbarSlots
     * Bind touch events to mobile hotbar slots
     */

    this.__hotbarEditMode = false;

    // Only bind actual hotbar slots (with data-slot attribute), not the edit button
    let slots = document.querySelectorAll('.mobile-hotbar-slot[data-slot]');

    // Bind edit mode toggle button. DUAL behavior, decided at event time:
    // default = toggles hotbar edit mode (unchanged); with the
    // "edit button as 9th slot" setting on (Settings > Controls) it acts
    // as hotbar slot index 11 — edit mode is then toggled from Settings.
    const EDIT_SLOT_INDEX = 11;
    let editBtn = document.getElementById('mobile-hotbar-edit-btn');
    let editBtnIsSlot = function () {
        return editBtn.hasAttribute('data-slot');
    };
    if (editBtn) {
        editBtn.addEventListener('touchstart', (e) => {
            e.preventDefault();
            if (!editBtnIsSlot()) return;
            // Slot behavior — mirrors the regular slot touchstart below.
            if (this.__layoutEditActive || this.__hotbarEditMode) return;
            if (this.__isHotbarSlotEmpty(EDIT_SLOT_INDEX)) return;
            this.__handleHotbarSlotTap(EDIT_SLOT_INDEX);
            this.__startHotbarHold(EDIT_SLOT_INDEX);
        }, { passive: false });
        editBtn.addEventListener('touchend', (e) => {
            e.preventDefault();
            e.stopPropagation();
            if (!editBtnIsSlot()) {
                return this.__toggleHotbarEditMode();
            }
            // Slot behavior — mirrors the regular slot touchend below.
            this.__clearHotbarHold(EDIT_SLOT_INDEX);
            if (this.__layoutEditActive) return;
            if (this.__hotbarEditMode) {
                if (navigator.vibrate) navigator.vibrate(30);
                this.__highlightEditSlot(editBtn);
                gameClient.interface.modalManager.open("hotbar-add-modal", EDIT_SLOT_INDEX);
                return;
            }
            if (this.__isHotbarSlotEmpty(EDIT_SLOT_INDEX)) {
                if (navigator.vibrate) navigator.vibrate(30);
                gameClient.interface.modalManager.open("hotbar-add-modal", EDIT_SLOT_INDEX);
                return;
            }
        }, { passive: false });
        editBtn.addEventListener('click', (e) => {
            e.preventDefault();
            e.stopPropagation();
        });
    }

    // Apply the saved "edit button as slot" preference at boot.
    try {
        if (gameClient.interface.settings.isHotbarEditSlotEnabled()) {
            this.setHotbarEditAsSlot(true);
        }
    } catch (e) { /* settings not ready — default (edit button) stands */ }

    slots.forEach((slot, index) => {
        slot.addEventListener('touchstart', (e) => {
            e.preventDefault();
            if (this.__layoutEditActive || this.__hotbarEditMode) return;
            if (this.__isHotbarSlotEmpty(index)) return;
            // Fire immediately and start per-slot repeat interval
            this.__handleHotbarSlotTap(index);
            this.__startHotbarHold(index);
        }, { passive: false });

        slot.addEventListener('touchend', (e) => {
            e.preventDefault();
            this.__clearHotbarHold(index);

            // Ignore while layout editor is active
            if (this.__layoutEditActive) return;

            // Edit mode: tapping any slot opens the add modal
            if (this.__hotbarEditMode) {
                if (navigator.vibrate) navigator.vibrate(30);
                this.__highlightEditSlot(slot);
                gameClient.interface.modalManager.open("hotbar-add-modal", index);
                return;
            }

            // Empty slot: single tap opens add modal
            if (this.__isHotbarSlotEmpty(index)) {
                if (navigator.vibrate) navigator.vibrate(30);
                gameClient.interface.modalManager.open("hotbar-add-modal", index);
                return;
            }
        }, { passive: false });

        slot.addEventListener('touchcancel', (e) => {
            this.__clearHotbarHold(index);
        });

        slot.addEventListener('click', (e) => {
            e.preventDefault();
        });
    });

}

Touch.prototype.__bindExtraHotbarSlots = function () {

    /*
     * Function Touch.__bindExtraHotbarSlots
     * Bind touch events to the extra mobile hotbar slots (indices 8-10)
     */

    let extraSlots = document.querySelectorAll('.mobile-extra-hotbar-slot[data-slot]');

    extraSlots.forEach((slot) => {
        let slotIndex = parseInt(slot.getAttribute('data-slot'));

        slot.addEventListener('touchstart', (e) => {
            e.preventDefault();
            if (this.__layoutEditActive || this.__hotbarEditMode) return;
            if (this.__isHotbarSlotEmpty(slotIndex)) return;
            this.__handleHotbarSlotTap(slotIndex);
            this.__startHotbarHold(slotIndex);
        }, { passive: false });

        slot.addEventListener('touchend', (e) => {
            e.preventDefault();
            this.__clearHotbarHold(slotIndex);

            if (this.__layoutEditActive) return;

            // Edit mode: tapping any slot opens the add modal
            if (this.__hotbarEditMode) {
                if (navigator.vibrate) navigator.vibrate(30);
                this.__highlightEditSlot(slot);
                gameClient.interface.modalManager.open("hotbar-add-modal", slotIndex);
                return;
            }

            // Empty slot: single tap opens add modal
            if (this.__isHotbarSlotEmpty(slotIndex)) {
                if (navigator.vibrate) navigator.vibrate(30);
                gameClient.interface.modalManager.open("hotbar-add-modal", slotIndex);
                return;
            }
        }, { passive: false });

        slot.addEventListener('touchcancel', (e) => {
            this.__clearHotbarHold(slotIndex);
        });

        slot.addEventListener('click', (e) => {
            e.preventDefault();
        });
    });

    // Apply saved setting once gameClient is ready (constructor hasn't finished yet)
    // Only show the element — defer positioning until first resize when layout is stable
    let self = this;
    setTimeout(function () {
        if (typeof gameClient !== 'undefined' && gameClient.interface && gameClient.interface.settings && gameClient.interface.settings.isExtraHotbarEnabled()) {
            let extraHotbar = document.getElementById('mobile-extra-hotbar');
            if (extraHotbar) {
                extraHotbar.style.display = '';
                extraHotbar.classList.add('visible');
            }
        }
    }, 0);

}

Touch.prototype.setHotbarEditAsSlot = function (enabled) {

    /*
     * Function Touch.setHotbarEditAsSlot
     * Transforms the hotbar's edit (✎) button into hotbar slot 11 — or
     * back. The button keeps its single set of listeners (they dispatch
     * on the data-slot attribute at event time, see __bindHotbarSlots);
     * gaining data-slot also enrolls it in the hotbar manager's mobile
     * canvas sync + edit-mode highlighting automatically. Settings >
     * Controls owns the toggle; default (off) is the classic edit button.
     */

    let editBtn = document.getElementById('mobile-hotbar-edit-btn');
    if (!editBtn) return;

    // Leaving a half-active edit mode in either direction would strand
    // the highlight state — exit it first.
    if (this.__hotbarEditMode) {
        this.__toggleHotbarEditMode();
    }

    if (enabled) {
        editBtn.setAttribute('data-slot', '11');
        editBtn.removeAttribute('title');
        editBtn.innerHTML = '<canvas></canvas><span class="mobile-hotbar-duration"></span><span class="mobile-slot-key">9</span>';
    } else {
        editBtn.removeAttribute('data-slot');
        editBtn.title = 'Edit hotbar slots';
        editBtn.innerHTML = '&#9998;';
    }

    // The edit-slot is the visual "9", so the Extra Hotbar renumbers to
    // 10/11/12 while active (back to 9/10/11 when off). Labels are
    // display-only on mobile — no key bindings change.
    let extraSlots = document.querySelectorAll('.mobile-extra-hotbar-slot[data-slot]');
    extraSlots.forEach(function (slot) {
        let keySpan = slot.querySelector('.mobile-slot-key');
        if (!keySpan) return;
        let base = parseInt(slot.getAttribute('data-slot'));   // 8, 9, 10
        if (isNaN(base)) return;
        keySpan.textContent = String(base + (enabled ? 2 : 1));
    });

    // Redraw mobile canvases so an already-assigned slot 11 shows its icon.
    this.syncMobileHotbar();

}

Touch.prototype.setExtraHotbarVisible = function (visible) {

    /*
     * Function Touch.setExtraHotbarVisible
     * Shows or hides the extra mobile hotbar
     */

    let extraHotbar = document.getElementById('mobile-extra-hotbar');

    if (!extraHotbar) return;

    if (visible) {
        extraHotbar.style.display = '';
        extraHotbar.classList.add('visible');
    } else {
        extraHotbar.classList.remove('visible');
    }

    this.__positionExtraHotbar();

}

Touch.prototype.__positionExtraHotbar = function (retryCount) {

    /*
     * Function Touch.__positionExtraHotbar
     * Positions the extra hotbar: right of d-pad in landscape, above main hotbar in portrait.
     * Grid direction (vertical/horizontal) handled by CSS media queries.
     * Skipped when layout editor has a custom position for this orientation.
     *
     * Self-retry on zero-rect: if the reference element (d-pad / main
     * hotbar) isn't laid out yet (silent reconnect mid-fade, orientation
     * change between frames, browser layout race) we schedule another
     * attempt next frame instead of bailing forever. Without this, a
     * silent reconnect during a hunt could leave the extra hotbar
     * .visible but positioned at default (top:0 left:0 — no CSS
     * fallback exists) — Songo 2026-05-08 reported the 3 extra slots
     * vanishing mid-hunt, no heal, died, lost blessings.
     */

    let extraHotbar = document.getElementById('mobile-extra-hotbar');

    if (!extraHotbar) return;

    // Skip the whole positioning + retry path when the hotbar isn't shown.
    // Without this, players who toggled the setting off still trip the
    // 10-frame zero-rect retry loop on every resize / orientation change
    // and burn a clienterror.log entry on give-up. 77% of [extra-hotbar]
    // log lines in the 2026-05-11 sweep were visible=false — purely noise.
    if (!extraHotbar.classList.contains('visible')) return;

    // If layout editor has a custom position saved AND we're in fullscreen, don't override
    if (this.layoutEditor && this.layoutEditor.__isFullscreen()) {
        let orientation = this.layoutEditor.__getOrientation();
        let layout = this.layoutEditor.__layout[orientation];
        if (layout && layout.extraHotbar) return;
    }

    // Clear any leftover custom layout styles (scale, transform-origin)
    extraHotbar.style.removeProperty("transform");
    extraHotbar.style.removeProperty("transform-origin");
    extraHotbar.style.removeProperty("top");
    extraHotbar.style.removeProperty("right");

    let isLandscape = window.innerWidth > window.innerHeight;
    let refEl = isLandscape
        ? document.getElementById('mobile-joystick-zone')
        : document.getElementById('mobile-hotbar');
    if (!refEl) return;

    let rect = refEl.getBoundingClientRect();

    // Reference element isn't laid out yet — retry next frame (up to ~10
    // frames ≈ 160ms) instead of leaving the hotbar at default position.
    if (rect.width === 0 && rect.height === 0) {
        let attempt = retryCount || 0;
        if (attempt >= 10) {
            // Give up — log so we can correlate "extra hotbar vanished"
            // reports with the specific reference element that stayed
            // zero-rect. clienterror.log captures it server-side.
            try {
                if (typeof gameClient !== "undefined" && gameClient && typeof gameClient.sendDebug === "function") {
                    gameClient.sendDebug("[extra-hotbar] zero-rect-give-up ref=" + refEl.id
                        + " landscape=" + isLandscape
                        + " visible=" + extraHotbar.classList.contains('visible'));
                }
            } catch (e) { /* never break on debug */ }
            return;
        }
        let self = this;
        requestAnimationFrame(function () { self.__positionExtraHotbar(attempt + 1); });
        return;
    }

    if (isLandscape) {
        extraHotbar.style.left = (rect.right + 15) + 'px';
        extraHotbar.style.bottom = (window.innerHeight - rect.bottom) + 'px';
    } else {
        extraHotbar.style.left = rect.left + 'px';
        extraHotbar.style.bottom = (window.innerHeight - rect.top + 6) + 'px';
    }

}

Touch.prototype.__toggleHotbarEditMode = function () {

    /*
     * Function Touch.__toggleHotbarEditMode
     * Toggles the hotbar edit mode on/off
     */

    this.__hotbarEditMode = !this.__hotbarEditMode;

    let editBtn = document.getElementById('mobile-hotbar-edit-btn');
    let slots = document.querySelectorAll('.mobile-hotbar-slot[data-slot], .mobile-extra-hotbar-slot[data-slot]');

    if (this.__hotbarEditMode) {
        // 'active' marks the TOGGLE-button look — skip it when the button
        // is acting as a slot (data-slot set); it then receives the same
        // edit-mode highlight as every other slot via the query above.
        if (editBtn && !editBtn.hasAttribute('data-slot')) editBtn.classList.add('active');
        slots.forEach(function (slot) { slot.classList.add('edit-mode'); });
        if (navigator.vibrate) navigator.vibrate(30);
    } else {
        if (editBtn) editBtn.classList.remove('active');
        slots.forEach(function (slot) {
            slot.classList.remove('edit-mode');
            slot.classList.remove('edit-selected');
        });
    }

}

Touch.prototype.__highlightEditSlot = function (selectedSlot) {

    /*
     * Function Touch.__highlightEditSlot
     * Highlights the selected slot in edit mode to show which one is being edited
     */

    let slots = document.querySelectorAll('.mobile-hotbar-slot[data-slot], .mobile-extra-hotbar-slot[data-slot]');

    slots.forEach(function (slot) { slot.classList.remove('edit-selected'); });
    selectedSlot.classList.add('edit-selected');

}

Touch.prototype.__handleHotbarSlotTap = function (slotIndex) {

    /*
     * Function Touch.__handleHotbarSlotTap
     * Handle tap on mobile hotbar slot - trigger corresponding F-key action
     * Uses differentiated haptic feedback: double-tap for success, triple-buzz for reject
     */

    if (!gameClient || !gameClient.interface) return;

    let hotbarManager = gameClient.interface.hotbarManager;
    if (!hotbarManager) return;

    // Check if the spell/rune in this slot is on cooldown or player lacks mana
    let slot = hotbarManager.slots[slotIndex];
    let shouldReject = false;

    if (slot && slot.spell !== null) {
        let spellbook = gameClient.player ? gameClient.player.spellbook : null;
        if (spellbook) {
            let isOnCooldown = spellbook.cooldowns.has(spellbook.GLOBAL_COOLDOWN) || spellbook.cooldowns.has(slot.spell.sid);
            let notEnoughMana = slot.spell.mana && (gameClient.player.state.mana || 0) < slot.spell.mana;
            shouldReject = isOnCooldown || notEnoughMana;
        }
    } else if (slot && slot.item !== null && gameClient.itemDefinitionsByCid) {
        let def = gameClient.itemDefinitionsByCid[slot.item.id];
        if (def && def.properties && def.properties.type === "rune") {
            let cd = hotbarManager.__getRuneEffectiveCooldown(def.properties.aggressive !== false);
            shouldReject = cd !== null && performance.now() < cd.until;
        }
    }

    // Map slot index (0-3) to F1-F4 keys (112-115)
    let fKeyCode = 112 + slotIndex;
    hotbarManager.handleKeyPress(fKeyCode);

    // Haptic feedback: success double-tap or reject triple-buzz
    if (navigator.vibrate) {
        navigator.vibrate(shouldReject ? [20, 20, 20, 20, 20] : [30, 40, 30]);
    }

    // Animate mobile hotbar slot (check both regular and extra hotbar)
    let slotElement = document.querySelector('.mobile-hotbar-slot[data-slot="' + slotIndex + '"]')
        || document.querySelector('.mobile-extra-hotbar-slot[data-slot="' + slotIndex + '"]');
    if (slotElement) {
        let feedbackClass = shouldReject ? "hotbar-reject" : "hotbar-success";
        let duration = shouldReject ? 300 : 200;
        slotElement.classList.remove("hotbar-success", "hotbar-reject");
        // Force reflow to restart animation if same class is applied again
        void slotElement.offsetWidth;
        slotElement.classList.add(feedbackClass);
        setTimeout(function () { slotElement.classList.remove(feedbackClass); }, duration);
    }

}

Touch.prototype.__startHotbarHold = function (slotIndex) {

    /*
     * Function Touch.__startHotbarHold
     * Starts per-slot hold-to-repeat timer for mobile hotbar.
     * Each slot tracks its own timer/interval so multi-touch
     * cannot orphan a running repeat interval.
     */

    if (!this.__hotbarHoldTimers) this.__hotbarHoldTimers = new Map();
    if (!this.__hotbarRepeatIntervals) this.__hotbarRepeatIntervals = new Map();

    // Clear any existing hold on this slot first
    this.__clearHotbarHold(slotIndex);

    let self = this;
    this.__hotbarHoldTimers.set(slotIndex, setTimeout(function () {
        self.__hotbarHoldTimers.delete(slotIndex);
        self.__hotbarRepeatIntervals.set(slotIndex, setInterval(function () {
            self.__handleHotbarSlotTap(slotIndex);
        }, self.HOTBAR_REPEAT_RATE));
    }, this.HOTBAR_HOLD_DELAY));

}

Touch.prototype.__clearHotbarHold = function (slotIndex) {

    /*
     * Function Touch.__clearHotbarHold
     * Clears the hold-to-repeat timer and interval for a specific mobile hotbar slot.
     * If no slotIndex is provided, clears all slots (safety fallback).
     */

    if (!this.__hotbarHoldTimers) this.__hotbarHoldTimers = new Map();
    if (!this.__hotbarRepeatIntervals) this.__hotbarRepeatIntervals = new Map();

    if (slotIndex !== undefined) {
        if (this.__hotbarHoldTimers.has(slotIndex)) {
            clearTimeout(this.__hotbarHoldTimers.get(slotIndex));
            this.__hotbarHoldTimers.delete(slotIndex);
        }
        if (this.__hotbarRepeatIntervals.has(slotIndex)) {
            clearInterval(this.__hotbarRepeatIntervals.get(slotIndex));
            this.__hotbarRepeatIntervals.delete(slotIndex);
        }
    } else {
        // Clear all — safety fallback
        this.__hotbarHoldTimers.forEach(function (timer) { clearTimeout(timer); });
        this.__hotbarHoldTimers.clear();
        this.__hotbarRepeatIntervals.forEach(function (interval) { clearInterval(interval); });
        this.__hotbarRepeatIntervals.clear();
    }

}

Touch.prototype.__isHotbarSlotEmpty = function (slotIndex) {

    /*
     * Function Touch.__isHotbarSlotEmpty
     * Returns true if the hotbar slot has no spell, text, or item assigned
     */

    if (!gameClient || !gameClient.interface || !gameClient.interface.hotbarManager) return true;

    let slot = gameClient.interface.hotbarManager.slots[slotIndex];

    if (!slot) return true;

    return slot.spell === null && slot.text === null && slot.item === null && slot.action === null;

}

Touch.prototype.syncMobileHotbar = function () {

    /*
     * Function Touch.syncMobileHotbar
     * Sync mobile hotbar slots with desktop hotbar icons
     */

    if (!this.isMobileMode) return;
    if (!gameClient || !gameClient.interface || !gameClient.interface.hotbarManager) return;

    // Reposition extra hotbar if it has no inline position yet (first load, reconnect, etc.)
    let extraHotbar = document.getElementById('mobile-extra-hotbar');
    if (extraHotbar && extraHotbar.classList.contains('visible') && !extraHotbar.style.left) {
        this.__positionExtraHotbar();
    }

    let desktopSlots = gameClient.interface.hotbarManager.slots;
    let mobileSlots = document.querySelectorAll('.mobile-hotbar-slot[data-slot], .mobile-extra-hotbar-slot[data-slot]');
    let icons = gameClient.interface.hotbarManager.ICONS;

    mobileSlots.forEach((mobileSlot) => {
        let index = parseInt(mobileSlot.getAttribute('data-slot'));
        if (index >= desktopSlots.length) return;

        let desktopSlot = desktopSlots[index];
        let canvas = mobileSlot.querySelector('canvas');

        if (!canvas) return;

        // Skip the full slot repaint when nothing visible changed — this
        // sync runs EVERY frame and used to reset (canvas.width=32 implies
        // a full clear) + redraw every slot each time. The key covers all
        // pixel inputs per slot type + whether a cooldown overlay is
        // animating; while one is, we repaint per frame exactly as before.
        // The cdActive flag inside the key forces one final clean repaint
        // when the cooldown ends. Stored on the canvas element (stable DOM).
        let syncKey;
        let cdActive = false;
        if (desktopSlot.spell) {
            let fr = gameClient.player.spellbook.getCooldownFraction(desktopSlot.spell.sid);
            cdActive = fr < 1;
            let runeReady = desktopSlot.spell.runeId
                ? (gameClient.interface.hotbarManager.getRuneIcon(desktopSlot.spell.runeId) !== null)
                : false;
            syncKey = "spell|" + desktopSlot.spell.sid + "|" + runeReady
                + "|" + desktopSlot.mode + "|" + cdActive;
        } else if (desktopSlot.text) {
            syncKey = "text|" + desktopSlot.text;
        } else if (desktopSlot.action) {
            syncKey = "action|" + desktopSlot.action;
        } else if (desktopSlot.item) {
            let hm = gameClient.interface.hotbarManager;
            let def = gameClient.itemDefinitionsByCid ? gameClient.itemDefinitionsByCid[desktopSlot.item.id] : null;
            let isRune = def && def.properties && def.properties.type === "rune";
            let isFluid = def && def.properties && def.properties.type === "fluidContainer";
            let cd = isRune ? hm.__getRuneEffectiveCooldown(def.properties.aggressive !== false)
                   : isFluid ? hm.__getFluidEffectiveCooldown()
                   : null;
            cdActive = !!(cd && cd.until > performance.now());
            syncKey = "item|" + desktopSlot.item.id + "|" + (desktopSlot.item.fluidType || 0)
                + "|" + (desktopSlot.item.sid || 0) + "|" + (desktopSlot.item.tintId || 0)
                + "|" + desktopSlot.mode + "|" + cdActive;
        } else {
            syncKey = "empty";
        }
        if (!cdActive && canvas.__lastSyncKey === syncKey) return;
        canvas.__lastSyncKey = syncKey;

        let ctx = canvas.getContext('2d');

        // Set canvas size
        canvas.width = 32;
        canvas.height = 32;

        // Clear canvas
        ctx.clearRect(0, 0, 32, 32);

        // Clean up text-slot residue if this slot is no longer text-bound.
        // The text-preview path sets a data-text-label attribute + custom
        // centered positioning on the .mobile-hotbar-duration span; without
        // a cleanup here, a former text slot rebound to a spell/item/action
        // keeps the centered label position and cooldown / item-count text
        // renders in the wrong place.
        if (!desktopSlot.text) {
            let durEl = mobileSlot.querySelector('.mobile-hotbar-duration');
            if (durEl && durEl.hasAttribute('data-text-label')) {
                durEl.removeAttribute('data-text-label');
                durEl.textContent = '';
                durEl.style.cssText = '';
            }
        }

        // Draw spell icon if available. Conjure spells show the sprite of
        // the item they conjure (runeId, cached canvas via HotbarManager);
        // falls back to the icons.png sheet icon when not drawable.
        if (desktopSlot.spell) {
            let runeIcon = desktopSlot.spell.runeId
                ? gameClient.interface.hotbarManager.getRuneIcon(desktopSlot.spell.runeId)
                : null;
            if (runeIcon !== null) {
                ctx.drawImage(runeIcon, 0, 0);
            } else {
                ctx.drawImage(
                    icons,
                    32 * desktopSlot.spell.icon.x,
                    32 * desktopSlot.spell.icon.y,
                    32, 32,
                    0, 0,
                    32, 32
                );
            }

            // Apply cooldown overlay
            let fraction = gameClient.player.spellbook.getCooldownFraction(desktopSlot.spell.sid);
            let durationEl = mobileSlot.querySelector('.mobile-hotbar-duration');

            if (fraction < 1) {
                let gradients = gameClient.interface.hotbarManager.GRADIENTS;
                ctx.fillStyle = gradients[Math.round(360 * (fraction.clamp(0, 1) % 1))];
                ctx.fillRect(0, 0, 32, 32);

                if (durationEl) {
                    let seconds = gameClient.player.spellbook.getCooldownSeconds(desktopSlot.spell.sid);
                    durationEl.textContent = seconds > 60 ? (seconds / 60).toFixed(1) + "m" : seconds.toFixed(1) + "s";
                }
            } else if (durationEl) {
                durationEl.textContent = "";
            }
        } else if (desktopSlot.text) {
            // Mirror desktop text-slot rendering: small chat-bubble corner
            // indicator + compressed preview label in the existing
            // .mobile-hotbar-duration span. Discriminator attribute
            // data-text-label is the CSS hook that re-centers the span
            // (mobile.css). Other branches in this loop clean up the
            // attribute when overwriting a text slot — see below.
            ctx.fillStyle = '#222';
            ctx.fillRect(0, 0, 32, 32);
            // Corner bubble (8×6 body + 2px tail) at top-right.
            ctx.fillStyle = '#4a90a4';
            ctx.fillRect(22, 2, 8, 6);
            ctx.beginPath();
            ctx.moveTo(26, 8);
            ctx.lineTo(24, 10);
            ctx.lineTo(28, 10);
            ctx.fill();
            // Preview label via DOM span. Cache by attribute to avoid
            // style recalc on no-op syncs.
            let labelEl = mobileSlot.querySelector('.mobile-hotbar-duration');
            let hm = gameClient.interface && gameClient.interface.hotbarManager;
            // Mirror desktop: name-targeted commands (exiva <name>, exura sio
            // <name>) show the TARGET NAME with a tiny command tag above it,
            // instead of every slot reading "EXIV". __parseTextLabel does the
            // tag+name split; fall back to the plain compressor if unavailable.
            let parsed = (hm && typeof hm.__parseTextLabel === "function")
                ? hm.__parseTextLabel(desktopSlot.text)
                : { tag: null, label: (hm && hm.__compressHotbarText ? hm.__compressHotbarText(desktopSlot.text) : "…") };
            let cacheKey = (parsed.tag ? parsed.tag + ":" : "") + parsed.label;
            if (labelEl && labelEl.getAttribute('data-text-label') !== cacheKey) {
                labelEl.style.color = '#ffffff';
                labelEl.style.fontWeight = 'bold';
                labelEl.style.top = '50%';
                labelEl.style.left = '50%';
                labelEl.style.transform = 'translate(-50%, -50%)';
                if (parsed.tag) {
                    // Two-line: tiny command tag above the compressed target name.
                    // Built via textContent on child spans (not innerHTML) so a
                    // name can't inject markup. .hk-cmd/.hk-name sized in mobile.css.
                    labelEl.textContent = "";
                    labelEl.style.fontSize = "";
                    let cmd = document.createElement("span");
                    cmd.className = "hk-cmd";
                    cmd.textContent = parsed.tag;
                    let nm = document.createElement("span");
                    nm.className = "hk-name";
                    nm.textContent = parsed.label;
                    labelEl.appendChild(cmd);
                    labelEl.appendChild(nm);
                } else {
                    labelEl.textContent = parsed.label;
                    labelEl.style.fontSize = (parsed.label.length >= 4 ? '11px' : '14px');
                }
                labelEl.setAttribute('data-text-label', cacheKey);
            }
        } else if (desktopSlot.action) {
            // Draw action icon on mobile slot
            let actionDef = HotbarManager.prototype.ACTIONS[desktopSlot.action];
            if (actionDef) {
                ctx.fillStyle = actionDef.bg;
                ctx.beginPath();
                ctx.arc(16, 16, 14, 0, 2 * Math.PI);
                ctx.fill();
                ctx.strokeStyle = actionDef.border;
                ctx.lineWidth = 2;
                ctx.stroke();
                ctx.fillStyle = actionDef.fg;
                ctx.font = "18px Arial";
                ctx.textAlign = "center";
                ctx.textBaseline = "middle";
                ctx.fillText(actionDef.icon, 16, 17);
            }
        } else if (desktopSlot.item) {
            // Draw item sprite on mobile slot
            let mobileCanvas = new Canvas(canvas, 32, 32);
            let item;
            if (desktopSlot.item.fluidType > 0) {
              item = new FluidThing(desktopSlot.item.id, 1, desktopSlot.item.fluidType);
            } else {
              item = new Item(desktopSlot.item.id, 1);
            }
            // Apply glow outline and tint if the slot has SID or tintId
            let glow = getItemGlow(desktopSlot.item.sid || 0, desktopSlot.item.tintId || 0);
            if (glow) {
              mobileCanvas.drawGlowOutline(item, Position.prototype.NULL, 32, glow);
            }
            let tint = getItemTint(desktopSlot.item.sid || 0, desktopSlot.item.tintId || 0);
            if (tint) {
              mobileCanvas.setTint(tint.r, tint.g, tint.b, tint.gray, tint.mix, tint.bright);
            }
            mobileCanvas.drawSprite(item, Position.prototype.NULL, 32);
            if (tint) {
              mobileCanvas.resetTint();
            }

            // Apply rune/fluid cooldown overlay on mobile (per-bucket, see hotbar-manager.__getRuneEffectiveCooldown / __getFluidEffectiveCooldown)
            let hm = gameClient.interface.hotbarManager;
            let def = gameClient.itemDefinitionsByCid ? gameClient.itemDefinitionsByCid[desktopSlot.item.id] : null;
            let isRune = def && def.properties && def.properties.type === "rune";
            let isFluid = def && def.properties && def.properties.type === "fluidContainer";
            let cd = isRune ? hm.__getRuneEffectiveCooldown(def.properties.aggressive !== false)
                   : isFluid ? hm.__getFluidEffectiveCooldown()
                   : null;
            let durationEl = mobileSlot.querySelector('.mobile-hotbar-duration');
            if (cd && cd.until > performance.now()) {
              let remaining = cd.until - performance.now();
              let dur = Math.max(1, cd.duration);
              let fraction = 1 - (remaining / dur);
              ctx.fillStyle = hm.GRADIENTS[Math.round(360 * (fraction.clamp(0, 1) % 1))];
              ctx.fillRect(0, 0, 32, 32);
              if (durationEl) {
                durationEl.textContent = (remaining / 1000).toFixed(1) + "s";
              }
            } else if (durationEl) {
              durationEl.textContent = "";
            }
        }

        // Draw mode indicator for item slots
        if (desktopSlot.item !== null && desktopSlot.mode && desktopSlot.mode !== "self") {
            let mx = 3;
            let my = 25;
            if (desktopSlot.mode === "target") {
                ctx.strokeStyle = "red";
                ctx.lineWidth = 1.5;
                ctx.beginPath();
                ctx.arc(mx + 3, my + 3, 3, 0, 2 * Math.PI);
                ctx.stroke();
                ctx.beginPath();
                ctx.moveTo(mx + 3, my);
                ctx.lineTo(mx + 3, my + 6);
                ctx.moveTo(mx, my + 3);
                ctx.lineTo(mx + 6, my + 3);
                ctx.stroke();
            } else if (desktopSlot.mode === "crosshair") {
                ctx.strokeStyle = "yellow";
                ctx.lineWidth = 1.5;
                ctx.beginPath();
                ctx.moveTo(mx + 3, my);
                ctx.lineTo(mx + 3, my + 6);
                ctx.moveTo(mx, my + 3);
                ctx.lineTo(mx + 6, my + 3);
                ctx.stroke();
            } else if (desktopSlot.mode === "cook") {
                ctx.fillStyle = "orange";
                ctx.font = "10px Arial";
                ctx.textAlign = "left";
                ctx.textBaseline = "top";
                ctx.fillText("\u{1F525}", mx, my);
            }
        }
    });

}

Touch.prototype.__bindGlobalEvents = function () {

    /*
     * Function Touch.__bindGlobalEvents
     * Binds single-tap use on equipment slots for mobile
     */

    let equipWrapper = document.querySelector('.equipment.wrapper');

    if (equipWrapper) {
        this.__bindEquipmentSingleTap(equipWrapper);
    }

}

Touch.prototype.__bindEquipmentSingleTap = function (equipWrapper) {

    /*
     * Function Touch.__bindEquipmentSingleTap
     * Binds touch events directly on the equipment wrapper for reliable single-tap use
     */

    let self = this;
    let tapStart = 0;
    let tapX = 0;
    let tapY = 0;
    let tapSlot = null;

    equipWrapper.addEventListener('touchstart', function (event) {
        if (!self.isMobileMode) return;

        let touch = event.touches[0];
        let element = document.elementFromPoint(touch.clientX, touch.clientY);
        if (!element) return;

        let slotElement = element.closest('.slot');
        if (!slotElement) return;

        tapStart = Date.now();
        tapX = touch.clientX;
        tapY = touch.clientY;
        tapSlot = slotElement;

    }, { passive: true });

    equipWrapper.addEventListener('touchend', function (event) {
        if (!self.isMobileMode) return;
        if (!tapSlot) return;

        let touch = event.changedTouches[0];
        let duration = Date.now() - tapStart;
        let dx = Math.abs(touch.clientX - tapX);
        let dy = Math.abs(touch.clientY - tapY);
        let savedSlot = tapSlot;

        // Reset state
        tapStart = 0;
        tapSlot = null;

        // Quick tap with minimal movement: use the item
        if (duration < 250 && dx < 20 && dy < 20) {
            event.preventDefault();

            // Cancel drag timer manually instead of stopPropagation
            // (stopPropagation would prevent the body-level touchend from
            // cleaning up the drag system, causing an eternal drag state)
            if (self.__dragState && self.__dragState.dragTimer) {
                clearTimeout(self.__dragState.dragTimer);
                self.__dragState.dragTimer = null;
            }

            if (navigator.vibrate) navigator.vibrate(50);

            // Use, look, or context menu for equipment slot
            let slotObject = self.__getSlotObject(savedSlot);
            if (slotObject && slotObject.which && gameClient.mouse) {
                // Use-with target: if a multi-use source is already armed
                // (player picked "Use With" on ore/rope/shovel/key earlier),
                // this tap is the TARGET — complete the action. Mirrors the
                // desktop guard at mouse.js:__handleSlotMouseUp:1659.
                if (gameClient.mouse.__multiUseObject !== null) {
                    gameClient.mouse.__handleItemUseWith(gameClient.mouse.__multiUseObject, slotObject);
                    gameClient.mouse.__multiUseObject = null;
                    gameClient.mouse.setCursor("auto");
                } else if (self.actionMode === 'look') {
                    gameClient.mouse.look(slotObject);
                    self.__clearActionMode();
                } else if (self.actionMode === 'context') {
                    self.__openSlotContextMenu(slotObject, touch);
                    self.__clearActionMode();
                } else if (gameClient.mouse.use) {
                    // For multiuse items, open context menu instead of entering crosshair mode
                    let item = slotObject.which.peekItem(slotObject.index);
                    if (item && item.isMultiUse()) {
                        self.__openSlotContextMenu(slotObject, touch);
                    } else {
                        gameClient.mouse.use(slotObject);
                    }
                }
            }
        }

    }, { passive: false });

}

Touch.prototype.__getSlotObject = function (element) {

    /*
     * Function Touch.__getSlotObject
     * Resolves a DOM element to a game object (Container or Equipment slot)
     * Ported logic from Mouse.__getSlotObject
     */

    if (!element) return null;

    let slotIndex, containerIndex;

    // Check if body-style (equipment usually has specific structure)
    if (element.className === "body") {
        slotIndex = 0;
        containerIndex = Number(element.parentElement.getAttribute("containerIndex"));
    } else {
        // Regular slot
        if (element.getAttribute("slotIndex")) {
            slotIndex = Number(element.getAttribute("slotIndex"));
        } else {
            return null;
        }

        // Find container index (parent of parent usually)
        if (element.parentElement && element.parentElement.parentElement) {
            containerIndex = Number(element.parentElement.parentElement.getAttribute("containerIndex"));
        } else {
            containerIndex = Number(element.parentElement.getAttribute("containerIndex"));
        }
    }

    if (isNaN(slotIndex) || isNaN(containerIndex)) return null;

    // Fetch the container from the player
    let container = gameClient.player.getContainer(containerIndex);

    if (!container) return null;

    return new Object({
        "which": container,
        "index": slotIndex
    });

}

Touch.prototype.__enableDepotPanelDragAndCenter = function () {

    /*
     * Function Touch.__enableDepotPanelDragAndCenter
     * Restores the touch-drag + recenter button the old depot floating
     * window had. The depot panel still has a header (.mobile-panel-header)
     * so we can drag from there without conflicting with tab-strip taps.
     * Position is NOT persisted across sessions — recenter button strips
     * inline styles so the CSS default takes over.
     */

    this.__enablePanelDragAndCenter("mobile-depot-panel", ".depot-panel-close", "depot-center", function () {
        return gameClient.touch ? gameClient.touch.mobileDepotPanel : null;
    });

};

Touch.prototype.__enablePanelDragAndCenter = function (panelDomId, closeSelector, centerAction, getPanel) {

    /*
     * Function Touch.__enablePanelDragAndCenter
     * Generic floating-panel chrome: close-all button, recenter button and
     * header touch-drag. Extracted from the depot-only version so the
     * "Open in Window" float panel gets identical behaviour (2026-07-06).
     */

    let panel = document.getElementById(panelDomId);
    if (!panel) return;
    let header = panel.querySelector(".mobile-panel-header");
    if (!header) return;

    // Close button — cascades through every tab in the panel so the
    // whole window goes away in one tap (mirrors closing the tab itself,
    // which the cascade-close in MobileContainerPanel already handles).
    let closeBtn = header.querySelector(closeSelector);
    if (closeBtn) {
        let closeAll = function (e) {
            if (e) { e.preventDefault(); e.stopPropagation(); }
            let hostPanel = getPanel ? getPanel() : null;
            if (!hostPanel) return;
            let toClose = [];
            hostPanel.__containers.forEach(function (_entry, cid) { toClose.push(cid); });
            toClose.forEach(function (cid) {
                let c = gameClient.player.getContainer(cid);
                if (c) gameClient.player.closeContainer(c);
            });
        };
        closeBtn.addEventListener("touchend", closeAll, { passive: false });
        closeBtn.addEventListener("click", closeAll);
    }

    // Center button — inserted next to the existing minimize button so the
    // header reads: minimize | center | title.
    if (!header.querySelector('button[action="' + centerAction + '"]')) {
        let centerBtn = document.createElement("button");
        centerBtn.className = "symbol-button small";
        centerBtn.setAttribute("action", centerAction);
        centerBtn.title = "Center";
        centerBtn.textContent = "⌖"; // position-indicator glyph
        let minBtn = header.querySelector(".mobile-panel-minimize");
        if (minBtn && minBtn.nextSibling) {
            header.insertBefore(centerBtn, minBtn.nextSibling);
        } else {
            header.appendChild(centerBtn);
        }
        let recenter = function (e) {
            if (e) { e.preventDefault(); e.stopPropagation(); }
            panel.style.removeProperty("left");
            panel.style.removeProperty("top");
            panel.style.removeProperty("right");
            panel.style.removeProperty("bottom");
            panel.style.removeProperty("transform");
            panel.style.removeProperty("margin-left");
        };
        centerBtn.addEventListener("touchend", recenter, { passive: false });
        centerBtn.addEventListener("click", recenter);
    }

    // Touch-drag on the header. Skip if the touch started on a button.
    let dragState = null;
    header.addEventListener("touchstart", function (e) {
        if (e.target.closest("button")) return;
        if (e.touches.length !== 1) return;
        let touch = e.touches[0];
        let rect = panel.getBoundingClientRect();
        dragState = {
            startTouchX: touch.clientX,
            startTouchY: touch.clientY,
            startLeft: rect.left,
            startTop: rect.top
        };
        e.preventDefault();
    }, { passive: false });

    header.addEventListener("touchmove", function (e) {
        if (!dragState) return;
        if (e.touches.length !== 1) return;
        let touch = e.touches[0];
        let dx = touch.clientX - dragState.startTouchX;
        let dy = touch.clientY - dragState.startTouchY;
        let newLeft = dragState.startLeft + dx;
        let newTop = dragState.startTop + dy;

        // Clamp so at least 40px of the header stays on screen
        let rect = panel.getBoundingClientRect();
        newLeft = Math.max(-rect.width + 40, Math.min(window.innerWidth - 40, newLeft));
        newTop = Math.max(0, Math.min(window.innerHeight - 40, newTop));

        panel.style.setProperty("left", newLeft + "px", "important");
        panel.style.setProperty("top", newTop + "px", "important");
        panel.style.setProperty("right", "auto", "important");
        panel.style.setProperty("bottom", "auto", "important");
        panel.style.setProperty("margin-left", "0", "important");
        // Cancel the CSS centering transform — otherwise the panel keeps
        // shifting by half its own size on top of the drag offset.
        panel.style.setProperty("transform", "none", "important");
        e.preventDefault();
    }, { passive: false });

    header.addEventListener("touchend", function () { dragState = null; }, { passive: true });
    header.addEventListener("touchcancel", function () { dragState = null; }, { passive: true });

};

Touch.prototype.__bindHotbarPresetButton = function () {

    /*
     * Function Touch.__bindHotbarPresetButton
     * Tap-to-cycle hotkey preset switcher. Round 44×44 floater above
     * the PK lock; each tap advances activePreset by 1 mod 4 and
     * updates the button label (P1/P2/P3/P4).
     *
     * Existing HotbarManager.switchPreset does the heavy lifting
     * (saves the current slots into the active preset, clears the
     * UI, applies the new preset). We just call it and re-label.
     */

    let btn = document.getElementById("mobile-hotbar-preset-btn");
    if (!btn) return;

    let self = this;

    let updateLabel = function () {
        // window.gameClient instead of bare `gameClient` — the bare ref throws
        // ReferenceError if the symbol isn't declared yet (setTimeout(updateLabel,0)
        // can fire before gameclient.js's global assignment lands). window.x
        // safely returns undefined for unset globals.
        let gc = window.gameClient;
        let hm = gc && gc.interface && gc.interface.hotbarManager;
        if (!hm) return;
        btn.textContent = "P" + (((hm.activePreset || 0) % 4) + 1);
    };

    let cycle = function (e) {
        if (e) { e.preventDefault(); e.stopPropagation(); }
        let gc = window.gameClient;
        let hm = gc && gc.interface && gc.interface.hotbarManager;
        if (!hm || typeof hm.switchPreset !== "function") return;
        let next = ((hm.activePreset || 0) + 1) % 4;
        hm.switchPreset(next);
        updateLabel();
        // Brief flash so the player knows the tap registered.
        btn.classList.add("flash");
        setTimeout(function () { btn.classList.remove("flash"); }, 200);
    };

    btn.addEventListener("touchstart", function (e) { e.preventDefault(); }, { passive: false });
    btn.addEventListener("touchend", cycle, { passive: false });
    btn.addEventListener("click", cycle);

    // Sync the label once the hotbar manager finishes loading the
    // saved active preset (login order: hotbar inits AFTER touch).
    setTimeout(updateLabel, 0);
    self.__updateHotbarPresetLabel = updateLabel; // public for external callers

};

Touch.prototype.__bindContainerSlotDoubleTap = function () {

    /*
     * Function Touch.__bindContainerSlotDoubleTap
     * Binds a delegated event listener for single-tap and double-tap on container slots.
     * Single-tap: uses the item (opens containers, enters crosshair for multi-use items like runes)
     * Double-tap: moves item to the first available backpack slot
     */

    let self = this;
    let lastSlotTapElement = null;
    self.__singleTapTimer = null;
    const SINGLE_TAP_DELAY = 250; // ms — wait before confirming single tap
    const SCROLL_THRESHOLD = 10; // px — movement beyond this cancels the tap
    let slotTouchStartX = 0;
    let slotTouchStartY = 0;
    let slotTouchMoved = false;

    // Track touch start position to distinguish taps from scrolls
    document.body.addEventListener('touchstart', function (event) {
        if (!self.isMobileMode) return;

        let target = event.target;
        let slotElement = target.closest('.slot');
        if (!slotElement) return;

        let containerWindow = slotElement.closest('.window[containerIndex]')
                           || slotElement.closest('.container-content[containerIndex]');
        if (!containerWindow) return;

        let touch = event.touches[0];
        slotTouchStartX = touch.clientX;
        slotTouchStartY = touch.clientY;
        slotTouchMoved = false;
        self.__dragWasActive = false;
    }, { passive: true });

    // Detect finger movement during touch
    document.body.addEventListener('touchmove', function (event) {
        if (!self.isMobileMode || slotTouchMoved) return;

        let touch = event.touches[0];
        let dx = Math.abs(touch.clientX - slotTouchStartX);
        let dy = Math.abs(touch.clientY - slotTouchStartY);

        if (dx > SCROLL_THRESHOLD || dy > SCROLL_THRESHOLD) {
            slotTouchMoved = true;

            // Cancel any pending single-tap if the user is scrolling
            if (self.__singleTapTimer) {
                clearTimeout(self.__singleTapTimer);
                self.__singleTapTimer = null;
                // Remove highlight from canceled tap
                if (lastSlotTapElement) {
                    lastSlotTapElement.classList.remove("mobile-tap-highlight");
                }
                lastSlotTapElement = null;
            }
        }
    }, { passive: true });

    // Use delegated listener on document body to catch dynamically created slots
    document.body.addEventListener('touchend', function (event) {
        if (!self.isMobileMode) return;
        if (!gameClient || !gameClient.player) return;

        // A long-press already opened the slot context menu — swallow this tap.
        if (self.__slotLongPressFired) {
            self.__slotLongPressFired = false;
            return;
        }

        // Ignore if the finger moved (was a scroll, not a tap)
        if (slotTouchMoved) return;

        // Ignore if a drag was active (long press started a drag, not a tap)
        if (self.__dragState && self.__dragState.active) return;

        // Check if the tap target is a slot element
        let target = event.target;
        let slotElement = target.closest('.slot');

        if (!slotElement) return;

        // Ignore equipment slots (they have different parent structure)
        let containerWindow = slotElement.closest('.window[containerIndex]')
                           || slotElement.closest('.container-content[containerIndex]');
        if (!containerWindow) return;

        // Double-tap: same slot tapped while single-tap timer is pending
        if (lastSlotTapElement === slotElement && self.__singleTapTimer !== null) {
            // Cancel the pending single-tap
            clearTimeout(self.__singleTapTimer);
            self.__singleTapTimer = null;
            lastSlotTapElement = null;

            // Remove highlight
            slotElement.classList.remove("mobile-tap-highlight");

            event.preventDefault();
            event.stopPropagation();

            self.__handleSlotDoubleTap(slotElement, containerWindow);
            return;
        }

        // First tap — prevent synthesized mouse events and schedule single-tap action
        event.preventDefault();

        // Cancel drag timer to avoid interference (same as equipment handler)
        if (self.__dragState && self.__dragState.dragTimer) {
            clearTimeout(self.__dragState.dragTimer);
            self.__dragState.dragTimer = null;
        }

        // Clear any previous highlights before adding new one
        document.querySelectorAll(".mobile-tap-highlight").forEach(function(el) {
            el.classList.remove("mobile-tap-highlight");
        });

        // Highlight the tapped slot to show it's selected
        slotElement.classList.add("mobile-tap-highlight");

        lastSlotTapElement = slotElement;
        let savedSlot = slotElement;
        let savedTouch = event.changedTouches[0];
        let savedTouchX = savedTouch.clientX;
        let savedTouchY = savedTouch.clientY;

        if (self.__singleTapTimer) {
            clearTimeout(self.__singleTapTimer);
        }

        self.__singleTapTimer = setTimeout(function () {
            self.__singleTapTimer = null;
            lastSlotTapElement = null;

            // Remove highlight when single-tap fires
            savedSlot.classList.remove("mobile-tap-highlight");

            // A drag occurred during this touch — do not fire use action
            if (self.__dragWasActive) return;

            // Single-tap confirmed: use, look, or context menu for the item
            let slotObject = self.__getSlotObject(savedSlot);
            if (slotObject && slotObject.which && gameClient.mouse) {
                if (navigator.vibrate) navigator.vibrate(50);
                // Use-with target: if a multi-use source is already armed,
                // this tap is the TARGET — complete the action instead of
                // doing a regular use. See equipment-slot path above.
                if (gameClient.mouse.__multiUseObject !== null) {
                    gameClient.mouse.__handleItemUseWith(gameClient.mouse.__multiUseObject, slotObject);
                    gameClient.mouse.__multiUseObject = null;
                    gameClient.mouse.setCursor("auto");
                } else if (self.actionMode === 'look') {
                    gameClient.mouse.look(slotObject);
                    self.__clearActionMode();
                } else if (self.actionMode === 'context') {
                    self.__openSlotContextMenu(slotObject, { clientX: savedTouchX, clientY: savedTouchY });
                    self.__clearActionMode();
                } else if (gameClient.mouse.use) {
                    gameClient.mouse.use(slotObject);
                }
            }
        }, SINGLE_TAP_DELAY);
    }, { passive: false });

}

Touch.prototype.__handleSlotDoubleTap = function (slotElement, containerWindow) {

    /*
     * Function Touch.__handleSlotDoubleTap
     * Handle double-tap on a container slot - move item to backpack
     */

    if (!slotElement) return;

    // If containerWindow not passed, try to find it from slotElement
    if (!containerWindow) {
        containerWindow = slotElement.closest('.window[containerIndex]')
                       || slotElement.closest('.container-content[containerIndex]');
    }

    // Get source slot info
    let slotIndex = Number(slotElement.getAttribute('slotIndex'));

    // Handle case where containerWindow is still null (e.g., equipment slots)
    if (!containerWindow) {
        return;
    }

    let containerIndex = Number(containerWindow.getAttribute('containerIndex'));

    if (isNaN(slotIndex) || isNaN(containerIndex)) {
        return;
    }


    let sourceContainer = gameClient.player.getContainer(containerIndex);
    if (!sourceContainer) {
        return;
    }

    let item = sourceContainer.getSlotItem(slotIndex);
    if (!item) {
        return;
    }

    // Skip auto-move-to-backpack for container items. Double-tapping an
    // Inbox / sub-chest / loot bag would otherwise shove it into the BP
    // slot, which is destructive and confusing (especially inside the
    // depot where players usually want to OPEN the sub-container, not
    // relocate it). Single-tap still opens the container normally.
    if (item.isContainer && item.isContainer()) {
        return;
    }

    // Always move items to the player's own backpack via equipment backpack slot
    // The server redirects items sent to the equipment backpack slot into the equipped container
    // (including containers from inside the backpack — server handles the redirect)
    let targetContainer = gameClient.player.equipment;
    let targetSlotIndex = CONST.EQUIPMENT.BACKPACK;

    // Create source and target objects for sendItemMove
    let fromObject = {
        "which": sourceContainer,
        "index": slotIndex
    };

    let toObject = {
        "which": targetContainer,
        "index": targetSlotIndex
    };

    // Stackable items (gold, arrows, etc.): move the full stack
    // Non-stackable items: move 1 at a time to prevent accidental transfers
    let count = item.isStackable() ? item.getCount() : 1;

    // Send the move
    gameClient.mouse.sendItemMove(fromObject, toObject, count);

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(30);

}

Touch.prototype.__bindItemDrag = function () {

    /*
     * Function Touch.__bindItemDrag
     * Binds touch drag events for moving items on mobile.
     * Long press on a slot starts dragging, release on another slot or canvas completes the move.
     */

    let self = this;

    document.body.addEventListener("touchstart", function (event) {
        if (!self.isMobileMode) return;
        if (!gameClient || !gameClient.player) return;

        let touch = event.changedTouches[0];
        let element = document.elementFromPoint(touch.clientX, touch.clientY);
        if (!element) return;

        let slotElement = element.closest(".slot");
        if (!slotElement) return;

        // Record start position
        self.__dragState.startX = touch.clientX;
        self.__dragState.startY = touch.clientY;

        // Start drag timer (200ms hold to start drag)
        self.__dragState.dragTimer = setTimeout(function () {
            self.__startItemDrag(slotElement, touch);
        }, 200);

        // Opt-in: a long stationary hold on a slot opens the item context menu.
        // Coexists with the 200ms drag above — finger movement cancels it, and a
        // lifted drag is torn down (no move) when the menu opens.
        self.__slotLongPressFired = false;
        if (gameClient.interface && gameClient.interface.settings
            && gameClient.interface.settings.isLongPressMenuEnabled
            && gameClient.interface.settings.isLongPressMenuEnabled()) {
            let lpSlot = slotElement;
            let lpX = touch.clientX, lpY = touch.clientY;
            self.__slotContextLongPressTimer = setTimeout(function () {
                self.__slotContextLongPressTimer = null;
                self.__triggerSlotLongPressMenu(lpSlot, lpX, lpY);
            }, self.LONG_PRESS_CONTEXT_DURATION);
        }

    }, { passive: true });

    document.body.addEventListener("touchmove", function (event) {
        if (!self.isMobileMode) return;

        let touch = event.changedTouches[0];

        // Cancel the slot long-press menu timer once the finger moves
        if (self.__slotContextLongPressTimer
            && (Math.abs(touch.clientX - self.__dragState.startX) > self.LONG_PRESS_CONTEXT_MOVE_TOLERANCE
             || Math.abs(touch.clientY - self.__dragState.startY) > self.LONG_PRESS_CONTEXT_MOVE_TOLERANCE)) {
            clearTimeout(self.__slotContextLongPressTimer);
            self.__slotContextLongPressTimer = null;
        }

        // If drag timer is pending and finger moved too much, cancel it
        if (self.__dragState.dragTimer && !self.__dragState.active) {
            let dx = Math.abs(touch.clientX - self.__dragState.startX);
            let dy = Math.abs(touch.clientY - self.__dragState.startY);
            if (dx > 15 || dy > 15) {
                clearTimeout(self.__dragState.dragTimer);
                self.__dragState.dragTimer = null;
            }
            return;
        }

        if (!self.__dragState.active) return;

        event.preventDefault();

        // Update floating element position (offset above finger for visibility)
        if (self.__dragState.floatingElement) {
            self.__dragState.floatingElement.style.left = (touch.clientX - 20) + "px";
            self.__dragState.floatingElement.style.top = (touch.clientY - 66) + "px";
        }

        // Update tile highlight on canvas during drag
        let fakeEvent = { clientX: touch.clientX, clientY: touch.clientY };
        let dropEl = document.elementFromPoint(touch.clientX, touch.clientY);
        if (dropEl && (dropEl.id === "screen" || dropEl.closest("#screen"))) {
            let tileObj = gameClient.renderer.screen.getWorldCoordinates(fakeEvent);
            if (tileObj !== gameClient.renderer.__dragHighlightTile) {
                gameClient.renderer.__dragHighlightColor = null;
            }
            gameClient.renderer.__dragHighlightTile = tileObj || null;
        } else {
            gameClient.renderer.__dragHighlightTile = null;
            gameClient.renderer.__dragHighlightColor = null;
        }

        // Highlight potential drop targets
        self.__updateDragHighlight(touch);

    }, { passive: false });

    document.body.addEventListener("touchend", function (event) {
        if (!self.isMobileMode) return;

        // Cancel pending drag timer
        if (self.__dragState.dragTimer) {
            clearTimeout(self.__dragState.dragTimer);
            self.__dragState.dragTimer = null;
        }

        // Cancel pending slot long-press menu timer (released before it fired)
        if (self.__slotContextLongPressTimer) {
            clearTimeout(self.__slotContextLongPressTimer);
            self.__slotContextLongPressTimer = null;
        }

        if (!self.__dragState.active) return;

        event.preventDefault();
        // Prevent the slot tap handler from also firing on this touchend
        event.stopImmediatePropagation();

        let touch = event.changedTouches[0];
        self.__endItemDrag(touch);

    }, { passive: false });

    document.body.addEventListener("touchcancel", function () {
        if (self.__slotContextLongPressTimer) {
            clearTimeout(self.__slotContextLongPressTimer);
            self.__slotContextLongPressTimer = null;
        }
        self.__cancelItemDrag();
    }, { passive: true });

}

Touch.prototype.__startItemDrag = function (slotElement, touch) {

    /*
     * Function Touch.__startItemDrag
     * Initiates item dragging from a slot element
     */

    let slotObject = this.__getSlotObject(slotElement);
    if (!slotObject || !slotObject.which) return;

    // Check if slot has an item
    let slotIndex = Number(slotElement.getAttribute("slotIndex"));
    let item = null;

    if (typeof slotObject.which.getSlotItem === "function") {
        item = slotObject.which.getSlotItem(slotIndex);
    }

    if (!item) return;

    // Set drag state
    this.__dragState.active = true;
    this.__dragWasActive = true;
    this.__dragState.sourceSlot = slotElement;
    this.__dragState.sourceContainer = slotObject.which;
    this.__dragState.sourceIndex = slotIndex;
    this.__dragState.dragTimer = null;

    // Cancel any pending single-tap to prevent use action firing after drag
    if (this.__singleTapTimer) {
        clearTimeout(this.__singleTapTimer);
        this.__singleTapTimer = null;
    }

    // Create floating element with item sprite
    this.__removeAllDragFloats();

    let floater = document.createElement("div");
    floater.className = "mobile-drag-float mobile-push-float";
    floater.style.cssText = "position:fixed;z-index:10000;pointer-events:none;width:40px;height:40px;opacity:0.85;";
    floater.style.left = (touch.clientX - 20) + "px";
    floater.style.top = (touch.clientY - 66) + "px";

    let canvas = document.createElement("canvas");
    canvas.width = 32;
    canvas.height = 32;
    canvas.style.cssText = "width:40px;height:40px;image-rendering:pixelated;";
    floater.appendChild(canvas);

    // Draw the item sprite on the floating canvas
    let drawCanvas = new Canvas(canvas, 32, 32);
    drawCanvas.drawSprite(item, Position.prototype.NULL, 32);

    document.body.appendChild(floater);
    this.__dragState.floatingElement = floater;

    // Dim source slot
    slotElement.style.opacity = "0.4";

    // Vibrate feedback
    if (navigator.vibrate) navigator.vibrate(40);

}

Touch.prototype.__updateDragHighlight = function (touch) {

    /*
     * Function Touch.__updateDragHighlight
     * Updates visual highlight on potential drop targets during drag.
     * Highlights slots with CSS class, and canvas tiles with the renderer highlight.
     */

    // Remove previous slot highlight
    let prev = document.querySelector(".mobile-drag-target");
    if (prev) prev.classList.remove("mobile-drag-target");

    // Find element under finger (ignore floating element)
    if (this.__dragState.floatingElement) {
        this.__dragState.floatingElement.style.display = "none";
    }
    let target = document.elementFromPoint(touch.clientX, touch.clientY);
    if (this.__dragState.floatingElement) {
        this.__dragState.floatingElement.style.display = "";
    }
    if (!target) return;

    // --- Tab hover detection during drag ---
    let tabElement = target.closest(".mobile-container-tab");
    let tabStrip = target.closest(".mobile-container-tabs");
    if (tabStrip || tabElement) {

        // Auto-scroll the tab strip when dragging near its edges
        let strip = tabStrip || tabElement.parentElement;
        let rect = strip.getBoundingClientRect();
        let edgeZone = 30;
        if (touch.clientX < rect.left + edgeZone) {
            strip.scrollLeft -= 3;
        } else if (touch.clientX > rect.right - edgeZone) {
            strip.scrollLeft += 3;
        }

        if (tabElement && !tabElement.classList.contains("mobile-container-tab-close")) {
            let tabCid = Number(tabElement.getAttribute("data-cid"));
            if (tabCid !== this.__dragTabHoverCid) {
                // Finger moved to a different tab — reset timer
                this.__dragTabHoverCid = tabCid;
                clearTimeout(this.__dragTabHoverTimer);
                this.__dragTabHoverTimer = setTimeout(function () {
                    // Route to whichever panel actually owns this tab so drag-hover
                    // switches work on tablet's second container panel too.
                    let panel = gameClient.touch.getContainerPanelFor(tabCid);
                    if (panel) panel.switchTab(tabCid);
                }, 300);
            }
        }
        return;
    }
    // Finger left the tab strip — clear tab hover state
    if (this.__dragTabHoverTimer) {
        clearTimeout(this.__dragTabHoverTimer);
        this.__dragTabHoverTimer = null;
    }
    this.__dragTabHoverCid = null;

    let slotElement = target.closest(".slot");
    if (slotElement && slotElement !== this.__dragState.sourceSlot) {
        slotElement.classList.add("mobile-drag-target");
        // Clear canvas highlight when over a slot
        gameClient.mouse.__currentMouseTile = null;
    } else if (!this.__dragState.isPush && (target.id === "screen" || target.closest("#screen"))) {
        // Dragging over the game canvas — show tile highlight (items only, not pushes)
        let fakeEvent = { clientX: touch.clientX, clientY: touch.clientY };
        gameClient.mouse.__currentMouseTile = gameClient.renderer.screen.getWorldCoordinates(fakeEvent);
    } else {
        gameClient.mouse.__currentMouseTile = null;
    }

}

Touch.prototype.__endItemDrag = function (touch) {

    /*
     * Function Touch.__endItemDrag
     * Completes the item drag by determining the drop target
     */

    // Remove slot and canvas highlights
    let highlighted = document.querySelector(".mobile-drag-target");
    if (highlighted) highlighted.classList.remove("mobile-drag-target");
    gameClient.mouse.__currentMouseTile = null;
    gameClient.renderer.__dragHighlightTile = null;
    gameClient.renderer.__dragHighlightColor = null;
    gameClient.renderer.__pushHighlightTile = null;

    // Find drop target
    // Temporarily hide floater so elementFromPoint finds the real target
    if (this.__dragState.floatingElement) {
        this.__dragState.floatingElement.style.display = "none";
    }

    let dropTarget = document.elementFromPoint(touch.clientX, touch.clientY);

    // Restore floater (will be removed in cleanup)
    if (this.__dragState.floatingElement) {
        this.__dragState.floatingElement.style.display = "";
    }

    let fromObject = {
        "which": this.__dragState.sourceContainer,
        "index": this.__dragState.sourceIndex
    };

    let moved = false;

    if (dropTarget) {
        let slotElement = dropTarget.closest(".slot");

        if (slotElement && slotElement !== this.__dragState.sourceSlot) {
            // Dropped on another slot — move item there
            let targetObject = this.__getSlotObject(slotElement);
            if (targetObject && targetObject.which) {
                let toObject = {
                    "which": targetObject.which,
                    "index": targetObject.index
                };

                // Mobile usability: dragging a container onto the equipment backpack
                // slot should nest it inside the equipped backpack, not swap/equip.
                // Desktop has the open-backpack contents area for nesting; mobile
                // doesn't, so without this redirect every ground-bag drop becomes
                // an accidental swap.
                if (toObject.which === gameClient.player.equipment
                        && Number(toObject.index) === CONST.EQUIPMENT.BACKPACK) {
                    let sourceItem = typeof fromObject.which.getSlotItem === "function"
                        ? fromObject.which.getSlotItem(fromObject.index) : null;
                    if (sourceItem && sourceItem.isContainer && sourceItem.isContainer()) {
                        let equippedBp = typeof gameClient.player.equipment.peekItem === "function"
                            ? gameClient.player.equipment.peekItem(CONST.EQUIPMENT.BACKPACK) : null;
                        if (equippedBp) {
                            let opened = Array.from(gameClient.player.__openedContainers);
                            for (let i = 0; i < opened.length; i++) {
                                if (opened[i].id === equippedBp.id && opened[i] !== fromObject.which) {
                                    toObject.which = opened[i];
                                    toObject.index = 0;
                                    break;
                                }
                            }
                        }
                    }
                }

                gameClient.mouse.__bindMoveCallback(fromObject, toObject);
                moved = true;
            }
        } else if (dropTarget.id === "screen" || dropTarget.closest("#screen")) {
            // Dropped on game canvas — throw item on ground
            let fakeEvent = { clientX: touch.clientX, clientY: touch.clientY };
            let tileObject = gameClient.mouse.getWorldObject(fakeEvent);
            if (tileObject && tileObject.which) {
                let toObject = {
                    "which": tileObject.which,
                    "index": tileObject.index
                };
                gameClient.mouse.__bindMoveCallback(fromObject, toObject);
                moved = true;
            }
        }
    }

    if (moved && navigator.vibrate) {
        navigator.vibrate(30);
    }

    // Cleanup
    this.__cancelItemDrag();

}

Touch.prototype.__cancelItemDrag = function () {

    /*
     * Function Touch.__cancelItemDrag
     * Cancels an active item drag and cleans up
     */

    // Cancel pending tab-hover timer
    if (this.__dragTabHoverTimer) {
        clearTimeout(this.__dragTabHoverTimer);
        this.__dragTabHoverTimer = null;
    }
    this.__dragTabHoverCid = null;

    // Cancel pending timer
    if (this.__dragState.dragTimer) {
        clearTimeout(this.__dragState.dragTimer);
        this.__dragState.dragTimer = null;
    }

    // Restore source slot opacity
    if (this.__dragState.sourceSlot) {
        this.__dragState.sourceSlot.style.opacity = "";
    }

    // Remove floating element
    this.__removeAllDragFloats();

    // Remove any drag highlight
    let highlighted = document.querySelector(".mobile-drag-target");
    if (highlighted) highlighted.classList.remove("mobile-drag-target");

    // Clear drag tile highlights
    gameClient.renderer.__dragHighlightTile = null;
    gameClient.renderer.__dragHighlightColor = null;
    gameClient.renderer.__pushHighlightTile = null;

    // Reset state
    this.__dragState.active = false;
    this.__dragState.isPush = false;
    this.__dragState.sourceSlot = null;
    this.__dragState.sourceContainer = null;
    this.__dragState.sourceIndex = -1;

}

Touch.prototype.__stackPanels = function () {

    /*
     * Function Touch.__stackPanels
     * Position visible panels vertically below each other.
     * Centered panels (minimap, stats, friends) are skipped — they use CSS centering.
     * Layout-custom panels (user dragged them via layout editor) are also
     * skipped — stacking with inline top would clobber the saved top:auto /
     * bottom: Xpx anchor and visibly displace / stretch the panel. This was
     * the iPhone "equipment jumps after switching to minimap and back" bug:
     * __showPanel ran reapplyElement (top: auto), then __stackPanels ran
     * right after and overwrote top with an inline px value, leaving the
     * panel with conflicting top + bottom anchors.
     */

    let order = ['equipment', 'minimap', 'stats', 'friends'];
    let centeredPanels = ['minimap', 'stats', 'friends'];
    let panels = this.__getTabPanels();
    let statusBar = document.getElementById('mobile-status-bar');
    let layoutCustom = document.body.classList.contains('layout-custom');
    // When status-bar-bottom (user toggle) or iphone-notch is active, the
    // status bar isn't at the top — mobile.css pins panels to `top: 5px
    // !important`. Using the status-bar offset as the starting top would
    // bake in ~37px of empty space. Start from 5px to match the CSS.
    let statusBarBottom = document.documentElement.classList.contains('status-bar-bottom')
                       || document.documentElement.classList.contains('iphone-notch');
    let currentTop = statusBarBottom ? 5 : (statusBar ? (statusBar.offsetHeight + 1) : 37);

    for (let i = 0; i < order.length; i++) {
        let name = order[i];
        let panel = panels[name];
        if (!panel || !this.__visiblePanels || !this.__visiblePanels.has(name)) continue;

        // Skip centered panels — they use CSS centering via translate(-50%, -50%)
        if (centeredPanels.indexOf(name) !== -1) continue;

        // Skip stacking when layout-custom is active — the layout editor
        // already placed this panel at the saved coordinates, and setting
        // top here would fight that.
        if (layoutCustom) continue;

        panel.style.setProperty('top', currentTop + 'px', 'important');
        let rect = panel.getBoundingClientRect();
        currentTop += rect.height + 1;
    }

}

Touch.prototype.__togglePanel = function (panelName, show) {

    /*
     * Function Touch.__togglePanel
     * Force show or hide a panel
     */

    if (!this.__visiblePanels) {
        return;
    }

    if (show && !this.__visiblePanels.has(panelName)) {
        this.__showPanel(panelName);
        this.__visiblePanels.add(panelName);
    } else if (!show && this.__visiblePanels.has(panelName)) {
        this.__hidePanel(panelName);
        this.__visiblePanels.delete(panelName);
    }

    this.__updateTabButtons();
    this.__stackPanels();

}

Touch.prototype.__bindPanelHeaders = function () {

    /*
     * Function Touch.__bindPanelHeaders
     * Bind close and minimize buttons in mobile panel headers
     */

    let self = this;
    let panels = this.__getTabPanels();

    document.querySelectorAll('.mobile-panel-header').forEach(function (header) {
        let panel = header.parentElement;
        let panelName = null;

        for (let name in panels) {
            if (panels[name] === panel) {
                panelName = name;
                break;
            }
        }

        if (!panelName) return;

        let closeBtn = header.querySelector('.mobile-panel-close');
        if (closeBtn) {
            closeBtn.addEventListener('touchstart', function (e) {
                e.preventDefault();
                e.stopPropagation();
                self.__togglePanel(panelName, false);
            }, { passive: false });
            closeBtn.addEventListener('click', function (e) {
                e.stopPropagation();
                self.__togglePanel(panelName, false);
            });
        }

        let minBtn = header.querySelector('.mobile-panel-minimize');
        if (minBtn) {
            minBtn.addEventListener('touchstart', function (e) {
                e.preventDefault();
                e.stopPropagation();
                self.__minimizePanel(panelName, minBtn);
            }, { passive: false });
            minBtn.addEventListener('click', function (e) {
                e.stopPropagation();
                self.__minimizePanel(panelName, minBtn);
            });
        }
    });

}

Touch.prototype.__bindWindowRestack = function () {

    /*
     * Function Touch.__bindWindowRestack
     * Bind to existing window minimize/close buttons to re-stack panels
     */

    let self = this;
    let windows = {
        'skill-window': 'stats',
        'friend-window': 'friends',
        // Battle window shares the 'friends' tab key — closing it via the ✕
        // button dismisses the whole People panel just like closing Friends.
        'battle-window': 'friends'
    };

    for (let id in windows) {
        let win = document.getElementById(id);
        if (!win) continue;
        let tabName = windows[id];

        // Minimize button — re-stack after body toggle
        let minBtn = win.querySelector('button[action="minimize"]');
        if (minBtn) {
            let handler = function () {
                setTimeout(function () {
                    if (self.__visiblePanels) self.__stackPanels();
                }, 50);
            };
            minBtn.addEventListener('click', handler);
            minBtn.addEventListener('touchstart', handler);
        }

        // Close button — properly hide panel (removes mobile-tab-panel class)
        let closeBtn = win.querySelector('button[action="close"]');
        if (closeBtn) {
            let closeHandler = function (e) {
                e.preventDefault();
                e.stopPropagation();
                self.__togglePanel(tabName, false);
            };
            closeBtn.addEventListener('touchstart', closeHandler, { passive: false });
            closeBtn.addEventListener('click', closeHandler);
        }
    }

}

Touch.prototype.__minimizePanel = function (panelName, button) {

    /*
     * Function Touch.__minimizePanel
     * Toggle minimized state of a panel
     */

    let panels = this.__getTabPanels();
    let panel = panels[panelName];
    if (!panel) return;

    let isMinimized = panel.classList.toggle('mobile-minimized');
    button.textContent = isMinimized ? '+' : '\u2212';

    this.__stackPanels();

}



