    if (__provTicks >= 120) {
      __provTicks = 0;
      if (__imA + __imB > 0) {
        try {
          gameClient.sendDebug("[imx] t=" + __imA
            + " u=" + __imB
            + " r=" + (Math.round(100 * __imA / (__imA + __imB)) / 100));
        } catch (e) {}
        __imA = 0;
        __imB = 0;
      }
    }

