PacketHandler.prototype.__UNDEAD_NAMES = /skeleton|ghost|lich|banshee|bonebeast|crypt shambler|mummy|pharaoh|beholder|braindeath|undead|zombie|ghoul|vampire|necromancer|deathslicer|demon skeleton|stalker/i;
PacketHandler.prototype.__SLIME_NAMES = /slime|spider|wasp|bug|scorpion|larva|poison|toad|snake|serpent|swamp|acid|scarab|centipede|ant|beetle|worm|rotworm|carrion/i;
PacketHandler.prototype.__FIRE_NAMES = /demon|devil|fire|hellhound|flame|lava|infernal|magma|pyro|hellfire|cerberus|fury/i;
PacketHandler.prototype.__ELEMENTAL_NAMES = /elemental|djinn|efreet|marid|energy|crystal|ice|frost|water|earth/i;

PacketHandler.prototype.__getCreatureBloodColor = function (creature) {

  /*
   * Function PacketHandler.__getCreatureBloodColor
   * Returns the RGBA blood splatter color based on creature name
   */

  let name = creature.name;

  if (creature.type !== CONST.TYPES.MONSTER) {
    return [160, 10, 10];
  }

  if (PacketHandler.prototype.__UNDEAD_NAMES.test(name)) {
    return [180, 180, 170];
  }

  if (PacketHandler.prototype.__SLIME_NAMES.test(name)) {
    return [30, 160, 20];
  }

  if (PacketHandler.prototype.__FIRE_NAMES.test(name)) {
    return [255, 120, 20];
  }

  if (PacketHandler.prototype.__ELEMENTAL_NAMES.test(name)) {
    return [60, 140, 220];
  }

  return [160, 10, 10];

}

// Body size category for death explosion particle scaling
PacketHandler.prototype.__BODY_SMALL = /rat|bat|snake|cobra|chicken|rabbit|skunk|squirrel|frog|toad|fish|crab/i;

PacketHandler.prototype.__updateDamageTint = function (creature, newHealth) {

  /*
   * Function PacketHandler.__updateDamageTint
   * Sets the damage tint intensity (0-1) and color based on HP percentage
   * and creature type. Tint starts at 75% HP and scales linearly to 0 HP.
   */

  if (creature === gameClient.player) {
    creature.__damageTint = 0;
    return;
  }

  let pct = creature.maxHealth > 0 ? newHealth / creature.maxHealth : 1;

  if (pct > 0.75) {
    creature.__damageTint = 0;
  } else {
    creature.__damageTint = 1.0 - (pct / 0.75);
  }

  // Set tint color on first damage (based on creature blood type)
  if (creature.__damageTint > 0 && !creature.__damageTintColor) {
    creature.__damageTintColor = this.__getDamageTintColor(creature);
  }

}

PacketHandler.prototype.__getDamageTintColor = function (creature) {

  /*
   * Function PacketHandler.__getDamageTintColor
   * Returns [r, g, b] tint target color based on creature type.
   * Used as the color the sprite shifts toward when damaged.
   */

  let name = creature.name;

  if (PacketHandler.prototype.__UNDEAD_NAMES.test(name)) {
    return [0.45, 0.45, 0.35];
  }

  if (PacketHandler.prototype.__SLIME_NAMES.test(name)) {
    return [0.15, 0.55, 0.1];
  }

  if (PacketHandler.prototype.__FIRE_NAMES.test(name)) {
    return [0.2, 0.05, 0.05];
  }

  if (PacketHandler.prototype.__ELEMENTAL_NAMES.test(name)) {
    return [0.15, 0.35, 0.6];
  }

  // Default: red blood
  return [0.55, 0.05, 0.05];

}



/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/network/packet.js ===== */

"use strict";

const Packet = function() {

  /*
   * Class Packet
   * Container for a packet (writeable or readable)
   */

  this.index = 0;

}

Packet.prototype.advance = function(amount) {

  /*
   * Function Packet.advance 
   * Advanced the packet by a number of bytes
   */

  this.index += amount;

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/network/packetreader.js ===== */

"use strict";

const PacketReader = function (buffer) {

  /*
   * Class PacketReader
   * Container for a packet (writeable or readable)
   */

  Packet.call(this);

  // Set the buffer
  this.buffer = new Uint8Array(buffer);

}

PacketReader.prototype = Object.create(Packet.prototype);
PacketReader.prototype.constructor = PacketReader;

PacketReader.prototype.slice = function (start, end) {

  /*
   * Function PacketReader.slice
   * Returns the slice of a packetreader class as a new packetreader class
   */

  return new PacketReader(this.buffer.subarray(start, end));

}

PacketReader.prototype.readCharacterStatistics = function () {

  /*
   * Function PacketReader.readCharacterStatistics
   * Reads the character statistics
   */

  return new Object({
    "capacity": this.readUInt32(),
    "attack": this.readUInt8(),
    "armor": this.readUInt8(),
    "speed": this.readUInt16()
  });

}

PacketReader.prototype.readProperty = function () {

  return new Object({
    "guid": this.readUInt32(),
    "property": this.readUInt8(),
    "value": this.readUInt32()
  });

}

PacketReader.prototype.readCharacterInformation = function () {

  let info = new Object({
    "name": this.readString(),
    "isPlayer": this.readBoolean(),
    "level": this.readUInt16(),
    "sex": this.readUInt8(),
    "vocation": this.readUInt8(),
    "role": this.readUInt8(),
    "hasGuild": false,
    "guildName": null,
    "guildRank": null,
    "hasMaster": false,
    "masterName": null,
    "masterIsMonster": false
  });

  // Read guild data if present
  info.hasGuild = this.readBoolean();

  if (info.hasGuild) {
    info.guildName = this.readString();
    info.guildRank = this.readString();
  }

  // Read summon master data if present (who owns this creature)
  info.hasMaster = this.readBoolean();

  if (info.hasMaster) {
    info.masterName = this.readString();
    info.masterIsMonster = this.readBoolean();
  }

  return info;

}

PacketReader.prototype.readToggleCondition = function () {

  /*
   * Function PacketReader.readToggleCondition
   * Reads a packet that contains a condition toggle
   * Includes optional properties byte (e.g., light level for LIGHT condition)
   */

  return new Object({
    "guid": this.readUInt32(),
    "toggle": this.readBoolean(),
    "cid": this.readUInt16(),
    "properties": this.readUInt8(),
    "permanent": this.readBoolean()
  });

}

PacketReader.prototype.readCastSpell = function () {

  /*
   * Function PacketReader.readCastSpell
   * Reads a cast spell packet from the server
   */

  return new Object({
    "id": this.readUInt16(),
    "cooldown": this.readUInt32()
  });

}

PacketReader.prototype.readUseGlobalCooldown = function () {
  /*
   * Function PacketReader.readUseGlobalCooldown
   * Reads a use-global-cooldown packet (spell→rune lockout duration in ms
   * + 1 byte bucket: 0 = attack, 1 = heal). Bucket dims only that bucket's
   * rune slots; the other bucket's slots stay free.
   */
  return { "durationMs": this.readUInt32(), "bucket": this.readUInt8() };
}

PacketReader.prototype.readFluidGlobalCooldown = function () {
  /*
   * Function PacketReader.readFluidGlobalCooldown
   * Reads a fluid-global-cooldown packet (fluid drink lockout duration ms).
   * Independent from rune/spell bucket — only dims fluid hotbar slots.
   */
  return { "durationMs": this.readUInt32() };
}
PacketReader.prototype.readSingleTradeOffer = function () {

  /*
   * Function PacketReader.readSingleTradeOffer
   * Reads a single trade offer provided by an NPC
   */

  return new Object({
    "id": this.readUInt16(),
    "name": this.readString(),
    "price": this.readUInt32(),
    "type": this.readBoolean() ? "sell" : "buy"
  });

}

PacketReader.prototype.readTradeOffer = function () {

  /*
   * Function PacketReader.readTradeOffer
   * Reads all the trade offers provided by an NPC
   */

  // The identifier of the NPC
  let id = this.readUInt32();

  // These are the offers that must be read
  let offers = new Array();
  let length = this.readUInt8();

  for (let i = 0; i < length; i++) {
    offers.push(this.readSingleTradeOffer());
  }

  return new Object({
    "id": id,
    "offers": offers
  });

}

PacketReader.prototype.readReadable = function () {

  /*
   * Function PacketReader.readReadable
   * Reads a readable thing
   */

  return new Object({
    "itemId": this.readUInt32(),
    "writeable": this.readBoolean(),
    "content": this.readString(),
    "name": this.readString(),
    "writer": this.readString()
  });

}

PacketReader.prototype.readAddAchievement = function (packet) {

  /*
   * Function PacketReader.readAddAchievement
   * 
   */

  return new Object({
    "title": this.readString(),
    "description": this.readString()
  });

}

PacketReader.prototype.readZoneInformation = function () {

  /*
   * Funciton PacketReader.readZoneInformation
   * Reads zone information passed by the server (e.g., weather and zone name)
   */

  return new Object({
    "name": this.readString(),
    "title": this.readString(),
    "music": this.readString(),
    "weather": this.readUInt8() / 255,
    "ambient": new RGBA(
      this.readUInt8(),
      this.readUInt8(),
      this.readUInt8(),
      this.readUInt8()
    ),
    "rain": this.readBoolean()
  });

}

PacketReader.prototype.readWeather = function () {

  /*
   * Function PacketReader.readWeather
   * Reads weather data sent by the server
   * precipitation: 0 = none, 1 = rain, 2 = snow, 3 = sandstorm, 4 = drizzle, 5 = hail, 6 = ash, 7 = leaves, 9 = mist, 10 = dust
   * thunder: 0 = disabled, 1 = enabled
   */

  let weather = this.readUInt8() / 255;
  let ambient = new RGBA(
    this.readUInt8(),
    this.readUInt8(),
    this.readUInt8(),
    this.readUInt8()
  );
  let precipitation = this.readUInt8();
  let flags = this.readUInt8();

  return new Object({
    "weather": weather,
    "ambient": ambient,
    "precipitation": precipitation,
    "thunder": (flags & 1) === 1,
    "clouds": (flags & 2) === 2,
    "aurora": (flags & 4) === 4
  });

}

PacketReader.prototype.readDefaultMessage = function () {

  /*
   * Function PacketReader.readDefaultMessage
   * Reads a message in the default channel
   */

  return new Object({
    "id": this.readUInt32(),
    "type": this.readUInt8(),
    "message": this.readString(),
    "color": this.readUInt8(),
    "loudness": this.readUInt8()
  });

}

PacketReader.prototype.readFriend = function (defensive) {

  /*
   * Function PacketReader.readFriend
   * Reads friend name + online status + icon marker.
   *
   * defensive=true (NO-RESTART desync mitigation, 2026-06-11): the
   * FRIEND_STATUS / FRIEND_ADD writers omit the icon field that the
   * FRIEND-LIST writer includes (server bug shipped 2026-04-03; the
   * server-side fix is committed but awaits an engine restart). Reading a
   * phantom icon here makes readString consume the NEXT packet's bytes as
   * a giant string length and desyncs the whole frame — THE root of the
   * seq-gap / frozen-HP / ghost-monster / fake-watch epidemic. Defensive
   * read PEEKS the icon length: a real VIP icon is tiny, the fixed server
   * sends length 0, but the broken server's phantom length is huge
   * garbage — so if it exceeds the cap, the field isn't there: rewind and
   * treat the icon as absent. Robust to BOTH server states (broken now,
   * fixed after the restart sends length 0 < cap), so it never needs a
   * revert. The FRIEND-LIST loop reads non-defensively (icons always
   * present there). Belt-and-suspenders with the server-side fix.
   */

  let name = this.readString();
  let online = this.readBoolean();

  if (!defensive) {
    return new Object({ "name": name, "online": online, "icon": this.readString() });
  }

  let icon = "";
  let mark = this.index;
  let iconLen = this.readUInt16();
  // 32 bytes comfortably exceeds any real VIP-icon marker AND the fixed
  // server's empty (0); a phantom over-read is almost always far larger.
  if (iconLen <= 32) {
    this.index = mark;          // plausible — re-read it properly as a string
    icon = this.readString();
  } else {
    this.index = mark;          // implausible — server omitted the icon; rewind
  }
  return new Object({ "name": name, "online": online, "icon": icon });

}

PacketReader.prototype.readAnimationLength = function () {

  /*
   * Function PacketReader.readAnimationLength
   * Read the minimum and maximum length of an animation (1098 client versions)
   */

  return new Object({
    "min": this.readUInt32(),
    "max": this.readUInt32()
  });

}

