PacketReader.prototype.readEntityMove = function () {

  /*
   * Function PacketReader.readEntityMove
   * Reads an entity move event towards a position with a particular speed
   */

  return new Object({
    "id": this.readUInt32(),
    "position": this.readPosition(),
    "speed": this.readUInt16()
  });

}

PacketReader.prototype.readMapArea = function () {

  /*
   * Function PacketReader.readMapArea
   * Reads a MAP_AREA packet — full rectangular area around player.
   * Wire format: playerPos, floorCount, per-floor (z, w, h, w*h tiles).
   */

  let playerPos = {
    x: this.readUInt16(),
    y: this.readUInt16(),
    z: this.readUInt16()
  };
  let floorCount = this.readUInt8();
  let floors = [];
  for (let i = 0; i < floorCount; i++) {
    let z = this.readUInt8();
    let width = this.readUInt8();
    let height = this.readUInt8();
    let tiles = [];
    for (let j = 0; j < width * height; j++) {
      tiles.push({
        id: this.readUInt16(),
        flags: this.readUInt8(),
        items: this.readItems()
      });
    }
    floors.push({ z: z, width: width, height: height, tiles: tiles });
  }
  return { playerPos: playerPos, floors: floors };

}

PacketReader.prototype.readMapSlice = function () {

  /*
   * Function PacketReader.readMapSlice
   * Reads a MAP_SLICE_* packet — single row or column of tiles at the
   * leading edge after a player step. Direction is encoded in the
   * opcode (handled by caller). Wire format: playerPos, floorCount,
   * per-floor (z, tileCount, tileCount tiles).
   */

  let playerPos = {
    x: this.readUInt16(),
    y: this.readUInt16(),
    z: this.readUInt16()
  };
  let floorCount = this.readUInt8();
  let floors = [];
  for (let i = 0; i < floorCount; i++) {
    let z = this.readUInt8();
    let tileCount = this.readUInt8();
    let tiles = [];
    for (let j = 0; j < tileCount; j++) {
      tiles.push({
        id: this.readUInt16(),
        flags: this.readUInt8(),
        items: this.readItems()
      });
    }
    floors.push({ z: z, tiles: tiles });
  }
  return { playerPos: playerPos, floors: floors };

}

PacketReader.prototype.__readChunkTiles = function () {

  /*
   * Function PacketReader.__readChunkTiles
   * Reads all tile identifiers from the passed chunk
   */

  let tiles = new Array();

  for (let i = 0; i < 8; i++) {

    let ntiles = this.readUInt8();

    // Read the number of tiles in a chunk
    for (let j = 0; j < Chunk.prototype.getNumberTilesLayer(); j++) {

      if (ntiles === 0) {
        tiles.push(new Object({
          "id": 0,
          "flags": 0,
          "items": new Array()
        }));
      } else {
        tiles.push(new Object({
          "id": this.readUInt16(),
          "flags": this.readUInt8(),
          "items": this.readItems()
        }));
      }

    }

  }

  return tiles;

}

PacketReader.prototype.readServerData = function () {

  /*
   * Function PacketReader.readServerData
   * Reads important server data: this is the first packet sent by the server to the client
   */

  return new Object({
    "width": this.readUInt16(),
    "height": this.readUInt16(),
    "depth": this.readUInt8(),
    "chunk": {
      "width": this.readUInt8(),
      "height": this.readUInt8(),
      "depth": this.readUInt8()
    },
    "tick": this.readUInt8(),
    "clock": this.readUInt16(),
    "version": this.readString(),
    "clientVersion": this.readUInt16()
  });

}

PacketReader.prototype.readUInt16 = function () {

  /*
   * Function PacketReader.readUInt16
   * Unpacks and reads a value as an unsigned 2 byte integer
   */

  return this.buffer[this.index++] + (this.buffer[this.index++] << 8);

}

