PacketReader.prototype.readQuestLog = function () {
  /*
   * Function PacketReader.readQuestLog
   * Reads the achievement list with progress + quest chest completion
   */
  let length = this.readUInt16();
  let achievements = [];
  for (let i = 0; i < length; i++) {
    achievements.push({
      id: this.readUInt16(),
      name: this.readString(),
      description: this.readString(),
      completed: this.readBoolean(),
      current: this.readUInt16(),
      required: this.readUInt16()
    });
  }

  // Quest chests section
  let questChests = [];
  let chestCount = this.readUInt16();
  for (let i = 0; i < chestCount; i++) {
    questChests.push({
      name: this.readString(),
      reward: this.readString(),
      completed: this.readBoolean()
    });
  }

  return { achievements: achievements, questChests: questChests };
}

