const StrictMovementPacket = function (direction, position) {

  /*
   * Class StrictMovementPacket
   * Experimental "Strict Walk" variant of MovementPacket. In addition to
   * the step direction, it carries the BASE tile the client stepped FROM
   * (its position before this step's client-side prediction advanced it).
   * The server resolves the step from this base — validated within the
   * prediction window — instead of from its own (lagging) position, so the
   * two agree at turns and the "diagonal sidestep" desync goes away.
   * Only sent when the "Strict Walk" client setting is ON; otherwise the
   * client sends the plain MovementPacket and the server takes the
   * byte-identical legacy MOVE path. Wire shape: UInt8 dir, UInt16 x,
   * UInt16 y, UInt8 z (6 bytes), mirroring WalkToDestinationPacket's
   * position layout.
   */

  PacketWriter.call(this, CONST.PROTOCOL.CLIENT.STRICT_MOVE, 6);

  this.writeUInt8(direction);
  this.writeUInt16(position.x);
  this.writeUInt16(position.y);
  this.writeUInt8(position.z);

}

