const AutoWalkPacket = function (directions) {

  /*
   * Class AutoWalkPacket
   * Sends a full path (direction list) to the server for server-owned autowalking
   */

  let count = Math.min(directions.length, 255);

  PacketWriter.call(this, CONST.PROTOCOL.CLIENT.AUTO_WALK, 1 + count);

  this.writeUInt8(count);
  for (let i = 0; i < count; i++) {
    this.writeUInt8(directions[i]);
  }

}

