const GameLobbyPacket = function (game, op, name, stake) {
  /* Simple/table-game lobby op: game + op (open/challenge/accept/decline/resign/
   * create/join/leave/start) + name + optional u32 gold STAKE (0 = free game;
   * used by challenge + create). The server reads the stake only if present, so
   * older clients that omit it are safe. */
  let g = this.encodeString(game), o = this.encodeString(op), n = this.encodeString(name || "");
  PacketWriter.call(this, CONST.PROTOCOL.CLIENT.GAME_LOBBY, g.stringLength + o.stringLength + n.stringLength + 4);
  this.writeBuffer(g.stringEncoded); this.writeBuffer(o.stringEncoded); this.writeBuffer(n.stringEncoded);
  this.writeUInt32(Math.max(0, Math.floor(stake || 0)));
};
