const CaptchaResponsePacket = function (actionId, clickedIndex, clickXByte, clickYByte) {

  /*
   * Class CaptchaResponsePacket
   * Posts the tile index the player clicked back to the server.
   * Server kept the correct answer at issue time and compares.
   *
   * clickXByte / clickYByte (optional): UInt8 0-255 ≈ normalized
   * 0.0-1.0 click position within the clicked tile. Default 127 (mid)
   * if caller didn't supply. Used by Phase 1 behavioral fingerprinting
   * server-side — log-only, no enforcement.
   */

  PacketWriter.call(this, CONST.PROTOCOL.CLIENT.CAPTCHA_RESPONSE, 7);

  this.writeUInt32(actionId);
  this.writeUInt8(Number(clickedIndex) & 0xFF);
  this.writeUInt8((typeof clickXByte === "number" ? Math.max(0, Math.min(255, clickXByte | 0)) : 127) & 0xFF);
  this.writeUInt8((typeof clickYByte === "number" ? Math.max(0, Math.min(255, clickYByte | 0)) : 127) & 0xFF);

}

CaptchaResponsePacket.prototype = Object.create(PacketWriter.prototype);
CaptchaResponsePacket.prototype.constructor = CaptchaResponsePacket;

