Canvas.prototype.__drawOutfitCellGL = function (spriteBufferMount, outfit, characterGroup, mountGroup, characterFrame, mountFrame, xPattern, zPattern, x, y, position, size) {

  /*
   * Function Canvas.__drawOutfitCellGL
   * Draws one outfit sprite cell via the GPU outfit-color shader: each
   * active layer (base + enabled addons) is drawn as a masked quad straight
   * from the shared sprite atlas — no per-creature composed copy. Returns
   * true when the cell was handled; false = caller uses the composed path.
   */

  let global = gameClient.spriteBuffer;

  // Resolve every active layer BEFORE drawing anything so a miss can fall
  // back to the composed path for the whole cell (mirrors addComposedOutfit)
  let baseSprites = [];
  let maskSprites = [];

  for (let yPattern = 0; yPattern < 3; yPattern++) {

    if (yPattern === 1 && !(outfit.addonOne && characterGroup.pattern.y > 1)) continue;
    if (yPattern === 2 && !(outfit.addonTwo && characterGroup.pattern.y > 2)) continue;

    let baseId = characterGroup.getSpriteId(characterFrame, xPattern, yPattern, zPattern, 0, x, y);
    if (baseId === 0) {
      continue;
    }

    let baseSprite = global.get(baseId);
    if (baseSprite === null || !baseSprite.glTexture) {
      return false;
    }

    let maskId = characterGroup.getSpriteId(characterFrame, xPattern, yPattern, zPattern, 1, x, y);
    let maskSprite = null;
    if (maskId !== 0) {
      maskSprite = global.get(maskId);
      // Base and mask must share the atlas texture (single sampler)
      if (maskSprite === null || !maskSprite.glTexture || maskSprite.glTexture !== baseSprite.glTexture) {
        return false;
      }
    }

    baseSprites.push(baseSprite);
    maskSprites.push(maskSprite);

  }

  // Empty cell: handled (the composed path draws nothing here either)
  if (baseSprites.length === 0) {
    return true;
  }

  // The mount is enabled and available — drawn beneath, same as composed path
  if (zPattern === 1 && mountGroup) {
    let mountSprite = mountGroup.getSpriteId(mountFrame, xPattern, 0, 0, 0, x, y);
    this.__drawSprite(spriteBufferMount.get(mountSprite), position, x, y, size);
  }

  // Destination rect: identical math to __drawSprite's WebGL branch
  let dX = Math.round(32 * (position.x - x));
  let dY = Math.round(32 * (position.y - y));
  let dW = 32;
  let dH = 32;

  let sc = this.__spriteBatch.__spriteScale;
  if (sc && sc !== 1.0) {
    let center = this.__spriteBatch.__spriteScaleCenter;
    dX = center.x + (dX - center.x) * sc;
    dY = center.y + (dY - center.y) * sc;
    dW = 32 * sc;
    dH = 32 * sc;
  }

  let colors = outfit.getColorsNormalized();

  for (let i = 0; i < baseSprites.length; i++) {

    gameClient.renderer.drawCalls++;

    let baseSprite = baseSprites[i];
    let maskSprite = maskSprites[i];

    if (maskSprite === null) {
      // Layer without a color mask: plain draw (mutual flushing in the
      // batch keeps painter's order between the two queues)
      this.__spriteBatch.bindTexture(baseSprite.glTexture);
      this.__spriteBatch.draw(
        32 * baseSprite.position.x,
        32 * baseSprite.position.y,
        32, 32,
        dX, dY, dW, dH,
        this.__spriteBatch.__globalAlpha,
        baseSprite.atlasWidth,
        baseSprite.atlasHeight
      );
    } else {
      this.__spriteBatch.drawMasked(
        baseSprite.glTexture,
        32 * baseSprite.position.x,
        32 * baseSprite.position.y,
        32 * maskSprite.position.x,
        32 * maskSprite.position.y,
        dX, dY, dW, dH,
        this.__spriteBatch.__globalAlpha,
        baseSprite.atlasWidth,
        baseSprite.atlasHeight,
        colors
      );
    }

  }

  return true;

}

Canvas.prototype.drawItemAsCreature = function (itemId, position, size) {

  /*
   * Function Canvas.drawItemAsCreature
   * Tibia 7.4: Renders an item sprite at a creature position (for lookTypeEx outfits like the Oracle)
   */

  let dataObject = gameClient.dataObjects.get(itemId);

  if (!dataObject) {
    return;
  }

  let frameGroup = dataObject.frameGroups[0];
  let frame = 0;

  // Handle animated items
  if (frameGroup.animationLength > 1) {
    frame = ((gameClient.renderer.__nMiliseconds / 500) % frameGroup.animationLength) | 0;
  }

  for (let x = 0; x < frameGroup.width; x++) {
    for (let y = 0; y < frameGroup.height; y++) {
      for (let l = 0; l < frameGroup.layers; l++) {
        let index = frameGroup.getSpriteIndex(frame, 0, 0, 0, l, x, y);
        this.__drawSprite(frameGroup.getSprite(index), position, x, y, size);
      }
    }
  }

}

Canvas.prototype.__compositeAux = function () {

  /*
   * Function Canvas.__compositeAux
   * Composites the auxiliary 2D canvas onto the WebGL screen and clears it
   * Skips the expensive texSubImage2D upload if nothing was drawn
   */

  if (!this.__isWebGL || !this.__auxCanvas || !this.__auxDirty) {
    return;
  }

  this.__spriteBatch.drawCanvasOverlay(
    this.__auxCanvas,
    0, 0, this.__auxCanvas.width, this.__auxCanvas.height,
    0, 0, this.canvas.width, this.canvas.height
  );

  // Clear aux canvas for next use
  this.context.clearRect(0, 0, this.__auxCanvas.width, this.__auxCanvas.height);
  this.__auxDirty = false;

}

Canvas.prototype.__compositeCanvas = function (sourceCanvas) {

  /*
   * Function Canvas.__compositeCanvas
   * Composites an external canvas directly onto the WebGL screen
   * Avoids the aux canvas intermediary for better performance
   */

  if (!this.__isWebGL) {
    return;
  }

  this.__spriteBatch.drawCanvasOverlay(
    sourceCanvas,
    0, 0, sourceCanvas.width, sourceCanvas.height,
    0, 0, this.canvas.width, this.canvas.height
  );

}

Canvas.prototype.__parseHexColor = function (hex) {

  /*
   * Function Canvas.__parseHexColor
   * Parses a hex color string "#RRGGBB" to RGB float array [r, g, b] in 0-1 range
   */

  if (hex && hex.charAt(0) === "#") {
    return [
      parseInt(hex.slice(1, 3), 16) / 255,
      parseInt(hex.slice(3, 5), 16) / 255,
      parseInt(hex.slice(5, 7), 16) / 255
    ];
  }

  return [1, 0, 0];

}

Canvas.prototype.__reference = function (id) {

  /*
   * Function Canvas.__reference
   * References a new or existing canvas
   */

  // Create an offscreen canvas or find the one existing in the DOM from string, or use a passed canvas
  if (id === null) {
    return document.createElement("canvas");
  }

  // If the passed identifier is a string: read it from the DOM
  if (typeof id === "string") {
    return document.getElementById(id);
  }

  return id;

}




Canvas.prototype.drawBloodSplatter = function (position, particles, progress, color) {

  /*
   * Function Canvas.drawBloodSplatter
   * Draws small colored dots that spray outward from the creature in the attack direction
   */

  let cx = 32 * position.x + 16;
  let cy = 32 * position.y + 16;
  let alpha = 1.0 - progress * progress;
  let r = color[0];
  let g = color[1];
  let b = color[2];

  this.context.save();
  this.context.fillStyle = "rgba(" + r + "," + g + "," + b + "," + alpha + ")";
  for (let i = 0; i < particles.length; i++) {
    let p = particles[i];
    let px = cx + p.vx * progress * 10;
    let py = cy + p.vy * progress * 10;
    let sz = p.size * (1.0 - progress * 0.3);
    this.context.beginPath();
    this.context.arc(px, py, sz, 0, 2 * Math.PI);
    this.context.fill();
  }
  this.context.restore();

  if (this.__isWebGL) {
    this.__auxDirty = true;
  }

}

Canvas.prototype.drawBlockSpark = function (cx, cy, progress) {

  /*
   * Function Canvas.drawBlockSpark
   * Draws a white/silver star burst of radiating lines (block/parry visual)
   */

  let ctx = this.context;
  let alpha = (1.0 - progress);
  let lineLen = 4 + progress * 6;
  let expand = 2 + progress * 10;

  ctx.save();

  // Bright center flash at start
  if (progress < 0.3) {
    let flashAlpha = 0.6 * (1.0 - progress / 0.3);
    ctx.fillStyle = "rgba(255, 255, 255, " + flashAlpha + ")";
    ctx.beginPath();
    ctx.arc(cx, cy, 3, 0, 2 * Math.PI);
    ctx.fill();
  }

  ctx.strokeStyle = "rgba(240, 245, 255, " + alpha + ")";
  ctx.lineWidth = 2;
  ctx.lineCap = "round";

  for (let i = 0; i < 8; i++) {
    let angle = (i / 8) * Math.PI * 2;
    let startX = cx + Math.cos(angle) * expand;
    let startY = cy + Math.sin(angle) * expand;
    let endX = cx + Math.cos(angle) * (expand + lineLen);
    let endY = cy + Math.sin(angle) * (expand + lineLen);
    ctx.beginPath();
    ctx.moveTo(startX, startY);
    ctx.lineTo(endX, endY);
    ctx.stroke();
  }

  ctx.restore();

  if (this.__isWebGL) {
    this.__auxDirty = true;
  }

}

Canvas.prototype.drawSlashArc = function (position, ndx, ndy, progress) {

  /*
   * Function Canvas.drawSlashArc
   * Draws a curved slash arc between attacker and target on melee hit
   */

  // Midpoint between attacker and target tile
  let cx = 32 * position.x + 16 + ndx * 16;
  let cy = 32 * position.y + 16 + ndy * 16;

  // Angle of attack direction
  let baseAngle = Math.atan2(ndy, ndx);

  let alpha = 1.0 - progress * progress;
  let ctx = this.context;
  ctx.save();

  // Silver slash arc sweeping perpendicular to attack direction
  ctx.strokeStyle = "rgba(210, 220, 230, " + (alpha * 0.85) + ")";
  ctx.lineWidth = 1.5;
  ctx.lineCap = "round";
  ctx.beginPath();
  ctx.arc(cx, cy, 9, baseAngle + Math.PI * 0.55, baseAngle - Math.PI * 0.55, true);
  ctx.stroke();

  ctx.restore();

  if (this.__isWebGL) {
    this.__auxDirty = true;
  }

}




/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/rendering/debugger.js ===== */

const Debugger = function() {

  /*
   * Class Debugger
   * Container for debugging information visible when pressing F8
   *
   * API:
   *
   * @Debugger.renderStatistics - renders the statistics to the screen
   * @Debugger.toggleStatistics - toggles visibility of statistics on/off
   * @Debugger.UPDATE_INTERVAL - constant that determines how often the statistics are updated (unit is frames)
   *
   */

   // Debugger state. Two independent inputs:
   //   __hudEnabled  — mirrors the persistent "Show Performance" checkbox;
   //                   when true (and __devOverride is false) → minimal HUD.
   //   __devOverride — session-only flag flipped by the /dev chat command
   //                   or Ctrl+F8 hotkey; when true → full debug HUD.
   //                   Never saved to localStorage.
   // Resolved display mode is computed in __resolveMode().
  this.__hudEnabled = false;
  this.__devOverride = false;
  this.__mode = "off";
  this.__showStatistics = false;
  this.__nFrames = 0;
  this.__averageFPS = 0;
  this.__averageEvictions = 0;
  this.__averageDrawCalls = 0;
  this.__averageDrawTime = 0;
  this.__nSeconds = performance.now();

  // Information on the GPU
  this.__GPU = this.__getGPUInformation();

  // Keep the HUD glued to the canvas's top-left when the viewport changes
  // (orientation flip, resize). __positionHud is a cheap no-op while the HUD
  // is off. Guarded for non-browser/test contexts.
  if (typeof window !== "undefined" && window.addEventListener) {
    let self = this;
    let reposition = function () { self.__positionHud(); };
    window.addEventListener("resize", reposition);
    window.addEventListener("orientationchange", reposition);
  }

  // Always-on, zero-per-frame-cost FPS-health probe (see __startHealthMonitor).
  this.__startHealthMonitor();

}

// How often the statistics are updated
Debugger.prototype.UPDATE_INTERVAL = 60;

// FPS-health probe tunables.
Debugger.prototype.HEALTH_INTERVAL_MS = 5000;             // sample window
Debugger.prototype.HEALTH_LOW_FPS = 18;                   // below this = "low"
Debugger.prototype.HEALTH_IMPOSSIBLE_FPS = 200;           // above this = loop-stack tell
Debugger.prototype.HEALTH_ANOMALY_COOLDOWN_MS = 1200000;  // 20 min between anomaly reports
Debugger.prototype.HEALTH_MAX_ANOMALY_REPORTS = 5;        // hard per-session cap (chronic-slow spam guard)
Debugger.prototype.HEALTH_BASELINE_AFTER_WINDOWS = 3;     // skip login-spike windows; measure steady-state

Debugger.prototype.__startHealthMonitor = function () {

  /*
   * Function Debugger.__startHealthMonitor
   * Lightweight, always-on FPS-health probe. ZERO per-frame cost: a 5s
   * setInterval samples the monotonic render-frame counter (__nFrames) and
   * derives FPS from the delta, so it works whether or not the HUD is shown.
   * Emits a compact "[fps]" telemetry line (routed server-side to
   * fps-health.log + /fpscheck) in three cases, each carrying the WHY:
   *   - once per session: a baseline (renderer + route reason + device + build).
   *   - sustained low FPS while in-game + visible — the lag symptom.
   *   - impossible-high FPS — the rAF-loop-stacking regression tell.
   * Context-loss is reported separately from the webglcontextlost listener.
   * Started once (the Debugger is created once with the Renderer), so the
   * interval never accumulates across reconnects.
   */

  if (this.__healthStarted || typeof setInterval !== "function") {
    return;
  }
  this.__healthStarted = true;

  let self = this;
  self.__healthLastFrames = self.__nFrames;
  self.__healthLastAt = (typeof performance !== "undefined" ? performance.now() : Date.now());
  self.__healthSentBaseline = false;
  self.__healthLowStreak = 0;
  self.__healthLastAnomalyAt = 0;
  self.__healthWindow = 0;
  self.__healthAnomalyCount = 0;

  setInterval(function () {
    try { self.__healthTick(); } catch (e) { /* telemetry must never break the client */ }
  }, self.HEALTH_INTERVAL_MS);

}

Debugger.prototype.__healthTick = function () {

  /*
   * Function Debugger.__healthTick
   * One sample window. Derives FPS from the __nFrames delta and classifies it.
   */

  let nowT = (typeof performance !== "undefined" ? performance.now() : Date.now());
  let elapsed = nowT - this.__healthLastAt;
  let dFrames = this.__nFrames - this.__healthLastFrames;
  this.__healthLastAt = nowT;
  this.__healthLastFrames = this.__nFrames;

  // Clock skew or a counter reset → skip this window.
  if (elapsed <= 0 || dFrames < 0) {
    return;
  }

  // Only judge while the tab is visible, a session is live, and the player is
  // in-world. A backgrounded tab throttles rAF to ~1Hz (false "low fps");
  // pre-login there's nothing to measure.
  if (typeof document !== "undefined" && document.visibilityState && document.visibilityState !== "visible") {
    return;
  }
  if (typeof gameClient === "undefined" || !gameClient || !gameClient.player) {
    return;
  }

  let fps = Math.round(1000 * dFrames / elapsed);
  this.__healthWindow++;

  // Frame COMPOSITION over this window — the discriminator for "what's eating
  // the frame": drawMs is render time per frame (always tracked: renderer
  // totalDrawTime/drawCalls are monotonic while the HUD is off). If fps is low
  // but drawMs is SMALL, the time is spent OUTSIDE rendering (layout/reflow,
  // GC, main-thread JS) → a code/overlay cause. If drawMs is LARGE, it's
  // GPU/scene-bound → thermal/hardware. drawCalls + tiles = scene density.
  this.__healthDrawMs = -1;
  this.__healthDrawCalls = -1;
  this.__healthTiles = -1;
  try {
    let r = (typeof gameClient !== "undefined" && gameClient.renderer) ? gameClient.renderer : null;
    if (r) {
      if (this.__healthLastDrawTime != null && dFrames > 0) {
        let dMs = r.totalDrawTime - this.__healthLastDrawTime;
        let dCalls = r.drawCalls - this.__healthLastDrawCalls;
        if (dMs >= 0) this.__healthDrawMs = Math.round(dMs / dFrames);          // ms per frame in render
        if (dCalls >= 0) this.__healthDrawCalls = Math.round(dCalls / dFrames); // draws per frame
      }
      this.__healthLastDrawTime = r.totalDrawTime;
      this.__healthLastDrawCalls = r.drawCalls;
      if (typeof r.numberOfTiles === "number") this.__healthTiles = r.numberOfTiles;
    }
  } catch (e) { /* composition is best-effort */ }

  // (1) Baseline once per session — but only after a few in-game windows so it
  // measures STEADY-STATE, not the login asset-load / chunk-stream spike (which
  // otherwise floods the baseline with bogus 0-2 fps samples).
  if (!this.__healthSentBaseline && this.__healthWindow >= this.HEALTH_BASELINE_AFTER_WINDOWS) {
    this.__healthSentBaseline = true;
    this.__sendHealth("baseline", fps);
  }

  // (2) Impossible-high FPS — render frames advancing far faster than any real
  // display = stacked rAF loops. Report immediately (cooldown-gated).
  if (fps > this.HEALTH_IMPOSSIBLE_FPS) {
    this.__maybeAnomaly("impossible-fps", fps);
    return;
  }

  // (3) Sustained low FPS — two consecutive low windows (one-off GC/load hitches
  // don't count).
  if (fps > 0 && fps < this.HEALTH_LOW_FPS) {
    this.__healthLowStreak++;
    if (this.__healthLowStreak >= 2) {
      this.__maybeAnomaly("low-fps", fps);
    }
  } else {
    this.__healthLowStreak = 0;
  }

}

Debugger.prototype.__maybeAnomaly = function (reason, fps) {

  /*
   * Function Debugger.__maybeAnomaly
   * Sends an anomaly report, throttled to one per HEALTH_ANOMALY_COOLDOWN_MS so
   * a struggling client surfaces the problem without flooding the log.
   */

  if ((this.__healthAnomalyCount || 0) >= this.HEALTH_MAX_ANOMALY_REPORTS) {
    return;   // per-session cap — a chronically-slow client need not report forever
  }
  let now = Date.now();
  if (now - (this.__healthLastAnomalyAt || 0) < this.HEALTH_ANOMALY_COOLDOWN_MS) {
    return;
  }
  this.__healthLastAnomalyAt = now;
  this.__healthAnomalyCount = (this.__healthAnomalyCount || 0) + 1;
  this.__sendHealth(reason, fps);

}

Debugger.prototype.__sendHealth = function (reason, fps) {

  /*
   * Function Debugger.__sendHealth
   * Builds + ships one "[fps]" line via the throttle-bypassing health channel.
   */

  if (typeof gameClient === "undefined" || !gameClient || typeof gameClient.sendHealthReport !== "function") {
    return;
  }
  gameClient.sendHealthReport(this.__buildHealthPayload(reason, fps));

}

Debugger.prototype.__buildHealthPayload = function (reason, fps) {

  /*
   * Function Debugger.__buildHealthPayload
   * Assembles the compact, ASCII, <240-byte "[fps]" line (kept well under the
   * client string's u8 byte-length prefix). Every field answers "why is this
   * device slow": which renderer it actually uses, why it was routed there
   * (Canvas.__webglAutoRouted), its strike/crash/amnesty state, whether GL was
   * lost, and the device/build so a population pattern is visible.
   */

  let ls = function (k) { try { return localStorage.getItem(k); } catch (e) { return null; } };
  let webgl = false, route = "n/a", ios = false;
  // Read the ACTUAL active renderer (screen sprite-batch), not Canvas.isWebGLEnabled
  // — that is always true now, so it would mislabel a genuine no-GL fallback device.
  try {
    let scr = (typeof gameClient !== "undefined" && gameClient && gameClient.renderer) ? gameClient.renderer.screen : null;
    webgl = !!(scr && scr.__spriteBatch);
  } catch (e) {}
  try { if (typeof Canvas !== "undefined" && Canvas.__webglAutoRouted) route = String(Canvas.__webglAutoRouted); } catch (e) {}
  try { ios = (typeof Canvas !== "undefined" && Canvas.__isIOS && Canvas.__isIOS()); } catch (e) {}

  let mem = "?", cores = "?", dpr = "?", build = "?", lost = "n";
  try { if (navigator.deviceMemory) mem = String(navigator.deviceMemory); } catch (e) {}
  try { if (navigator.hardwareConcurrency) cores = String(navigator.hardwareConcurrency); } catch (e) {}
  try { dpr = String(Math.round((window.devicePixelRatio || 0) * 100) / 100 || "?"); } catch (e) {}
  try { build = String(window.__CLIENT_BUILD || "?"); } catch (e) {}
  try { lost = (window.__renderContextLost ? "y" : "n"); } catch (e) {}

  let gpu = "?";
  // Trimmed 40->28 to keep the line under the client string's 255-byte u8 length
  // prefix after the rtt fields were added (see client_string_u8_length_bug).
  try { gpu = String(this.__GPU || "?").substring(0, 28); } catch (e) {}

  let lowspec = "?";
  try { lowspec = (gameClient.interface.settings.isLowSpecMode() ? "y" : "n"); } catch (e) {}

  // #2 RTT trend — p50/p95 over the rolling pong buffer (degrading-connection signal).
  let rttP50 = "?", rttP95 = "?";
  try {
    let pct = (typeof gameClient !== "undefined" && gameClient.networkManager && gameClient.networkManager.getRttPercentiles)
      ? gameClient.networkManager.getRttPercentiles() : null;
    if (pct) { rttP50 = pct.p50; rttP95 = pct.p95; }
  } catch (e) {}

  let clean = function (s) { return String(s).replace(/\s+/g, "_"); };
  let n = function (v) { return (typeof v === "number" && v >= 0) ? v : "?"; };

  return "[fps] reason=" + reason
    + " fps=" + fps
    + " drawms=" + n(this.__healthDrawMs)        // render time per frame; low+lowfps = NOT render-bound
    + " draws=" + n(this.__healthDrawCalls)       // draw calls per frame (scene density)
    + " tiles=" + n(this.__healthTiles)
    + " lowspec=" + lowspec
    + " renderer=" + (webgl ? "webgl" : "canvas2d")
    + " route=" + clean(route)
    + " strikes=" + (ls("webgl-strikes") || "0")
    + " crash=" + (ls("webgl-crash-count") || "0")
    + " amnesty=" + (ls("webgl-amnesty") ? "y" : "n")
    + " ctxlost=" + lost
    + " ios=" + (ios ? "y" : "n")
    + " mem=" + mem
    + " cores=" + cores
    + " dpr=" + dpr
    + " rtt50=" + rttP50          // RTT trend (#2): degrading-connection early warning
    + " rtt95=" + rttP95
    + " gpu=" + clean(gpu)
    + " build=" + clean(build);

}

Debugger.prototype.isActive = function() {

  /*
   * Function Debugger.isActive
   * Returns true if the debugger is active
   */

  return this.__showStatistics;

}

Debugger.prototype.renderStatistics = function() {

  /*
   * Function Debugger.renderStatistics
   * Render statistics to the top of the screen
   */

  // Statistics are not opened
  if(!this.isActive()) {
    return;
  }

  // Update the average number of frames
  if(!this.__shouldUpdate()) {
    return;
  }

  this.__renderStatistics();

}

Debugger.prototype.__resolveMode = function() {

  /*
   * Function Debugger.__resolveMode
   * Picks the displayed HUD mode from the two independent inputs.
   * dev override beats the checkbox — typing /dev with the checkbox on
   * still shows the full HUD, not minimal.
   */

  if (this.__devOverride) return "full";
  if (this.__hudEnabled) return "minimal";
  return "off";

}

Debugger.prototype.__applyMode = function() {

  /*
   * Function Debugger.__applyMode
   * Re-renders the HUD to match the current resolved mode. Internal —
   * setHudEnabled / setDevOverride call this after mutating their flag.
   * Renders immediately on a mode change so the user sees the result
   * without waiting for the next UPDATE_INTERVAL frame.
   */

  let mode = this.__resolveMode();
  this.__mode = mode;
  this.__showStatistics = (mode !== "off");

  if (mode === "off") {
    let el = document.getElementById("debug-statistics");
    if (el) el.innerHTML = "";
  } else {
    this.__renderStatistics();
  }

}

Debugger.prototype.setHudEnabled = function(enabled) {

  /*
   * Function Debugger.setHudEnabled
   * Sets the persistent checkbox-driven minimal HUD on/off. Called by
   * the "Show Performance" toggle handler and by gameclient init.
   * Independent of __devOverride — does not touch the /dev session flag.
   */

  this.__hudEnabled = !!enabled;
  this.__applyMode();

}

Debugger.prototype.setDevOverride = function(on) {

  /*
   * Function Debugger.setDevOverride
   * Session-only flag flipped by the /dev chat command and the Ctrl+F8
   * hotkey. When true → full HUD, regardless of the checkbox. Never
   * saved to localStorage; resets on reload. Does NOT mutate
   * __hudEnabled here — the /dev command handler in channel-manager is
   * responsible for unchecking the Show Performance checkbox + saving
   * settings state as the side effect, since "dev overrules minimal".
   */

  this.__devOverride = !!on;
  this.__applyMode();

}

Debugger.prototype.toggleStatistics = function() {

  /*
   * Function Debugger.toggleStatistics
   * Hotkey entry (Ctrl+F8). Toggles the session-only dev override — same
   * effect as typing /dev. Turning dev ON unchecks the persistent Show
   * Performance checkbox (since dev overrules it). Turning dev OFF
   * leaves the checkbox alone so the player explicitly manages whether
   * minimal returns. Mirrors the /dev handler in channel-manager.
   */

  let next = !this.__devOverride;
  this.setDevOverride(next);

  if (next && typeof gameClient !== "undefined" && gameClient.interface && gameClient.interface.settings) {
    let s = gameClient.interface.settings;
    if (s.__state["show-performance"] === true) {
      s.__state["show-performance"] = false;
      s.saveState();
      let checkbox = document.getElementById("show-performance");
      if (checkbox) checkbox.checked = false;
      this.setHudEnabled(false);
    }
  }

}

Debugger.prototype.__getGPUInformation = function() {

  /*
   * Function Debugger.__getGPUInformation
   * Returns the GPU information if available.
   *
   * getContext("webgl") can return null when the browser refuses a new
   * WebGL context (Chrome's ~16-context cap, GPU process crash, hw accel
   * disabled, iOS resource pressure, multiple game tabs open). The main
   * game canvas already has its context by this point — this throwaway
   * canvas is only for the F8 GPU-name string. Falling back to "unknown"
   * is harmless; throwing here aborts client init mid-stream and leaves
   * the player on a white screen (Courvoiser incident 2026-05-07).
   */

  try {
    let webgl = document.createElement("canvas").getContext("webgl");
    if (!webgl) return "unknown (no webgl context)";
    return webgl.getParameter(webgl.RENDERER);
  } catch (e) {
    return "unknown";
  }

}

Debugger.prototype.__updateAverageStatistics = function() {

  /*
   * Function Debugger.__updateAverageStatistics
   * Updates the state variables of the debugger
   */

   // Time elapsed since the previous update
   let elapsed = performance.now() - this.__nSeconds;

   // Calculate average statistics over the interval
   this.__averageEvictions = ((1E3 * gameClient.spriteBuffer.nEvictions) / elapsed).toFixed(0);
   this.__averageFPS = (1E3 * this.UPDATE_INTERVAL / elapsed).toFixed(0);
   this.__averageDrawCalls = (gameClient.renderer.drawCalls / this.UPDATE_INTERVAL).toFixed(0);
   this.__averageDrawTime = (1E3 * gameClient.renderer.totalDrawTime / this.UPDATE_INTERVAL).toFixed(0);

   // Track GL flush count if WebGL is active
   let batch = gameClient.renderer.screen.__spriteBatch;
   this.__averageGLFlushes = batch ? batch.__flushCount : 0;

   this.__nSeconds = performance.now();

   gameClient.networkManager.getLatency();

   // Reset
   gameClient.renderer.drawCalls = 0;
   gameClient.spriteBuffer.nEvictions = 0;
   gameClient.renderer.totalDrawTime = 0;

}

Debugger.prototype.__shouldUpdate = function() {

  /*
   * Function Debugger.__shouldUpdate
   * Returns true if the debugger should update on this frame (1 / 60)
   */

  return this.__nFrames % this.UPDATE_INTERVAL === 0;

}

Debugger.prototype.__getMemoryUsage = function() {

  /*
   * Function Debugger.getMemoryUsage
   * Returns the number of bytes used in memory (MB) - may not be supported by a browser
   */

  try {
    return (1E-6 * performance.memory.totalJSHeapSize).toFixed(0) + "MB";
  } catch(exception) {
    return "Metric Not Available";
  }

}

Debugger.prototype.__positionHud = function() {

  /*
   * Function Debugger.__positionHud
   * Anchors the perf HUD (#debug-statistics) to the actual game canvas's
   * top-left on MOBILE. CSS alone can't do this: in landscape the canvas is
   * pillarboxed (aspect-locked + centered), so a screen-relative top/left lands
   * in the black bar, not on the canvas. We read the live canvas rect (and the
   * top status bar that may overlap it) and set inline !important top/left.
   * Mobile only — desktop keeps its working CSS placement. Cosmetic: this must
   * never throw into the render loop.
   */

  try {
    let isMobile = document.body.classList.contains("force-mobile")
      || (window.matchMedia && window.matchMedia("(max-width: 768px), (max-height: 500px)").matches);
    if (!isMobile) return;

    let el = document.getElementById("debug-statistics");
    if (!el || this.__mode === "off") return;

    // Portrait already lands correctly via CSS (top:4/left:4): the canvas is
    // full-width there, so there's no pillarbox to correct. The JS anchor is
    // only needed in landscape. Clear any inline top/left left over from a
    // previous landscape orientation so the CSS rule takes back over after
    // rotating to portrait.
    let isLandscape = window.matchMedia && window.matchMedia("(orientation: landscape)").matches;
    if (!isLandscape) {
      el.style.removeProperty("top");
      el.style.removeProperty("left");
      return;
    }

    let canvas = document.getElementById("screen");
    let parent = el.offsetParent || el.parentElement;
    if (!canvas || !parent) return;

    let cRect = canvas.getBoundingClientRect();
    if (cRect.width === 0 || cRect.height === 0) return; // not laid out yet
    let pRect = parent.getBoundingClientRect();

    // If a top status bar overlaps the canvas's top edge, start below it so the
    // HUD isn't hidden behind it. On notch phones the bar is moved to the
    // bottom — then it doesn't overlap the top and we leave the edge alone.
    let topEdge = cRect.top;
    let bar = document.getElementById("mobile-status-bar");
    if (bar) {
      let bRect = bar.getBoundingClientRect();
      if (bRect.height > 0 && bRect.top <= cRect.top + 1 && bRect.bottom > cRect.top) {
        topEdge = bRect.bottom;
      }
    }

    let pad = 4;
    el.style.setProperty("top", (topEdge - pRect.top + pad) + "px", "important");
    el.style.setProperty("left", (cRect.left - pRect.left + pad) + "px", "important");
  } catch (e) { /* positioning is cosmetic — never break the HUD */ }

};

Debugger.prototype.__activeRenderer = function() {

  /*
   * Function Debugger.__activeRenderer
   * The renderer ACTUALLY in use for the gamescreen: "WebGL" when the screen
   * canvas obtained a sprite-batch (WebGL2) context, else "Canvas2D". Reads the
   * live batch rather than Canvas.isWebGLEnabled (which is always true now) so a
   * genuine no-GL device that fell back at init still reports honestly.
   */

  try {
    let scr = gameClient && gameClient.renderer && gameClient.renderer.screen;
    return (scr && scr.__spriteBatch) ? "WebGL" : "Canvas2D";
  } catch (e) {
    return "?";
  }

};

Debugger.prototype.__renderStatistics = function() {

  /*
   * Function Debugger.__renderStatistics
   * Renders debug statistics to the top-left of the gamescreen. Minimal
   * mode shows just FPS + Latency (the two stats players actually want
   * during play). Full mode keeps the original dump for diagnostics.
   */

  // Update the average statistics
  this.__updateAverageStatistics();

  let el = document.getElementById("debug-statistics");
  if (!el) return;

  // Anchor the HUD to the canvas top-left (mobile pillarbox/letterbox + top
  // status-bar correction). No-op on desktop.
  this.__positionHud();

  if (this.__mode === "minimal") {
    // Build line: the ACTUAL loaded bundle version (window.__CLIENT_BUILD, baked
    // into index.html, kept == SW_VERSION). Lets a /dev screenshot prove which
    // build a player is really on — the missing piece when diagnosing stale iOS
    // PWA caches (a stale phone reads the old build here even with no pill).
    let build = (typeof window !== "undefined" && window.__CLIENT_BUILD) ? window.__CLIENT_BUILD : "?";
    el.innerHTML = new Array(
      "Frame Rate: %sfps".format(this.__averageFPS),
      "Latency: %sms".format(Math.round(gameClient.networkManager.state.latency)),
      "Renderer: %s".format(this.__activeRenderer()),
      "Build: %s".format(build)
    ).join("<br>");
    return;
  }

  // Update the innerHTML of the statistics element
  el.innerHTML = new Array(
    // Version information
    "Server Version: ".format(gameClient.serverVersion),
    "Client Version: ".format(gameClient.clientVersion),
    "Server Tick Interval: %sms".format(gameClient.getTickInterval()),
    // Graphics information
    "Current Frame: %s".format(gameClient.eventQueue.getFrame()),
    "Frame Rate: %sfps".format(this.__averageFPS),
    "Renderer: %s".format(this.__activeRenderer()),
    "Draw Calls: %s".format(this.__averageDrawCalls),
    "GL Flushes: %s".format(this.__averageGLFlushes || 0),
    "Draw Time: %sµs".format(this.__averageDrawTime),
    "Draw Tiles: %s".format(gameClient.renderer.numberOfTiles),
    // Entity information
    "Active Entities: %s".format(Object.keys(gameClient.world.activeCreatures).length),
    // Other
    "Latency: %sms".format(Math.round(gameClient.networkManager.state.latency)),
    "Packets Received: %s".format(gameClient.networkManager.state.nPackets),
    "Packets Sent: %s".format(gameClient.networkManager.nPacketsSent),
    "Bytes Recieved: %sKB".format(Math.round(1E-3 * gameClient.networkManager.state.bytesRecv)),
    "Bytes Sent: %sKB".format(Math.round(1E-3 * gameClient.networkManager.state.bytesSent)),
    // Performance
    "Sprite Buffer Size: %sMB".format(Math.round(1E-6 * gameClient.spriteBuffer.size * gameClient.spriteBuffer.size * 4 * 32 * 32)),
    "Sprite Buffer Evictions: %s".format(this.__averageEvictions),
    "Memory Usage: %s".format(this.__getMemoryUsage()),
    "GPU: %s".format(this.__GPU),
    // Player information
    "Identifier: %s".format(gameClient.player.id),
    "Current Position: %s".format(gameClient.player.getPosition().toString()),
    // Null-guard: getChunk can return null in the post-teleport gap before
    // the destination chunk's MAP_AREA / chunk push lands (god /goto, stair
    // step, etc.). Without the guard the debug overlay throws on null.id
    // and the renderer crashes the frame.
    "Current Chunk: %s".format(gameClient.player.getChunk() ? gameClient.player.getChunk().id : "(loading)"),
    "Opened Containers: %s".format(gameClient.player.__openedContainers.size),
    "Outfit: %s".format(gameClient.player.outfit.toString())
  ).join("<br>");

}


