  let layerBtn = document.getElementById("minimap-current-layer");
  layerBtn.title = "Open map";
  layerBtn.innerHTML = '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" aria-hidden="true" style="pointer-events:none"><circle cx="10" cy="10" r="6"></circle><line x1="14.5" y1="14.5" x2="20.5" y2="20.5"></line></svg>';
