  on(document.getElementById("minimap-zoom-down"), "click", "changeZoomLevel", [-1]);
  on(document.getElementById("minimap-zoom-el"), "click", "changeLevel", [-1]);
  on(document.getElementById("minimap-zoom-dl"), "click", "changeLevel", [1]);

  // Listeners to the full canvas (#minimap is the same DOM node every session)
  on(this.minimap.canvas, "wheel", "scroll");

  // Left-click walks to location, right-click pans the minimap (desktop).
  on(this.minimap.canvas, "click", "walkTo");
  on(this.minimap.canvas, "contextmenu", "move");

  // Mobile: press-drag the ✕ cross to a target, lift to walk. passive:false
  // so preventDefault can stop page scroll and the synthetic post-touch click.
  on(this.minimap.canvas, "touchstart", "__touchStart", [], { passive: false });
  on(this.minimap.canvas, "touchmove", "__touchMove", [], { passive: false });
  on(this.minimap.canvas, "touchend", "__touchEnd", [], { passive: false });
  // The OS can interrupt a drag (incoming call, notification swipe) with a
  // touchcancel instead of touchend — clean up so the loupe / cross don't stick.
  on(this.minimap.canvas, "touchcancel", "__touchCancel", [], { passive: false });

