HotbarManager.prototype.addSlot = function (index, sid) {

  /*
   * Function HotbarManager.addSlot
   * Adds a spell to a particular slot on the hotbar
   */

  // Invalid index
  if (index < 0 || index >= this.slots.length) {
    return;
  }

  let spell = gameClient.interface.getSpell(sid);

  // Set the new reference (clear other types)
  this.slots[index].spell = new Object({
    "sid": sid,
    "icon": spell.icon,
    "runeId": spell.runeId || 0,
    "mana": spell.mana || 0
  });
  this.slots[index].text = null;
  this.slots[index].item = null;
  this.slots[index].action = null;
  this.slots[index].mode = "self";
  // Force a repaint on rebind — render() skips slots whose visual key is
  // unchanged, and a stale key from a previous binding of the same spell
  // (via a different slot type in between) would wrongly skip the redraw.
  this.slots[index].__lastDrawKey = null;
  this.__clearTextLabel(this.slots[index]);

  if (this.slots[index].canvas) {
    this.slots[index].canvas.canvas.parentNode.lastElementChild.style.color = "white";
    this.slots[index].canvas.canvas.parentNode.title = "%s: %s".format(spell.name, spell.description);
  }

  this.__saveConfiguration();

}

HotbarManager.prototype.addTextSlot = function (index, text) {

  /*
   * Function HotbarManager.addTextSlot
   * Adds a custom text to a particular slot on the hotbar
   */

  // Invalid index
  if (index < 0 || index >= this.slots.length) {
    return;
  }

  // Clear other types and set text
  this.slots[index].spell = null;
  this.slots[index].item = null;
  this.slots[index].action = null;
  this.slots[index].text = text;
  this.slots[index].__lastDrawKey = null;

  // Clear the canvas and show text icon (desktop only). Mark dirty so the
  // per-frame render loop redraws once and then skips (see render() text
  // branch). We no longer redraw the corner bubble every frame — wasted
  // canvas ops when the visual is static between rebinds.
  if (this.slots[index].canvas) {
    this.slots[index].canvas.clear();
    this.slots[index].__textDirty = true;
    this.__drawTextIcon(this.slots[index]);
    this.slots[index].canvas.canvas.parentNode.lastElementChild.style.color = "lightblue";
    this.slots[index].canvas.canvas.parentNode.title = "Say: " + text;
  }

  this.__saveConfiguration();

}

HotbarManager.prototype.__compressHotbarText = function (text) {

  /*
   * Function HotbarManager.__compressHotbarText
   * Reduces a string down to a 4-5 char uppercase label that fits in the
   * 32×32 slot. Pure compressor — no command parsing (the tag/name split
   * lives in __parseTextLabel). Strips whitespace/control chars first.
   *
   * Examples:
   *   "exori"          → "EXOR"
   *   "exevo flam hur" → "EXEV"
   *   "mlvl"           → "MLVL"
   *   ""               → "…"   (single ellipsis char, narrower than three dots)
   */

  if (!text || typeof text !== "string") return "…";
  let normalized = text.replace(/[\r\n\t]+/g, " ").replace(/\s+/g, " ").trim();
  if (normalized.length === 0) return "…";
  // 5 chars when source is exactly 5 (preserves "exori"-style words);
  // otherwise truncate to 4 so the label fits at 9px bold.
  let max = (normalized.length === 5) ? 5 : 4;
  return normalized.substring(0, max).toUpperCase();

}

// Commands whose ARGUMENT is the meaningful part: the slot is labelled by the
// target name, with this short word shown tiny above it. "exura sio" tags as
// just "sio" (owner request). Longest prefix isn't an issue here — the two are
// mutually exclusive.
HotbarManager.prototype.NAME_TARGET_TAGS = [
  { "prefix": "exiva ", "tag": "exiva" },
  { "prefix": "exura sio ", "tag": "sio" }
];

HotbarManager.prototype.__parseTextLabel = function (text) {

  /*
   * Function HotbarManager.__parseTextLabel
   * Splits a text-hotkey into { tag, label } for the slot preview. For a
   * name-targeted command (Find Person "exiva <name>", Heal Friend
   * "exura sio <name>") the label is the compressed TARGET NAME and `tag` is
   * the tiny command word ("exiva" / "sio") drawn above it — so a row of exiva
   * hotkeys reads "MLVL"/"SELE" instead of every slot showing "EXIV", while
   * still showing the command. Otherwise `tag` is null and the whole text is
   * compressed as before. Quotes and the "~" prefix-wildcard are stripped.
   */

  if (!text || typeof text !== "string") return { "tag": null, "label": "…" };
  let normalized = text.replace(/[\r\n\t]+/g, " ").replace(/\s+/g, " ").trim();
  if (normalized.length === 0) return { "tag": null, "label": "…" };

  let lower = normalized.toLowerCase();
  for (let i = 0; i < this.NAME_TARGET_TAGS.length; i++) {
    let entry = this.NAME_TARGET_TAGS[i];
    if (lower.startsWith(entry.prefix)) {
      let arg = normalized.substring(entry.prefix.length).replace(/["~]/g, "").trim();
      if (arg.length > 0) {
        return { "tag": entry.tag, "label": this.__compressHotbarText(arg) };
      }
    }
  }
  return { "tag": null, "label": this.__compressHotbarText(normalized) };

}

HotbarManager.prototype.__drawTextIcon = function (slot) {

  /*
   * Function HotbarManager.__drawTextIcon
   * Renders a text-hotkey slot: a small chat-bubble corner indicator on
   * the canvas (so the slot is recognizable as a "text" slot at a glance)
   * plus a compressed preview label rendered in the existing DOM span
   * (.hotbar-text, exposed as slot.duration in __createSlot). Replaces
   * the previous generic "..." chat bubble that made every text slot
   * look identical.
   *
   * The DOM span is shared with item-count display and spell-cooldown
   * text. The `data-text-label` attribute is the discriminator: CSS in
   * hotbar.css overrides positioning only when this attribute is set,
   * so non-text slots keep their bottom-anchored count/duration display.
   * Other add*Slot paths remove the attribute when overwriting a text
   * slot.
   *
   * Bubble lives at top-RIGHT (x=22, y=2) to avoid colliding with the
   * .hotbar-key F-label that sits at top-left (hotbar.css:61-67).
   */

  let ctx = slot.canvas.context;

  // Small chat-bubble corner indicator (8×6 body + 2px tail).
  ctx.fillStyle = "#4a90a4";
  ctx.fillRect(22, 2, 8, 6);
  ctx.beginPath();
  ctx.moveTo(26, 8);
  ctx.lineTo(24, 10);
  ctx.lineTo(28, 10);
  ctx.fill();

  // Compressed preview into the existing DOM span. `data-text-label`
  // doubles as a change-detection cache (no DOM write if unchanged) and
  // as the CSS discriminator.
  let parsed = this.__parseTextLabel(slot.text);
  let cacheKey = (parsed.tag ? parsed.tag + ":" : "") + parsed.label;
  if (slot.duration && slot.duration.getAttribute("data-text-label") !== cacheKey) {
    slot.duration.style.color = "#ffffff";
    slot.duration.style.fontWeight = "bold";
    if (parsed.tag) {
      // Two-line: tiny command tag above the compressed target name. Built via
      // textContent on child spans (not innerHTML) so an arbitrary name can't
      // inject markup. .hk-cmd / .hk-name sizing lives in hotbar.css.
      slot.duration.textContent = "";
      slot.duration.style.fontSize = "";
      let cmd = document.createElement("span");
      cmd.className = "hk-cmd";
      cmd.textContent = parsed.tag;
      let nm = document.createElement("span");
      nm.className = "hk-name";
      nm.textContent = parsed.label;
      slot.duration.appendChild(cmd);
      slot.duration.appendChild(nm);
    } else {
      slot.duration.textContent = parsed.label;
      slot.duration.style.fontSize = (parsed.label.length >= 4 ? "9px" : "11px");
    }
    slot.duration.setAttribute("data-text-label", cacheKey);
  }

}

HotbarManager.prototype.__clearTextLabel = function (slot) {

  /*
   * Function HotbarManager.__clearTextLabel
   * Reset the duration span when rebinding a text slot to another kind
   * (item / spell / action). Without this, the text-preview's centered
   * positioning + bold styling carries over and item counts render in
   * the wrong place. Called from addSlot / addItemSlot / addActionSlot.
   */

  if (!slot.duration) return;
  if (!slot.duration.hasAttribute("data-text-label")) return;
  slot.duration.removeAttribute("data-text-label");
  slot.duration.textContent = "";
  slot.duration.style.cssText = "";

}

HotbarManager.prototype.addActionSlot = function (index, actionId) {

  /*
   * Function HotbarManager.addActionSlot
   * Adds an action (e.g., attack nearest monster) to a hotbar slot
   */

  if (index < 0 || index >= this.slots.length) {
    return;
  }

  let actionDef = this.ACTIONS[actionId];

  if (!actionDef) {
    return;
  }

  // Clear other types
  this.slots[index].spell = null;
  this.slots[index].text = null;
  this.slots[index].item = null;
  this.slots[index].action = actionId;
  this.slots[index].__lastDrawKey = null;
  this.slots[index].mode = "self";
  this.__clearTextLabel(this.slots[index]);

  // Draw the action icon (desktop only)
  if (this.slots[index].canvas) {
    this.slots[index].canvas.clear();
    this.__drawActionIcon(this.slots[index]);
    this.slots[index].canvas.canvas.parentNode.lastElementChild.style.color = actionDef.border || "#ff8866";
    this.slots[index].canvas.canvas.parentNode.title = actionDef.name;
  }

  this.__saveConfiguration();

}

HotbarManager.prototype.__drawActionIcon = function (slot) {

  /*
   * Function HotbarManager.__drawActionIcon
   * Draws an action icon on the slot canvas
   */

  let ctx = slot.canvas.context;
  let actionDef = this.ACTIONS[slot.action];

  if (!actionDef) {
    return;
  }

  // Draw background circle
  ctx.fillStyle = actionDef.bg;
  ctx.beginPath();
  ctx.arc(16, 16, 14, 0, 2 * Math.PI);
  ctx.fill();

  // Draw border
  ctx.strokeStyle = actionDef.border;
  ctx.lineWidth = 2;
  ctx.stroke();

  // Draw the icon character
  ctx.fillStyle = actionDef.fg;
  ctx.font = "18px Arial";
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.fillText(actionDef.icon, 16, 17);

}

HotbarManager.prototype.__executeAction = function (actionId) {

  /*
   * Function HotbarManager.__executeAction
   * Executes a hotbar action by its ID
   */

  if (!gameClient || !gameClient.player || gameClient.player.isDead) {
    return;
  }

  switch (actionId) {
    case "attackNearest":
      return this.__attackNearestMonster();
    case "attackNearestPlayer":
      return this.__attackNearestPlayer();
    case "attackFurthestPlayer":
      return this.__attackFurthestPlayer();
    case "attackHighestHpPlayer":
      return this.__attackHighestHpPlayer();
    case "attackLowestHpPlayer":
      return this.__attackLowestHpPlayer();
    case "cycleTargetPlayer":
      return this.__cycleTargetPlayer();
    case "attackFurthest":
      return this.__attackFurthestMonster();
    case "attackHighestHp":
      return this.__attackHighestHpMonster();
    case "attackLowestHp":
      return this.__attackLowestHpMonster();
    case "cycleTarget":
      return this.__cycleTargetMonster();
    case "stopAttack":
      return this.__stopAttack();
    case "convertCurrency":
      return this.__convertCurrency();
    case "useCrosshair":
      return this.__useCrosshair();
    case "lookCrosshair":
      return this.__lookCrosshair();
    case "contextMenu":
      return this.__toggleContextMenu();
  }

}

HotbarManager.prototype.__stopAttack = function () {

  /*
   * Function HotbarManager.__stopAttack
   * Clears the current attack target (stop attacking) — mirrors the de-target
   * path the attack actions use (TargetPacket(0)). Bindable to a hotbar slot /
   * hotkey like every other attack action, so mobile players (no Esc key) get a
   * one-tap "stop attack". No-op if nothing is targeted.
   */

  if (!gameClient.player) return;
  gameClient.player.setTarget(null);
  gameClient.send(new TargetPacket(0));

};

HotbarManager.prototype.__useCrosshair = function () {

  /*
   * Function HotbarManager.__useCrosshair
   * Enters crosshair targeting for a plain USE action. The next canvas click
   * fires ItemUsePacket on that tile — intended for ladders, holes, levers,
   * and other world objects you'd normally right-click to use.
   */

  if (!gameClient.mouse) return;

  // Cancel any conflicting crosshair/multi-use state, then arm ours.
  gameClient.mouse.__multiUseObject = null;
  gameClient.mouse.__hotbarCrosshairItem = null;
  gameClient.mouse.__hotbarLookCrosshair = false;
  gameClient.mouse.__hotbarUseCrosshair = true;
  gameClient.mouse.setCursor("crosshair");

};

HotbarManager.prototype.__lookCrosshair = function () {

  /*
   * Function HotbarManager.__lookCrosshair
   * Enters crosshair targeting for a LOOK action. The next canvas click
   * fires ItemLookPacket on that tile, same as shift+click.
   */

  if (!gameClient.mouse) return;

  gameClient.mouse.__multiUseObject = null;
  gameClient.mouse.__hotbarCrosshairItem = null;
  gameClient.mouse.__hotbarUseCrosshair = false;
  gameClient.mouse.__hotbarLookCrosshair = true;
  gameClient.mouse.setCursor("crosshair");

};

HotbarManager.prototype.__toggleContextMenu = function () {

  /*
   * Function HotbarManager.__toggleContextMenu
   * "Context Menu" hotbar action — arms context-menu mode so the next
   * click / tap on a tile, creature or item opens the on-screen context
   * menu. Replaces the removed floating mobile button.
   *   Mobile  — reuses the tap-to-open context mode (same as two-finger tap).
   *   Desktop — arms a crosshair; the next canvas click opens the menu.
   */

  if (gameClient.touch && gameClient.touch.isMobileMode
      && typeof gameClient.touch.toggleContextMode === "function") {
    return gameClient.touch.toggleContextMode();
  }

  // Desktop: arm a crosshair — mirrors __useCrosshair / __lookCrosshair.
  if (!gameClient.mouse) return;
  gameClient.mouse.__multiUseObject = null;
  gameClient.mouse.__hotbarCrosshairItem = null;
  gameClient.mouse.__hotbarUseCrosshair = false;
  gameClient.mouse.__hotbarLookCrosshair = false;
  gameClient.mouse.__hotbarContextCrosshair = true;
  gameClient.mouse.setCursor("crosshair");

};

HotbarManager.prototype.__attackNearestMonster = function () {

  /*
   * Function HotbarManager.__attackNearestMonster
   * Finds the nearest monster and toggles it as the attack target
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let nearestMonster = null;
  let nearestDist = Infinity;

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.MONSTER) {
      continue;
    }

    if (creature.masterId === gameClient.player.id) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    if (dist < nearestDist) {
      nearestDist = dist;
      nearestMonster = creature;
    }
  }

  if (nearestMonster) {
    if (gameClient.player.__target === nearestMonster) {
      gameClient.player.setTarget(null);
      gameClient.send(new TargetPacket(0));
    } else {
      gameClient.player.setTarget(nearestMonster);
      gameClient.send(new TargetPacket(nearestMonster.id));
    }
  }

}

HotbarManager.prototype.__attackNearestPlayer = function () {

  /*
   * Function HotbarManager.__attackNearestPlayer
   * Finds the nearest player and toggles it as the attack target
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let nearestPlayer = null;
  let nearestDist = Infinity;

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.PLAYER || creature === gameClient.player) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    if (dist < nearestDist) {
      nearestDist = dist;
      nearestPlayer = creature;
    }
  }

  if (nearestPlayer) {
    if (gameClient.player.__target === nearestPlayer) {
      gameClient.player.setTarget(null);
      gameClient.send(new TargetPacket(0));
    } else {
      gameClient.player.setTarget(nearestPlayer);
      gameClient.send(new TargetPacket(nearestPlayer.id));
    }
  }

}

HotbarManager.prototype.__attackFurthestPlayer = function () {

  /*
   * Function HotbarManager.__attackFurthestPlayer
   * PvP variant of __attackFurthestMonster — finds the furthest other
   * player within 8 tiles on the same floor and targets them.
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let furthestPlayer = null;
  let furthestDist = 0;

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.PLAYER || creature === gameClient.player) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    if (dist > furthestDist) {
      furthestDist = dist;
      furthestPlayer = creature;
    }
  }

  if (furthestPlayer && gameClient.player.__target !== furthestPlayer) {
    gameClient.player.setTarget(furthestPlayer);
    gameClient.send(new TargetPacket(furthestPlayer.id));
  }

}

HotbarManager.prototype.__attackHighestHpPlayer = function () {

  /*
   * Function HotbarManager.__attackHighestHpPlayer
   * PvP variant of __attackHighestHpMonster — finds the other player
   * with the highest current HP within 8 tiles on the same floor.
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let bestPlayer = null;
  let highestHp = 0;

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.PLAYER || creature === gameClient.player) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    if (creature.state.health > highestHp) {
      highestHp = creature.state.health;
      bestPlayer = creature;
    }
  }

  if (bestPlayer && gameClient.player.__target !== bestPlayer) {
    gameClient.player.setTarget(bestPlayer);
    gameClient.send(new TargetPacket(bestPlayer.id));
  }

}

HotbarManager.prototype.__attackLowestHpPlayer = function () {

  /*
   * Function HotbarManager.__attackLowestHpPlayer
   * PvP variant of __attackLowestHpMonster — finds the other player
   * with the lowest current HP within 8 tiles on the same floor.
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let bestPlayer = null;
  let lowestHp = Infinity;

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.PLAYER || creature === gameClient.player) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    if (creature.state.health < lowestHp) {
      lowestHp = creature.state.health;
      bestPlayer = creature;
    }
  }

  if (bestPlayer && gameClient.player.__target !== bestPlayer) {
    gameClient.player.setTarget(bestPlayer);
    gameClient.send(new TargetPacket(bestPlayer.id));
  }

}

HotbarManager.prototype.__cycleTargetPlayer = function () {

  /*
   * Function HotbarManager.__cycleTargetPlayer
   * PvP variant of __cycleTargetMonster — cycles through visible other
   * players sorted by distance, targeting the next one each press.
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let players = [];

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.PLAYER || creature === gameClient.player) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    players.push({ "creature": creature, "dist": dist, "id": Number(id) });
  }

  if (players.length === 0) {
    return;
  }

  // Sort by distance, then by ID for stable ordering
  players.sort(function (a, b) {
    return a.dist - b.dist || a.id - b.id;
  });

  // Find current target index
  let currentIndex = -1;
  let currentTarget = gameClient.player.__target;

  if (currentTarget) {
    for (let i = 0; i < players.length; i++) {
      if (players[i].creature === currentTarget) {
        currentIndex = i;
        break;
      }
    }
  }

  // Cycle to the next player
  let nextIndex = (currentIndex + 1) % players.length;
  let next = players[nextIndex].creature;

  gameClient.player.setTarget(next);
  gameClient.send(new TargetPacket(next.id));

}

HotbarManager.prototype.__attackFurthestMonster = function () {

  /*
   * Function HotbarManager.__attackFurthestMonster
   * Finds the furthest monster and toggles it as the attack target
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let furthestMonster = null;
  let furthestDist = 0;

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.MONSTER) {
      continue;
    }

    if (creature.masterId === gameClient.player.id) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    if (dist > furthestDist) {
      furthestDist = dist;
      furthestMonster = creature;
    }
  }

  if (furthestMonster && gameClient.player.__target !== furthestMonster) {
    gameClient.player.setTarget(furthestMonster);
    gameClient.send(new TargetPacket(furthestMonster.id));
  }

}

HotbarManager.prototype.__attackHighestHpMonster = function () {

  /*
   * Function HotbarManager.__attackHighestHpMonster
   * Finds the monster with the highest HP and toggles it as the attack target
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let bestMonster = null;
  let highestHp = 0;

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.MONSTER) {
      continue;
    }

    if (creature.masterId === gameClient.player.id) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    if (creature.state.health > highestHp) {
      highestHp = creature.state.health;
      bestMonster = creature;
    }
  }

  if (bestMonster && gameClient.player.__target !== bestMonster) {
    gameClient.player.setTarget(bestMonster);
    gameClient.send(new TargetPacket(bestMonster.id));
  }

}

HotbarManager.prototype.__attackLowestHpMonster = function () {

  /*
   * Function HotbarManager.__attackLowestHpMonster
   * Finds the monster with the lowest HP and toggles it as the attack target
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let bestMonster = null;
  let lowestHp = Infinity;

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.MONSTER) {
      continue;
    }

    if (creature.masterId === gameClient.player.id) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    if (creature.state.health < lowestHp) {
      lowestHp = creature.state.health;
      bestMonster = creature;
    }
  }

  if (bestMonster && gameClient.player.__target !== bestMonster) {
    gameClient.player.setTarget(bestMonster);
    gameClient.send(new TargetPacket(bestMonster.id));
  }

}

HotbarManager.prototype.__cycleTargetMonster = function () {

  /*
   * Function HotbarManager.__cycleTargetMonster
   * Cycles through visible monsters sorted by distance, targeting the next one
   */

  let playerPos = gameClient.player.getPosition();
  let creatures = gameClient.world.activeCreatures;
  let monsters = [];

  for (let id in creatures) {
    let creature = creatures[id];

    if (creature.type !== CONST.TYPES.MONSTER) {
      continue;
    }

    if (creature.masterId === gameClient.player.id) {
      continue;
    }

    let pos = creature.getPosition();

    if (pos.z !== playerPos.z) {
      continue;
    }

    // Candidate must be on the visible 15x11 screen (canSeeSmall), not an
    // 8-tile chebyshev square that overshot the viewport's top/bottom edge.
    if (!gameClient.player.canSeeSmall(creature)) {
      continue;
    }

    let dist = Math.max(Math.abs(pos.x - playerPos.x), Math.abs(pos.y - playerPos.y));

    monsters.push({ "creature": creature, "dist": dist, "id": Number(id) });
  }

  if (monsters.length === 0) {
    return;
  }

  // Sort by distance, then by ID for stable ordering
  monsters.sort(function (a, b) {
    return a.dist - b.dist || a.id - b.id;
  });

  // Find current target index
  let currentIndex = -1;
  let currentTarget = gameClient.player.__target;

  if (currentTarget) {
    for (let i = 0; i < monsters.length; i++) {
      if (monsters[i].creature === currentTarget) {
        currentIndex = i;
        break;
      }
    }
  }

  // Cycle to the next monster
  let nextIndex = (currentIndex + 1) % monsters.length;
  let next = monsters[nextIndex].creature;

  gameClient.player.setTarget(next);
  gameClient.send(new TargetPacket(next.id));

}

HotbarManager.prototype.__convertCurrency = function () {

  /*
   * Function HotbarManager.__convertCurrency
   * Finds a full stack of 100 gold or platinum coins and uses it to convert up
   */

  // CIDs for coins
  let GOLD_CID = 3031;
  let PLATINUM_CID = 3035;

  // Search for a full stack of 100 coins (gold first, then platinum)
  let coinIds = [GOLD_CID, PLATINUM_CID];

  for (let c = 0; c < coinIds.length; c++) {
    let found = this.__findFullCoinStack(coinIds[c]);
    if (found !== null) {
      gameClient.send(new ItemUsePacket(found));
      return;
    }
  }

  gameClient.interface.setCancelMessage("You need a full stack of 100 coins.");

}

HotbarManager.prototype.__findFullCoinStack = function (coinId) {

  /*
   * Function HotbarManager.__findFullCoinStack
   * Searches equipment and open containers for a coin stack with count === 100
   * Returns { which, index } source object or null
   */

  // Search equipment slots
  let equipment = gameClient.player.equipment;
  for (let s = 0; s < equipment.slots.length; s++) {
    let item = equipment.getSlotItem(s);
    if (item !== null && item.id === coinId && item.count === 100) {
      return new Object({ "which": equipment, "index": s });
    }
  }

  // Search opened containers
  let containers = Array.from(gameClient.player.__openedContainers);
  for (let c = 0; c < containers.length; c++) {
    let container = containers[c];
    for (let s = 0; s < container.slots.length; s++) {
      let item = container.getSlotItem(s);
      if (item !== null && item.id === coinId && item.count === 100) {
        return new Object({ "which": container, "index": s });
      }
    }
  }

  return null;

}

HotbarManager.prototype.clearSlot = function (index) {

  /*
   * Function HotbarManager.clearSlot
   * Clears a hotbar slot by removing the reference to the spell/text and clearing the canvas
   */

  // Clear all references and the canvas
  this.slots[index].spell = null;
  this.slots[index].text = null;
  this.slots[index].item = null;
  this.slots[index].__lastDrawKey = null;
  this.slots[index].action = null;
  this.slots[index].mode = "self";

  // Desktop slots have canvas/duration DOM refs; mobile-only slots (8-10) do not
  if (this.slots[index].canvas) {
    this.slots[index].canvas.clear();
    this.slots[index].canvas.canvas.parentNode.lastElementChild.style.color = "grey";
    this.slots[index].canvas.canvas.parentNode.title = "";
  }
  if (this.slots[index].duration) {
    this.slots[index].duration.textContent = '';
  }

  this.__saveConfiguration();

}

HotbarManager.prototype.resetToDefault = function () {

  /*
   * Function HotbarManager.resetToDefault
   * Clears every slot in the active preset, restores the onboarding defaults
   * (slot 1 = attack nearest, mobile slot 2 = context menu) and resets the
   * hotbar keybinds back to F1-F12. Drives the client-side /resethotkeys
   * command (owner request 2026-06-13). Only the active preset is touched;
   * the other presets keep their setup.
   */

  for (let i = 0; i < this.slots.length; i++) {
    this.clearSlot(i);
  }

  this.__seedDefaultSlots();
  this.__saveConfiguration();

  // Restore the default key bindings (F1-F12) for the active preset. The splice
  // inside applyHotbarKeybindPreset replaces the whole bind array, so any stray
  // bank-2 keybind entries (binds[12..23], left over from a build that allowed
  // rebinding Shift+F slots) are dropped here too.
  if (gameClient.keyboard) {
    gameClient.keyboard.applyHotbarKeybindPreset("f-keys");
  }

  // Restore the bank-2 (Shift+F) key labels to their authored defaults. They are
  // static text that updateAllKeyLabels/applyHotbarKeybindPreset never touch (only
  // bank 1, slots 0-11), so a previous build that let bank-2 slots be rebound
  // could have overwritten "⇧F1".."⇧F12" with a captured key name. Without this,
  // reset clears bank-2 content but leaves the wrong key text — the "doesn't set
  // them to default" report (2026-06-13).
  let bank2 = document.querySelectorAll(".hotbar-item.hotbar-bank2");
  for (let i = 0; i < bank2.length; i++) {
    let span = bank2[i].querySelector(".hotbar-key");
    if (span) span.textContent = "⇧F" + (i + 1);
  }

  if (gameClient.interface) {
    gameClient.interface.setCancelMessage("Your hotkeys have been reset to default.");
  }

}

HotbarManager.prototype.handleKeyPress = function (key) {

  /*
   * Function HotbarManager.handleKeyPress
   * Function called when the keyboard delegates the F* press to the hotbar manager. This is equal to a click event.
   */

  // Determine the index of the pressed key
  this.__handleClick(key - Keyboard.prototype.KEYS.F1);

}

HotbarManager.prototype.render = function () {

  /*
   * Function HotbarManager.render
   * Renders the hotbar to the DOM
   */

  // Every frame go over all the slots
  this.slots.forEach(function (slot) {

    // Skip mobile-only slots (no desktop canvas)
    if (slot.canvas === null) return;

    // The slot is empty and not active
    if (slot.spell === null && slot.text === null && slot.item === null && slot.action === null) {
      return;
    }

    // If slot has an action, redraw action icon (no cooldown)
    if (slot.action !== null) {
      this.__drawActionIcon(slot);
      return;
    }

    // If slot has an item, redraw item sprite and apply rune/fluid cooldown if active
    if (slot.item !== null) {
      let def = gameClient.itemDefinitionsByCid ? gameClient.itemDefinitionsByCid[slot.item.id] : null;
      let isRune = def && def.properties && def.properties.type === "rune";
      let isFluid = def && def.properties && def.properties.type === "fluidContainer";
      let cd = isRune ? this.__getRuneEffectiveCooldown(def.properties.aggressive !== false)
             : isFluid ? this.__getFluidEffectiveCooldown()
             : null;

      // Skip the repaint when nothing visible changed. The key covers every
      // input that affects the pixels (binding identity, tint/glow source,
      // use-mode indicator, cooldown-active state); while a cooldown is
      // animating we repaint every frame exactly as before. The cdActive
      // flag is part of the key, so the active->idle transition produces
      // one final clean repaint (icon without overlay + count restored)
      // before the slot goes dormant. Saves a new Item() allocation + full
      // 32x32 redraw per bound slot per frame.
      let cdActive = !!(cd && cd.until > performance.now());
      let drawKey = "item|" + slot.item.id + "|" + (slot.item.fluidType || 0)
        + "|" + (slot.item.sid || 0) + "|" + (slot.item.tintId || 0)
        + "|" + slot.mode + "|" + cdActive;
      if (!cdActive && slot.__lastDrawKey === drawKey) {
        return;
      }
      slot.__lastDrawKey = drawKey;

      this.__drawItemSlot(slot);
      if (cdActive) {
        let remaining = cd.until - performance.now();
        let fraction = 1 - (remaining / Math.max(1, cd.duration));
        slot.canvas.context.fillStyle = this.__getConicGradient(fraction);
        slot.canvas.context.fillRect(0, 0, 32, 32);
        slot.duration.innerHTML = (remaining / 1000).toFixed(1) + "s";
      } else if (slot.duration) {
        let savedCount = slot.duration.getAttribute("data-count");
        if (savedCount) {
          slot.duration.textContent = savedCount;
          slot.duration.style.color = "#88ff88";
        } else {
          slot.duration.innerHTML = "";
        }
      }
      return;
    }

    // If slot has text, redraw text icon ONCE on bind (dirty flag). The
    // text-slot visual (corner bubble + DOM label) is static between
    // rebinds — no animation, no cooldown — so per-frame canvas ops are
    // wasted. addTextSlot sets __textDirty; we clear it after redraw.
    if (slot.text !== null) {
      if (slot.__textDirty) {
        this.__drawTextIcon(slot);
        slot.__textDirty = false;
      }
      return;
    }

    // Get the remaining fraction of the cooldown
    let fraction = gameClient.player.spellbook.getCooldownFraction(slot.spell.sid);
    let runeIcon = slot.spell.runeId ? this.getRuneIcon(slot.spell.runeId) : null;

    // Skip the repaint when nothing visible changed (same scheme as the
    // item branch above): the key covers the bound spell, the use-mode
    // indicator, whether the conjure rune-sprite icon is available yet,
    // and whether a cooldown is animating. While on cooldown we repaint
    // every frame as before (the conic overlay moves); the cdActive flag
    // in the key forces one final clean repaint when the cooldown ends.
    let spellCdActive = fraction < 1;
    let spellDrawKey = "spell|" + slot.spell.sid + "|" + slot.mode
      + "|" + (runeIcon !== null) + "|" + spellCdActive;
    if (!spellCdActive && slot.__lastDrawKey === spellDrawKey) {
      return;
    }
    slot.__lastDrawKey = spellDrawKey;

    // Always render the spell icon. Conjure spells draw the sprite of the
    // item they conjure (runeId) so each rune/ammo is distinguishable;
    // sprite has transparency, so clear first (sheet icons are opaque and
    // skip the clear). Falls back to the sheet icon if not drawable yet.
    if (runeIcon !== null) {
      slot.canvas.clear();
      slot.canvas.context.drawImage(runeIcon, 0, 0);
    } else {
      slot.canvas.context.drawImage(
        this.ICONS,
        32 * slot.spell.icon.x,
        32 * slot.spell.icon.y,
        32, 32,
        0, 0,
        32, 32
      );
    }

    // Below one means it is on cooldown
    if (fraction < 1) {
      this.__applyCooldownEffect(fraction, slot);
    }

    if (fraction === 1) {
      slot.duration.innerHTML = null;
    }

    // Draw mode indicator on top of spell icon
    this.__drawModeIndicator(slot);

  }, this);

}

HotbarManager.prototype.__applyCooldownEffect = function (fraction, slot) {

  /*
   * Function HotbarManager.__applyCooldownEffect
   * Returns the conic gradient that belongs to a certain fraction
   */

  slot.canvas.context.fillStyle = this.__getConicGradient(fraction);
  slot.canvas.context.fillRect(0, 0, 32, 32);

  let seconds = gameClient.player.spellbook.getCooldownSeconds(slot.spell.sid);
  if (seconds > 60) {
    slot.duration.innerHTML = "%sm".format((seconds / 60).toFixed(1));
  } else {
    slot.duration.innerHTML = "%ss".format(seconds.toFixed(1));
  }

}

HotbarManager.prototype.__getConicGradient = function (fraction) {

  /*
   * Function HotbarManager.__getConicGradient
   * Returns the conic gradient that belongs to a certain fraction.
   * Browsers without createConicGradient (Chrome < 89, Safari < 14.1)
   * leave GRADIENTS null — return a flat dark-overlay fillStyle as
   * fallback so cooldowns still visually dim the slot, just without
   * the sweep animation.
   */

  if (!this.GRADIENTS) {
    return "rgba(0, 0, 0, 0.55)";
  }
  return this.GRADIENTS[Math.round(360 * (fraction.clamp(0, 1) % 1))];

}

HotbarManager.prototype.__addClickEventListeners = function (DOMElement, i) {

  /*
   * Function HotbarManager.__addClickEventListeners
   * Attaches click event listeners to the hotbar slots. Ctrl+Click enters rebind mode.
   */

  DOMElement.addEventListener("click", function (event) {
    if (gameClient.keyboard && gameClient.keyboard.isControlOrMetaDown()) {
      return this.__enterRebindMode(i);
    }
    this.__handleClick(i);
  }.bind(this));

}

HotbarManager.prototype.__handleLightUp = function (slot, type) {

  /*
   * Function HotbarManager.__handleLightUp
   * Handles lighting up of the hotbar to give feedback a button is pressed
   * Type can be "success" (default) or "reject" for cooldown/failed actions
   */

  let feedbackClass = (type === "reject") ? "hotbar-reject" : "hotbar-success";
  let duration = (type === "reject") ? 300 : 200;

  // Use classList (not a className overwrite) so the slot keeps any other
  // classes — notably hotbar-bank2. The old overwrite reset className to
  // "hotbar-item", stripping hotbar-bank2 whenever a bank-2 slot fired, which
  // leaked it into bank 1 and broke the toggle.
  let el = slot.canvas.canvas.parentNode;
  el.classList.remove("hotbar-success", "hotbar-reject");
  el.classList.add(feedbackClass);

  // Use a timeout to reset the feedback class
  setTimeout(function () {
    el.classList.remove(feedbackClass);
  }.bind(this), duration);

}

HotbarManager.prototype.__handleClick = function (i) {

  /*
   * Function HotbarManager.__handleClick
   * Function called when a hotbar slot is clicked or F* key is pressed
   * Respects the slot's use mode (self, target, crosshair)
   * Uses "success" or "reject" feedback depending on action outcome
   */

  let slot = this.slots[i];

  // A click or hotkey can arrive for an index that has no slot — an
  // out-of-range F-key, an extra-hotbar index, a stale handler. There
  // is nothing to trigger, so no-op instead of dereferencing undefined
  // (threw "Cannot read properties of undefined (reading 'action')").
  if (!slot) {
    return;
  }

  // Handle action hotkey
  if (slot.action !== null) {
    this.__handleLightUp(slot, "success");
    return this.__executeAction(slot.action);
  }

  // Handle text hotkey - mode doesn't apply (always sends text)
  if (slot.text !== null) {
    // Spell glow: if the text matches known spell words and player can cast it, trigger glow
    let matchedSpellSid = null;
    if (gameClient.player && gameClient.interface.SPELLS) {
      let textLower = slot.text.toLowerCase().trim();
      let self = this;
      gameClient.interface.SPELLS.forEach(function(spell, sid) {
        if (matchedSpellSid === null && spell.words && spell.words.toLowerCase() === textLower) {
          matchedSpellSid = sid;
        }
      });
    }
    let canCast = matchedSpellSid === null || this.__canPlayerCastSpell(matchedSpellSid);
    this.__handleLightUp(slot, canCast ? "success" : "reject");
    if (canCast && matchedSpellSid !== null) {
      let glowColor = HotbarManager.prototype.__getSpellGlowColor(slot.text);
      gameClient.player.__spellGlow = { start: performance.now(), color: glowColor };
    }
    gameClient.send(new ChannelMessagePacket(CONST.CHANNEL.DEFAULT, 1, slot.text));
    return;
  }

  // Handle item hotkey with mode
  if (slot.item !== null) {
    // Check rune cooldown for reject animation
    let isRuneOnCooldown = false;
    if (gameClient.itemDefinitionsByCid) {
      let def = gameClient.itemDefinitionsByCid[slot.item.id];
      if (def && def.properties && def.properties.type === "rune") {
        let cd = this.__getRuneEffectiveCooldown(def.properties.aggressive !== false);
        if (cd && performance.now() < cd.until) {
          isRuneOnCooldown = true;
        }
        // Cooldown is now started by the server via HOTBAR_ITEM_COUNT packet
        // to prevent cooldown burning when the server rejects the action
      }
    }
    this.__handleLightUp(slot, isRuneOnCooldown ? "reject" : "success");
    return this.__handleItemUseWithMode(slot.item, slot.mode);
  }

  if (slot.spell === null) {
    return;
  }

  // Check if spell is on cooldown, player lacks mana, or wrong vocation/level
  let spellbook = gameClient.player ? gameClient.player.spellbook : null;
  let isOnCooldown = spellbook && (spellbook.cooldowns.has(spellbook.GLOBAL_COOLDOWN) || spellbook.cooldowns.has(slot.spell.sid));
  let notEnoughMana = gameClient.player && slot.spell.mana && (gameClient.player.state.mana || 0) < slot.spell.mana;
  let cannotCast = gameClient.player && !this.__canPlayerCastSpell(slot.spell.sid);

  let shouldReject = isOnCooldown || notEnoughMana || cannotCast;

  this.__handleLightUp(slot, shouldReject ? "reject" : "success");

  // Don't cast or animate if the player cannot use this spell
  if (cannotCast) {
    return;
  }

  // Spell glow: trigger before cast, only when not on cooldown and has enough mana
  if (!isOnCooldown && !notEnoughMana && gameClient.player) {
    let spell = gameClient.interface.getSpell(slot.spell.sid);
    if (spell && spell.words) {
      let glowColor = HotbarManager.prototype.__getSpellGlowColor(spell.words);
      gameClient.player.__spellGlow = { start: performance.now(), color: glowColor };
    }
  }

  // Handle spell hotkey with mode
  return this.__handleSpellUseWithMode(slot.spell, slot.mode);

}

HotbarManager.prototype.__handleSpellUseWithMode = function (spellConfig, mode) {

  /*
   * Function HotbarManager.__handleSpellUseWithMode
   * Handles spell activation from hotbar, respecting the configured use mode
   * In Tibia 7.4, spells are words-based and targeting is server-side, so all modes cast normally
   */

  let spell = gameClient.interface.getSpell(spellConfig.sid);

  if (spell && spell.words) {
    gameClient.send(new ChannelMessagePacket(CONST.CHANNEL.DEFAULT, 1, spell.words));
    return;
  }

  // Fallback: use direct spell cast if no words defined
  return gameClient.player.spellbook.castSpell(spellConfig.sid);

}

HotbarManager.prototype.__handleItemUseWithMode = function (itemConfig, mode) {

  /*
   * Function HotbarManager.__handleItemUseWithMode
   * Handles using an item from the hotbar with the configured mode
   * Modes: "self" = use on player, "target" = use on battle target, "crosshair" = manual aim
   *        "quiver" = move highest-count stack into the quiver equipment slot
   */

  // "quiver" / "amulet" / "ring" are equip-moves, not uses — they need
  // best-stack semantics (pick the heaviest stack of ammo, not the
  // first one we find). Short-circuit before the first-match lookup
  // so we don't pick a tiny leftover stack when a full one exists.
  let QUIVER_SLOT = (typeof CONST !== "undefined" && CONST.EQUIPMENT && typeof CONST.EQUIPMENT.QUIVER === "number") ? CONST.EQUIPMENT.QUIVER : 9;
  let NECKLACE_SLOT = (typeof CONST !== "undefined" && CONST.EQUIPMENT && typeof CONST.EQUIPMENT.NECKLACE === "number") ? CONST.EQUIPMENT.NECKLACE : 7;
  let RING_SLOT = (typeof CONST !== "undefined" && CONST.EQUIPMENT && typeof CONST.EQUIPMENT.RING === "number") ? CONST.EQUIPMENT.RING : 8;
  if (mode === "quiver") return this.__moveItemToEquipSlot(itemConfig, QUIVER_SLOT, "ammo");
  if (mode === "amulet") return this.__moveItemToEquipSlot(itemConfig, NECKLACE_SLOT, "amulet");
  if (mode === "ring")   return this.__moveItemToEquipSlot(itemConfig, RING_SLOT,   "ring");

  let found = this.__findItemInInventory(itemConfig.id, itemConfig.fluidType, itemConfig.sid);

  if (found !== null) {

    let sourceObject = new Object({
      "which": found.container,
      "index": found.slotIndex
    });

    let item = found.container.getSlotItem(found.slotIndex);

    if (item === null) {
      gameClient.interface.setCancelMessage("You do not have this item.");
      return;
    }

    switch (mode) {
      case "self":
        return this.__useItemOnSelf(sourceObject, item);
      case "target":
        return this.__useItemOnTarget(sourceObject, item);
      case "crosshair":
        return this.__useItemCrosshair(sourceObject, item);
      case "cook":
        return this.__useItemCrosshair(sourceObject, item, true);
    }

    return;
  }

  // Item not found locally — ask the server to search full inventory
  // useModes: 0 = generic use, 1 = use on target creature, 2 = use on self
  let useMode = 0;
  let targetCreatureId = 0;

  switch (mode) {
    case "self":
      useMode = 2;
      break;
    case "target":
      // gameClient.player can be null briefly between disconnect and the
      // next PlayerStatePacket — clicking a "use on target" hotbar slot
      // in that window crashed the click handler (Seledoz 2026-05-10
      // [ERROR] TypeError: Cannot read properties of null reading
      // 'getTarget'). Bail cleanly instead.
      if (!gameClient.player) {
        gameClient.interface.setCancelMessage("You are not in the world.");
        return;
      }
      let target = gameClient.player.getTarget();
      if (target !== null) {
        useMode = 1;
        targetCreatureId = target.id;
      } else {
        gameClient.interface.setCancelMessage("You have no target.");
        return;
      }
      break;
    case "crosshair":
    case "cook":
      // Enter crosshair mode with server-side item lookup
      // Store item info so the mouse/touch handler can send a HotbarUsePacket on click
      gameClient.mouse.__hotbarCrosshairItem = new Object({
        "id": itemConfig.id,
        "fluidType": itemConfig.fluidType || 0
      });
      gameClient.mouse.setCursor("move");
      return;
  }

  gameClient.send(new HotbarUsePacket(itemConfig.id, itemConfig.fluidType || 0, useMode, targetCreatureId));

}

HotbarManager.prototype.__useItemOnSelf = function (sourceObject, item) {

  /*
   * Function HotbarManager.__useItemOnSelf
   * Uses an item on the player's own tile
   */

  let playerTile = gameClient.player.getTile();

  if (playerTile === null) {
    return;
  }

  if (item.isFluidContainer() || item.isMultiUse()) {
    // Route all self-targeting through the creature packet (player.id) so
    // the server always resolves our current position from the player object
    // on its side. Previously runes used ItemUseWith with a client-side
    // tile reference — in rare client/server desyncs the client would send
    // a tile that didn't match the server's idea of where we're standing,
    // and the rune would silently do nothing or target an adjacent tile.
    gameClient.send(new ItemUseOnCreaturePacket(sourceObject, gameClient.player.id));
  } else {
    gameClient.send(new ItemUsePacket(sourceObject));
  }

}

HotbarManager.prototype.__useItemOnTarget = function (sourceObject, item) {

  /*
   * Function HotbarManager.__useItemOnTarget
   * Uses an item on the current battle target creature
   */

  let target = gameClient.player.getTarget();

  if (target === null) {
    gameClient.interface.setCancelMessage("You have no target.");
    return;
  }

  if (item.isFluidContainer() || item.isMultiUse()) {
    gameClient.send(new ItemUseOnCreaturePacket(sourceObject, target.id));
  } else {
    gameClient.send(new ItemUsePacket(sourceObject));
  }

}

HotbarManager.prototype.__useItemCrosshair = function (sourceObject, item) {

  /*
   * Function HotbarManager.__useItemCrosshair
   * Enters crosshair mode for manual targeting
   */

  // Check if the item is a rune via definitions (in case .dat multiUse flag is missing)
  let isRune = false;
  if (gameClient.itemDefinitionsByCid) {
    let def = gameClient.itemDefinitionsByCid[item.id];
    isRune = def && def.properties && def.properties.type === "rune";
  }

  // Also check if this is being called from cook mode (food items aren't multiuse)
  let isCookMode = arguments.length > 2 && arguments[2] === true;

  if (item.isFluidContainer() || item.isMultiUse() || isRune || isCookMode) {
    gameClient.mouse.__multiUseObject = sourceObject;
    gameClient.mouse.setCursor("move");
  } else {
    gameClient.send(new ItemUsePacket(sourceObject));
  }

}

HotbarManager.prototype.__createSlot = function (DOMElement) {

  /*
   * Function HotbarManager.__createSlot
   * Function to create a single slot with a canvas and reference to spell/text (null when empty)
   */

  return new Object({
    "canvas": new Canvas(DOMElement.firstChild, 32, 32),
    "duration": DOMElement.children[1],
    "spell": null,
    "text": null,
    "item": null,
    "action": null,
    "mode": "self"
  });

}

HotbarManager.prototype.__createConicGradients = function () {

  /*
   * Function HotbarManager.__createConicGradients
   * Internally creates a lookup table for the conic gradients per degree so they do not need to be generated on the fly.
   *
   * Feature gate: createConicGradient was added in Chrome 89 (Mar 2021) /
   * Firefox 83 / Safari 14.1. Older browsers (e.g. Chrome 87 on Android)
   * throw "context.createConicGradient is not a function" here, which
   * crashes HotbarManager → Interface → GameClient construction and
   * leaves the loading screen frozen at "Initializing…".
   *
   * If unavailable, leave GRADIENTS undefined and let __drawCooldownArc
   * (which is the only consumer) fall back to a plain circular overlay
   * via its own null-guard. Cosmetic-only — cooldown still visible.
   */
  let temp = new Canvas(null, 32, 32);
  if (typeof temp.context.createConicGradient !== "function") {
    this.GRADIENTS = null;
    return;
  }

  let gradients = new Array();
  for (let i = 0; i < 360; i++) {
    gradients.push(this.__createConicGradient(i / 360, temp.context));
  }
  this.GRADIENTS = gradients;

}

HotbarManager.prototype.__createConicGradient = function (fraction, context) {

  /*
   * Function HotbarManager.__createConicGradient
   * Internally creates a lookup table for the conic gradients per degree so they do not need to be generated on the fly
   */

  let gradient = context.createConicGradient(fraction * 2 * Math.PI, 16, 16);

  // Add five color stops
  gradient.addColorStop(0, "rgba(0, 0, 0, 0.75)");
  gradient.addColorStop(1 - fraction, "rgba(0, 0, 0, 0.75)");
  gradient.addColorStop(1 - fraction, "rgba(0, 0, 0, 0)");

  return gradient;

}

HotbarManager.prototype.__loadConfiguration = function () {

  /*
   * Function HotbarManager.__loadConfiguration
   * Reads the configuration from local storage, migrating old format if needed
   */

  let storage = localStorage.getItem("hotbar");

  // Default slot 0 to attack nearest monster if not saved or empty.
  // Mobile/tablet also gets contextMenu on slot 1 — see __seedDefaultSlots.
  if (storage === null) {
    this.__presets = [this.__emptyPreset(), this.__emptyPreset(), this.__emptyPreset(), this.__emptyPreset()];
    this.activePreset = 0;
    this.__seedDefaultSlots();
    return;
  }

  let parsed;

  try {
    parsed = JSON.parse(storage);
  } catch (e) {
    this.__presets = [this.__emptyPreset(), this.__emptyPreset(), this.__emptyPreset(), this.__emptyPreset()];
    this.activePreset = 0;
    this.__seedDefaultSlots();
    return;
  }

  let migrated = false;

  // Detect old format: flat array of 12 slots
  if (Array.isArray(parsed)) {
    this.__presets = [parsed, this.__emptyPreset(), this.__emptyPreset(), this.__emptyPreset()];
    this.activePreset = 0;
    migrated = true;
  } else if (parsed.version === 2) {
    // New format
    this.activePreset = Math.max(0, Math.min(3, parsed.activePreset || 0));
    this.__presets = parsed.presets || [];
    // Pad to 4 presets if needed
    while (this.__presets.length < 4) {
      this.__presets.push(this.__emptyPreset());
    }
  } else {
    // Unknown format, reset
    this.__presets = [this.__emptyPreset(), this.__emptyPreset(), this.__emptyPreset(), this.__emptyPreset()];
    this.activePreset = 0;
    this.__seedDefaultSlots();
    return;
  }

  // Suppress saves during loading
  this.__loading = true;

  // Apply the active preset config to slots
  this.__applyPresetConfig(this.__presets[this.activePreset]);

  // Sync keybinds to the active preset on load
  if (gameClient.keyboard) {
    gameClient.keyboard.switchKeybindPreset(this.activePreset);
  }

  this.__loading = false;

  // Update UI to reflect active preset
  this.__updatePresetButtons();

  // Re-save in new format if migrated
  if (migrated) {
    this.__saveConfiguration();
  }

}

HotbarManager.prototype.__saveConfiguration = function () {

  /*
   * Function HotbarManager.__saveConfiguration
   * Writes the configuration to local storage using the preset format
   */

  // Skip saving during initial load to prevent overwriting stored modes
  if (this.__loading) {
    return;
  }

  this.__presets[this.activePreset] = this.__serializeSlots();

  localStorage.setItem("hotbar", JSON.stringify({
    "version": 2,
    "activePreset": this.activePreset,
    "presets": this.__presets
  }));

}

HotbarManager.prototype.getServerBlob = function () {

  /*
   * Function HotbarManager.getServerBlob
   * Bundles the full hotbar setup (slots — both banks, all presets — plus the
   * per-preset key bindings) into one JSON string. Flushes the live active
   * preset to localStorage first so the blob reflects unsaved edits. Used by
   * exportToFile(); the two source blobs are stored verbatim so importing is a
   * straight restore.
   */

  this.__saveConfiguration();

  return JSON.stringify({
    "v": 1,
    "hotbar": localStorage.getItem("hotbar"),
    "keybinds": localStorage.getItem("hotbarKeybinds")
  });

}

HotbarManager.prototype.applyServerBlob = function (blobString) {

  /*
   * Function HotbarManager.applyServerBlob
   * Applies an exported hotbar blob (from /importhotkeys). Writes the two source
   * blobs back to localStorage, then re-runs the normal load path so slots + key
   * bindings + UI refresh. Keybinds reload BEFORE the hotbar so the active-preset
   * keybind sync picks up the new bindings. Returns true on success.
   */

  let parsed;
  try {
    parsed = JSON.parse(blobString);
  } catch (e) {
    return false;
  }
  if (!parsed || typeof parsed !== "object" || (typeof parsed.hotbar !== "string" && typeof parsed.keybinds !== "string")) {
    return false;
  }

  try {
    if (typeof parsed.hotbar === "string") {
      localStorage.setItem("hotbar", parsed.hotbar);
    }
    if (typeof parsed.keybinds === "string") {
      localStorage.setItem("hotbarKeybinds", parsed.keybinds);
    }
  } catch (e) {
    // localStorage blocked — nothing to restore from; bail rather than half-apply
    return false;
  }

  if (gameClient.keyboard && gameClient.keyboard.__loadHotbarKeybinds) {
    gameClient.keyboard.__loadHotbarKeybinds();
  }
  this.__loadConfiguration();
  return true;

}

HotbarManager.prototype.exportToFile = function () {

  /*
   * Function HotbarManager.exportToFile
   * /exporthotkeys — downloads the current hotbar setup as a JSON file the
   * player keeps locally (and can load on another character/device with
   * /importhotkeys). Purely local; nothing is sent to the server.
   */

  let blob;
  try {
    blob = this.getServerBlob();
  } catch (e) {
    return this.__hotkeyNotify("Couldn't read your hotkeys to export.");
  }

  try {
    let data = new Blob([blob], { "type": "application/json" });
    let url = URL.createObjectURL(data);
    let a = document.createElement("a");
    let d = new Date();
    let p = function (n) { return (n < 10 ? "0" : "") + n; };
    a.href = url;
    a.download = "minibia-hotkeys-" + d.getFullYear() + p(d.getMonth() + 1) + p(d.getDate()) + ".json";
    a.style.display = "none";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(function () { try { URL.revokeObjectURL(url); } catch (e) {} }, 10000);
    this.__hotkeyNotify("Hotkeys exported — load it on another character with /importhotkeys.");
  } catch (e) {
    this.__hotkeyNotify("Couldn't export your hotkeys.");
  }

}

HotbarManager.prototype.importFromFile = function () {

  /*
   * Function HotbarManager.importFromFile
   * /importhotkeys — opens a file picker, reads a hotkeys file exported with
   * /exporthotkeys, and applies it to this character's hotbar. Local-only.
   */

  let self = this;
  let input = document.createElement("input");
  input.type = "file";
  input.accept = ".json,application/json";
  input.style.display = "none";

  input.addEventListener("change", function () {
    let file = input.files && input.files[0];
    try { document.body.removeChild(input); } catch (e) {}
    if (!file) return;
    let reader = new FileReader();
    reader.onload = function () {
      if (self.applyServerBlob(String(reader.result))) {
        self.__hotkeyNotify("Hotkeys imported.");
      } else {
        self.__hotkeyNotify("That file isn't a valid hotkeys export.");
      }
    };
    reader.onerror = function () { self.__hotkeyNotify("Couldn't read that file."); };
    reader.readAsText(file);
  });

  document.body.appendChild(input);
  input.click();

}

HotbarManager.prototype.__hotkeyNotify = function (msg) {
  try {
    if (window.gameClient && gameClient.interface && typeof gameClient.interface.setCancelMessage === "function") {
      gameClient.interface.setCancelMessage(msg);
    }
  } catch (e) {}
}

HotbarManager.prototype.addItemSlot = function (index, itemId, fluidType, mode) {

  /*
   * Function HotbarManager.addItemSlot
   * Adds an item (rune or fluid container) to a particular slot on the hotbar
   */

  // Invalid index
  if (index < 0 || index >= this.slots.length) {
    return;
  }

  // Clear other types
  this.slots[index].spell = null;
  this.slots[index].text = null;
  this.slots[index].action = null;
  this.slots[index].mode = (mode && this.USE_MODES.indexOf(mode) !== -1) ? mode : "self";
  this.slots[index].item = new Object({
    "id": itemId,
    "fluidType": fluidType || 0,
    "sid": arguments[4] || 0,
    "tintId": arguments[5] || 0
  });
  this.slots[index].__lastDrawKey = null;
  this.__clearTextLabel(this.slots[index]);

  // Draw the item sprite immediately (desktop only)
  if (this.slots[index].canvas) {
    this.__drawItemSlot(this.slots[index]);
    this.slots[index].canvas.canvas.parentNode.lastElementChild.style.color = "white";
    this.slots[index].canvas.canvas.parentNode.title = "Use Item";
  }

  this.__saveConfiguration();

}

// Conjure-spell icon cache: CID -> offscreen 32x32 canvas with the conjured
// item's sprite. Rendered once per item type, then every consumer (desktop
// hotbar, mobile hotbar, hotbar-add picker, spellbook) blits it with a plain
// drawImage — same per-frame cost as the icons.png sheet path it replaces.
HotbarManager.prototype.__runeIconCache = new Map();

HotbarManager.prototype.getRuneIcon = function (cid) {

  /*
   * Function HotbarManager.getRuneIcon
   * Returns a 32x32 canvas with the item sprite for a conjure spell's
   * runeId (client item id), or null when it cannot be drawn yet (assets
   * not loaded) — callers must fall back to the icons.png sheet icon.
   */

  if (this.__runeIconCache.has(cid)) {
    return this.__runeIconCache.get(cid);
  }

  // Sprites unavailable (e.g. pre-game) — do not cache, retry next call
  if (typeof gameClient === "undefined" || !gameClient || !gameClient.interface
      || !gameClient.interface.areAssetsLoaded()) {
    return null;
  }

  try {
    let wrapper = new Canvas(null, 32, 32);
    wrapper.drawSprite(new Item(cid, 1), Position.prototype.NULL, 32);
    // Conjure marker: without it a bound conjure spell is indistinguishable
    // from an item slot holding that same rune. Baked into the cache so all
    // consumers get it and real item slots (no runeId) stay unmarked.
    this.__drawConjureSparkle(wrapper.context);
    this.__runeIconCache.set(cid, wrapper.canvas);
    return wrapper.canvas;
  } catch (exception) {
    return null;
  }

}

HotbarManager.prototype.__drawConjureSparkle = function (ctx) {

  /*
   * Function HotbarManager.__drawConjureSparkle
   * Stamps a golden 4-point magic glint (plus a small secondary one) in the
   * top-RIGHT corner of a 32x32 conjure icon. Top-right is the free corner:
   * the F-key label sits top-left, the use-mode indicator bottom-left and
   * the count/cooldown text along the bottom (same reasoning as the
   * text-slot bubble in __drawTextIcon).
   */

  function star(cx, cy, r) {
    let pinch = r * 0.25;
    ctx.beginPath();
    ctx.moveTo(cx, cy - r);
    ctx.quadraticCurveTo(cx + pinch, cy - pinch, cx + r, cy);
    ctx.quadraticCurveTo(cx + pinch, cy + pinch, cx, cy + r);
    ctx.quadraticCurveTo(cx - pinch, cy + pinch, cx - r, cy);
    ctx.quadraticCurveTo(cx - pinch, cy - pinch, cx, cy - r);
    ctx.closePath();
  }

  // Main glint: dark halo (readable on bright sprites) -> gold -> white core
  ctx.fillStyle = "rgba(0, 0, 0, 0.55)";
  star(24.5, 7.5, 7.5);
  ctx.fill();
  ctx.fillStyle = "#ffd24a";
  star(24.5, 7.5, 6);
  ctx.fill();
  ctx.fillStyle = "#ffffff";
  star(24.5, 7.5, 2.6);
  ctx.fill();

  // Secondary mini sparkle, lower-left of the main one
  ctx.fillStyle = "rgba(0, 0, 0, 0.45)";
  star(18.5, 13, 3.4);
  ctx.fill();
  ctx.fillStyle = "#ffd24a";
  star(18.5, 13, 2.4);
  ctx.fill();

}

HotbarManager.prototype.__drawItemSlot = function (slot) {

  /*
   * Function HotbarManager.__drawItemSlot
   * Draws the item sprite on the hotbar slot canvas
   */

  slot.canvas.clear();

  let item;

  if (slot.item.fluidType > 0) {
    item = new FluidThing(slot.item.id, 1, slot.item.fluidType);
  } else {
    item = new Item(slot.item.id, 1);
  }

  // Draw glow outline behind the sprite if present
  let hbGlow = getItemGlow(slot.item.sid || 0, slot.item.tintId || 0);
  if (hbGlow) {
    slot.canvas.drawGlowOutline(item, Position.prototype.NULL, 32, hbGlow);
  }

  // Apply tint if the slot has SID or tintId
  let tint = getItemTint(slot.item.sid || 0, slot.item.tintId || 0);
  if (tint) {
    slot.canvas.setTint(tint.r, tint.g, tint.b, tint.gray, tint.mix, tint.bright);
  }

  slot.canvas.drawSprite(item, Position.prototype.NULL, 32);

  // Reset tint
  if (tint) {
    slot.canvas.resetTint();
  }

  // Draw mode indicator on top of item sprite
  this.__drawModeIndicator(slot);

}

HotbarManager.prototype.__drawModeIndicator = function (slot) {

  /*
   * Function HotbarManager.__drawModeIndicator
   * Draws a small use-mode icon in the bottom-left corner of the slot canvas
   * Self: green dot, Target: red crosshair, Crosshair: yellow crosshair
   */

  if (slot.mode === "self") {
    return;
  }

  let ctx = slot.canvas.context;
  let x = 3;
  let y = 25;

  if (slot.mode === "target") {

    // Red circle with cross (target indicator)
    ctx.strokeStyle = "red";
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.arc(x + 3, y + 3, 3, 0, 2 * Math.PI);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(x + 3, y);
    ctx.lineTo(x + 3, y + 6);
    ctx.moveTo(x, y + 3);
    ctx.lineTo(x + 6, y + 3);
    ctx.stroke();

  } else if (slot.mode === "crosshair") {

    // Yellow crosshair
    ctx.strokeStyle = "yellow";
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.moveTo(x + 3, y);
    ctx.lineTo(x + 3, y + 6);
    ctx.moveTo(x, y + 3);
    ctx.lineTo(x + 6, y + 3);
    ctx.stroke();

  } else if (slot.mode === "cook") {

    // Orange flame icon
    ctx.fillStyle = "orange";
    ctx.font = "10px Arial";
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    ctx.fillText("\u{1F525}", x, y);

  } else if (slot.mode === "quiver") {

    // Cyan arrow icon — signals "move to quiver slot"
    ctx.fillStyle = "cyan";
    ctx.font = "10px Arial";
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    ctx.fillText("\u{2B06}", x, y);

  } else if (slot.mode === "amulet") {

    // Yellow letter A — signals "move to amulet (necklace) slot"
    ctx.fillStyle = "yellow";
    ctx.font = "bold 10px Arial";
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    ctx.fillText("A", x, y);

  } else if (slot.mode === "ring") {

    // Yellow letter R — signals "move to ring slot"
    ctx.fillStyle = "yellow";
    ctx.font = "bold 10px Arial";
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    ctx.fillText("R", x, y);

  }

}

HotbarManager.prototype.__findItemInInventory = function (itemId, fluidType, sidFilter) {

  /*
   * Function HotbarManager.__findItemInInventory
   * Searches the player's equipment and open containers for an item matching
   * the given CID (and optionally SID + fluid type). Returns { container,
   * slotIndex } or null.
   *
   * sidFilter: when provided (> 0), requires item.sid to match too. Two SIDs
   * can share the same CID (e.g. old rod 14050 / regular rod 2580 both use
   * sprite 3483). Without the SID filter, the hotkey for one rod would
   * silently pick up the other. The filter is opt-in so existing hotbar
   * configs that never recorded a SID still work via CID match.
   */

  // First search equipment slots (so items work even with backpack closed)
  if (!gameClient.player) return null;
  let equipment = gameClient.player.equipment;
  for (let s = 0; s < equipment.slots.length; s++) {
    let item = equipment.getSlotItem(s);

    if (item === null) {
      continue;
    }

    if (item.id !== itemId) {
      continue;
    }

    if (sidFilter && item.sid && item.sid !== sidFilter) {
      continue;
    }

    // For fluid containers, also match the fluid type
    if (fluidType > 0 && item.isFluidContainer() && item.fluidType !== fluidType) {
      continue;
    }

    return new Object({
      "container": equipment,
      "slotIndex": s
    });
  }

  // Then search opened containers (backpack, etc.)
  let containers = Array.from(gameClient.player.__openedContainers);

  for (let c = 0; c < containers.length; c++) {
    let container = containers[c];
    for (let s = 0; s < container.slots.length; s++) {
      let item = container.getSlotItem(s);

      if (item === null) {
        continue;
      }

      if (item.id !== itemId) {
        continue;
      }

      if (sidFilter && item.sid && item.sid !== sidFilter) {
        continue;
      }

      // For fluid containers, also match the fluid type
      if (fluidType > 0 && item.isFluidContainer() && item.fluidType !== fluidType) {
        continue;
      }

      return new Object({
        "container": container,
        "slotIndex": s
      });
    }
  }

  return null;

}

HotbarManager.prototype.__findBestStackInInventory = function (itemId, fluidType, skipEquipSlot, sidFilter) {

  /*
   * Function HotbarManager.__findBestStackInInventory
   * Returns the { container, slotIndex } of the HIGHEST-COUNT stack of
   * the given item across equipment + all open containers. Unlike
   * __findItemInInventory (which returns first match), this scans
   * everything and picks the biggest pile — used by the "equip" hotbar
   * actions (quiver / amulet / ring) so swapping equipment grabs the
   * intended source instead of whichever stack happens to be first in
   * iteration order.
   *
   * skipEquipSlot: equipment slot index to exclude as a source (so a
   * "Move to Ring Slot" action doesn't pick the ring it's about to
   * replace). Pass -1 / null to scan everything.
   *
   * sidFilter: SID disambiguator for items that share a CID (e.g. old
   * rod / regular rod, premium / point scrolls). Mirrors the same
   * filter on __findItemInInventory.
   */

  if (!gameClient.player) return null;

  let best = null;
  let bestCount = -1;

  let consider = function (container, slotIndex, item) {
    if (item === null) return;
    if (item.id !== itemId) return;
    if (sidFilter && item.sid && item.sid !== sidFilter) return;
    if (fluidType > 0 && item.isFluidContainer() && item.fluidType !== fluidType) return;
    let count = (typeof item.getCount === "function" ? item.getCount() : (item.count || 1)) || 1;
    if (count > bestCount) {
      bestCount = count;
      best = { container: container, slotIndex: slotIndex };
    }
  };

  // Equipment is deliberately NOT a source for equip-moves (2026-07-19,
  // ROZPIERDALACZ report): scanning worn slots let a ring parked in a
  // HAND slot be "equipped" by hotkey, and the server's equipment<->
  // equipment swap then displaced the worn ring back into the hand —
  // two ring hotkeys became an instant hand<->ring flip-flop that
  // hammered the transform rate-limit and desynced the client until the
  // hotkeys were unbound. Equip hotkeys pull from BAGS only, exactly
  // like the server's closed-backpack fallback (containersOnly=true);
  // an item found nowhere in open containers falls through to that
  // server search, which also refuses worn items. skipEquipSlot is kept
  // in the signature for call-site compatibility.

  // Every open container
  let containers = Array.from(gameClient.player.__openedContainers);
  for (let c = 0; c < containers.length; c++) {
    let container = containers[c];
    for (let s = 0; s < container.slots.length; s++) {
      consider(container, s, container.getSlotItem(s));
    }
  }

  return best;

};

HotbarManager.prototype.__moveItemToEquipSlot = function (itemConfig, equipSlot, label) {

  /*
   * Function HotbarManager.__moveItemToEquipSlot
   * Finds the largest stack of itemConfig.id in the player's open
   * inventory and sends an ItemMovePacket to drop it into the given
   * equipment slot. If the slot currently holds a different item the
   * server's swap logic returns the old item to the source slot.
   *
   * Used by mode="quiver" (equipSlot=QUIVER), "amulet" (NECKLACE),
   * and "ring" (RING). Typical paladin workflow: bind an arrow and a
   * bolt to two slots with mode="quiver"; one tap swaps ammo without
   * opening inventory. Same pattern for amulet of loss / crystal
   * ring etc.
   *
   * Client-side mirror of the server's 10-transforms-in-30s rate
   * limit on equip-transform items (rings, soft boots, etc). The
   * server has a bug where hitting that limit during a swap clears
   * the equipment slot before refusing — losing the worn item. The
   * server fix is in 51a04208 but takes effect on next restart;
   * this gate prevents the offending packet from being sent in the
   * first place. Quiver/amulet hotkeys also pass through here but
   * they don't have transform-on-equip, so the gate's a no-op for
   * them in practice — only ring swaps tick the counter.
   */

  // Server-side rate cap was disabled per player request — the
  // disappearing-ring bug it was guarding against is now structurally
  // fixed in Equipment.removeIndex (51a04208). Client mirror removed
  // to match. Re-enable here with the same sliding-window pattern
  // if server load from ring spam ever returns.

  // Debounce rapid equip-moves: firing the next one BEFORE the previous move's
  // inventory update returns makes __findBestStackInInventory pick a stale slot,
  // so the server swap displaces a ring it can't cleanly re-home and drops it on
  // the floor (player report: spamming a ring/amulet hotkey with several copies
  // in the bp). One equip-move per EQUIP_MOVE_DEBOUNCE_MS is plenty for
  // intentional swaps and blocks the machine-gun spam that races. NOT the old
  // 10/30s cap — just enough to serialize one move at a time.
  let __nowEq = Date.now();
  if (this.__lastEquipMoveAt && (__nowEq - this.__lastEquipMoveAt) < HotbarManager.prototype.EQUIP_MOVE_DEBOUNCE_MS) {
    return;
  }
  this.__lastEquipMoveAt = __nowEq;

  let best = this.__findBestStackInInventory(itemConfig.id, itemConfig.fluidType, equipSlot, itemConfig.sid);
  if (best === null) {
    // Not in equipment or any OPEN container — but it may be sitting in a CLOSED
    // backpack (the usual case on mobile, where the ring/amulet bag isn't kept
    // open). The client can't see closed-container contents, so it can't build a
    // move source; ask the server to find it across the full inventory and equip
    // it. useMode 4 = equip-to-slot; the slot index rides in the targetCreatureId
    // field. Mirrors the existing server fallback for self/target item uses.
    gameClient.send(new HotbarUsePacket(itemConfig.id, itemConfig.fluidType || 0, 4, equipSlot));
    return;
  }

  let item = best.container.getSlotItem(best.slotIndex);
  if (item === null) {
    // Stale slot reference (inventory changed mid-resolve) — let the server
    // re-find and equip rather than failing outright.
    gameClient.send(new HotbarUsePacket(itemConfig.id, itemConfig.fluidType || 0, 4, equipSlot));
    return;
  }

  let from = new Object({ "which": best.container, "index": best.slotIndex });
  let to = new Object({ "which": gameClient.player.equipment, "index": equipSlot });
  let count = (typeof item.getCount === "function" ? item.getCount() : (item.count || 1)) || 1;

  gameClient.send(new ItemMovePacket(from, to, count));

};

HotbarManager.prototype.setRuneGlobalCooldown = function (durationMs, bucket) {

  /*
   * Function HotbarManager.setRuneGlobalCooldown
   * Called from the UseGlobalCooldown packet handler. Bucket-scoped:
   *   bucket=0 (attack) → dim attack-rune slots only
   *   bucket=1 (heal)   → dim heal-rune slots only
   * Per-slot render picks max of (bucket-specific global) vs (per-rune timer).
   */

  if (!durationMs || durationMs <= 0) return;
  let until = performance.now() + durationMs;
  if (bucket === 1) {
    if (until > this.__runeHealGlobalUntil) {
      this.__runeHealGlobalUntil = until;
      this.__runeHealGlobalDuration = durationMs;
    }
  } else {
    if (until > this.__runeAttackGlobalUntil) {
      this.__runeAttackGlobalUntil = until;
      this.__runeAttackGlobalDuration = durationMs;
    }
  }

};

HotbarManager.prototype.setFluidGlobalCooldown = function (durationMs) {

  /*
   * Function HotbarManager.setFluidGlobalCooldown
   * Called from the FluidGlobalCooldown packet handler — drinking any
   * fluid container locks fluid hotbar slots for `durationMs`. Does
   * NOT affect rune/spell slots.
   */

  if (!durationMs || durationMs <= 0) return;
  let until = performance.now() + durationMs;
  if (until > this.__fluidCooldownUntil) {
    this.__fluidCooldownUntil = until;
    this.__fluidCooldownDuration = durationMs;
  }

};

HotbarManager.prototype.__getFluidEffectiveCooldown = function () {

  /*
   * Function HotbarManager.__getFluidEffectiveCooldown
   * Returns { until, duration } if a fluid cooldown is active, else null.
   */

  if (this.__fluidCooldownUntil > performance.now()) {
    return { until: this.__fluidCooldownUntil, duration: this.__fluidCooldownDuration };
  }
  return null;

};

HotbarManager.prototype.__getRuneEffectiveCooldown = function (isAttack) {

  /*
   * Function HotbarManager.__getRuneEffectiveCooldown
   * For a rune slot of the given bucket, returns the effective {until, duration}
   * by picking whichever ends LATER between the per-rune-type timer and the
   * matching bucket's spell→rune global timer. Returns null when neither
   * is active. Bucket-scoped: attack-rune slots use only attack-bucket
   * timers; heal-rune slots use only heal-bucket timers.
   */

  let perRuneUntil = isAttack ? this.__runeAttackUntil : this.__runeHealUntil;
  let perRuneDur = isAttack ? this.__runeAttackDuration : this.__runeHealDuration;
  let globalUntil = isAttack ? this.__runeAttackGlobalUntil : this.__runeHealGlobalUntil;
  let globalDur = isAttack ? this.__runeAttackGlobalDuration : this.__runeHealGlobalDuration;
  let pickPerRune = perRuneUntil >= globalUntil;
  let until = pickPerRune ? perRuneUntil : globalUntil;
  let duration = pickPerRune ? perRuneDur : globalDur;
  if (until <= performance.now()) return null;
  return { until: until, duration: duration };

};

HotbarManager.prototype.updateItemCount = function (itemId, fluidType, count) {

  /*
   * Function HotbarManager.updateItemCount
   * Updates the item count display on both desktop and mobile hotbar slots
   * Also starts rune cooldown — this packet is only sent after a successful rune use
   */

  // Start rune cooldown only when the count decreased (rune was consumed).
  // Count increases (picking up runes) or refreshes should not trigger cooldown.
  if (gameClient.itemDefinitionsByCid) {
    let def = gameClient.itemDefinitionsByCid[itemId];
    if (def && def.properties && def.properties.type === "rune") {
      let key = itemId + ":" + fluidType;
      let prev = this.__runeCountCache ? this.__runeCountCache[key] : undefined;
      if (prev !== undefined && count < prev) {
        // Self-rune-use cooldown is 2s, scoped to the rune's bucket
        // (attack vs heal — server keeps these locks independent so
        // SD on cooldown doesn't dim UH and vice-versa).
        let isAttack = def.properties.aggressive !== false;
        let until = performance.now() + 2000;
        if (isAttack) {
          if (until > this.__runeAttackUntil) {
            this.__runeAttackUntil = until;
            this.__runeAttackDuration = 2000;
          }
        } else {
          if (until > this.__runeHealUntil) {
            this.__runeHealUntil = until;
            this.__runeHealDuration = 2000;
          }
        }
      }
      if (!this.__runeCountCache) this.__runeCountCache = {};
      this.__runeCountCache[key] = count;
    }
  }

  this.slots.forEach(function (slot, index) {
    if (!slot.item || slot.item.id !== itemId || (slot.item.fluidType || 0) !== fluidType) return;

    // Update desktop hotbar count via the duration (hotbar-text) span
    slot.duration.textContent = count > 0 ? count : '';
    slot.duration.style.color = "#88ff88";
    if (count > 0) {
      slot.duration.setAttribute("data-count", count);
    } else {
      slot.duration.removeAttribute("data-count");
    }

  }.bind(this));

  // Update mobile hotbar count badges (includes extra hotbar slots)
  let mobileSlots = document.querySelectorAll('.mobile-hotbar-slot, .mobile-extra-hotbar-slot');

  mobileSlots.forEach(function (mobileSlot) {
    let index = parseInt(mobileSlot.getAttribute('data-slot'));
    if (isNaN(index) || index >= this.slots.length) return;

    let slot = this.slots[index];

    if (!slot.item || slot.item.id !== itemId || (slot.item.fluidType || 0) !== fluidType) return;

    let badge = mobileSlot.querySelector('.hotbar-count');

    if (!badge) {
      badge = document.createElement('span');
      badge.className = 'hotbar-count';
      mobileSlot.appendChild(badge);
    }

    badge.textContent = count > 0 ? count : '';

  }.bind(this));

}

HotbarManager.prototype.refreshAllItemCounts = function () {

  /*
   * Function HotbarManager.refreshAllItemCounts
   * Requests the server to send accurate item counts for all hotbar item slots
   * Server searches the full inventory including nested/closed backpacks
   * Debounced to avoid flooding the server on rapid inventory changes
   */

  if (!gameClient || !gameClient.player) return;

  // Debounce: delay the request and reset on repeated calls
  if (this.__refreshTimer) {
    clearTimeout(this.__refreshTimer);
  }

  this.__refreshTimer = setTimeout(function () {

    this.__refreshTimer = null;

    if (!gameClient || !gameClient.player || !gameClient.networkManager.isConnected()) return;

    // Collect unique item types from hotbar slots
    let items = [];
    let seen = {};

    this.slots.forEach(function (slot) {
      if (!slot.item) return;
      let key = slot.item.id + ":" + (slot.item.fluidType || 0);
      if (seen[key]) return;
      seen[key] = true;
      items.push({ "id": slot.item.id, "fluidType": slot.item.fluidType || 0 });
    });

    if (items.length === 0) return;

    // Mark these as a SOLICITED refresh: the incoming HOTBAR_ITEM_COUNT replies
    // must seed the supply-message cache SILENTLY. Only an UNSOLICITED count drop
    // (a real use, sent directly by the use handler) shows "Using one of N ...".
    // Without this, moving stackable supplies (potions/runes) to the depot — which
    // fires a container refresh → this request → lower counts — wrongly triggered
    // the supply line. Expiry-bounded so a missed reply can't gag a later real use.
    let nm = gameClient.networkManager;
    if (nm) {
      if (!nm.__supplySeedExpect) nm.__supplySeedExpect = {};
      let exp = Date.now() + 3000;
      for (let i = 0; i < items.length; i++) {
        nm.__supplySeedExpect[items[i].id + ":" + items[i].fluidType] = exp;
      }
    }

    gameClient.send(new HotbarCountsRequestPacket(items));

  }.bind(this), 100);

}

HotbarManager.prototype.__VOCATION_NAMES = {
  0: "none",
  1: "knight", 2: "paladin", 3: "sorcerer", 4: "druid",
  5: "knight", 6: "paladin", 7: "sorcerer", 8: "druid"
};

HotbarManager.prototype.__canPlayerCastSpell = function (sid) {

  /*
   * Function HotbarManager.__canPlayerCastSpell
   * Returns true if the player meets the vocation requirement for a spell.
   */

  let player = gameClient.player;
  if (!player) return true;

  let spell = gameClient.interface.getSpell(sid);
  if (!spell || !spell.vocations || spell.vocations.length === 0) return true;

  let vocationName = this.__VOCATION_NAMES[player.vocation] || "none";
  return spell.vocations.indexOf(vocationName) !== -1;

}

HotbarManager.prototype.__getSpellGlowColor = function (words) {

  /*
   * Function HotbarManager.__getSpellGlowColor
   * Returns RGB color array based on spell element keywords (Tibia convention)
   * Uses word-level matching to avoid false positives (e.g. "vita" matching "vis")
   * Healing takes priority so "adori vita vis" shows green, not purple
   */

  let tokens = words.toLowerCase().split(" ");
  let has = function(keyword) { return tokens.indexOf(keyword) !== -1; };

  // Healing first (so vita+vis spells like "adori vita vis" show green)
  if (has("san") || has("vita") || has("sio") || has("res")) return [80, 255, 80];
  if (has("flam")) return [255, 130, 30];
  if (has("mort")) return [100, 100, 100];
  if (has("frigo")) return [100, 200, 255];
  if (has("pox")) return [80, 180, 50];
  if (has("tera")) return [80, 180, 50];
  if (has("vis")) return [180, 80, 255];
  return [255, 255, 200];

}

HotbarManager.prototype.__emptyPreset = function () {

  /*
   * Function HotbarManager.__emptyPreset
   * Returns an empty preset array of null slots covering the 24 desktop slots
   * (bank 1 F1-F12 + bank 2 Shift+F1-F12). The 4 mobile-vestigial pushed slots
   * serialize as null on top and need no preset entry.
   */

  return new Array(24).fill(null);

}

HotbarManager.prototype.__seedDefaultSlots = function () {

  /*
   * Function HotbarManager.__seedDefaultSlots
   * Onboarding defaults for a fresh hotbar (no localStorage / corrupt JSON
   * / unknown saved format). Slot 1 is always "attack nearest monster" so
   * the player can start fighting without configuring anything; the
   * tutorial highlight at client/src/ui/tutorial-highlight.js:155 and the
   * hint at src/player/player-hint-manager.js:241 both point at it.
   *
   * On mobile/tablet/foldable layouts we also seed slot 2 with the
   * context menu action — the touch UI has no easy way to invoke the
   * context menu without a hotbar binding (right-click doesn't exist),
   * and surfacing it on slot 2 mirrors the discoverability of the
   * attack-nearest default. Desktop players have right-click and don't
   * need the slot eaten. Gated to the same first-load paths as slot 1,
   * so a player who deliberately empties slot 2 keeps it empty.
   */

  this.addActionSlot(0, "attackNearest");

  // gameClient is assigned by the time Spellbook calls __loadConfiguration
  // (post-login), so `gameClient.touch` is reliably present here.
  let isMobile = (typeof gameClient !== "undefined")
    && gameClient.touch && gameClient.touch.isMobileMode;
  if (isMobile) {
    this.addActionSlot(1, "contextMenu");
  }

}

HotbarManager.prototype.__serializeSlots = function () {

  /*
   * Function HotbarManager.__serializeSlots
   * Serializes the current hotbar slots into a saveable array
   */

  return this.slots.map(function (slot) {
    if (slot.action !== null) return { "action": slot.action };
    if (slot.spell !== null) return { "sid": slot.spell.sid, "mode": slot.mode };
    if (slot.text !== null) return { "text": slot.text };
    if (slot.item !== null) return { "item": slot.item.id, "fluidType": slot.item.fluidType || 0, "mode": slot.mode, "sid": slot.item.sid || 0, "tintId": slot.item.tintId || 0 };
    return null;
  });

}

HotbarManager.prototype.__initPresetButtons = function () {

  /*
   * Function HotbarManager.__initPresetButtons
   * Binds click listeners to the desktop and mobile preset buttons
   */

  let self = this;

  let desktopBtns = document.querySelectorAll(".hotbar-preset-btn");

  desktopBtns.forEach(function (btn) {
    btn.addEventListener("click", function () {
      self.switchPreset(parseInt(btn.getAttribute("data-preset")));
    });
  });

  let presetDropdown = document.getElementById("hotbar-preset");
  if (presetDropdown) {
    presetDropdown.value = this.activePreset.toString();
    presetDropdown.addEventListener("change", function () {
      self.switchPreset(parseInt(presetDropdown.value));
    });
  }

  // Bank toggle — flips which 12-slot bank the bar DISPLAYS (bank 1 F1-F12 /
  // bank 2 Shift+F1-F12). Shift+F always fires bank 2 regardless; this is the
  // mouse affordance for viewing/assigning bank-2 slots.
  let bankToggle = document.getElementById("hotbar-bank-toggle");
  if (bankToggle) {
    bankToggle.addEventListener("click", function () { self.toggleBank(); });
  }

}

HotbarManager.prototype.toggleBank = function () {

  /*
   * Function HotbarManager.toggleBank
   * Flips the displayed hotbar bank (bank 1 <-> bank 2) by toggling .show-bank2
   * on the .hotbar container; CSS swaps which 12 slots are visible. Purely a
   * display switch — the slot contents and the Shift+F key mapping are
   * unaffected.
   */

  let bar = document.querySelector(".hotbar");
  if (!bar) return;
  let showBank2 = !bar.classList.contains("show-bank2");
  bar.classList.toggle("show-bank2", showBank2);
  let btn = document.getElementById("hotbar-bank-toggle");
  if (btn) btn.classList.toggle("active", showBank2);

}

HotbarManager.prototype.__updatePresetButtons = function () {

  /*
   * Function HotbarManager.__updatePresetButtons
   * Toggles the active class on preset buttons to match the active preset
   */

  let active = this.activePreset;

  document.querySelectorAll(".hotbar-preset-btn").forEach(function (btn) {
    btn.classList.toggle("active", parseInt(btn.getAttribute("data-preset")) === active);
  });

  let presetDropdown = document.getElementById("hotbar-preset");
  if (presetDropdown) presetDropdown.value = active.toString();

}

HotbarManager.prototype.__applyPresetConfig = function (config) {

  /*
   * Function HotbarManager.__applyPresetConfig
   * Applies a preset config array to the current slots
   */

  if (!config) return;

  config.forEach(function (entry, i) {
    if (entry === null || i >= this.slots.length) return;

    if (entry.action) {
      this.addActionSlot(i, entry.action);
    } else if (entry.text) {
      this.addTextSlot(i, entry.text);
    } else if (entry.item) {
      this.addItemSlot(i, entry.item, entry.fluidType || 0, entry.mode || "self", entry.sid || 0, entry.tintId || 0);
    } else if (entry.sid) {
      this.addSlot(i, entry.sid);
      if (entry.mode) {
        this.slots[i].mode = entry.mode;
      }
    }
  }, this);

}

HotbarManager.prototype.switchPreset = function (index) {

  /*
   * Function HotbarManager.switchPreset
   * Saves the current preset and switches to the given preset index
   */

  if (index === this.activePreset) return;
  if (index < 0 || index > 3) return;

  // Save current slots to the current preset
  this.__presets[this.activePreset] = this.__serializeSlots();

  // Suppress saves during switching
  this.__loading = true;

  // Clear all slots
  for (let i = 0; i < this.slots.length; i++) {
    this.slots[i].spell = null;
    this.slots[i].text = null;
    this.slots[i].item = null;
    this.slots[i].action = null;
    this.slots[i].mode = "self";
    this.slots[i].__lastDrawKey = null;
    if (this.slots[i].canvas) {
      this.slots[i].canvas.clear();
      this.slots[i].canvas.canvas.parentNode.lastElementChild.style.color = "grey";
      this.slots[i].canvas.canvas.parentNode.title = "";
    }
    if (this.slots[i].duration) {
      this.slots[i].duration.textContent = '';
    }
  }

  // Switch to the new preset
  this.activePreset = index;

  // Load config from the new preset
  this.__applyPresetConfig(this.__presets[index]);

  // Switch keybinds to this preset
  if (gameClient.keyboard) {
    gameClient.keyboard.switchKeybindPreset(index);
  }

  this.__loading = false;

  this.__saveConfiguration();
  this.__updatePresetButtons();
  this.updateAllKeyLabels();
  this.refreshAllItemCounts();

  // Sync mobile hotbar canvases immediately
  if (gameClient.touch) {
    gameClient.touch.syncMobileHotbar();
  }

}

HotbarManager.prototype.__initRebindListener = function () {

  /*
   * Function HotbarManager.__initRebindListener
   * Adds a document-level keydown listener that captures the new key during rebind mode
   */

  document.addEventListener("keydown", function (event) {

    // Not in rebind mode
    if (this.__rebindSlot === null) {
      return;
    }

    event.preventDefault();
    event.stopPropagation();

    // Escape cancels rebind
    if (event.keyCode === 27) {
      this.__exitRebindMode(false);
      return;
    }

    // Try to set the keybind
    let success = gameClient.keyboard.setHotbarKeybind(this.__rebindSlot, event.keyCode);

    if (!success) {
      // Reserved key — flash the slot red briefly and show message
      gameClient.interface.setCancelMessage("That key is reserved.");
      return;
    }

    this.__exitRebindMode(true);

  }.bind(this), true);

}

HotbarManager.prototype.__enterRebindMode = function (slotIndex) {

  /*
   * Function HotbarManager.__enterRebindMode
   * Puts a hotbar slot into rebind mode: pulsing border, waiting for key press
   */

  // Bank-2 (Shift+F) slots share their key with the matching bank-1 slot —
  // Shift+<bank-1 key> always fires bank 2, so they have no independent keybind
  // to edit (the keybind array is 12 entries, bank 1 only). Refuse the rebind
  // and point the player at the bank-1 slot. Covers both the Ctrl+Click path
  // and (defensively) the context menu, which already hides "Change Key".
  let candidate = this.__getSlotElement(slotIndex);
  if (candidate && candidate.classList.contains("hotbar-bank2")) {
    if (gameClient.interface && gameClient.interface.notificationManager) {
      gameClient.interface.notificationManager.setCancelMessage("Shift+F slots use the matching bank-1 key — change the bank-1 slot instead.");
    }
    return;
  }

  // If already rebinding a different slot, exit that first
  if (this.__rebindSlot !== null) {
    this.__exitRebindMode(false);
  }

  this.__rebindSlot = slotIndex;

  // Temporarily blur chat input so key capture works with chat-always-unlocked
  if (gameClient.interface && gameClient.interface.settings.isChatAlwaysUnlocked()) {
    document.getElementById("chat-input").blur();
    this.__chatWasUnlocked = true;
  }

  // Add visual indicator
  let element = this.__getSlotElement(slotIndex);

  if (element) {
    element.classList.add("rebinding");
  }

  // Show "..." on the key label
  let keySpan = this.__getKeySpan(slotIndex);

  if (keySpan) {
    keySpan.textContent = "...";
  }

}

HotbarManager.prototype.__exitRebindMode = function (success) {

  /*
   * Function HotbarManager.__exitRebindMode
   * Exits rebind mode, restoring the key label if cancelled
   */

  if (this.__rebindSlot === null) {
    return;
  }

  let slotIndex = this.__rebindSlot;
  let element = this.__getSlotElement(slotIndex);

  if (element) {
    element.classList.remove("rebinding");
  }

  // If cancelled, restore the original label
  if (!success && gameClient.keyboard && gameClient.keyboard.__hotbarKeybindArray) {
    let keyCode = gameClient.keyboard.__hotbarKeybindArray[slotIndex];
    this.updateKeyLabel(slotIndex, Keyboard.getKeyName(keyCode));
  }

  this.__rebindSlot = null;

  // Restore chat focus after rebind if chat-always-unlocked was active
  if (this.__chatWasUnlocked) {
    this.__chatWasUnlocked = false;
    document.getElementById("chat-input").focus();
  }

}

HotbarManager.prototype.updateKeyLabel = function (slotIndex, keyName) {

  /*
   * Function HotbarManager.updateKeyLabel
   * Updates the key label text for a hotbar slot
   */

  let keySpan = this.__getKeySpan(slotIndex);

  if (keySpan) {
    keySpan.textContent = keyName;
  }

}

HotbarManager.prototype.updateAllKeyLabels = function () {

  /*
   * Function HotbarManager.updateAllKeyLabels
   * Sets all 12 hotbar key labels from the current keybind configuration
   */

  if (!gameClient.keyboard || !gameClient.keyboard.__hotbarKeybindArray) {
    return;
  }

  let binds = gameClient.keyboard.__hotbarKeybindArray;

  for (let i = 0; i < binds.length && i < this.slots.length; i++) {
    this.updateKeyLabel(i, Keyboard.getKeyName(binds[i]));
  }

}

HotbarManager.prototype.__getSlotElement = function (slotIndex) {

  /*
   * Function HotbarManager.__getSlotElement
   * Returns the DOM element for a hotbar slot by index
   */

  let elements = document.querySelectorAll(".hotbar-item");

  if (slotIndex >= 0 && slotIndex < elements.length) {
    return elements[slotIndex];
  }

  return null;

}

HotbarManager.prototype.__getKeySpan = function (slotIndex) {

  /*
   * Function HotbarManager.__getKeySpan
   * Returns the .hotbar-key span element for a slot
   */

  let element = this.__getSlotElement(slotIndex);

  if (element) {
    return element.querySelector(".hotbar-key");
  }

  return null;

}

/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/interface.js ===== */

const Interface = function () {
  /*
   * Class Interface
   * Wrapper for the entire game interface
   *
   * API:
   *
   * @setCancelMessage(message) - Sets a cancel message on the client that is automatically cleared
   * @getColor(int) - Returns the color that is mapped to a specific identifier
   * @getAccountDetails() - Returns the filled in account details (aCCount number, password)
   * @updateStatusBar() - Call to update the status bar with the available conditions
   *
   */

  // Interface settings
  this.settings = new Settings();

  // Manager for chat channels
  this.channelManager = new ChannelManager();

  // Manager for hotbar
  this.hotbarManager = new HotbarManager();

  // Manager for fight mode selector (Full Attack, Balanced, Full Defense)
  this.fightModeSelector = new FightModeSelector();

  // Manager for notifications
  this.notificationManager = new NotificationManager();

  // The manager for modals (popup windows in the center of the screen)
  this.modalManager = new ModalManager();

  this.statusBar = new StatusBar();

  // The manager for windows (windows in the sidebars, particularly containers)
  this.windowManager = new WindowManager();

  // Manager for sound
  this.soundManager = new SoundManager(this.settings.isSoundEnabled());

  // Restore persisted volume sliders into the freshly created SoundManager
  // (Settings is constructed before it, so __applyState couldn't).
  this.settings.applySavedVolumes(this.soundManager);

  // Store the anti-connection-loss preference without starting the oscillator yet.
  // The oscillator is deferred until a user gesture (game connection) to satisfy browser autoplay policy.
  if (this.settings.isAntiConnectionLossEnabled()) {
    this.soundManager.__antiConnectionLoss = true;
  }

  // Manager for popup menus
  this.menuManager = new MenuManager();

  // NPC conversation dialog (floating keyword popup)
  this.npcDialog = new NpcDialog();

  // Manager for the text window
  this.screenElementManager = new ScreenElementManager();

  // Tooltip manager
  this.tooltip = new Tooltip();

  // Quest Tracker Overlay
  this.questTracker = new QuestTracker();

  // Tutorial UI highlight system
  this.tutorialHighlight = new TutorialHighlight();

  // Enable all the listeners in the DOM
  this.__enableListeners();

  // Create the state variable for the interface and callbacks when the properties are changed
  this.state = new State();
  this.state.add("spritesLoaded", this.enableEnterGame.bind(this));
  this.state.add("dataLoaded", this.enableEnterGame.bind(this));

  let chatInputEl = document.getElementById("chat-input");
  chatInputEl.contentEditable = "false";
  chatInputEl.classList.add("chat-disabled");

  this.addAvailableResolutions();

  document
    .getElementById("keyring")
    .addEventListener("click", this.__openKeyRing.bind(this));

  // Cache for mobile scale to avoid layout thrashing
  this.__cachedMobileScale = null;
};

