/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/menus/menu-container.js ===== */

const ContainerMenu = function (id) {

    /*
     * Class ContainerMenu
     * Wrapper for the menu that displays on container slots
     */

    // Inherits from menu
    Menu.call(this, id);

    // Store reference to the slot object
    this.slotObject = null;

}

ContainerMenu.prototype = Object.create(Menu.prototype);
ContainerMenu.prototype.constructor = ContainerMenu;

ContainerMenu.prototype.open = function (event, slotObject) {

    /*
     * Function ContainerMenu.open
     * Opens the container menu with the slot object reference
     */

    this.slotObject = slotObject;

    // Call parent open
    return Menu.prototype.open.call(this, event);

}

ContainerMenu.prototype.click = function (event) {

    /*
     * Function ContainerMenu.click
     * Callback fired specially for the ContainerMenu after a button is clicked
     */

    if (this.slotObject === null) {
        return true;
    }

    // The "open-here" button is always the *override* — it flips whatever
    // the current right-click default is. With setting OFF (default right-
    // click = new window), it opens in same window. With setting ON
    // (default right-click = same window), it opens in new window and the
    // button label is "Open in new window" instead of "Open Here".
    let settings = gameClient.interface && gameClient.interface.settings;
    let sameWindow = settings && settings.__state && settings.__state["open-containers-same-window"];

    // Take action depending on the button
    switch (this.__getAction(event)) {
        case "set-name": {
            let so = this.slotObject;
            let parentCid = so.which ? so.which.__containerId : null;
            if (parentCid === null || parentCid === undefined) break;
            let modal = gameClient.interface.modalManager.get("enter-name-modal");
            if (!modal) break;
            modal.setConfirmCallback(function (name) {
                name = String(name || "").trim();
                if (name.length === 0) return;
                let cm = gameClient.interface && gameClient.interface.channelManager;
                if (!cm) return;
                cm.sendMessageText("/namebag " + parentCid + " " + so.index + " " + name, undefined, true);
                // refresh the slot chips once the server has applied it
                gameClient.networkManager.__requestBagNames();   // debounced + history-exempt
            });
            gameClient.interface.modalManager.open("enter-name-modal");
            break;
        }
        case "clear-name": {
            let so2 = this.slotObject;
            let parentCid2 = so2.which ? so2.which.__containerId : null;
            if (parentCid2 === null || parentCid2 === undefined) break;
            let cm2 = gameClient.interface && gameClient.interface.channelManager;
            if (cm2) {
                cm2.sendMessageText("/namebag " + parentCid2 + " " + so2.index + " clear", undefined, true);
                gameClient.networkManager.__requestBagNames();   // debounced + history-exempt
            }
            break;
        }
        case "look":
            gameClient.mouse.look(this.slotObject);
            break;
        case "use":
            // When the setting is ON, "Open" should match the new default
            // (same window for nested containers), not silently diverge
            // from what a direct right-click does.
            {
                let useItem = this.slotObject.which && this.slotObject.which.peekItem
                  ? this.slotObject.which.peekItem(this.slotObject.index)
                  : null;
                let isContainerItem = useItem !== null && useItem.isContainer && useItem.isContainer();
                if (sameWindow && isContainerItem && this.slotObject.which.constructor.name === "Container") {
                    gameClient.__ctrlContainerOpen = this.slotObject.which.__containerId;
                    clearTimeout(gameClient.__ctrlContainerOpenTimeout);
                    gameClient.__ctrlContainerOpenTimeout = setTimeout(function() {
                      gameClient.__ctrlContainerOpen = null;
                    }, 2000);
                } else if (isContainerItem && this.slotObject.which.constructor.name === "Container") {
                    gameClient.__newWindowParentOpen = this.slotObject.which.__containerId;
                    clearTimeout(gameClient.__newWindowParentOpenTimeout);
                    gameClient.__newWindowParentOpenTimeout = setTimeout(function() {
                      gameClient.__newWindowParentOpen = null;
                    }, 2000);
                }
                // Auto-retry on toggle-close — same as the open-here case
                // and the direct right-click in mouse.js. If the bag is
                // already open elsewhere, server's first toggle closes it
                // and the user has to click again. Latency-tolerant window;
                // cleared on a successful open (handleContainerOpen) so it's
                // safe to hold this long.
                if (isContainerItem) {
                    gameClient.__forceOpenAfterClose = this.slotObject;
                    clearTimeout(gameClient.__forceOpenAfterCloseTimeout);
                    gameClient.__forceOpenAfterCloseTimeout = setTimeout(function() {
                      gameClient.__forceOpenAfterClose = null;
                    }, 1500);
                }
            }
            gameClient.mouse.use(this.slotObject);
            break;
        case "open-window":
            // Mobile long-press: route the resulting CONTAINER_OPEN into the
            // floating centered panel (consumed in getContainerPanelFor).
            gameClient.__nextOpenInFloatPanel = true;
            clearTimeout(gameClient.__nextOpenInFloatPanelTimeout);
            gameClient.__nextOpenInFloatPanelTimeout = setTimeout(function () {
                gameClient.__nextOpenInFloatPanel = false;
            }, 2500);
            // Bag ALREADY open: the server's first use TOGGLES it closed, so we
            // must re-send on the close to actually pop it out. This uses its
            // OWN flag with a mobile-latency-tolerant window instead of the
            // shared __forceOpenAfterClose (300ms) — that expired before the
            // close round-trip completed on phones, so the bag just closed and
            // never reopened (player report 2026-07-07). handleContainerClose
            // re-asserts the float routing flag before re-sending.
            gameClient.__floatReopenAfterClose = this.slotObject;
            clearTimeout(gameClient.__floatReopenAfterCloseTimeout);
            gameClient.__floatReopenAfterCloseTimeout = setTimeout(function () {
                gameClient.__floatReopenAfterClose = null;
            }, 2500);
            gameClient.mouse.use(this.slotObject);
            break;
        case "open-here":
            if (!sameWindow) {
                // Setting OFF: this button is "Open Here" → open in same window.
                gameClient.__ctrlContainerOpen = this.slotObject.which.__containerId;
                clearTimeout(gameClient.__ctrlContainerOpenTimeout);
                gameClient.__ctrlContainerOpenTimeout = setTimeout(function() {
                  gameClient.__ctrlContainerOpen = null;
                }, 2000);
            } else {
                // Setting ON: "Open in new window" — record the parent so the
                // new window still carries a back button.
                if (this.slotObject.which && this.slotObject.which.constructor.name === "Container") {
                  gameClient.__newWindowParentOpen = this.slotObject.which.__containerId;
                  clearTimeout(gameClient.__newWindowParentOpenTimeout);
                  gameClient.__newWindowParentOpenTimeout = setTimeout(function() {
                    gameClient.__newWindowParentOpen = null;
                  }, 2000);
                }
                // Setting ON: this button is "Open in new window". Server's
                // toggleContainer CLOSES a bag that is already open (authentic
                // Tibia toggle). If the bag the user targets happens to be
                // open elsewhere, the first click closes it and the user has
                // to click again to actually open. Arm an auto-retry: if a
                // close packet arrives within 300ms of this use, re-send.
                gameClient.__forceOpenAfterClose = this.slotObject;
                clearTimeout(gameClient.__forceOpenAfterCloseTimeout);
                gameClient.__forceOpenAfterCloseTimeout = setTimeout(function() {
                  gameClient.__forceOpenAfterClose = null;
                }, 1500);   // latency-tolerant; cleared on a successful open (handleContainerOpen)
            }
            gameClient.mouse.use(this.slotObject);
            break;
        case "cook":
            gameClient.mouse.__setMultiUseItem(this.slotObject);
            break;
        case "trade":
            gameClient.mouse.startTradeTargetSelect(this.slotObject);
            break;
        case "lootlist-add": {
            // One-tap "/lootlist add <sid>" — server validates premium,
            // catalog membership, dedup and the 500 cap, and answers with
            // a colored confirmation. noHistory like the /namebag sends.
            let addItem = this.slotObject.which && this.slotObject.which.peekItem
              ? this.slotObject.which.peekItem(this.slotObject.index)
              : null;
            if (addItem && addItem.sid) {
                let cml = gameClient.interface && gameClient.interface.channelManager;
                if (cml) cml.sendMessageText("/lootlist add " + addItem.sid, undefined, true);
            }
            break;
        }
    }

    // Reset slot object reference
    this.slotObject = null;

    // Return true to close the menu after clicking
    return true;

}


