const FriendListMenu = function(id) {

  /*
   * Class FriendListMenu
   * Wrapper for the menu that displays on the main game screen
   */

  // Inherits from menu
  Menu.call(this, id);

}

FriendListMenu.prototype = Object.create(Menu.prototype);
FriendListMenu.prototype.constructor = FriendListMenu;

FriendListMenu.prototype.__getFriendEntry = function() {

  /*
   * Function FriendListMenu.__getFriendEntry
   * Returns the friend entry element from the context menu event
   */

  return this.downEvent.friendEntry || this.downEvent.target.closest(".friend-entry") || this.downEvent.target;

}

FriendListMenu.prototype.removeFriend = function() {

  /*
   * Function FriendListMenu.removeFriend
   * Removes a friend from the friend list
   */

  let entry = this.__getFriendEntry();
  let friend = entry.getAttribute("friend");

  gameClient.send(new FriendRemovePacket(friend));

  return true;

}

FriendListMenu.prototype.setIcon = function(icon) {

  /*
   * Function FriendListMenu.setIcon
   * Sets an emoji icon marker on a friend entry (saved server-side)
   */

  let entry = this.__getFriendEntry();
  let friend = entry.getAttribute("friend");

  // Update local state and send to server
  gameClient.player.friendlist.setIcon(friend, icon);
  gameClient.send(new FriendIconPacket(friend, icon || ""));

  return true;

}

FriendListMenu.prototype.copyName = function() {

  /*
   * Function FriendListMenu.copyName
   * Copies the friend's name to the clipboard. Sets the IN-GAME clipboard
   * (works everywhere, incl. iOS / http, no prompt — same store the VK paste
   * reads) AND best-effort the system clipboard.
   */

  let entry = this.__getFriendEntry();
  let friend = entry.getAttribute("friend");
  if (!friend) return true;

  try { gameClient.__clipboardText = friend; } catch (e) {}
  try { if (navigator.clipboard && navigator.clipboard.writeText) navigator.clipboard.writeText(friend); } catch (e) {}
  try { gameClient.interface.setCancelMessage('Copied "' + friend + '" to clipboard.'); } catch (e) {}

  return true;

}

FriendListMenu.prototype.findPlayer = function() {

  /*
   * Function FriendListMenu.findPlayer
   * Casts Exiva on the friend by "saying" it on the local channel (id 0) — the
   * server parses the spell + target name exactly as if the player typed it.
   */

  let entry = this.__getFriendEntry();
  let friend = entry.getAttribute("friend");
  if (!friend) return true;

  try { gameClient.send(new ChannelMessagePacket(0, 1, 'exiva "' + friend + '"')); } catch (e) {}

  return true;

}

FriendListMenu.prototype.click = function(event) {

  /*
   * Function FriendListMenu.click
   * Callback fired specially for the FriendListMenu after a button is clicked
   */

  switch(event.target.getAttribute("action")) {
    case "find-player":
      return this.findPlayer();
    case "copy-name":
      return this.copyName();
    case "remove":
      return this.removeFriend();
    // "Emoji >" submenu toggle (touch / click): expand the chooser inline and
    // keep the context menu OPEN (return falsy so buttonClose doesn't close it).
    // Desktop also expands on CSS :hover, so this is mainly for touch.
    case "emoji-menu": {
      let parent = event.target.closest(".friend-emoji-parent");
      if (parent) parent.classList.toggle("open");
      return false;
    }
    // Emoji chooser \u2014 data-driven: each emoji button carries its glyph in
    // data-icon (empty = clear). Add/remove emojis in the markup only, no code.
    case "set-icon":
      return this.setIcon(event.target.getAttribute("data-icon") || null);
  }

}

FriendListMenu.prototype.open = function(event) {

  /*
   * Function FriendListMenu.open
   * Opens the menu with the "Emoji" submenu collapsed (clear any .open left from
   * a previous touch-expand), then defers to the base Menu.open.
   */

  let parent = this.element.querySelector(".friend-emoji-parent");
  if (parent) parent.classList.remove("open");

  return Menu.prototype.open.call(this, event);

}


