HotbarMenu.prototype.open = function (event) {

  /*
   * Function HotbarMenu.open
   * Bank-2 (Shift+F) slots share their key with the matching bank-1 slot —
   * Shift+<bank-1 key> always fires bank 2, so they have no independent keybind
   * to edit. Hide "Change Key" for them (the rebind is also refused in
   * HotbarManager.__enterRebindMode for the Ctrl+Click path).
   */

  let slot = event.target.closest && event.target.closest(".hotbar-item");
  let changeKeyBtn = this.element.querySelector("button[action=changekey]");
  if (changeKeyBtn) {
    changeKeyBtn.style.display = (slot && slot.classList.contains("hotbar-bank2")) ? "none" : "";
  }

  return Menu.prototype.open.call(this, event);

}

HotbarMenu.prototype.click = function (event) {

  /*
   * Function HotbarMenu.click
   * Callback fired specially for the ScreenMenu after a button is clicked
   */

  // Normalize target to the .hotbar-item element (click may land on a child canvas/span)
  let slot = this.downEvent.target.closest(".hotbar-item");
  if(!slot) return true;
  let index = Array.from(slot.parentNode.querySelectorAll(".hotbar-item")).indexOf(slot);

  // Take action depending on the button
  switch (event.target.getAttribute("action")) {
    case "add":
      gameClient.interface.modalManager.open("hotbar-add-modal", index);
      break;
    case "remove":
      gameClient.interface.hotbarManager.clearSlot(index);
      break;
    case "changekey":
      gameClient.interface.hotbarManager.__enterRebindMode(index);
      break;
  }

  return true;

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/menus/menu-manager.js ===== */

const MenuManager = function () {

  /*
   * Class MenuManager
   * Container for the context menu that is opened by a right click
   *
   * Public API:
   *
   * MenuManager.getMenu(name) - Returns the menu with a particular name or null
   * MenuManager.open(name, event) - Opens the registered menu by the identifier. Requires to be passed the open event to delegate
   * MenuManager.isOpened() - Returns true if the a menu is opened
   * MenuManager.close() - Closes any opened menu
   *
   */

  // Register the configured menus and classes
  this.menus = new Object({
    "screen-menu": new ScreenMenu("screen-menu"),
    "chat-header-menu": new ChatHeaderMenu("chat-header-menu"),
    "chat-entry-menu": new MessageMenu("chat-entry-menu"),
    "chat-body-menu": new ChatBodyMenu("chat-body-menu"),
    "friend-list-menu": new FriendListMenu("friend-list-menu"),
    "friend-window-menu": new FriendWindowMenu("friend-window-menu"),
    "hotbar-menu": new HotbarMenu("hotbar-menu"),
    "container-menu": new ContainerMenu("container-menu"),
  });

  // Reference the currently active open menu
  this.__activeMenu = null;

}

MenuManager.prototype.getMenu = function (name) {

  /*
   * Function MenuManager.getMenu
   * Returns the menu if it exists otherwise return NULL
   */

  if (!this.menus.hasOwnProperty(name)) {
    return null;
  }

  return this.menus[name];

}

MenuManager.prototype.open = function (name, event) {

  /*
   * Function MenuManager.open
   * Opens a context menu by an identifier. The click event must be passed too!
   */

  let menuElement = this.getMenu(name);

  // Has a menu with this name been registered
  if (menuElement === null) {
    return console.error("Cannot open menu %s because the menu has not been registered.".format(name));
  }

  // If another menu is already opened, close it first
  if (this.isOpened()) {
    this.close();
  }

  // Set the currently active menu
  this.__activeMenu = menuElement.open(event);

  return this.__activeMenu;
}

MenuManager.prototype.isOpened = function () {

  /*
   * Function MenuManager.isOpened
   * Returns true if a context window is already opened
   */

  return this.__activeMenu !== null;

}

MenuManager.prototype.close = function (event) {

  /*
   * Function MenuManager.close
   * Returns true if a context window is already opened
   */

  // No menu is opened: do nothing
  if (!this.isOpened()) {
    return;
  }

  // Close the active menu
  this.__activeMenu.close();

  // Drop reference
  this.__activeMenu = null;

  // Remove focus from any focused element
  this.__defocus();

}

MenuManager.prototype.__defocus = function () {

  /*
   * Function MenuManager.defocus
   * Removes focus from the opened menu and returns it to the main body
   */

  if (document.activeElement) {
    document.activeElement.blur();
  }

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/menus/menu-message.js ===== */

const MessageMenu = function(id) {

  /*
   * Class MessageMenu
   * Opens menu to open a chat channel with another character
   */

  // Inherits from menu
  Menu.call(this, id);

}

MessageMenu.prototype = Object.create(Menu.prototype);
MessageMenu.prototype.constructor = MessageMenu;

MessageMenu.prototype.open = function(event) {

  /*
   * Function MessageMenu.open
   * Overrides Menu.open so we can adapt buttons to the right-clicked entry:
   *   - Speaker-dependent buttons (Message / Whisper / Add Friend / Copy
   *     Name) hide when the chat line has no `name` attribute (system /
   *     console / broadcast messages — no speaker).
   *   - "Add to Friends" additionally hides for self or already-friended.
   */

  let name = event.target && event.target.getAttribute ? event.target.getAttribute("name") : null;
  let hasSpeaker = !!name;

  // Speaker-dependent buttons: drop them entirely when no speaker
  let menuRoot = document.getElementById("chat-entry-menu");
  if (menuRoot) {
    let speakerActions = ["message", "whisper", "copy-name"];
    speakerActions.forEach(function (action) {
      let btn = menuRoot.querySelector("button[action=\"" + action + "\"]");
      if (btn) btn.style.display = hasSpeaker ? "" : "none";
    });
  }

  // Add to Friends: also hide for self / already-friended
  let btn = document.getElementById("chat-entry-add-friend");
  if (btn) {
    let canAdd = false;
    if (hasSpeaker && gameClient.player) {
      let selfName = gameClient.player.name;
      let alreadyFriend = gameClient.player.friendlist && gameClient.player.friendlist.has(name);
      canAdd = (name !== selfName) && !alreadyFriend;
    }
    btn.style.display = canAdd ? "" : "none";
  }

  // Ignore / Unignore: hide for no-speaker or self. The label reflects a
  // session-local ignore set (the server doesn't push the list), so a mistaken
  // ignore can be undone right from an older, pre-ignore message still in the
  // log. /ignore toggles, so clicking sends the same command either way.
  let ignoreBtn = document.getElementById("chat-entry-ignore");
  if (ignoreBtn) {
    let canIgnore = hasSpeaker && gameClient.player && name !== gameClient.player.name;
    ignoreBtn.style.display = canIgnore ? "" : "none";
    if (canIgnore) {
      if (!gameClient.__ignoredNames) gameClient.__ignoredNames = new Set();
      ignoreBtn.textContent = gameClient.__ignoredNames.has(name.toLowerCase()) ? "Unignore" : "Ignore";
    }
  }

  return Menu.prototype.open.call(this, event);

}

MessageMenu.prototype.click = function(event) {

  /*
   * Function ScreenMenu.click
   * Callback fired specially for the ScreenMenu after a button is clicked
   */

  // Take action depending on the button
  switch(event.target.getAttribute("action")) {
    case "message":
      return this.message(this.downEvent.target);
    case "whisper":
      return this.whisper(this.downEvent.target);
    case "add-friend":
      return this.addFriend(this.downEvent.target);
    case "ignore":
      return this.toggleIgnore(this.downEvent.target);
    case "copy-name":
      return this.copyName(this.downEvent.target);
    case "copy-message":
      return this.copyMessage(this.downEvent.target);
  }

}

MessageMenu.prototype.addFriend = function(target) {

  /*
   * Function MessageMenu.addFriend
   * Sends a FriendAddPacket for the right-clicked player's name.
   */

  let name = target.getAttribute("name");
  if (name === null) return;
  gameClient.send(new FriendAddPacket(name));
  return true;

}

MessageMenu.prototype.toggleIgnore = function(target) {

  /*
   * Function MessageMenu.toggleIgnore
   * Ignore / unignore the right-clicked player. /ignore is a chat command that
   * TOGGLES server-side (player.storage.__ignoredPlayers), routed via the
   * default channel (CONST.CHANNEL.DEFAULT) — same pattern as the /report menu.
   * We mirror the toggle in a session-local set so the menu label tracks state
   * and a mistaken ignore can be undone from an older message still in the log.
   */

  let name = target.getAttribute("name");
  if (name === null) return;
  gameClient.send(new ChannelMessagePacket(CONST.CHANNEL.DEFAULT, 1, "/ignore " + name));
  if (!gameClient.__ignoredNames) gameClient.__ignoredNames = new Set();
  let key = name.toLowerCase();
  if (gameClient.__ignoredNames.has(key)) {
    gameClient.__ignoredNames.delete(key);
  } else {
    gameClient.__ignoredNames.add(key);
  }
  return true;

}

MessageMenu.prototype.message = function(target) {

  /*
   * Function MessageMenu.message
   * Opens a private message channel with the player whose message was right-clicked
   */

  let name = target.getAttribute("name");

  if(name === null) {
    return;
  }

  gameClient.interface.channelManager.addPrivateChannel(name);
  return true;

}

MessageMenu.prototype.copyName = function(target) {

  /*
   * Function MessageMenu.copyName
   * Copies the player name to the clipboard
   */

  let name = target.getAttribute("name");

  if(name === null) {
    return;
  }

  this.__copyToClipboard(name);
  return true;

}

MessageMenu.prototype.copyMessage = function(target) {

  /*
   * Function MessageMenu.copyMessage
   * Copies just the message BODY — NOT the "<time> <name> says:" prefix and
   * none of format()'s line-wrap artifacts. Re-pasting into chat (almost always
   * the Trade channel) then doesn't waste the short character limit and truncate
   * the message. The raw body is stamped on the .chat-message span as
   * data-message (createNode); the server HTML-escapes chat text, so we decode
   * it via a <textarea> — safe (RCDATA, no script execution) and a no-op for
   * plain text. Falls back to textContent for any span without the attribute.
   */

  let el = (target && target.closest) ? (target.closest(".chat-message") || target) : target;
  if (!el) {
    return;
  }

  let raw = el.getAttribute ? el.getAttribute("data-message") : null;
  let text;
  if (raw !== null && raw !== "") {
    let decoder = document.createElement("textarea");
    decoder.innerHTML = raw;
    text = decoder.value;
  } else {
    text = el.textContent;
  }

  if(!text) {
    return;
  }

  this.__copyToClipboard(text);
  return true;

}

MessageMenu.prototype.__copyToClipboard = function(text) {

  /*
   * Function MessageMenu.__copyToClipboard
   * Writes text to the clipboard. navigator.clipboard is undefined
   * outside a secure context (plain http:// origins, some webviews) —
   * the cause of the intermittent "Cannot read properties of undefined
   * (reading 'writeText')" crash. Falls back to a hidden textarea +
   * execCommand("copy"), which needs no secure context.
   */

  if(!text) {
    return;
  }

  // In-game clipboard — a plain in-memory copy that always works, even on http
  // or iOS where the browser Clipboard API is unavailable / blocks reads. This
  // is what the mobile paste button reads (MobileChat.__pasteFromClipboard).
  if(typeof gameClient !== "undefined" && gameClient) {
    gameClient.__clipboardText = text;
  }

  let self = this;

  // Preferred path - async Clipboard API (secure contexts only)
  if(navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text).catch(function() {
      // Even in a secure context the write can be rejected (document
      // not focused, denied permission) - fall back to the legacy path.
      self.__legacyCopy(text);
    });
    return;
  }

  // Fallback - works on insecure origins and older browsers
  this.__legacyCopy(text);

}

MessageMenu.prototype.__legacyCopy = function(text) {

  /*
   * Function MessageMenu.__legacyCopy
   * Clipboard copy via a temporary off-screen textarea and
   * execCommand("copy"). Used when the async Clipboard API is
   * unavailable or rejects. Runs synchronously inside the click
   * handler so the required user activation is still in effect.
   */

  try {
    let textarea = document.createElement("textarea");
    textarea.value = text;
    textarea.setAttribute("readonly", "");
    textarea.style.position = "fixed";
    textarea.style.top = "-9999px";
    textarea.style.left = "-9999px";
    document.body.appendChild(textarea);
    textarea.focus();
    textarea.select();
    textarea.setSelectionRange(0, text.length);
    document.execCommand("copy");
    document.body.removeChild(textarea);
  } catch(e) {
    // Clipboard genuinely unavailable - nothing more we can do
  }

}

MessageMenu.prototype.whisper = function(target) {

  /*
   * Function ScreenMenu.click
   * Callback fired specially for the ScreenMenu after a button is clicked
   */

  let name = target.getAttribute("name");

  if(name === null) {
    return;
  }

  gameClient.interface.channelManager.addPrivateChannel(name);
  return true;

}

/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/menus/menu-screen.js ===== */

const ScreenMenu = function(id) {

  /*
   * Class ScreenMenu
   * Wrapper for the menu that displays on the main game screen
   */

  // Inherits from menu
  Menu.call(this, id);

}

ScreenMenu.prototype = Object.create(Menu.prototype);
ScreenMenu.prototype.constructor = ScreenMenu;

ScreenMenu.prototype.click = function(event) {

  /*
   * Function ScreenMenu.click
   * Callback fired specially for the ScreenMenu after a button is clicked
   */

  // Use the stored tile reference (set when the menu was opened) for reliability
  let object = this.__tile || Mouse.prototype.getWorldObject(this.downEvent);

  // Take action depending on the button
  switch(this.__getAction(event)) {
    case "look":
      gameClient.mouse.look(object);
      break;
    case "use": {
      // The "Use" button is relabeled "Rotate" for rotatable items (see the
      // menu-populate in mouse.js). A rotatable CONTAINER (dresser/trunk) would
      // OPEN on a plain use before the server reaches its rotate branch, so send
      // a dedicated rotate request for rotatable items instead.
      let useTop = (object && object.which && object.which.peekItem)
        ? object.which.peekItem(0xFF) : null;
      if (useTop !== null && useTop.isRotateable && useTop.isRotateable()) {
        gameClient.mouse.rotate(object);
      } else {
        gameClient.mouse.use(object);
      }
      break;
    }
    case "open": {
      // Explicit container open (player report 2026-07-08): bypasses the
      // rotate branch above — the whole reason trunks had no way to open.
      gameClient.mouse.use(object);
      break;
    }
    case "open-window": {
      // Open in its own window even when the container is open/nested
      // elsewhere: arm the toggle-retry (a use on an already-open container
      // first CLOSES it server-side; the retry re-uses so it lands open) —
      // the same machinery the in-container menu uses.
      gameClient.__forceOpenAfterClose = object;
      clearTimeout(gameClient.__forceOpenAfterCloseTimeout);
      gameClient.__forceOpenAfterCloseTimeout = setTimeout(function () {
        gameClient.__forceOpenAfterClose = null;
      }, 1500);
      gameClient.mouse.use(object);
      break;
    }
    case "attack":
      if (this.__targetCreature) {
        if (gameClient.player.isCreatureTarget(this.__targetCreature)) {
          gameClient.player.setTarget(null);
          gameClient.send(new TargetPacket(0));
        } else {
          gameClient.player.setTarget(this.__targetCreature);
          gameClient.send(new TargetPacket(this.__targetCreature.id));
        }
      }
      break;
    case "follow":
      if (this.__targetCreature) {
        if (gameClient.player.isCreatureFollowTarget(this.__targetCreature)) {
          gameClient.player.setFollowTarget(null);
          gameClient.send(new FollowPacket(0));
        } else {
          gameClient.player.setFollowTarget(this.__targetCreature);
          gameClient.send(new FollowPacket(this.__targetCreature.id));
        }
      }
      break;
    case "party-invite":
      // Sub-action 0 = invite
      if (this.__targetCreatureId) {
        gameClient.send(new PartyActionPacket(0, this.__targetCreatureId));
      }
      break;
    case "party-join":
      // Sub-action 1 = join (targetId is the leader who invited us)
      if (this.__targetCreatureId) {
        gameClient.send(new PartyActionPacket(1, this.__targetCreatureId));
        gameClient.player.__pendingPartyInvite = null;
      }
      break;
    case "party-leave":
      // Sub-action 2 = leave (targetId unused, send 0)
      gameClient.send(new PartyActionPacket(2, 0));
      gameClient.player.__sharedExperienceEnabled = false;
      break;
    case "party-kick":
      // Sub-action 3 = kick
      if (this.__targetCreatureId) {
        gameClient.send(new PartyActionPacket(3, this.__targetCreatureId));
      }
      break;
    case "party-shared-xp":
      // Sub-action 4 = toggle shared XP (targetId unused, send 0).
      // Don't flip __sharedExperienceEnabled locally — the server can
      // reject (not leader, <2 members, level spread too wide) and
      // we'd desync. The server broadcasts "Shared experience has been
      // enabled/disabled." on success, parsed in handleServerMessage.
      gameClient.send(new PartyActionPacket(4, 0));
      break;
    case "cook":
      gameClient.mouse.__setMultiUseItem(object);
      break;
    case "repackage":
      // Turn a placed shop-furniture piece back into its kit. Server
      // validates house ownership + that the item is repackageable.
      gameClient.send(new ItemRepackagePacket(object));
      break;
    case "trade":
      // Start trade target selection with the top item on the tile
      if (object && object.which && object.which.items && object.which.items.length > 0) {
        gameClient.mouse.startTradeTargetSelect(object);
      }
      break;
    case "message":
      // Open a private chat channel with the target player
      if (this.__targetPlayerName) {
        gameClient.interface.channelManager.addPrivateChannel(this.__targetPlayerName);
        // On mobile, also open the chat bar to that private channel
        if (gameClient.touch && gameClient.touch.__mobileChat) {
          gameClient.touch.__mobileChat.openPrivateChat(this.__targetPlayerName);
        }
      }
      break;
    case "report":
      // Report for unofficial software — small confirm dialog first (owner
      // request), then the /report chat command: ALL validation, the live
      // evidence snapshot and the rate limits stay server-side in
      // command-handler.js. Name interpolation into innerHTML is safe: the
      // creation validator restricts names to letters + single spaces.
      if (this.__targetPlayerName) {
        let reportName = this.__targetPlayerName;
        let modal = gameClient.interface.modalManager.open("confirm-modal", function () {
          gameClient.send(new ChannelMessagePacket(CONST.CHANNEL.DEFAULT, 1, "/report " + reportName));
        });
        if (modal) {
          modal.setTitle("Report Player");
          modal.element.querySelector(".modal-body > div").innerHTML =
            "You are about to report <b>" + reportName + "</b> for using unofficial software.<br>Continue?";
        }
      }
      break;
    case "change-outfit":
      // Open the outfit modal — shown only when the right-clicked/tapped
      // tile contains the player themselves (gate lives in mouse.js /
      // touch.js menu-populate paths).
      gameClient.interface.modalManager.open("outfit-modal");
      break;
  }

  // Return true to close the menu after clicking
  return true;

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/menus/menu.js ===== */

const Menu = function (id) {

  /*
   * Class Menu
   * Blueprint for an openeable menu. To add another menu a bit of HTML needs to be added and a class
   * that implements this class needs to be created.
   *
   */

  // Set the state and reference the element
  this.element = document.getElementById(id);

  // State to keep the down event
  this.downEvent = null;

  // Attach event listeners to the action buttons
  this.__addEventListeners();

}

// Empty function callback
Menu.prototype.click = Function.prototype;

Menu.prototype.__addEventListeners = function () {

  /*
   * Function ContextMenu.__addEventListeners
   * Opens the context menu at the event position
   */

  // Get all the buttons in the menu
  let buttons = Array.from(this.element.getElementsByTagName("button"));

  // Reference click event: the "click" function needs to be implemented in the inheriting class
  buttons.forEach(function (button) {

    // Debug listener for mousedown
    button.addEventListener("mousedown", function (e) {
      e.stopPropagation(); // Try preventing body mousedown from interfering
    });

    button.addEventListener("click", this.buttonClose.bind(this));
  }, this);

}

Menu.prototype.__getAction = function (event) {

  /*
   * Function Menu.__getAction
   * Returns the action configured in the DOM that belongs to an event
   */

  return event.target.getAttribute("action");

}

Menu.prototype.open = function (event) {

  /*
   * Function Menu.open
   * Opens the context menu at the event position
   */

  // Show the element
  this.element.style.display = "block";

  // Briefly disable pointer events to prevent ghost clicks from touch events
  // On mobile, synthesized click events arrive ~300ms after touchend and can
  // accidentally hit menu buttons that open at the original touch position
  this.element.style.pointerEvents = "none";
  let element = this.element;
  setTimeout(function () {
    element.style.pointerEvents = "";
  }, 100);

  // Update the position of the element based on the clicked position
  this.updateElementPosition(event);

  // Save the event
  this.downEvent = event;

  return this;

}

Menu.prototype.updateElementPosition = function (event) {

  /*
   * Function Menu.updateElementPosition
   * Updates the CSS to place the element at the clicked position
   */

  // Use viewport dimensions for proper positioning
  let viewportWidth = window.innerWidth;
  let viewportHeight = window.innerHeight;
  let menuWidth = this.element.offsetWidth;
  let menuHeight = this.element.offsetHeight;

  // Calculate left position (stay within viewport)
  let left = Math.min(viewportWidth - menuWidth, Math.floor(event.clientX));
  left = Math.max(0, left);

  // Calculate top position - if menu would go below viewport, show it ABOVE the click point
  let top = Math.floor(event.clientY);
  if (top + menuHeight > viewportHeight) {
    top = top - menuHeight; // Position above the click point
  }
  top = Math.max(0, top);

  this.element.style.left = left + "px";
  this.element.style.top = top + "px";

}

Menu.prototype.close = function () {

  /*
   * Function Menu.close
   * Closes the menu by hiding the element
   */

  this.element.style.display = "none";

  if (document.activeElement) {
    document.activeElement.blur();
  }

}

Menu.prototype.buttonClose = function (event) {

  /*
   * Function Menu.buttonClose
   * Hides the context menu via the MenuManager so __activeMenu is properly cleared
   */

  // Fire any callbacks
  if (this.click(event)) {
    // Close through the MenuManager so isOpened() returns false afterwards
    if (gameClient && gameClient.interface && gameClient.interface.menuManager) {
      gameClient.interface.menuManager.close();
    } else {
      this.close();
    }
  }

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/minimap-markers.js ===== */

/*
 * MinimapMarkers — client-local, player-placed minimap markers.
 *
 * MVP: markers are stored in localStorage (per browser, not synced to the
 * server — a later upgrade could add server sync). Each marker is one per tile,
 * keyed "x.y.z", with an icon index + a text label. Markers are PLACED/edited
 * from the big map modal (modal-map.js) and RENDERED on both the big map and
 * the small minimap (minimap.js). Icons are simple canvas-drawn glyphs (no
 * sprites): a coloured disc + a glyph, readable at small sizes.
 *
 * Global singleton (classic <script> include, no module system).
 */
const MinimapMarkers = (function () {

  const STORE_KEY = "minimap-markers";

  // Simple canvas icons: { name, glyph, color }. Glyphs are widely-rendering
  // characters so we need no sprite sheet. Add/reorder freely — markers store
  // the index, so keep existing indices stable.
  const ICONS = [
    { name: "Danger",   glyph: "X", color: "#ff4d4d" },
    { name: "Favourite",glyph: "★", color: "#ffd54a" },  // star
    { name: "Objective",glyph: "⚑", color: "#5fd35f" },  // flag
    { name: "Gold",     glyph: "$", color: "#ffd700" },
    { name: "Caution",  glyph: "!", color: "#ff9800" },
    { name: "Quest",    glyph: "?", color: "#4fc3f7" },
    { name: "Special",  glyph: "♦︎", color: "#e06ce0" },  // diamond (+U+FE0E: emoji-capable codepoint — emoji render ignores the pink tint)
    { name: "Point",    glyph: "●", color: "#5b9dff" }   // dot
  ];

  let __markers = null;   // lazy-loaded array

  function load() {
    if (__markers !== null) return __markers;
    __markers = [];
    try {
      let raw = localStorage.getItem(STORE_KEY);
      if (raw) {
        let parsed = JSON.parse(raw);
        if (Array.isArray(parsed)) __markers = parsed.filter(function (m) {
          return m && typeof m.x === "number" && typeof m.y === "number" && typeof m.z === "number";
        });
      }
    } catch (e) { __markers = []; }
    return __markers;
  }

  function save() {
    try { localStorage.setItem(STORE_KEY, JSON.stringify(load())); } catch (e) { /* quota / private mode */ }
  }

  // All markers on a given floor.
  function listOnFloor(z) {
    return load().filter(function (m) { return m.z === z; });
  }

  // Exact-tile lookup.
  function findAt(x, y, z) {
    let list = load();
    for (let i = 0; i < list.length; i++) {
      if (list[i].x === x && list[i].y === y && list[i].z === z) return list[i];
    }
    return null;
  }

  // Nearest marker within `radius` tiles on floor z (for click hit-testing).
  function findNear(x, y, z, radius) {
    let best = null, bestD = Infinity;
    load().forEach(function (m) {
      if (m.z !== z) return;
      let d = Math.max(Math.abs(m.x - x), Math.abs(m.y - y));
      if (d <= radius && d < bestD) { bestD = d; best = m; }
    });
    return best;
  }

  // Add or update the marker on a tile.
  function set(x, y, z, icon, label) {
    let m = findAt(x, y, z);
    if (m) {
      m.icon = icon; m.label = label;
    } else {
      load().push({ x: x, y: y, z: z, icon: icon, label: label });
    }
    save();
  }

  function remove(x, y, z) {
    let list = load();
    for (let i = 0; i < list.length; i++) {
      if (list[i].x === x && list[i].y === y && list[i].z === z) { list.splice(i, 1); save(); return true; }
    }
    return false;
  }

  // Draw one marker icon centred at canvas (cx, cy). `r` is the disc radius in
  // canvas px (scales with the map's zoom). Pure canvas — no sprites.
  function drawIcon(ctx, cx, cy, iconIndex, r) {
    let icon = ICONS[iconIndex] || ICONS[0];
    ctx.save();
    ctx.beginPath();
    ctx.arc(cx, cy, r, 0, 2 * Math.PI);
    ctx.fillStyle = icon.color;
    ctx.fill();
    ctx.lineWidth = Math.max(1, r * 0.18);
    ctx.strokeStyle = "rgba(0,0,0,0.85)";
    ctx.stroke();
    // Glyph in dark for contrast against the coloured disc.
    ctx.fillStyle = "#101010";
    ctx.font = "bold " + Math.round(r * 1.5) + "px monospace";
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.fillText(icon.glyph, cx, cy + r * 0.05);
    ctx.restore();
  }

  // Optional label drawn to the right of a marker. fontSize defaults to 10
  // (big map); the small minimap passes a smaller size to reduce clutter.
  function drawLabel(ctx, cx, cy, r, label, fontSize) {
    if (!label) return;
    ctx.save();
    ctx.font = "bold " + (fontSize || 10) + "px sans-serif";
    ctx.textAlign = "left";
    ctx.textBaseline = "middle";
    let tx = cx + r + 3;
    // dark outline for legibility over any minimap colour
    ctx.lineWidth = 3;
    ctx.strokeStyle = "rgba(0,0,0,0.85)";
    ctx.strokeText(label, tx, cy);
    ctx.fillStyle = "#ffffff";
    ctx.fillText(label, tx, cy);
    ctx.restore();
  }

  return {
    ICONS: ICONS,
    listOnFloor: listOnFloor,
    findAt: findAt,
    findNear: findNear,
    set: set,
    remove: remove,
    drawIcon: drawIcon,
    drawLabel: drawLabel
  };

})();


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/mobile-chat.js ===== */

"use strict";

const MobileChat = function(touch) {

  /*
   * Class MobileChat
   * Purpose-built mobile chat system with quick chat bar and full chat log.
   * Uses a custom VirtualKeyboard instead of the native keyboard,
   * eliminating all visualViewport / fullscreen / device-specific issues.
   *
   * States:
   *   1. closed   — only chat button visible
   *   2. bar      — quick chat bar at bottom, canvas fully visible
   *   3. full     — expandable semi-transparent message log
   *   4. keyboard — virtual keyboard open for typing
   */

  this.touch = touch;

  // State
  this.__state = "closed"; // "closed", "bar", "full", "keyboard"
  this.__unreadCount = 0;
  this.__unreadDMCount = 0;
  this.__unreadGuildCount = 0;
  this.__activeChannelIndex = 0;
  this.__previewExpanded = false;

  // DOM references
  this.__container = document.getElementById("mobile-chat");
  this.__bar = document.querySelector(".mobile-chat-bar");
  this.__input = document.querySelector(".mobile-chat-msg");
  // Real <input> for the OS keyboard — used in place of the VK display span
  // only when the "use device keyboard" setting is enabled (a span can't open
  // the native keyboard). See __openNativeInput / __closeNativeInput.
  this.__nativeInput = document.querySelector(".mobile-chat-native-input");
  this.__sendBtn = document.querySelector(".mobile-chat-send");
  this.__historyBtn = document.querySelector(".mobile-chat-history");
  this.__expandBtn = document.querySelector(".mobile-chat-expand");
  this.__channelPill = document.querySelector(".mobile-chat-channel-pill");
  this.__log = document.querySelector(".mobile-chat-log");
  this.__logMessages = document.querySelector(".mobile-chat-log-messages");
  this.__preview = document.querySelector(".mobile-chat-preview");
  this.__chatBtn = document.getElementById("mobile-chat-btn");
  this.__chatBadge = document.getElementById("mobile-chat-badge");
  this.__dmBadge = document.getElementById("mobile-dm-badge");
  this.__guildBadge = document.getElementById("mobile-guild-badge");
  this.__dmBtn = document.querySelector(".mobile-chat-dm");
  this.__pasteBtn = document.querySelector(".mobile-chat-paste");
  this.__closeBtn = document.querySelector(".mobile-chat-close");
  this.__closeChannelBtn = document.querySelector(".mobile-chat-close-channel");
  this.__dmOverlay = null;  // Active DM prompt overlay reference

  // Virtual keyboard — no native keyboard, no viewport issues
  let self = this;
  this.__keyboard = new VirtualKeyboard(this.__input, function(text) {
    self.__onKeyboardSend(text);
  });

  // Bind events
  this.__bindEvents();

};

/* ============================
 * Channel Color Map
 * Maps channel names to pill colors (matching desktop tab colors)
 * ============================ */
MobileChat.prototype.CHANNEL_COLORS = {
  "Default": "#ddb944",
  "World": "#55cc55",
  "Trade": "#55cc55",
  "Help": "#55cc55",
  "Console": "#999999"
};

MobileChat.prototype.PRIVATE_CHANNEL_COLOR = "#6699ff";

/* ============================
 * Event Binding
 * ============================ */

MobileChat.prototype.__bindEvents = function() {

  /*
   * Function MobileChat.__bindEvents
   * Wire up all touch/click events for the mobile chat system.
   * No native keyboard events — the VirtualKeyboard handles all input.
   */

  let self = this;

  // Chat button opens bar
  if(this.__chatBtn) {
    this.__chatBtn.addEventListener("touchend", function(e) {
      e.preventDefault();
      if(self.touch.__layoutEditActive) return;
      self.toggle();
    }, { passive: false });
    this.__chatBtn.addEventListener("click", function(e) {
      e.preventDefault();
      if(self.touch.__layoutEditActive) return;
      self.toggle();
    });
  }

  // Send button — sends message via virtual keyboard
  if(this.__sendBtn) {
    this.__sendBtn.addEventListener("touchstart", function(e) {
      e.stopPropagation();
    }, { passive: true });
    this.__sendBtn.addEventListener("touchend", function(e) {
      e.preventDefault();
      e.stopPropagation();
      self.__sendMessage();
    }, { passive: false });
  }

  // Paste button — reads the system clipboard into the on-screen keyboard
  // buffer at the cursor (mobile has no native input to paste into).
  if(this.__pasteBtn) {
    this.__pasteBtn.addEventListener("touchstart", function(e) {
      e.stopPropagation();
    }, { passive: true });
    this.__pasteBtn.addEventListener("touchend", function(e) {
      e.preventDefault();
      e.stopPropagation();
      self.__pasteFromClipboard();
    }, { passive: false });
  }

  // History recall button — mobile equivalent of desktop Shift+Up.
  // ChannelManager.suggestPrevious walks the send-history cursor and
  // writes the recalled message into the desktop #chat-input element.
  // We copy that text into the VirtualKeyboard buffer so the on-screen
  // mobile input shows the recalled message, ready to send or edit.
  // Each tap walks one step further back (cap 4 per SEND_HISTORY_MAX).
  if(this.__historyBtn) {
    this.__historyBtn.addEventListener("touchstart", function(e) {
      e.stopPropagation();
    }, { passive: true });
    this.__historyBtn.addEventListener("touchend", function(e) {
      e.preventDefault();
      e.stopPropagation();
      let cm = gameClient.interface.channelManager;
      if (!cm || !self.__keyboard) return;
      cm.suggestPrevious();
      let recalled = cm.__inputElement && cm.__inputElement.textContent;
      if (recalled) {
        if(self.__useNativeKeyboard() && self.__nativeInput && self.__nativeInput.style.display !== "none") {
          self.__nativeInput.value = recalled;
          try { self.__nativeInput.focus(); self.__nativeInput.setSelectionRange(recalled.length, recalled.length); } catch(e) {}
        } else {
          self.__keyboard.setText(recalled);
        }
      }
    }, { passive: false });
  }

  // DM button — opens name prompt to start private chat
  if(this.__dmBtn) {
    this.__dmBtn.addEventListener("touchstart", function(e) {
      e.stopPropagation();
    }, { passive: true });
    this.__dmBtn.addEventListener("touchend", function(e) {
      e.preventDefault();
      e.stopPropagation();
      self.__openDMPrompt();
    }, { passive: false });
  }

  // Close button (arrow down) — collapses full log back to bar
  if(this.__closeBtn) {
    this.__closeBtn.addEventListener("touchstart", function(e) {
      e.stopPropagation();
    }, { passive: true });
    this.__closeBtn.addEventListener("touchend", function(e) {
      e.preventDefault();
      e.stopPropagation();
      self.__closeLog();
    }, { passive: false });
  }

  // Close channel button (X) — closes current channel tab
  if(this.__closeChannelBtn) {
    this.__closeChannelBtn.addEventListener("touchstart", function(e) {
      e.stopPropagation();
    }, { passive: true });
    this.__closeChannelBtn.addEventListener("touchend", function(e) {
      e.preventDefault();
      e.stopPropagation();
      self.__closeCurrentChannel();
    }, { passive: false });
  }

  // Expand/collapse button
  if(this.__expandBtn) {
    this.__expandBtn.addEventListener("mousedown", function(e) {
      e.preventDefault();
    });
    this.__expandBtn.addEventListener("touchstart", function(e) {
      e.stopPropagation();
    }, { passive: true });
    this.__expandBtn.addEventListener("touchend", function(e) {
      e.preventDefault();
      e.stopPropagation();
      if(self.__state === "bar" || self.__state === "keyboard") {
        self.__openFullChat();
      } else if(self.__state === "full") {
        self.__closeLog();
      }
    }, { passive: false });
  }

  // Channel pill — tap to cycle channels
  if(this.__channelPill) {
    this.__channelPill.addEventListener("touchstart", function(e) {
      e.stopPropagation();
    }, { passive: true });
    this.__channelPill.addEventListener("touchend", function(e) {
      e.preventDefault();
      e.stopPropagation();
      self.__cycleChannel();
    }, { passive: false });
  }

  // Input display — tap to open virtual keyboard
  if(this.__input) {
    this.__input.addEventListener("touchend", function(e) {
      e.preventDefault();
      e.stopPropagation();
      if(self.__state === "bar" || self.__state === "full") {
        self.__openKeyboard();
      } else if(self.__state === "keyboard" && self.__useNativeKeyboard()) {
        // Device-keyboard mode: the OS keyboard can be dismissed (swipe-down /
        // Done) while __state stays "keyboard" — re-focus the native field
        // within THIS tap gesture to bring it back (setExternalInput blurs then
        // focuses, so it reopens even when focus never left the field). Without
        // this, a dismissed keyboard could only be recovered by a full reload —
        // the same wedge as the man-symbol path.
        self.__openNativeInput();
      }
    }, { passive: false });
  }

  // Canvas tap dismissal is handled by Touch.__handleCanvasTouchStart

  // Long-press a chat line → open the same context menu desktop uses on
  // right-click (Message / Copy Name / Copy Message / Add Friend). The shared
  // `longPressFired` flag lets the double-tap / preview-toggle handlers below
  // ignore the touch a long-press already consumed.
  let longPressFired = false;

  // Selection highlight — mark the chat line the long-press grabbed so it's
  // obvious which message the menu (Copy / Copy Name) will act on. Cleared on
  // the next touch anywhere, which is exactly when the menu dismisses (tapping
  // a menu button OR tapping outside). We track the MESSAGE object (not the
  // DOM node): an incoming message rebuilds the log via innerHTML, so
  // __renderMessages/__renderPreview re-apply the class to the message's fresh
  // node by identity — the selection survives people talking mid-copy.
  let lpClearListener = null;
  let clearChatHighlight = function() {
    self.__selectedMessage = null;
    // Strip the class from whatever node currently carries it — the node may
    // have been replaced by a re-render since we set it, so query live.
    [self.__logMessages, self.__preview].forEach(function(el) {
      if(!el) return;
      el.querySelectorAll(".chat-message-selected").forEach(function(n) {
        n.classList.remove("chat-message-selected");
      });
    });
    if(lpClearListener) {
      document.removeEventListener("touchstart", lpClearListener, true);
      document.removeEventListener("mousedown", lpClearListener, true);
      lpClearListener = null;
    }
  };
  let highlightChatMessage = function(span) {
    clearChatHighlight();
    if(!span) return;
    self.__selectedMessage = span.__message || null;
    span.classList.add("chat-message-selected");
    lpClearListener = function() { clearChatHighlight(); };
    // Registered async so the long-press's own in-flight touch sequence
    // (finger still down) doesn't immediately clear the highlight — only a
    // fresh tap afterwards does.
    setTimeout(function() {
      if(lpClearListener) {
        document.addEventListener("touchstart", lpClearListener, true);
        document.addEventListener("mousedown", lpClearListener, true);
      }
    }, 0);
  };

  let attachChatLongPress = function(el) {
    if(!el) return;
    let timer = null, sx = 0, sy = 0, span = null;
    let clear = function() { if(timer) { clearTimeout(timer); timer = null; } };
    el.addEventListener("touchstart", function(e) {
      longPressFired = false;
      clear();
      if(e.touches.length !== 1) return;
      let t = e.touches[0];
      sx = t.clientX; sy = t.clientY;
      span = (e.target && e.target.closest) ? e.target.closest(".chat-message") : null;
      if(!span) return;
      timer = setTimeout(function() {
        timer = null;
        longPressFired = true;
        if(navigator.vibrate) { try { navigator.vibrate(20); } catch(_) {} }
        highlightChatMessage(span);
        let fakeEvent = { target: span, clientX: sx, clientY: sy, preventDefault: function() {} };
        try { gameClient.interface.menuManager.open("chat-entry-menu", fakeEvent); } catch(_) {}
      }, 450);
    }, { passive: true });
    el.addEventListener("touchmove", function(e) {
      if(!timer || !e.touches[0]) return;
      if(Math.abs(e.touches[0].clientX - sx) > 10 || Math.abs(e.touches[0].clientY - sy) > 10) clear();
    }, { passive: true });
    el.addEventListener("touchend", clear, { passive: true });
    el.addEventListener("touchcancel", clear, { passive: true });
  };
  attachChatLongPress(this.__logMessages);
  attachChatLongPress(this.__preview);

  // Catch-up scroll listeners. While the user reads history (scrolled up),
  // incoming lines are buffered instead of rebuilding the log (see
  // __renderMessages/__renderPreview). When they scroll back to within a line
  // of the bottom, render the buffered lines and resume auto-stick. Guarded by
  // the *HasBuffered flag so the programmatic scroll-to-bottom inside the render
  // (which fires a scroll event with the flag already cleared) can't re-loop.
  let attachCatchUp = function(el, hasBufferedKey, rerender) {
    if(!el) return;
    el.addEventListener("scroll", function() {
      if(!self[hasBufferedKey]) return;
      let distanceFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight;
      if(distanceFromBottom <= 48) {
        rerender.call(self);
      }
    }, { passive: true });
  };
  attachCatchUp(this.__logMessages, "__logHasBuffered", this.__renderMessages);
  attachCatchUp(this.__preview, "__previewHasBuffered", this.__renderPreview);

  // Double-tap message to open DM (full log)
  if(this.__logMessages) {
    let lastTapTime = 0;
    this.__logMessages.addEventListener("touchend", function(e) {
      if(longPressFired) { longPressFired = false; return; }
      let now = Date.now();
      if(now - lastTapTime < 300) {
        // Double tap detected
        let target = e.target.closest(".chat-message[name]");
        if(target) {
          let playerName = target.getAttribute("name");
          if(playerName && playerName !== gameClient.player.name) {
            self.openPrivateChat(playerName);
          }
        }
      }
      lastTapTime = now;
    }, { passive: true });
  }

  // Tap preview to expand/collapse, double-tap message to open DM
  if(this.__preview) {
    let lastPreviewTapTime = 0;
    this.__preview.addEventListener("touchend", function(e) {
      if(longPressFired) { longPressFired = false; return; }
      let now = Date.now();
      if(now - lastPreviewTapTime < 300) {
        // Double tap — open DM
        let target = e.target.closest(".chat-message[name]");
        if(target) {
          let playerName = target.getAttribute("name");
          if(playerName && playerName !== gameClient.player.name) {
            self.openPrivateChat(playerName);
          }
        }
      } else {
        // Single tap — toggle expanded preview
        self.__previewExpanded = !self.__previewExpanded;
        if (self.__previewExpanded) {
          self.__preview.classList.add("preview-expanded");
        } else {
          self.__preview.classList.remove("preview-expanded");
        }
        self.__renderPreview();
      }
      lastPreviewTapTime = now;
    }, { passive: true });
  }

  // Dismiss chat on orientation change — avoids layout issues
  this.__orientationHandler = function() {
    if(self.__state !== "closed") {
      self.dismiss();
    }
  };
  if(window.screen && window.screen.orientation) {
    window.screen.orientation.addEventListener("change", this.__orientationHandler);
  } else {
    window.addEventListener("orientationchange", this.__orientationHandler);
  }

  // Dismiss chat on fullscreen change — avoids layout issues
  document.addEventListener("fullscreenchange", function() {
    if(self.__state !== "closed") {
      self.dismiss();
    }
  });
  document.addEventListener("webkitfullscreenchange", function() {
    if(self.__state !== "closed") {
      self.dismiss();
    }
  });

};

/* ============================
 * State Management
 * ============================ */

MobileChat.prototype.toggle = function() {

  /*
   * Function MobileChat.toggle
   * Toggle the chat bar open/closed from the chat button
   */

  if(this.__state === "closed") {
    this.__openBar();
  } else {
    this.dismiss();
  }

  if(navigator.vibrate) navigator.vibrate(30);

};

MobileChat.prototype.openPrivateChat = function(name) {

  /*
   * Function MobileChat.openPrivateChat
   * Open the chat bar and switch to the private channel for the given player name.
   * Creates the private channel if it doesn't exist yet.
   */

  // Ensure the private channel exists
  gameClient.interface.channelManager.addPrivateChannel(name);

  // Open bar if not already open
  if(this.__state === "closed") {
    this.__openBar();
  }

  // Find the private channel index. addPrivateChannel above capitalizes
  // the name internally ('uzur' → 'Uzur'), so a case-sensitive compare
  // against the caller's raw input misses — leaves __activeChannelIndex
  // pointing at the previous channel and the new DM doesn't auto-focus.
  // Case-insensitive match here so any input casing lands on the right tab.
  let channels = gameClient.interface.channelManager.channels;
  let lookup = name.toLowerCase();
  for(let i = 0; i < channels.length; i++) {
    if(channels[i].constructor === PrivateChannel
       && typeof channels[i].name === "string"
       && channels[i].name.toLowerCase() === lookup) {
      this.__activeChannelIndex = i;
      this.__syncChannelPill();
      break;
    }
  }

  // Sync preview to show the private channel messages
  this.__renderPreview();

  // Auto-open keyboard so the player can start typing immediately.
  let self = this;
  if (this.__useNativeKeyboard()) {
    // Device-keyboard mode: the native input's focus() MUST run synchronously
    // inside the triggering tap gesture. iOS ignores focus() called from a
    // setTimeout, so the OS keyboard never opened — AND __openKeyboard still
    // flipped __state to "keyboard", so the input tap handler (which only
    // re-opens from "bar"/"full") no-op'd and the chat was wedged until a full
    // browser reload (Antoua 2026-07-08: "open a new chat with the man symbol,
    // the device keyboard won't show again, have to close the browser fully").
    // Every caller (DM confirm, friend list, chat menu) is a touch handler, so
    // opening inline keeps focus() within the gesture. VK mode has no gesture
    // requirement and keeps the 50 ms bar-settle delay below.
    if (this.__state === "bar") this.__openKeyboard();
  } else {
    setTimeout(function() {
      if (self.__state === "bar") {
        self.__openKeyboard();
      }
    }, 50);
  }

};

MobileChat.prototype.__openBar = function() {

  /*
   * Function MobileChat.__openBar
   * Show the quick chat bar at the bottom of the screen
   */

  this.__state = "bar";

  if(this.__container) {
    this.__container.classList.add("mobile-chat-visible");
    this.__container.classList.remove("mobile-chat-full");
  }

  // Hide hotbar, d-pad, action buttons — chat bar replaces them at the bottom
  this.__hideControls();

  // Sync channel pill to current active channel
  this.__syncChannelPill();

  // Show last 2 messages as preview
  this.__renderPreview();

  // Clear unreads
  this.__unreadCount = 0;
  this.__unreadDMCount = 0;
  this.__unreadGuildCount = 0;
  this.__updateChatBadge();
  this.__updateDMBadge();
  this.__updateGuildBadge();

};

MobileChat.prototype.__openKeyboard = function() {

  /*
   * Function MobileChat.__openKeyboard
   * Show the virtual keyboard for typing.
   * No native keyboard, no viewport changes, no positioning hacks.
   */

  // Check if current channel is read-only
  let channels = gameClient.interface.channelManager.channels;
  let channel = channels[this.__activeChannelIndex];
  if(channel && channel.constructor === LocalChannel) return;

  this.__state = "keyboard";

  if(this.__container) {
    this.__container.classList.add("mobile-chat-visible", "mobile-chat-typing");
    this.__container.classList.remove("mobile-chat-full");
  }

  if(this.__useNativeKeyboard() && this.__nativeInput) {
    // Device keyboard mode: focus a real <input> so the OS keyboard opens.
    // No VK, so no bar-float-above-keyboard positioning.
    this.__openNativeInput();
  } else {
    this.__keyboard.show();

    // Position the chat bar above the keyboard (not inside it, so keyboard scaling doesn't affect it)
    if(this.__bar) {
      this.__bar.classList.add("chat-bar-floating");
      this.__positionBarAboveKeyboard();
    }
  }

  this.__hideControls();

};

MobileChat.prototype.__useNativeKeyboard = function() {

  /*
   * Function MobileChat.__useNativeKeyboard
   * True when the player has enabled "use device keyboard" in settings. The main
   * chat then routes typing to a real <input> (OS keyboard) instead of the VK —
   * mirroring how every modal input honours the setting via setExternalInput.
   */

  try {
    let s = gameClient.interface && gameClient.interface.settings;
    return !!(s && s.isNativeKeyboardEnabled && s.isNativeKeyboardEnabled());
  } catch(e) {
    return false;
  }

};

MobileChat.prototype.__openNativeInput = function() {

  /*
   * Function MobileChat.__openNativeInput
   * Show the real <input> in place of the VK display span and focus it within
   * the current tap gesture so the device keyboard opens. Reuses the VK's
   * native-passthrough gate (setExternalInput) so Enter -> send is wired and the
   * VK keeps its show() no-op flag consistent.
   */

  let input = this.__nativeInput;
  if(!input) { this.__keyboard.show(); return; }

  if(this.__input) this.__input.style.display = "none";
  input.style.display = "";

  let self = this;
  // setExternalInput's native path makes the field editable, focuses it (OS
  // keyboard) and wires Enter -> this callback; then show() no-ops on the flag.
  this.__keyboard.setExternalInput(input, function() { self.__sendMessage(); }, null);
  this.__keyboard.show();

};

MobileChat.prototype.__closeNativeInput = function() {

  /*
   * Function MobileChat.__closeNativeInput
   * Drop the OS keyboard, hide the native <input>, and restore the VK display
   * span so a later VK-mode session renders normally. Idempotent — safe to call
   * whenever we leave keyboard state.
   */

  let input = this.__nativeInput;
  if(input) {
    try { input.blur(); } catch(e) {}
    input.value = "";
    input.style.display = "none";
  }
  if(this.__input) this.__input.style.display = "";
  if(this.__keyboard) {
    try { this.__keyboard.clearExternalInput(); } catch(e) {}
    this.__keyboard.__nativePassthrough = false;
    // DM prompt also re-points the VK display at the span; keep that invariant.
    this.__keyboard.__inputDisplay = this.__input;
  }

};

MobileChat.prototype.__insertIntoNativeInput = function(text) {

  /*
   * Function MobileChat.__insertIntoNativeInput
   * Insert text at the cursor of the native <input> (paste path in device-
   * keyboard mode).
   */

  let input = this.__nativeInput;
  if(!input) return;
  let start = (typeof input.selectionStart === "number") ? input.selectionStart : input.value.length;
  let end = (typeof input.selectionEnd === "number") ? input.selectionEnd : input.value.length;
  input.value = input.value.slice(0, start) + text + input.value.slice(end);
  let pos = start + text.length;
  try { input.focus(); input.setSelectionRange(pos, pos); } catch(e) {}

};

MobileChat.prototype.__pasteFromClipboard = function() {

  /*
   * Function MobileChat.__pasteFromClipboard
   * Pastes from the IN-GAME clipboard — a plain in-memory string set by Copy
   * Message / Copy Name (MessageMenu.__copyToClipboard). Deliberately does NOT
   * use the browser Clipboard API: navigator.clipboard.readText() is gated
   * behind https + a permission prompt on Android and blocked outright on iOS
   * Safari. The in-game clipboard always works (http, iOS, no prompt); the only
   * trade-off is it pastes text copied IN-GAME, not from other apps.
   */

  let text = (typeof gameClient !== "undefined" && gameClient && gameClient.__clipboardText) || "";
  if(!text) {
    this.__pasteHint("Nothing copied yet — long-press a message and tap Copy");
    return;
  }

  this.__openKeyboard();
  if(this.__state === "keyboard" && this.__keyboard) {
    if(this.__useNativeKeyboard() && this.__nativeInput && this.__nativeInput.style.display !== "none") {
      this.__insertIntoNativeInput(text);
    } else {
      this.__keyboard.insertText(text);
    }
  } else {
    this.__pasteHint("Can't paste into this channel");
  }

};

MobileChat.prototype.__pasteHint = function(message) {

  /*
   * Function MobileChat.__pasteHint
   * Visible, non-fatal feedback for the paste button (clipboard denied / empty /
   * read-only). Uses the center server-message banner so it shows regardless of
   * keyboard state; falls back to the input placeholder if that's unavailable.
   */

  try {
    let nm = gameClient.interface && gameClient.interface.notificationManager;
    if(nm && nm.setServerMessage) {
      nm.setServerMessage(message, Interface.prototype.COLORS.RED, 1);
      return;
    }
  } catch(e) {}

  let input = this.__input;
  if(!input) {
    return;
  }

  let prev = input.getAttribute("data-placeholder") || "Tap to type...";
  input.setAttribute("data-placeholder", message);
  setTimeout(function() {
    // Only restore if we still own the placeholder (don't clobber a newer state).
    if(input.getAttribute("data-placeholder") === message) {
      input.setAttribute("data-placeholder", prev);
    }
  }, 2500);

};

MobileChat.prototype.__openFullChat = function() {

  /*
   * Function MobileChat.__openFullChat
   * Open the full chat log (expandable message area)
   */

  this.__state = "full";

  // Hide virtual keyboard if open
  if(this.__keyboard) {
    this.__keyboard.hide();
  }

  // Move chat bar back into #mobile-chat if it was reparented
  this.__restoreBar();

  if(this.__container) {
    this.__container.classList.add("mobile-chat-visible", "mobile-chat-full");
    this.__container.classList.remove("mobile-chat-typing");
    this.__container.style.removeProperty("display");
  }

  if(this.__expandBtn) {
    this.__expandBtn.textContent = "expand_more";
  }

  // Sync channel state (including close button visibility)
  this.__syncChannelPill();

  // Render current channel messages
  this.__renderMessages();

  // Clear unreads
  this.__unreadCount = 0;
  this.__unreadDMCount = 0;
  this.__unreadGuildCount = 0;
  this.__updateChatBadge();
  this.__updateDMBadge();
  this.__updateGuildBadge();

};

MobileChat.prototype.__closeLog = function() {

  /*
   * Function MobileChat.__closeLog
   * Close the message log but keep the input bar visible
   */

  this.__state = "bar";

  if(this.__container) {
    this.__container.classList.remove("mobile-chat-full");
  }

  if(this.__expandBtn) {
    this.__expandBtn.textContent = "expand_less";
  }

};

MobileChat.prototype.__restoreBar = function() {

  /*
   * Function MobileChat.__restoreBar
   * Remove floating positioning from the chat bar.
   * Called when leaving keyboard state (dismiss, full chat, etc.)
   */

  if(!this.__bar) return;

  this.__bar.classList.remove("chat-bar-floating");
  this.__bar.style.bottom = "";
  this.__bar.style.left = "";
  this.__bar.style.right = "";
  this.__bar.style.background = "";

  // Device-keyboard mode: drop the OS keyboard + restore the VK display span.
  this.__closeNativeInput();

};

MobileChat.prototype.isInputFocused = function() {

  /*
   * Function MobileChat.isInputFocused
   * Returns true if the mobile chat virtual keyboard is open
   */

  return this.__keyboard && this.__keyboard.__container && this.__keyboard.__container.style.display !== "none";

};

MobileChat.prototype.__positionBarAboveKeyboard = function() {

  /*
   * Function MobileChat.__positionBarAboveKeyboard
   * Positions the chat bar just above the scaled keyboard, matching its width
   */

  if(!this.__bar || !this.__keyboard || !this.__keyboard.__container) return;

  let kbRect = this.__keyboard.__container.getBoundingClientRect();
  let barBottom = window.innerHeight - kbRect.top;

  this.__bar.style.bottom = barBottom + "px";
  this.__bar.style.left = kbRect.left + "px";
  this.__bar.style.right = (window.innerWidth - kbRect.right) + "px";

  // Fixed 10% opacity for the input bar
  this.__bar.style.background = "rgba(0, 0, 0, 0.1)";

};

MobileChat.prototype.dismiss = function() {

  /*
   * Function MobileChat.dismiss
   * Dismiss all chat UI — close bar, log, keyboard. Back to chat-button-only state.
   */

  this.__state = "closed";
  this.__previewExpanded = false;
  if(this.__preview) this.__preview.classList.remove("preview-expanded");

  // Close DM prompt if open
  this.__closeDMPrompt();

  // Hide virtual keyboard
  if(this.__keyboard) {
    this.__keyboard.hide();
  }

  // Move chat bar back into #mobile-chat if it was reparented
  this.__restoreBar();

  if(this.__container) {
    this.__container.classList.remove("mobile-chat-visible", "mobile-chat-full", "mobile-chat-typing");
    this.__container.style.removeProperty("display");
  }

  if(this.__expandBtn) {
    this.__expandBtn.textContent = "expand_less";
  }

  // Restore controls hidden during chat
  this.__restoreControls();

};

/* ============================
 * Virtual Keyboard Callbacks
 * ============================ */

MobileChat.prototype.__onKeyboardSend = function(text) {

  /*
   * Function MobileChat.__onKeyboardSend
   * Called by VirtualKeyboard when Send is pressed with non-empty text
   */

  gameClient.interface.channelManager.sendMessageText(text, this.__activeChannelIndex);

  // Close keyboard, return to bar with preview
  this.__keyboard.hide();
  this.__restoreBar();

  if(this.__container) {
    this.__container.classList.remove("mobile-chat-typing");
    this.__container.classList.add("mobile-chat-visible");
    this.__container.style.removeProperty("display");
  }

  this.__state = "bar";
  this.__renderPreview();

};

/* ============================
 * Control Visibility
 * ============================ */

MobileChat.prototype.__hideControls = function() {

  /*
   * Function MobileChat.__hideControls
   * Hide all mobile controls when chat is open: hotbar, d-pad, action buttons,
   * chat bubble, PvP button, fullscreen button, portrait bars.
   * On iPhone (.iphone-notch), also hide the bottom status bar so chat input isn't covered.
   */

  let ids = [
    "mobile-action-bar",
    "mobile-hotbar",
    "portrait-bars",
    "mobile-chat-btn",
    "mobile-pk-lock-btn",
    "mobile-hotbar-preset-btn"
  ];

  // Hide bottom status bar on iPhone to avoid overlapping chat input
  if (document.documentElement.classList.contains("iphone-notch")) {
    ids.push("mobile-status-bar");
  }

  ids.forEach(function(id) {
    let el = document.getElementById(id);
    if(el) el.style.setProperty("display", "none", "important");
  });

};

MobileChat.prototype.__restoreControls = function() {

  /*
   * Function MobileChat.__restoreControls
   * Restore all mobile controls after chat is dismissed
   */

  let ids = [
    "mobile-action-bar",
    "mobile-hotbar",
    "portrait-bars",
    "mobile-chat-btn",
    "mobile-pk-lock-btn",
    "mobile-hotbar-preset-btn"
  ];

  // Restore bottom status bar on iPhone
  if (document.documentElement.classList.contains("iphone-notch")) {
    ids.push("mobile-status-bar");
  }

  ids.forEach(function(id) {
    let el = document.getElementById(id);
    if (!el) return;
    el.style.removeProperty("display");
  });

};

/* ============================
 * Message Sending
 * ============================ */

MobileChat.prototype.__sendMessage = function() {

  /*
   * Function MobileChat.__sendMessage
   * Send the message from the virtual keyboard buffer to the active channel
   */

  // Device-keyboard mode: text lives in the native <input>, not the VK buffer.
  if(this.__useNativeKeyboard() && this.__nativeInput && this.__nativeInput.style.display !== "none") {
    let nText = (this.__nativeInput.value || "").trim();
    this.__nativeInput.value = "";
    if(nText.length === 0) return;
    gameClient.interface.channelManager.sendMessageText(nText, this.__activeChannelIndex);
    // Keep focus so the OS keyboard stays up for the next line.
    try { this.__nativeInput.focus(); } catch(e) {}
    return;
  }

  if(!this.__keyboard) return;

  let text = this.__keyboard.getText().trim();
  this.__keyboard.clear();

  if(text.length === 0) return;

  gameClient.interface.channelManager.sendMessageText(text, this.__activeChannelIndex);

};

/* ============================
 * Channel Management
 * ============================ */

MobileChat.prototype.__cycleChannel = function() {

  /*
   * Function MobileChat.__cycleChannel
   * Cycle through open channels when the pill is tapped
   */

  let channels = gameClient.interface.channelManager.channels;
  if(channels.length === 0) return;

  this.__activeChannelIndex = (this.__activeChannelIndex + 1) % channels.length;

  this.__syncChannelPill();

  // Update visible messages for the new channel
  if(this.__state === "full") {
    this.__renderMessages();
  } else if(this.__state === "bar") {
    this.__renderPreview();
  }

};

MobileChat.prototype.__closeCurrentChannel = function() {

  /*
   * Function MobileChat.__closeCurrentChannel
   * Closes the currently active channel tab (private/global channels).
   * Falls back to the previous channel after closing.
   */

  let channels = gameClient.interface.channelManager.channels;
  if (this.__activeChannelIndex >= channels.length) return;

  let channel = channels[this.__activeChannelIndex];
  if (!channel) return;

  // Close the channel via the channel manager
  gameClient.interface.channelManager.closeChannel(channel);

  // Adjust active index
  channels = gameClient.interface.channelManager.channels;
  if (this.__activeChannelIndex >= channels.length) {
    this.__activeChannelIndex = Math.max(0, channels.length - 1);
  }

  this.__syncChannelPill();

  if (this.__state === "full") {
    this.__renderMessages();
  } else if (this.__state === "bar") {
    this.__renderPreview();
  }

};

MobileChat.prototype.__syncChannelPill = function() {

  /*
   * Function MobileChat.__syncChannelPill
   * Update the channel pill text and color to match the active channel
   */

  if(!this.__channelPill) return;

  let channels = gameClient.interface.channelManager.channels;

  // Clamp index
  if(this.__activeChannelIndex >= channels.length) {
    this.__activeChannelIndex = 0;
  }

  let channel = channels[this.__activeChannelIndex];
  if(!channel) return;

  // Set pill text with chevrons to hint tappable
  this.__channelPill.textContent = "\u2039 " + channel.name + " \u203A";

  // Set pill color based on channel type
  let color = this.CHANNEL_COLORS[channel.name] || "#ddb944";

  if(channel.constructor === PrivateChannel) {
    color = this.PRIVATE_CHANNEL_COLOR;
  } else if(channel.constructor === LocalChannel) {
    color = this.CHANNEL_COLORS["Console"] || "#999999";
  }

  this.__channelPill.style.borderColor = color;
  this.__channelPill.style.color = color;

  // Update input state based on channel type
  if(this.__input) {
    if(channel.constructor === LocalChannel) {
      this.__input.setAttribute("data-placeholder", "Read only");
      this.__input.classList.add("mobile-chat-msg-disabled");
    } else {
      this.__input.setAttribute("data-placeholder", "Tap to type...");
      this.__input.classList.remove("mobile-chat-msg-disabled");
    }
  }

  // Close button on every channel EXCEPT (owner 2026-07-15): World, the
  // always-on locals (Console/Loot — the only LocalChannels), and Default —
  // the channel manager hard-rejects closing id 0, so an X there would only
  // dead-end in a cancel message. DMs stay unconditionally closable.
  if(this.__closeChannelBtn) {
    let closable = (channel.constructor === PrivateChannel)
      || (channel.constructor !== LocalChannel
          && channel.id !== CONST.CHANNEL.DEFAULT
          && channel.id !== CONST.CHANNEL.WORLD);
    this.__closeChannelBtn.style.display = closable ? "flex" : "none";
  }

};

/* ============================
 * Message Rendering (Full Chat)
 * ============================ */

// Scroll-up hold expiry — after this long, the next incoming live message
// snaps the log/preview back to the latest line
MobileChat.prototype.SCROLL_HOLD_MS = 60000;

MobileChat.prototype.__renderMessages = function(preserveScroll) {

  /*
   * Function MobileChat.__renderMessages
   * Render the active channel's messages into the full chat log.
   *
   * preserveScroll (default false): when a live message arrives while the
   * user is reading (onNewMessage), keep their scroll position if they have
   * scrolled up to read/copy older lines instead of snapping to the bottom.
   * When false (opening the log / switching channels) always jump to the
   * latest. Reported 2026-05-31: on mobile you couldn't scroll back to copy
   * an older message — every incoming line snapped the view to current.
   */

  if(!this.__logMessages) return;

  // Measure scroll intent BEFORE wiping the log. "Stick to bottom" only
  // when the user is already there (within ~one line of slack); if they
  // have scrolled up, remember the offset so it can be restored after the
  // rebuild. New messages append at the bottom, so a top-anchored scrollTop
  // keeps the line they are reading in place.
  let stickToBottom = true;
  let prevScrollTop = 0;
  if(preserveScroll && this.__logMessages.childNodes.length > 0) {
    prevScrollTop = this.__logMessages.scrollTop;
    let distanceFromBottom = this.__logMessages.scrollHeight
      - this.__logMessages.scrollTop
      - this.__logMessages.clientHeight;
    stickToBottom = distanceFromBottom <= 48;
  }

  // Reading history: the user scrolled up. Do NOT wipe + rebuild the log here —
  // rebuilding the DOM under their finger cancels the in-progress touch-scroll
  // and, during any chatter/combat (a rebuild PER incoming line), makes it
  // impossible to hold a scroll-back. The new line is already buffered in
  // channel.__contents; it renders when they scroll back to the bottom (the
  // scroll listener catches up). Restoring scrollTop after a wipe wasn't enough
  // on mobile — still snapped to current (Jay Ashborne report 2026-06-24).
  if(preserveScroll && !stickToBottom) {
    // Scroll-up hold expiry (owner request 2026-07-02): the hold is a
    // reading/copying aid, not a permanent detach — after SCROLL_HOLD_MS
    // the next incoming line falls through to a full rebuild + snap.
    if(!this.__logScrolledUpAt) {
      this.__logScrolledUpAt = Date.now();
    }
    if(Date.now() - this.__logScrolledUpAt <= MobileChat.prototype.SCROLL_HOLD_MS) {
      this.__logHasBuffered = true;
      return;
    }
    this.__logScrolledUpAt = 0;
  }

  this.__logMessages.innerHTML = "";

  let channels = gameClient.interface.channelManager.channels;
  if(this.__activeChannelIndex >= channels.length) return;

  let channel = channels[this.__activeChannelIndex];
  if(!channel) return;

  // Access the channel's message contents
  let contents = channel.__contents;

  if(!contents || contents.length === 0) {
    this.__logMessages.innerHTML = "<span class='channel-empty'>No messages in channel " + channel.name + ".</span>";
    return;
  }

  // Render each message. Stamp the source message on its node so a long-press
  // selection can be re-found across re-renders, and re-apply the selection
  // highlight to the matching message's fresh node so it survives an incoming
  // message (which rebuilds this whole log).
  let self = this;
  let frag = document.createDocumentFragment();
  contents.forEach(function(message) {
    let node = message.createNode();
    node.__message = message;
    if(self.__selectedMessage && message === self.__selectedMessage) {
      node.classList.add("chat-message-selected");
    }
    frag.appendChild(node);
  });

  this.__logMessages.appendChild(frag);

  // Stick to the latest, or hold the user's position if they had scrolled
  // up to read history (so copying an older message is not interrupted by
  // an incoming line). They resume auto-scroll by scrolling back down.
  if(stickToBottom) {
    this.__logMessages.scrollTop = this.__logMessages.scrollHeight;
  } else {
    this.__logMessages.scrollTop = prevScrollTop;
  }

  // Fully rendered — nothing buffered/skipped remains; any scroll-up hold ends
  this.__logHasBuffered = false;
  this.__logScrolledUpAt = 0;

};

MobileChat.prototype.__renderPreview = function(preserveScroll) {

  /*
   * Function MobileChat.__renderPreview
   * Show the last 2 messages from the active channel above the chat bar.
   * When expanded (single-tap) it lists the full history and is scrollable,
   * so honour the same scroll-back preservation as the full log: a live
   * message must not snap the user to the bottom while they read older lines.
   */

  if(!this.__preview) return;

  // Only the expanded preview is a real history-scroll surface; the 3-line
  // collapsed preview always sticks to the latest. Measure before the wipe.
  let stickToBottom = true;
  let prevScrollTop = 0;
  if(preserveScroll && this.__previewExpanded && this.__preview.childNodes.length > 0) {
    prevScrollTop = this.__preview.scrollTop;
    let distanceFromBottom = this.__preview.scrollHeight
      - this.__preview.scrollTop
      - this.__preview.clientHeight;
    stickToBottom = distanceFromBottom <= 48;
  }

  // Same scroll-back protection as the full log: don't rebuild the expanded
  // preview under the user's finger while they read history. Buffer the line
  // and catch up when they scroll back to the bottom.
  if(preserveScroll && this.__previewExpanded && !stickToBottom) {
    // Same scroll-up hold expiry as the full log (see __renderMessages)
    if(!this.__previewScrolledUpAt) {
      this.__previewScrolledUpAt = Date.now();
    }
    if(Date.now() - this.__previewScrolledUpAt <= MobileChat.prototype.SCROLL_HOLD_MS) {
      this.__previewHasBuffered = true;
      return;
    }
    this.__previewScrolledUpAt = 0;
  }

  this.__preview.innerHTML = "";

  let channels = gameClient.interface.channelManager.channels;
  if(this.__activeChannelIndex >= channels.length) return;

  let channel = channels[this.__activeChannelIndex];
  if(!channel) return;

  let contents = channel.__contents;
  if(!contents || contents.length === 0) return;

  // Show last 3 messages by default; all messages when expanded
  let start = this.__previewExpanded ? 0 : Math.max(0, contents.length - 3);
  let frag = document.createDocumentFragment();

  for(let i = start; i < contents.length; i++) {
    let node = contents[i].createNode();
    node.__message = contents[i];
    if(this.__selectedMessage && contents[i] === this.__selectedMessage) {
      node.classList.add("chat-message-selected");
    }
    frag.appendChild(node);
  }

  this.__preview.appendChild(frag);

  // Stick to the latest, or hold position when the user scrolled up in the
  // expanded preview to read/copy history.
  if(stickToBottom) {
    this.__preview.scrollTop = this.__preview.scrollHeight;
  } else {
    this.__preview.scrollTop = prevScrollTop;
  }

  // Fully rendered — nothing buffered/skipped remains.
  this.__previewHasBuffered = false;

};

MobileChat.prototype.onNewMessage = function(channel, isConsole) {

  /*
   * Function MobileChat.onNewMessage
   * Called when a new message arrives in any channel.
   * Updates unread badge or appends to log if visible.
   * Console messages (damage, loot, status) do not increment unread count.
   */

  if(this.__state === "full") {
    // If viewing this channel, append the message
    let channels = gameClient.interface.channelManager.channels;
    let activeChannel = channels[this.__activeChannelIndex];
    if(activeChannel === channel) {
      this.__renderMessages(true);
    }
  }

  // Update preview when bar is showing
  if(this.__state === "bar") {
    this.__renderPreview(true);
  }

  // Update unread badge if chat is closed (skip console messages)
  if(this.__state === "closed" && !isConsole) {
    // Guild messages get their own gold badge
    if(channel.id === CONST.CHANNEL.GUILD) {
      this.__unreadGuildCount++;
      this.__updateGuildBadge();
    } else {
      this.__unreadCount++;
      this.__updateChatBadge();
    }
  }

};

MobileChat.prototype.onNewDM = function() {

  /*
   * Function MobileChat.onNewDM
   * Called when a new private message arrives
   */

  if(this.__state === "closed") {
    this.__unreadDMCount++;
    this.__updateDMBadge();
  }

};

/* ============================
 * Badge Updates
 * ============================ */

MobileChat.prototype.__updateChatBadge = function() {

  /*
   * Function MobileChat.__updateChatBadge
   * Update the unread message badge on the chat button
   */

  if(!this.__chatBadge) return;

  if(this.__unreadCount > 0 && this.__state === "closed") {
    this.__chatBadge.style.display = "flex";
    this.__chatBadge.textContent = this.__unreadCount > 99 ? "99+" : this.__unreadCount;
  } else {
    this.__chatBadge.style.display = "none";
  }

};

MobileChat.prototype.__updateDMBadge = function() {

  /*
   * Function MobileChat.__updateDMBadge
   * Update the unread DM badge on the chat button
   */

  if(!this.__dmBadge) return;

  if(this.__unreadDMCount > 0 && this.__state === "closed") {
    this.__dmBadge.style.display = "flex";
    this.__dmBadge.textContent = this.__unreadDMCount > 99 ? "99+" : this.__unreadDMCount;
  } else {
    this.__dmBadge.style.display = "none";
  }

};

MobileChat.prototype.__updateGuildBadge = function() {

  /*
   * Function MobileChat.__updateGuildBadge
   * Update the unread guild message badge on the chat button
   */

  if(!this.__guildBadge) return;

  if(this.__unreadGuildCount > 0 && this.__state === "closed") {
    this.__guildBadge.style.display = "flex";
    this.__guildBadge.textContent = this.__unreadGuildCount > 99 ? "99+" : this.__unreadGuildCount;
  } else {
    this.__guildBadge.style.display = "none";
  }

};

/* ============================
 * DM Name Prompt
 * ============================ */

MobileChat.prototype.__openDMPrompt = function() {

  /*
   * Function MobileChat.__openDMPrompt
   * Replaces the chat bar content with a DM name input inline.
   * Toggles: tapping the DM button again closes the prompt.
   */

  // Toggle: if already open, close it
  if (this.__dmOverlay) {
    this.__closeDMPrompt();
    return;
  }

  if (!this.__bar) return;

  let self = this;

  // Hide the bar's own children IN PLACE — never innerHTML-replace them.
  // The old save/restore approach DETACHED every original node: the
  // constructor-bound listeners died and __nativeInput kept pointing at
  // the dead .mobile-chat-native-input, so in device-keyboard mode the
  // next text-bar tap ran __openNativeInput on a ghost and the chat
  // wedged until reload (owner report 2026-07-08). Hiding keeps nodes,
  // listeners and references alive.
  this.__dmHiddenChildren = [];
  for (let ci = 0; ci < this.__bar.children.length; ci++) {
    let child = this.__bar.children[ci];
    this.__dmHiddenChildren.push([child, child.style.display]);
    child.style.display = "none";
  }
  this.__bar.classList.add("mobile-dm-bar");

  let input = document.createElement("input");
  input.className = "mobile-dm-input";
  input.type = "text";
  input.placeholder = "Enter player name...";
  input.readOnly = true;

  let confirmBtn = document.createElement("button");
  confirmBtn.className = "mobile-dm-confirm";
  confirmBtn.textContent = "Open";

  this.__bar.appendChild(input);
  this.__bar.appendChild(confirmBtn);

  // Use a truthy marker so toggle and dismiss work
  this.__dmOverlay = true;

  function confirm() {
    let name = input.value.trim();
    if (name.length === 0) return;

    // Cannot message yourself (case-insensitive since addPrivateChannel capitalizes)
    if (gameClient.player && gameClient.player.name.toLowerCase() === name.toLowerCase()) {
      return;
    }

    self.__closeDMPrompt();

    // Open the private channel and switch to it
    gameClient.interface.channelManager.addPrivateChannel(name);
    self.openPrivateChat(name);
  }

  // Route typing to this input. In "use device keyboard" mode setExternalInput
  // makes the field editable + focuses the OS keyboard (no VK); otherwise it
  // captures VK output (letter-only filter).
  this.__keyboard.setExternalInput(input, function() {
    confirm();
  }, /^[a-zA-Z ]$/);

  this.__state = "keyboard";

  if (this.__container) {
    this.__container.classList.add("mobile-chat-visible", "mobile-chat-typing");
    this.__container.classList.remove("mobile-chat-full");
  }

  // Only show + float above the VK in VK mode. In device-keyboard mode the field
  // is already focused; floating the bar above a VK that never shows mispositioned
  // the bar and broke the input (same branch __openKeyboard uses).
  if (!this.__useNativeKeyboard()) {
    this.__keyboard.show();
    if (this.__bar) {
      this.__bar.classList.add("chat-bar-floating");
      this.__positionBarAboveKeyboard();
    }
  }

  this.__hideControls();

  confirmBtn.addEventListener("touchstart", function(e) {
    e.stopPropagation();
  }, { passive: true });
  confirmBtn.addEventListener("touchend", function(e) {
    e.preventDefault();
    e.stopPropagation();
    confirm();
  }, { passive: false });

};

MobileChat.prototype.__closeDMPrompt = function() {

  /*
   * Function MobileChat.__closeDMPrompt
   * Restores the original chat bar content
   */

  if (!this.__dmOverlay) return;

  this.__keyboard.clearExternalInput();
  this.__keyboard.hide();

  // Remove typing state
  if (this.__container) {
    this.__container.classList.remove("mobile-chat-typing");
  }

  this.__state = "bar";

  // Remove the DM prompt nodes and unhide the bar's own children — they
  // were never detached (see __openDMPrompt), so every reference and
  // listener (including the native input) is still live: no re-query,
  // no re-bind.
  if (this.__bar) {
    let dmInput = this.__bar.querySelector(".mobile-dm-input");
    let dmConfirm = this.__bar.querySelector(".mobile-dm-confirm");
    if (dmInput && dmInput.parentNode) dmInput.parentNode.removeChild(dmInput);
    if (dmConfirm && dmConfirm.parentNode) dmConfirm.parentNode.removeChild(dmConfirm);
    if (this.__dmHiddenChildren) {
      for (let ci = 0; ci < this.__dmHiddenChildren.length; ci++) {
        this.__dmHiddenChildren[ci][0].style.display = this.__dmHiddenChildren[ci][1];
      }
      this.__dmHiddenChildren = null;
    }
    this.__bar.classList.remove("mobile-dm-bar");
    this.__bar.classList.remove("chat-bar-floating");
    this.__bar.style.bottom = "";
    this.__bar.style.left = "";
    this.__bar.style.right = "";
    this.__bar.style.background = "";
    this.__savedBarHTML = null;
  }

  this.__dmOverlay = null;

};

/* ============================
 * Back Button Integration
 * ============================ */

MobileChat.prototype.handleBackButton = function() {

  /*
   * Function MobileChat.handleBackButton
   * Handle the back button press — dismiss chat if open
   * Returns true if chat was open and got dismissed
   */

  if(this.__state !== "closed") {
    this.dismiss();
    return true;
  }
  return false;

};


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/mobile-container-panel.js ===== */

const MobileContainerPanel = function (panelId, layoutConfigId) {

  /*
   * Class MobileContainerPanel
   * Manages a single tabbed panel for all open containers on mobile.
   * Instead of spawning separate floating windows, all containers
   * render into this panel as switchable tabs.
   *
   * panelId — DOM id of the root element (default "mobile-container-panel").
   *   Tablet mode constructs a second instance against "mobile-container-panel-2"
   *   so backpack + extras can sit side-by-side.
   * layoutConfigId — layout-editor element config id used for re-applying the
   *   saved custom position when show() fires. Defaults to "container".
   */

  // Map of containerId -> { tab, content, title }
  this.__containers = new Map();

  // Currently active container ID
  this.__activeContainerId = null;

  // Minimized state
  this.__minimized = false;

  // Track equipped backpack container ID (first non-depot container opened)
  this.__backpackContainerId = null;

  // DOM references
  this.__panelId = panelId || "mobile-container-panel";
  this.__layoutConfigId = layoutConfigId || "container";
  this.__panel = document.getElementById(this.__panelId);
  if (!this.__panel) return;
  this.__tabStrip = this.__panel.querySelector(".mobile-container-tabs");
  this.__bodyArea = this.__panel.querySelector(".mobile-container-body");

  // Bind minimize button
  this.__bindMinimize();

}

MobileContainerPanel.prototype.__bindMinimize = function () {

  /*
   * Function MobileContainerPanel.__bindMinimize
   * Binds the minimize button on the panel header
   */

  let self = this;
  let minBtn = this.__panel.querySelector(".mobile-panel-minimize");

  if (!minBtn) return;

  minBtn.addEventListener("touchend", function (e) {
    e.preventDefault();
    e.stopPropagation();
    self.__toggleMinimize();
  }, { passive: false });

}

MobileContainerPanel.prototype.__toggleMinimize = function () {

  /*
   * Function MobileContainerPanel.__toggleMinimize
   * Toggles minimized state — hides tabs and body, keeps header visible
   */

  this.__minimized = !this.__minimized;

  if (this.__minimized) {
    this.__tabStrip.style.display = "none";
    this.__bodyArea.style.display = "none";
  } else {
    this.__tabStrip.style.display = "";
    this.__bodyArea.style.display = "";
  }

}


MobileContainerPanel.prototype.addContainer = function (containerId, title) {

  /*
   * Function MobileContainerPanel.addContainer
   * Adds a container to the panel with a new tab
   */

  // If already tracked, just switch to it
  if (this.__containers.has(containerId)) {
    this.switchTab(containerId);
    return this.__containers.get(containerId).body;
  }

  // Create tab button
  let tab = document.createElement("button");
  tab.className = "mobile-container-tab";
  tab.setAttribute("data-cid", containerId);

  // Track the first non-depot container as the equipped backpack
  // (neither depot — global nor Star Fishisland — may claim the backpack slot)
  // Server truth: the equipped backpack-slot container arrives already
  // titled "Main Backpack" (container-manager) — no client heuristics.
  if (title === "Main Backpack") {
    this.__backpackContainerId = containerId;
  }

  // The equipped backpack's tab reads "Main Backpack" (owner 2026-07-03 —
  // the old "*"-prefix marker was cryptic); other tabs truncate as before.
  let displayTitle;
  if (containerId === this.__backpackContainerId) {
    displayTitle = "Main Backpack";
  } else {
    displayTitle = title.length > 12 ? title.substring(0, 10) + ".." : title;
  }

  let titleSpan = document.createElement("span");
  titleSpan.textContent = displayTitle;
  titleSpan.title = title;
  tab.appendChild(titleSpan);

  // Close button on tab
  let closeBtn = document.createElement("span");
  closeBtn.className = "mobile-container-tab-close";
  closeBtn.textContent = "\u00D7";
  closeBtn.addEventListener("touchend", this.__handleTabClose.bind(this, containerId), { passive: false });
  tab.appendChild(closeBtn);

  // Tab click to switch
  tab.addEventListener("touchend", this.__handleTabClick.bind(this, containerId), { passive: false });

  this.__tabStrip.appendChild(tab);

  // Create content wrapper: .container-content[containerIndex] > .body
  let content = document.createElement("div");
  content.className = "container-content";
  content.setAttribute("containerIndex", containerId);
  content.style.display = "none";

  let body = document.createElement("div");
  body.className = "body";
  content.appendChild(body);

  this.__bodyArea.appendChild(content);

  // Store reference
  this.__containers.set(containerId, {
    tab: tab,
    content: content,
    body: body,
    title: title
  });

  // Un-minimize if minimized, show panel, switch to new tab
  if (this.__minimized) {
    this.__toggleMinimize();
  }
  this.show();
  this.switchTab(containerId);

  // Scroll new tab into view
  tab.scrollIntoView({ behavior: "smooth", block: "nearest", inline: "nearest" });

  return body;

}

MobileContainerPanel.prototype.removeContainer = function (containerId) {

  /*
   * Function MobileContainerPanel.removeContainer
   * Removes a container tab and content from the panel
   */

  let entry = this.__containers.get(containerId);

  if (!entry) return;

  // Remove DOM elements
  entry.tab.remove();
  entry.content.remove();
  this.__containers.delete(containerId);

  // If this was the active tab, switch to another. Prefer the equipped
  // backpack — that's "home base" for the player. Falling through to
  // first-in-map can land on a nested-bp or auto-loot-opened container
  // the player isn't expecting (Roy 2026-05-02: closing a dragon corpse
  // by walking away bumped the active tab to a secondary bp nested inside
  // the main backpack instead of returning to the main bp).
  if (this.__activeContainerId === containerId) {
    this.__activeContainerId = null;
    let preferred = (this.__backpackContainerId !== null
                     && this.__backpackContainerId !== containerId
                     && this.__containers.has(this.__backpackContainerId))
      ? this.__backpackContainerId
      : null;
    if (preferred !== null) {
      this.switchTab(preferred);
    } else {
      let remaining = this.__containers.keys();
      let next = remaining.next();
      if (!next.done) {
        this.switchTab(next.value);
      }
    }
  }

  // Hide panel if no containers left
  if (this.__containers.size === 0) {
    this.hide();
  }

}

MobileContainerPanel.prototype.switchTab = function (containerId) {

  /*
   * Function MobileContainerPanel.switchTab
   * Switches the visible container tab
   */

  let entry = this.__containers.get(containerId);

  if (!entry) return;

  // Hide all content and deactivate all tabs
  this.__containers.forEach(function (e) {
    e.content.style.display = "none";
    e.tab.className = "mobile-container-tab";
  });

  // Show selected
  entry.content.style.display = "";
  entry.tab.className = "mobile-container-tab active";
  this.__activeContainerId = containerId;

}

MobileContainerPanel.prototype.show = function () {

  /*
   * Function MobileContainerPanel.show
   * Shows the container panel. Re-applies the saved LayoutEditor position
   * for this panel BEFORE flipping display back on — otherwise the CSS
   * default top wins for one paint frame, conflicts with the saved
   * bottom offset, and the panel stretches / displaces visibly on iOS.
   * Same ordering fix as __showPanel in touch.js.
   */

  // Apply saved position first so the inline styles are in place when
  // the panel becomes visible.
  if (gameClient.touch && gameClient.touch.layoutEditor) {
    gameClient.touch.layoutEditor.reapplyElement(this.__layoutConfigId);
  }

  this.__panel.style.display = "flex";

}

MobileContainerPanel.prototype.hide = function () {

  /*
   * Function MobileContainerPanel.hide
   * Hides the container panel. When __resetPositionOnHide is set
   * (depot panel), strip the inline styles a drag may have set so the
   * panel always reopens at the CSS default position. Mirrors the
   * old depot floating window: closed → reopened → centered again.
   */

  this.__panel.style.display = "none";

  if (this.__resetPositionOnHide) {
    this.__panel.style.removeProperty("left");
    this.__panel.style.removeProperty("top");
    this.__panel.style.removeProperty("right");
    this.__panel.style.removeProperty("bottom");
    this.__panel.style.removeProperty("transform");
    this.__panel.style.removeProperty("margin-left");
  }

}

MobileContainerPanel.prototype.getContentBody = function (containerId) {

  /*
   * Function MobileContainerPanel.getContentBody
   * Returns the body element for a specific container
   */

  let entry = this.__containers.get(containerId);

  return entry ? entry.body : null;

}

MobileContainerPanel.prototype.clear = function () {

  /*
   * Function MobileContainerPanel.clear
   * Removes all containers without sending close packets (used on disconnect)
   */

  this.__containers.forEach(function (entry) {
    entry.tab.remove();
    entry.content.remove();
  });

  this.__containers.clear();
  this.__activeContainerId = null;
  this.__backpackContainerId = null;
  this.__minimized = false;
  this.__tabStrip.style.display = "";
  this.__bodyArea.style.display = "";
  this.hide();

}

MobileContainerPanel.prototype.__handleTabClick = function (containerId, event) {

  /*
   * Function MobileContainerPanel.__handleTabClick
   * Handles tapping a tab to switch containers
   */

  // Ignore if the close button was tapped
  if (event.target.classList.contains("mobile-container-tab-close")) return;

  event.preventDefault();
  event.stopPropagation();
  this.switchTab(containerId);

}

MobileContainerPanel.prototype.__handleTabClose = function (containerId, event) {

  /*
   * Function MobileContainerPanel.__handleTabClose
   * Handles tapping the close button on a tab — sends close packet to server.
   *
   * Special case: closing the DEPOT tab cascades — closes every other tab
   * in the depot panel too. The sub-containers (Inbox, Depot Chest 1-4)
   * are only meaningful as long as the depot is open, so leaving stale
   * sub-tabs after the depot itself closes is just confusing.
   */

  event.preventDefault();
  event.stopPropagation();

  // Cascade-close for the depot tab — collect IDs first so the iteration
  // doesn't trip over Map mutation as containers close out.
  if ((containerId === CONST.CONTAINER.DEPOT || containerId === CONST.CONTAINER.STARFISH_DEPOT) && gameClient.touch && gameClient.touch.mobileDepotPanel === this) {
    let toClose = [];
    this.__containers.forEach(function (_entry, cid) { toClose.push(cid); });
    toClose.forEach(function (cid) {
      let c = gameClient.player.getContainer(cid);
      if (c) gameClient.player.closeContainer(c);
    });
    return;
  }

  let container = gameClient.player.getContainer(containerId);

  if (container) {
    gameClient.player.closeContainer(container);
  }

}


