function captchaLocalizeInstruction(englishText) {
  /*
   * Function captchaLocalizeInstruction
   * Looks up a server-sent English instruction in CAPTCHA_INSTRUCTION_VARIANTS
   * and returns the locale-matched translation. Falls back to the literal
   * input when the locale is English, when no map entry exists for the
   * exact string (future server adds a new variant — we show English until
   * a translation lands), or when the entry has no translation for the
   * user's locale (defensive — never display "undefined").
   */
  if (!englishText) return englishText;
  let locale = captchaResolveLocale();
  if (locale === "en") return englishText;
  let entry = CAPTCHA_INSTRUCTION_VARIANTS[englishText];
  if (!entry) return englishText;
  return entry[locale] || englishText;
}

// Player-chosen captcha locale. Held in module memory (works even if
// localStorage is blocked) and persisted so it survives reloads + applies to
// every future captcha. The in-modal selector exists because
// navigator.language is often English even for non-English speakers — a
// Spanish player froze 4h on an English prompt (report 2026-05-29). Native
// language labels so a player can find theirs WITHOUT reading the current one.
const CAPTCHA_LOCALE_OPTIONS = [
  { code: "en",    label: "English",    flag: "🇬🇧" },
  { code: "es",    label: "Español",    flag: "🇪🇸" },
  { code: "pt-br", label: "Português",  flag: "🇧🇷" },
  { code: "nl",    label: "Nederlands", flag: "🇳🇱" },
  { code: "de",    label: "Deutsch",    flag: "🇩🇪" },
  { code: "sv",    label: "Svenska",    flag: "🇸🇪" },
  { code: "pl",    label: "Polski",     flag: "🇵🇱" },
  { code: "ru",    label: "Русский",    flag: "🇷🇺" }
];
const CAPTCHA_LOCALE_STORAGE_KEY = "captchaLocale";
let captchaLocaleOverride = "";
(function () {
  try {
    let v = (localStorage.getItem(CAPTCHA_LOCALE_STORAGE_KEY) || "");
    if (CAPTCHA_I18N[v]) captchaLocaleOverride = v;
  } catch (e) { /* localStorage unavailable — stay browser-detected */ }
})();
function captchaSetOverride(code) {
  captchaLocaleOverride = CAPTCHA_I18N[code] ? code : "";
  try { localStorage.setItem(CAPTCHA_LOCALE_STORAGE_KEY, captchaLocaleOverride); } catch (e) {}
}

function captchaResolveLocale() {
  /*
   * Resolution order: explicit in-modal selection (persisted) → browser
   * language → English. The override wins because the whole point of the
   * selector is to rescue players whose navigator.language doesn't match the
   * language they actually read.
   *
   * Browser tags look like "en-US", "sv-SE", "pt-BR", "es-ES", "nl-NL",
   * "de-DE", "ru-RU". European Portuguese (pt-PT) folds into pt-br (close enough).
   */
  if (captchaLocaleOverride) return captchaLocaleOverride;
  let lang = "";
  try { lang = (navigator.language || "").toLowerCase(); } catch (e) { return "en"; }
  if (lang.indexOf("pt") === 0) return "pt-br";
  if (lang.indexOf("sv") === 0) return "sv";
  if (lang.indexOf("pl") === 0) return "pl";
  if (lang.indexOf("es") === 0) return "es";
  if (lang.indexOf("nl") === 0) return "nl";
  if (lang.indexOf("de") === 0) return "de";
  if (lang.indexOf("ru") === 0) return "ru";
  return "en";
}

function captchaT(key, params) {
  /*
   * Translation lookup with {placeholder} substitution. Missing key in
   * the locale dict falls back to English; missing in English returns
   * the raw key (defensive — never display "undefined" to the user).
   */
  let locale = captchaResolveLocale();
  let dict = CAPTCHA_I18N[locale] || CAPTCHA_I18N.en;
  let str = (dict[key] !== undefined ? dict[key] : (CAPTCHA_I18N.en[key] !== undefined ? CAPTCHA_I18N.en[key] : key));
  if (params) {
    Object.keys(params).forEach(function (k) {
      str = str.split("{" + k + "}").join(params[k]);
    });
  }
  return str;
}

const CaptchaModal = function (id) {

  /*
   * Class CaptchaModal
   * In-game "odd one out" anti-bot challenge. Server sends N monster
   * lookType IDs (default 6, 2x3 grid) + an instruction; the player
   * clicks the one that doesn't belong to the same family as the
   * others. The correct answer index lives ONLY on the server — this
   * modal just renders the tiles and posts back which one was clicked.
   *
   * Hand-grown captcha (no third-party widget). The bot threat model
   * is the simple rune-hotkey-loop script: those have zero plumbing
   * for sprite-grid recognition + modal-click routing, so the modal
   * just sits there until the server's 60s timeout fires the freeze.
   *
   * Bigger bots / paid solvers can defeat this; the trigger gate plus
   * per-account log makes that economically and operationally costly
   * enough to push them to other targets. Plan: ~/.claude/plans/
   * shimmying-jumping-finch.md.
   *
   * Modal chrome (header, button, status text) is translated to every
   * supported locale via captchaT — see CAPTCHA_I18N above.
   */

  // Inherit from Modal — resolves this.element from the id
  Modal.call(this, id);

  // Cached DOM references
  this.__gridEl = this.element.querySelector(".captcha-grid");
  this.__instructionEl = this.element.querySelector(".captcha-instruction");
  this.__statusEl = this.element.querySelector(".captcha-status");
  this.__delayRowEl = this.element.querySelector(".captcha-delay-row");
  this.__delayBtnEl = this.element.querySelector(".captcha-delay-btn");
  this.__watermarkEl = this.element.querySelector(".captcha-watermark");
  this.__headerEl = this.element.querySelector(".modal-header");
  // Minimize button — created dynamically in JS so stale HTML can't
  // hide it. The HTML in client/index.html intentionally does NOT
  // declare this button; we inject it once here. Subsequent opens
  // re-use the same DOM node (constructor runs once, modal is
  // singleton). See __injectMinimizeButton.
  this.__minimizeBtnEl = this.__injectMinimizeButton();
  // Floating indicator — also injected dynamically for the same
  // reason. See __injectMinimizedIndicator.
  this.__minimizedIndicatorEl = this.__injectMinimizedIndicator();
  this.__minimizedTimerEl = this.__minimizedIndicatorEl
    ? this.__minimizedIndicatorEl.querySelector(".captcha-minimized-timer") : null;
  this.__isMinimized = false;

  // In-modal flag picker (injected once, directly above the question). Lets a
  // player tap their country flag to flip the captcha to a language they read —
  // see __injectLanguageSelector / __applyLocale.
  this.__langRowEl = this.__injectLanguageSelector();
  // Last English instruction the server sent — kept so __applyLocale can
  // re-localize the prompt when the player switches language mid-challenge.
  this.__lastInstructionEnglish = null;

  // Per-open state — reset in handleOpen
  this.__currentActionId = 0;
  this.__tiles = []; // [{ wrapper, canvas, spriteBuffer }]
  // Gamepad selection cursor (visual grid position). null = no cursor shown,
  // so mouse players never see a highlight; set on first gamepad navigation.
  this.__selectedIndex = null;
  this.__locked = false; // true after a click is sent, until close
  this.__deadline = 0;   // ms epoch when the server timeout fires
  this.__countdownInterval = null;

  // One-shot delay click. Wired once in the constructor (the button DOM
  // node is reused across opens). handleOpen flips display/disabled
  // based on server's canDelay flag.
  if (this.__delayBtnEl) {
    let self = this;
    this.__delayBtnEl.addEventListener("click", function () {
      if (self.__locked) return;
      try {
        gameClient.send(new CaptchaDelayPacket(self.__currentActionId));
        // Lock + visual feedback while we wait for the server to re-fire
        self.__locked = true;
        self.__delayBtnEl.disabled = true;
        if (self.__statusEl) {
          self.__statusEl.textContent = captchaT("delayStatus");
          self.__statusEl.style.color = "#ffaa00";
        }
        // Close optimistically — server's re-fire will pop it again.
        setTimeout(function () {
          try {
            if (gameClient.interface && gameClient.interface.modalManager) {
              gameClient.interface.modalManager.close();
            }
          } catch (e) {}
        }, 250);
      } catch (e) {
        self.__locked = false;
        if (self.__delayBtnEl) self.__delayBtnEl.disabled = false;
      }
    });
  }

  // Minimize button click handler is now attached INSIDE
  // __injectMinimizeButton itself (self-contained, runs every time
  // the button is created/recreated). The constructor used to attach
  // the handler here ONCE, which broke when handleOpen's textContent
  // setter wiped the original button — the re-injected button had no
  // listeners. See __injectMinimizeButton.

  // Restore: click the floating indicator to bring the modal back.
  if (this.__minimizedIndicatorEl) {
    let self = this;
    this.__minimizedIndicatorEl.addEventListener("click", function () {
      self.__restore();
    });
  }

}

CaptchaModal.prototype = Object.create(Modal.prototype);
CaptchaModal.constructor = CaptchaModal;

// Captcha-specific opt-in: keyboard input is NOT blocked while the
// modal is open. Walk / hotbar / spell keys all pass through to the
// game so the player isn't a sitting duck during the 60s solve
// window. Especially important for PvP — a captcha popping up
// shouldn't lock the player in place for an attacker to free-kill.
CaptchaModal.prototype.passthroughKeys = true;

// Suppress the modal-manager backdrop dim — user request 2026-05-26:
// 'remove the dropshadow behind the module'. Captcha can run without
// dimming the game world; keyboard passthrough lets the player
// interact normally anyway, and the dim wasn't doing anything useful
// (couldn't dismiss via backdrop click — handleCancel === false).
CaptchaModal.prototype.hideBackdrop = true;

// Methods defined AFTER the prototype reassignment above. Putting them
// before nukes them when Object.create(Modal.prototype) reassigns
// CaptchaModal.prototype to a fresh object. Bug 2026-05-26: original
// commit placed these before the assignment, callers hit
// 'self.__minimize is not a function' on first captcha.

CaptchaModal.prototype.__injectMinimizeButton = function () {
  /*
   * Function CaptchaModal.__injectMinimizeButton
   * Creates the minimize button at runtime and attaches it to the
   * modal-header element. Done in JS (not declared in HTML) so a
   * stale cached index.html can't ship a player without the button —
   * the JS bundle goes through the SW with cache:no-store so it's
   * always fresh.
   *
   * Idempotent: if a button with the class already exists in the
   * header (e.g. from older HTML), REUSE it but always (re-)attach
   * handlers via __wireMinimizeButton. Without re-wiring, the inert
   * HTML-declared button would remain handler-less and clicks would
   * be no-ops — that was the bug: button visible, click did nothing.
   */
  if (!this.__headerEl) return null;
  let existing = this.__headerEl.querySelector(".captcha-minimize-btn");
  if (existing) {
    this.__wireMinimizeButton(existing);
    return existing;
  }
  // Make the header positionable so our absolute button anchors right
  if (this.__headerEl.style.position !== "relative" &&
      this.__headerEl.style.position !== "absolute") {
    this.__headerEl.style.position = "relative";
  }
  let btn = document.createElement("button");
  btn.type = "button";
  btn.className = "captcha-minimize-btn";
  btn.title = "Collapse captcha (keep playing while it counts down)";
  btn.textContent = "−";
  // Inline styling — bigger hit area + bright yellow border on dark
  // fill so the click target is unambiguous against the textured
  // header background.
  let s = btn.style;
  s.position = "absolute";
  s.top = "3px";
  s.right = "4px";
  s.width = "40px";
  s.height = "26px";
  s.padding = "0";
  s.lineHeight = "20px";
  s.fontSize = "24px";
  s.fontWeight = "bold";
  s.cursor = "pointer";
  s.background = "#2a2a2a";
  s.border = "2px solid #ffdb7a";
  s.color = "#ffdb7a";
  s.borderRadius = "3px";
  s.boxShadow = "0 1px 3px rgba(0,0,0,0.6)";
  s.zIndex = "100";
  s.pointerEvents = "auto";

  this.__headerEl.appendChild(btn);
  this.__wireMinimizeButton(btn);
  return btn;
};

CaptchaModal.prototype.__wireMinimizeButton = function (btn) {
  /*
   * Function CaptchaModal.__wireMinimizeButton
   * Attaches all event handlers to the minimize button. Idempotent —
   * marks the element with __wired so re-injection (each captcha
   * re-runs __injectMinimizeButton) doesn't stack duplicate listeners.
   *
   * Mirrors InteractiveWindow's mobile pattern (window.js:41-55):
   * touchend fires before click on iOS, sets a suppressNextClick
   * flag so the same tap doesn't double-trigger. Without touchend
   * mobile taps were dropped silently — that was why depot's button
   * worked on mobile but captcha's didn't.
   */
  if (!btn || btn.__wired) return;
  btn.__wired = true;
  let self = this;
  let suppressNextClick = false;

  function runToggle(event) {
    try { event.stopPropagation(); event.preventDefault(); } catch (e) {}
    try { console.log("[captcha] minimize toggle, isMinimized=", self.__isMinimized); } catch (e) {}
    if (self.__isMinimized) {
      self.__restore();
    } else {
      self.__minimize();
    }
  }

  // Defeat the header's drag-to-move mousedown listener
  btn.addEventListener("mousedown", function (event) {
    event.stopPropagation();
    event.preventDefault();
  });
  btn.addEventListener("mouseup", function (event) {
    event.stopPropagation();
  });
  btn.addEventListener("touchstart", function (event) {
    event.stopPropagation();
  }, { passive: true });
  btn.addEventListener("touchend", function (event) {
    // Mobile path — fires before click. Suppress the subsequent
    // click so we don't double-toggle.
    suppressNextClick = true;
    setTimeout(function () { suppressNextClick = false; }, 500);
    runToggle(event);
  }, { passive: false });
  btn.addEventListener("click", function (event) {
    if (suppressNextClick) {
      suppressNextClick = false;
      event.stopPropagation();
      event.preventDefault();
      return;
    }
    runToggle(event);
  });
};

CaptchaModal.prototype.__injectMinimizedIndicator = function () {
  /*
   * Function CaptchaModal.__injectMinimizedIndicator
   * Same shape as __injectMinimizeButton — create the floating
   * countdown indicator at runtime so stale HTML can't hide it.
   * Lives on document.body (not inside the modal) so it remains
   * visible when the modal is display:none.
   *
   * Idempotent.
   */
  let existing = document.getElementById("captcha-minimized-indicator");
  if (existing) return existing;
  let container = document.createElement("div");
  container.id = "captcha-minimized-indicator";
  let s = container.style;
  s.display = "none";
  s.position = "fixed";
  s.top = "48px";
  s.right = "8px";
  s.zIndex = "10000";
  s.background = "#3a1a1a";
  s.border = "1px solid #c00";
  s.color = "#fff";
  s.padding = "6px 12px";
  s.borderRadius = "4px";
  s.fontFamily = "monospace";
  s.fontSize = "12px";
  s.cursor = "pointer";
  s.boxShadow = "0 2px 8px rgba(0,0,0,0.5)";
  container.title = "Click to restore captcha";
  let title = document.createElement("span");
  title.style.cssText = "color:#ff6; font-weight:600;";
  title.textContent = "🛡 Captcha:";
  let timer = document.createElement("span");
  timer.className = "captcha-minimized-timer";
  timer.style.color = "#fff";
  timer.textContent = "0s";
  let hint = document.createElement("span");
  hint.style.cssText = "color:#aaa; font-size:10px; margin-left:6px";
  hint.textContent = "click to solve";
  container.appendChild(title);
  container.appendChild(document.createTextNode(" "));
  container.appendChild(timer);
  container.appendChild(hint);
  document.body.appendChild(container);
  return container;
};

CaptchaModal.prototype.__minimize = function () {
  /*
   * Function CaptchaModal.__minimize
   * COLLAPSE — hide modal-body and backdrop, leave modal-header
   * visible as a small placeholder bar floating in the middle of
   * the screen. Header text shows the remaining seconds so the
   * player knows the captcha is still active.
   *
   * Backdrop hidden -> canvas mouse input works. Keyboard already
   * passes through (passthroughKeys=true). Player can play normally
   * with just the small header bar showing.
   *
   * The minimize button morphs to '+' (expand) so the same control
   * brings the body back.
   */
  if (this.__isMinimized) return;
  this.__isMinimized = true;
  // Hide body with !important — mirrors InteractiveWindow.setElementHidden
  // (window.js:187). Stylesheet display rules (esp. on mobile where
  // CSS may pin block/flex !important) would otherwise win the cascade.
  let body = this.element.querySelector(".modal-body");
  if (body) body.style.setProperty("display", "none", "important");
  // Force the modal-element to a tiny min-height. Without this the
  // modal can keep its previous size if any descendant has implicit
  // sizing — depot does the same (window.js:192). Stash the original
  // so __restore can put it back exactly.
  this.__savedMinHeight = this.element.style.minHeight || "";
  this.__savedHeight = this.element.style.height || "";
  this.element.style.minHeight = "0";
  this.element.style.height = "auto";
  // Morph button to expand icon
  if (this.__minimizeBtnEl) {
    this.__minimizeBtnEl.textContent = "+";
    this.__minimizeBtnEl.title = "Expand captcha";
  }
  // Update header text immediately to show countdown
  this.__updateMinimizedTimer();
};

CaptchaModal.prototype.__restore = function () {
  /*
   * Function CaptchaModal.__restore
   * EXPAND — reverse of collapse. Show body + backdrop, button
   * back to '−'. State (locked, tiles, delay availability) is all
   * preserved because we never tore them down.
   */
  if (!this.__isMinimized) return;
  this.__isMinimized = false;
  let body = this.element.querySelector(".modal-body");
  // removeProperty (not '=" "') because __minimize used setProperty
  // with the 'important' priority. style.display = '' only clears
  // when there's no priority — we need the explicit removal so the
  // stylesheet's display:block !important takes over again.
  if (body) body.style.removeProperty("display");
  // Restore the modal-element's original size hints
  this.element.style.minHeight = this.__savedMinHeight || "";
  this.element.style.height = this.__savedHeight || "";
  // Backdrop is intentionally left hidden — captcha modal runs with
  // no dim overlay per user request (see hideBackdrop=true above).
  // Player sees the world behind the modal in both expanded and
  // collapsed states.
  if (this.__minimizeBtnEl) {
    this.__minimizeBtnEl.textContent = "−";
    this.__minimizeBtnEl.title = "Collapse captcha (keep playing while it counts down)";
  }
  // Restore header text to the static title (no countdown suffix)
  this.__setHeaderTitle(captchaT("header"));
};

CaptchaModal.prototype.__updateMinimizedTimer = function () {
  /*
   * Function CaptchaModal.__updateMinimizedTimer
   * Renders the collapsed header text: "Anti-bot Verification — 47s".
   * Updates only the first text node (the title) so the minimize
   * button child element stays intact. Called from the 250ms
   * countdown tick; no-op when not collapsed.
   */
  if (!this.__isMinimized) return;
  let remainingMs = Math.max(0, this.__deadline - Date.now());
  let seconds = Math.ceil(remainingMs / 1000);
  this.__setHeaderTitle(captchaT("header") + " — " + seconds + "s");
};

CaptchaModal.prototype.__setHeaderTitle = function (text) {
  /*
   * Function CaptchaModal.__setHeaderTitle
   * Updates ONLY the title text of the modal-header without wiping
   * the minimize button. textContent= setter would replace all
   * children — instead we locate the existing text node (or insert
   * one before the button) and set its content.
   */
  if (!this.__headerEl) return;
  // Find the first text node child
  let textNode = null;
  for (let i = 0; i < this.__headerEl.childNodes.length; i++) {
    let n = this.__headerEl.childNodes[i];
    if (n.nodeType === 3) { textNode = n; break; }
  }
  if (textNode) {
    textNode.textContent = text + " ";
  } else {
    // No text node yet — insert one before the first child
    this.__headerEl.insertBefore(
      document.createTextNode(text + " "),
      this.__headerEl.firstChild
    );
  }
};

CaptchaModal.TILE_PX = 64;        // displayed tile size (CSS pixels)
CaptchaModal.SPRITE_SIZE = 64;    // rendering granularity (matches outfit modal)
CaptchaModal.SPRITE_SCALE = 0.25; // matches outfit modal scaling
CaptchaModal.FACE_DIRECTION = 2;  // 2 = south, the canonical front-facing pose

// Must match server src/player/player.js __ANTIBOT_SPRITE_* constants
CaptchaModal.SPRITE_MONSTER = 0;
CaptchaModal.SPRITE_ITEM = 1;

CaptchaModal.prototype.__ensureLanguageStyles = function () {
  /*
   * Function CaptchaModal.__ensureLanguageStyles
   * One-time <style> injection for the flag picker. Inline styles can't express
   * :hover / .active / the attention pulse, and there's no captcha CSS file — so
   * we add a tiny stylesheet to <head> once. Makes the flags read as obviously-
   * tappable buttons with a clear "current language" highlight (player feedback
   * 2026-05-29: a plain control wasn't obviously clickable).
   */
  if (document.getElementById("captcha-lang-style")) return;
  let style = document.createElement("style");
  style.id = "captcha-lang-style";
  style.textContent = ""
    + ".captcha-lang-row{display:flex;flex-wrap:nowrap;justify-content:center;gap:3px;margin:0 auto 8px;padding:0;}"
    + ".captcha-lang-flag{flex:0 0 auto;font-size:12px;line-height:1;padding:3px 4px;border-radius:4px;background:transparent;"
    + "opacity:0.6;border:1px solid transparent;cursor:pointer;-webkit-appearance:none;appearance:none;"
    + "transition:transform 100ms ease,opacity 120ms ease,border-color 120ms ease,background 120ms ease,box-shadow 120ms ease;}"
    + ".captcha-lang-flag:hover{opacity:1;background:#3a3a3a;transform:scale(1.2);}"
    + ".captcha-lang-flag.active{opacity:1;border-color:#6aa0ff;background:#34507a;box-shadow:0 0 4px rgba(106,160,255,0.5);}"
    + ".captcha-lang-pulse .captcha-lang-flag:not(.active){animation:captchaFlagPulse 1.2s ease-in-out 2;}"
    + "@keyframes captchaFlagPulse{0%,100%{opacity:0.6;}50%{opacity:1;}}";
  document.head.appendChild(style);
};

CaptchaModal.prototype.__pulseLanguageSelector = function () {
  /*
   * Function CaptchaModal.__pulseLanguageSelector
   * Restart the attention pulse so the selector visibly "blinks" each time the
   * captcha opens — the cue that it's interactive. Reflow between remove/add
   * restarts the CSS animation on the persistent (singleton) element.
   */
  if (!this.__langRowEl) return;
  this.__langRowEl.classList.remove("captcha-lang-pulse");
  void this.__langRowEl.offsetWidth;
  this.__langRowEl.classList.add("captcha-lang-pulse");
};

CaptchaModal.prototype.__injectLanguageSelector = function () {
  /*
   * Function CaptchaModal.__injectLanguageSelector
   * One-time: a row of clickable country flags placed directly above the
   * instruction. A player who got the wrong language (browser locale ≠ the one
   * they read) taps their flag and the whole challenge re-renders in that
   * language — purely visual, no reading required. The active language's flag
   * is highlighted. Choice persists (localStorage) for every future captcha.
   * Idempotent — reuses the existing row on re-open (singleton modal).
   *
   * Note: flag emoji render as real flags on iOS/Android/macOS; Windows has no
   * flag-emoji font and shows the 2-letter country code instead (still a clear,
   * clickable label). title= carries the native language name on every platform.
   */
  if (!this.__instructionEl || !this.__instructionEl.parentNode) return null;
  let existing = this.__instructionEl.parentNode.querySelector(".captcha-lang-row");
  if (existing) return existing;
  this.__ensureLanguageStyles();
  let row = document.createElement("div");
  row.className = "captcha-lang-row";
  row.setAttribute("role", "group");
  row.setAttribute("aria-label", "Language / Idioma");
  let self = this;
  CAPTCHA_LOCALE_OPTIONS.forEach(function (o) {
    let b = document.createElement("button");
    b.type = "button";
    b.className = "captcha-lang-flag";
    b.textContent = o.flag;
    b.title = o.label;
    b.setAttribute("aria-label", o.label);
    b.dataset.code = o.code;
    b.addEventListener("click", function () {
      captchaSetOverride(o.code);
      self.__applyLocale();
    });
    row.appendChild(b);
  });
  this.__instructionEl.parentNode.insertBefore(row, this.__instructionEl);
  return row;
};

CaptchaModal.prototype.__highlightActiveFlag = function () {
  /*
   * Function CaptchaModal.__highlightActiveFlag
   * Moves the .active ring to the flag matching the resolved locale. Called on
   * open and after every switch so the "current language" cue stays correct.
   */
  if (!this.__langRowEl) return;
  let active = captchaResolveLocale();
  let flags = this.__langRowEl.querySelectorAll(".captcha-lang-flag");
  for (let i = 0; i < flags.length; i++) {
    flags[i].classList.toggle("active", flags[i].dataset.code === active);
  }
};

CaptchaModal.prototype.__applyLocale = function () {
  /*
   * Function CaptchaModal.__applyLocale
   * Re-render every localised string in the OPEN modal after a language switch.
   * Mirrors the chrome set in handleOpen so the change is instant + complete.
   */
  this.__setHeaderTitle(captchaT("header"));
  if (this.__instructionEl) {
    this.__instructionEl.textContent = this.__lastInstructionEnglish
      ? captchaLocalizeInstruction(this.__lastInstructionEnglish)
      : captchaT("defaultInstruction");
  }
  if (this.__delayBtnEl) this.__delayBtnEl.textContent = captchaT("delayBtn");
  // Status line: leave it alone once locked (click handler owns it); otherwise
  // refresh the countdown text immediately rather than waiting for the tick.
  if (this.__statusEl && !this.__locked) {
    let remainingMs = Math.max(0, this.__deadline - Date.now());
    this.__statusEl.textContent = captchaT("timeLeft", { n: Math.ceil(remainingMs / 1000) });
  }
  this.__highlightActiveFlag();
};

CaptchaModal.prototype.handleOpen = function (data) {
  /*
   * Function CaptchaModal.handleOpen
   * data = { actionId, timeoutMs, instruction, lookTypes[] }
   * Renders one canvas per tile and wires click handlers.
   */

  this.__currentActionId = (data && data.actionId) || 0;
  this.__locked = false;
  if (this.__statusEl) {
    this.__statusEl.textContent = "";
    this.__statusEl.style.color = "";
  }
  // Re-render localised chrome each open — picks up navigator.language
  // each time in case the user changed their browser locale (rare but
  // legitimate).
  if (this.__headerEl) {
    // __setHeaderTitle updates only the title text node — leaves the
    // minimize button child intact. Then re-inject as belt-and-
    // suspenders (idempotent; reuses existing button if present).
    this.__setHeaderTitle(captchaT("header"));
    this.__minimizeBtnEl = this.__injectMinimizeButton();
  }

  // (Backdrop suppression is handled centrally now — the modal's
  // hideBackdrop=true tells ModalManager.open() to skip setting
  // backdrop.style.display='block' in the first place. No per-open
  // override needed. See modal-captcha.js prototype assignment.)
  if (this.__delayBtnEl) this.__delayBtnEl.textContent = captchaT("delayBtn");
  // Show / hide the one-shot delay button based on server's canDelay
  // flag. Initial prompt = true (button visible); re-fired prompt
  // after a delay was used = false (button hidden, can't chain).
  if (this.__delayRowEl) {
    let showDelay = !!(data && data.canDelay);
    this.__delayRowEl.style.display = showDelay ? "" : "none";
    if (this.__delayBtnEl) this.__delayBtnEl.disabled = false;
  }

  // Per-session watermark — account name + actionId hex. Tiny + faint
  // (rendered via inline style on the element) so real players barely
  // notice; vision-AI services scrape it as text and refusal heuristics
  // on captcha imagery trip on player-id labelling. If a screenshot
  // leaks (Discord / social), the source account + specific session
  // are traceable via captcha.log (server logs the same actionId).
  if (this.__watermarkEl) {
    let name = "anon";
    try {
      if (typeof gameClient !== "undefined" && gameClient.player && typeof gameClient.player.name === "string") {
        name = gameClient.player.name;
      }
    } catch (e) {}
    let aid = Number(this.__currentActionId) || 0;
    this.__watermarkEl.textContent = name + " · " + aid.toString(16);
  }

  // Server-sent instruction takes priority (it varies for the bot-
  // deterrence randomness). If server didn't send one, use the
  // localized default.
  //
  // Server keeps sending English variants from a fixed set of 6 per mode
  // (src/player/player.js __antibotInstructionsMonster + Item). We
  // map the literal English back to the player's locale here via
  // captchaLocalizeInstruction. Variants the client doesn't know about
  // pass through unchanged (forward-compat with future server additions).
  this.__lastInstructionEnglish = (data && data.instruction) ? data.instruction : null;
  let instruction = this.__lastInstructionEnglish
    ? captchaLocalizeInstruction(this.__lastInstructionEnglish)
    : captchaT("defaultInstruction");
  if (this.__instructionEl) this.__instructionEl.textContent = instruction;

  // Ensure the language selector exists (idempotent) and reflects the active
  // locale each open — so a choice made in a prior captcha is pre-selected.
  this.__langRowEl = this.__injectLanguageSelector();
  this.__highlightActiveFlag();
  this.__pulseLanguageSelector();

  this.__teardownTiles();
  // Server sends either monster lookTypes or item CIDs in the `ids`
  // field, distinguished by `spriteType` (0 = monster outfit, 1 =
  // item CID). Older server protocol sent `lookTypes` directly —
  // fall back to that for forward compat if a mismatched client
  // somehow boots against a pre-protocol-update engine.
  let ids = [];
  let spriteType = CaptchaModal.SPRITE_MONSTER;
  if (data) {
    if (Array.isArray(data.ids)) {
      ids = data.ids;
      spriteType = (typeof data.spriteType === "number") ? data.spriteType : CaptchaModal.SPRITE_MONSTER;
    } else if (Array.isArray(data.lookTypes)) {
      ids = data.lookTypes;
    }
  }

  // Cache for the shuffle timer — re-renders need the same sprite
  // identities + type to rebuild the grid in a different visual order.
  this.__cachedIds = ids;
  this.__cachedSpriteType = spriteType;
  this.__cachedDetails = data.details || null;

  // Initial render: identity == DOM index (no shuffle yet). The CLICK
  // handler closes over the identity index and sends it to the server,
  // so subsequent shuffles only change the visual layout — identity is
  // preserved and the server's answerIndex check stays valid.
  // Fresh captcha — clear any prior gamepad cursor (mouse players see none).
  this.__selectedIndex = null;
  this.__shuffleFrozen = false; // not in a pre-shuffle freeze window yet
  for (let i = 0; i < ids.length; i++) {
    let tile = this.__createTile(i, ids[i], spriteType, this.__cachedDetails ? this.__cachedDetails[i] : null);
    this.__tiles.push(tile);
    this.__gridEl.appendChild(tile.wrapper);
  }

  // Schedule random-interval reshuffles. Defeats single-screenshot
  // vision-AI bots: a captured image at T=0 plus a 2-4s AI round-trip
  // means the click at T=3 lands on a stale visual position. By then
  // the tiles have moved; click hits the wrong sprite, FAIL.
  if (this.__shuffleTimer) {
    clearTimeout(this.__shuffleTimer);
    this.__shuffleTimer = null;
  }
  this.__scheduleNextShuffle();

  // Countdown timer — shows the player how long until the server-side
  // timeout fires and applies the freeze. ms-aligned poll because a
  // 1s setInterval can drift up to 999ms past a wall-clock second; we
  // tick 4x/sec and round up to whole seconds. Stops on click (locked
  // state) and on modal close.
  let timeoutMs = Math.max(1000, (data && Number(data.timeoutMs)) || 60000);
  this.__deadline = Date.now() + timeoutMs;
  if (this.__countdownInterval) clearInterval(this.__countdownInterval);
  this.__updateCountdown();
  this.__countdownInterval = setInterval(this.__updateCountdown.bind(this), 250);
};

CaptchaModal.prototype.__updateCountdown = function () {
  // Always update the floating mini-indicator (cheap; no-op when not minimized)
  this.__updateMinimizedTimer();
  if (!this.__statusEl) return;
  if (this.__locked) return; // click handler owns the status text from here
  let remainingMs = Math.max(0, this.__deadline - Date.now());
  let seconds = Math.ceil(remainingMs / 1000);
  this.__statusEl.textContent = captchaT("timeLeft", { n: seconds });
  // Color shift as time runs low. Tibia palette: yellow ≤ 20s, red ≤ 10s.
  if (seconds <= 10) {
    this.__statusEl.style.color = "#ff4444";
  } else if (seconds <= 20) {
    this.__statusEl.style.color = "#ffaa00";
  } else {
    this.__statusEl.style.color = "";
  }
  if (remainingMs <= 0) {
    if (this.__countdownInterval) {
      clearInterval(this.__countdownInterval);
      this.__countdownInterval = null;
    }
    // Auto-close on local timeout. Server's modal-fail timer fires at
    // the same instant (both started from the same issuedAt), so by
    // the time the client deadline hits, the server has already
    // FAILed + applied the freeze + sent the cancel message. Keeping
    // the modal up with a static '0s' display is just noise — close
    // it client-side so the screen reflects reality.
    //
    // Skips the handleCancel guard (which is meant for *user-initiated*
    // dismissal like backdrop/Esc/walk) and goes straight to close()
    // so handleClose still runs and tears down tiles + timers + the
    // minimized indicator.
    try {
      if (gameClient.interface && gameClient.interface.modalManager
          && gameClient.interface.modalManager.isOpened()) {
        gameClient.interface.modalManager.close();
      }
    } catch (e) {}
  }
};

CaptchaModal.prototype.handleCancel = function () {
  /*
   * Function CaptchaModal.handleCancel
   * Block accidental dismissal — backdrop click + Esc would close the
   * modal locally without notifying the server, so the player's 60s
   * timeout would still fire and FAIL them. Returning false tells
   * ModalManager to refuse the cancel.
   *
   * Player exits the captcha by:
   *   - Clicking a tile (PASS or FAIL)
   *   - Clicking the Delay button (one-shot, modal re-opens in 30s)
   *   - Letting the 60s timeout fire (server-side FAIL)
   *
   * The only "safe" close is the optimistic auto-close after a click
   * (modal.js __teardownTiles via ModalManager.close() called from
   * the tile click handler). Backdrop / Esc never trigger that path.
   */
  return false;
};

CaptchaModal.prototype.handleConfirm = function () {
  /*
   * Function CaptchaModal.handleConfirm
   * Same shape as handleCancel — refuse Enter-key dismissal. The
   * keyboard.js __handleReturnKey path routes Enter to
   * modalManager.handleConfirm() when any modal is open, which by
   * default closes the modal. For captcha that's a silent FAIL: the
   * modal goes away client-side but the server's 60s timer keeps
   * running and the player gets the freeze. Returning false here
   * tells ModalManager (and any future Enter-routing path) to leave
   * the captcha alone.
   */
  return false;
};

CaptchaModal.prototype.handleClose = function () {
  /*
   * Function CaptchaModal.handleClose
   * Server enforces the timeout; closing the modal early just stops
   * the player from interacting. If they didn't click before close,
   * server's 60s timer will fail them.
   */
  this.__teardownTiles();
  if (this.__countdownInterval) {
    clearInterval(this.__countdownInterval);
    this.__countdownInterval = null;
  }
  if (this.__shuffleTimer) {
    clearTimeout(this.__shuffleTimer);
    this.__shuffleTimer = null;
  }
  // Reset minimize state on close — next captcha must open with the
  // body visible again. removeProperty clears the !important inline
  // override that __minimize set; the stylesheet's display:block
  // then takes over. Without this, a minimize→close→reopen sequence
  // would leave the body invisible on the next captcha.
  if (this.__isMinimized) {
    this.__isMinimized = false;
    let body = this.element.querySelector(".modal-body");
    if (body) body.style.removeProperty("display");
    if (this.__minimizedIndicatorEl) {
      this.__minimizedIndicatorEl.style.display = "none";
    }
  }
};

CaptchaModal.SHUFFLE_INTERVAL_MIN_MS = 7000;   // 7s
CaptchaModal.SHUFFLE_INTERVAL_MAX_MS = 13000;  // 13s
CaptchaModal.SHUFFLE_LOCKOUT_TAIL_MS = 4000;   // skip shuffle in last 4s
// Pre-shuffle freeze: dim the grid + ignore clicks for this long right BEFORE each
// reshuffle, so a click landing just as the tiles swap is harmlessly swallowed
// instead of submitting whatever sprite slid under the cursor (players were failing
// the captcha to mid-click shuffles). Kept >= the 600ms pointer-defer window in
// __performShuffle so that internal defer never fires inside the freeze flow.
CaptchaModal.SHUFFLE_FREEZE_MS = 1000;          // 1s pre-shuffle dim + click lock

CaptchaModal.prototype.__scheduleNextShuffle = function () {
  /*
   * Function CaptchaModal.__scheduleNextShuffle
   * Self-perpetuating timer that re-runs the shuffle every 7-13s
   * (uniform random per call — bots can't sync to a fixed interval).
   * Stops on close, on click-lock, or when the modal-fail countdown
   * has < SHUFFLE_LOCKOUT_TAIL_MS left (so the player isn't surprised
   * by a layout swap as they're about to click).
   */
  let self = this;
  let min = CaptchaModal.SHUFFLE_INTERVAL_MIN_MS;
  let max = CaptchaModal.SHUFFLE_INTERVAL_MAX_MS;
  let delay = min + Math.floor(Math.random() * (max - min + 1));
  this.__shuffleTimer = setTimeout(function () {
    self.__shuffleTimer = null;
    if (self.__locked) return; // already clicked — done
    let remainingMs = self.__deadline - Date.now();
    if (remainingMs < CaptchaModal.SHUFFLE_LOCKOUT_TAIL_MS) return;
    // Dim + lock the grid for SHUFFLE_FREEZE_MS, THEN swap, THEN re-enable. A
    // click in this danger window is ignored (not counted as a wrong answer) and
    // the dim is the "about to move — wait" cue. FREEZE_MS >= the 600ms pointer
    // window so __performShuffle's own mid-click defer never fires here.
    self.__beginShuffleFreeze();
    self.__shuffleTimer = setTimeout(function () {
      self.__shuffleTimer = null;
      self.__performShuffle();
      self.__endShuffleFreeze();
      if (self.__locked) return;
      self.__scheduleNextShuffle();
    }, CaptchaModal.SHUFFLE_FREEZE_MS);
  }, delay);
};

CaptchaModal.prototype.__beginShuffleFreeze = function () {
  /*
   * Function CaptchaModal.__beginShuffleFreeze
   * Enters the pre-shuffle danger window: ignore clicks (__shuffleFrozen, checked
   * in the tile click handler + gamepadSubmit) and dim the grid as a visual cue.
   * pointer-events:none stops real mouse/touch clicks; the flag also covers the
   * synthetic click gamepadSubmit dispatches (which bypasses pointer-events).
   */
  this.__shuffleFrozen = true;
  if (this.__gridEl) {
    this.__gridEl.style.transition = "opacity 150ms";
    this.__gridEl.style.opacity = "0.4";
    this.__gridEl.style.pointerEvents = "none";
  }
};

CaptchaModal.prototype.__endShuffleFreeze = function () {
  /*
   * Function CaptchaModal.__endShuffleFreeze
   * Leaves the danger window: the new layout is in place, re-enable clicks + undim.
   */
  this.__shuffleFrozen = false;
  if (this.__gridEl) {
    this.__gridEl.style.opacity = "";
    this.__gridEl.style.pointerEvents = "";
  }
};

CaptchaModal.prototype.__performShuffle = function () {
  /*
   * Function CaptchaModal.__performShuffle
   * Picks a fresh Fisher-Yates permutation distinct from the current
   * order, tears down all tiles, and rebuilds them with sprites placed
   * in the new visual sequence. The click-handler's index parameter is
   * the SPRITE IDENTITY (original ids[] position), NOT the new DOM
   * position — so the response sent to the server is identity-based
   * and the server's answerIndex comparison continues to work without
   * any protocol change.
   */

  // Pointer-activity defer (2026-05-27): if the player just touched
  // a tile in the last 600ms, tearing down the tiles destroys the
  // element under their finger BEFORE the click event fires. Result:
  // 'I clicked frost dragon and nothing happened.' Defer the shuffle
  // 750ms whenever pointer activity is recent so the click can
  // complete on the original element. Reschedule in case more
  // activity continues.
  if (this.__lastPointerDownMs && (Date.now() - this.__lastPointerDownMs) < 600) {
    let self = this;
    setTimeout(function () {
      // Re-check on retry — if user kept tapping we'll keep deferring
      self.__performShuffle();
    }, 750);
    return;
  }

  if (!Array.isArray(this.__cachedIds) || this.__cachedIds.length === 0) return;
  let n = this.__cachedIds.length;

  // Fisher-Yates. Re-roll up to 5 times until the permutation differs
  // from identity — avoids the no-op case where the "shuffle" happens
  // to land on 0,1,2,3,4,5 again (visually nothing changes).
  let perm;
  for (let attempt = 0; attempt < 5; attempt++) {
    perm = [];
    for (let i = 0; i < n; i++) perm.push(i);
    for (let i = n - 1; i > 0; i--) {
      let j = Math.floor(Math.random() * (i + 1));
      let tmp = perm[i]; perm[i] = perm[j]; perm[j] = tmp;
    }
    let isIdentity = true;
    for (let i = 0; i < n; i++) {
      if (perm[i] !== i) { isIdentity = false; break; }
    }
    if (!isIdentity) break;
  }

  this.__teardownTiles();
  for (let i = 0; i < n; i++) {
    let identity = perm[i];
    let tile = this.__createTile(identity, this.__cachedIds[identity], this.__cachedSpriteType, this.__cachedDetails ? this.__cachedDetails[identity] : null);
    this.__tiles.push(tile);
    this.__gridEl.appendChild(tile.wrapper);
  }
  // Re-apply the gamepad cursor to the new tiles at the same visual position.
  this.__renderSelection();
};

CaptchaModal.prototype.__teardownTiles = function () {
  for (let i = 0; i < this.__tiles.length; i++) {
    let t = this.__tiles[i];
    if (t.wrapper && t.wrapper.parentNode) t.wrapper.parentNode.removeChild(t.wrapper);
  }
  this.__tiles = [];
  if (this.__gridEl) this.__gridEl.innerHTML = "";
};

// ---------------------------------------------------------------------------
// Gamepad solving — lets a controller player select + submit a tile so they
// aren't locked out of the captcha (driven from input/gamepad.js while this
// modal is the open modal). Selection is by VISUAL grid position so it
// survives reshuffles; submit reuses the tile's own click handler.
// ---------------------------------------------------------------------------

CaptchaModal.prototype.__renderSelection = function () {
  /*
   * Function CaptchaModal.__renderSelection
   * Highlights the gamepad-selected tile by visual position. __selectedIndex
   * is null until a gamepad first navigates, so mouse players see no cursor.
   */
  if (!this.__gridEl) return;
  let kids = this.__gridEl.children;
  for (let i = 0; i < kids.length; i++) {
    let sel = (this.__selectedIndex !== null && i === this.__selectedIndex);
    kids[i].style.borderColor = sel ? "#6af" : "#555";
    kids[i].style.borderWidth = sel ? "2px" : "1px";
    kids[i].style.boxShadow = sel ? "0 0 8px #6af" : "none";
  }
};

CaptchaModal.prototype.gamepadMove = function (dx, dy) {
  /*
   * Function CaptchaModal.gamepadMove
   * Moves the gamepad cursor across the visual grid (2x3, cols=3). Horizontal
   * wraps; vertical steps a row and clamps. The first call just shows the
   * cursor at position 0 so a controller player can see where they are.
   */
  if (this.__locked || !this.__gridEl) return;
  let n = this.__gridEl.children.length;
  if (n === 0) return;
  let cols = 3;
  let idx = (this.__selectedIndex === null) ? 0 : this.__selectedIndex;
  if (this.__selectedIndex !== null) {
    if (dx !== 0) idx = (idx + dx + n) % n;
    if (dy !== 0) { let t = idx + dy * cols; if (t >= 0 && t < n) idx = t; }
  }
  this.__selectedIndex = idx;
  this.__renderSelection();
};

CaptchaModal.prototype.gamepadSubmit = function () {
  /*
   * Function CaptchaModal.gamepadSubmit
   * Submits the gamepad-selected tile by dispatching a click at its centre —
   * reuses the tile's own click handler (sends the correct identity index +
   * closes) and yields a sane mid-tile behavioural-fingerprint position.
   */
  if (this.__locked || this.__shuffleFrozen || this.__selectedIndex === null || !this.__gridEl) return;
  let w = this.__gridEl.children[this.__selectedIndex];
  if (!w) return;
  try {
    let rect = w.getBoundingClientRect();
    let ev = new MouseEvent("click", {
      bubbles: true,
      clientX: Math.round(rect.left + rect.width / 2),
      clientY: Math.round(rect.top + rect.height / 2)
    });
    w.dispatchEvent(ev);
  } catch (e) {
    try { w.click(); } catch (e2) {}
  }
};

CaptchaModal.prototype.__createTile = function (index, spriteId, spriteType, details) {
  /*
   * Function CaptchaModal.__createTile
   * Builds a clickable wrapper + canvas for one tile, renders the
   * sprite (monster outfit OR item, dispatched on spriteType), and
   * wires the click → sendResponse handler.
   */

  let wrapper = document.createElement("div");
  wrapper.className = "captcha-tile";
  wrapper.style.cssText = [
    "width: " + CaptchaModal.TILE_PX + "px",
    "height: " + CaptchaModal.TILE_PX + "px",
    "border: 1px solid #555",
    "background: #1a1a1a",
    "cursor: pointer",
    "display: flex",
    "align-items: center",
    "justify-content: center"
  ].join(";");

  let canvasEl = document.createElement("canvas");
  canvasEl.width = CaptchaModal.TILE_PX;
  canvasEl.height = CaptchaModal.TILE_PX;
  canvasEl.style.cssText = "image-rendering: pixelated; pointer-events: none;";
  wrapper.appendChild(canvasEl);

  let self = this;
  // Pointer-down tracking — used by __performShuffle to defer tile
  // teardown if the player is mid-click. Without this, a shuffle
  // firing between mousedown and mouseup destroys the targeted tile
  // and the click is either lost or fires on the replacement tile
  // with a different identity. Player report 2026-05-27 'clicked
  // frost dragon, nothing happened'.
  function markPointer() { self.__lastPointerDownMs = Date.now(); }
  wrapper.addEventListener("mousedown", markPointer);
  wrapper.addEventListener("touchstart", markPointer, { passive: true });

  wrapper.addEventListener("click", function (event) {
    if (self.__locked || self.__shuffleFrozen) return; // frozen = mid pre-shuffle window, ignore
    self.__locked = true;
    // Visual feedback — flash the chosen tile
    wrapper.style.borderColor = "#ffaa00";
    if (self.__statusEl) self.__statusEl.textContent = captchaT("sent");
    // Capture click position within the wrapper for the server-side
    // behavioral fingerprint pipeline (Phase 1 — log only). Normalize
    // to 0-255 (mapped from 0.0-1.0 click position within tile bounds).
    // event.offsetX/Y are relative to the event target (wrapper). If
    // offset isn't available (Firefox <100 weirdness), fall back to
    // bounding-rect math; if THAT fails, send 127 (mid-tile sentinel).
    let xByte = 127, yByte = 127;
    try {
      let rect = wrapper.getBoundingClientRect();
      let ox = (typeof event.offsetX === "number") ? event.offsetX : (event.clientX - rect.left);
      let oy = (typeof event.offsetY === "number") ? event.offsetY : (event.clientY - rect.top);
      let xNorm = Math.max(0, Math.min(1, ox / rect.width));
      let yNorm = Math.max(0, Math.min(1, oy / rect.height));
      xByte = Math.round(xNorm * 255);
      yByte = Math.round(yNorm * 255);
    } catch (e) { /* keep mid-tile sentinel */ }
    try {
      gameClient.send(new CaptchaResponsePacket(self.__currentActionId, index, xByte, yByte));
      // Close optimistically. The PASS / FAIL outcome lands as a cancel
      // message (and a freeze condition on fail) — the modal doesn't
      // need to wait for confirmation since the server has authoritative
      // state. Without this the modal lingered after a correct click
      // (no server→client "close" packet exists).
      setTimeout(function () {
        try {
          if (gameClient.interface && gameClient.interface.modalManager) {
            gameClient.interface.modalManager.close();
          }
        } catch (e) {}
      }, 250);
    } catch (e) {
      if (self.__statusEl) self.__statusEl.textContent = captchaT("sendFailed", { error: (e && e.message ? e.message : "unknown") });
      self.__locked = false;
    }
  });

  // Render the sprite. Wrapped in try/catch — a missing sprite in the
  // dat shouldn't strand a whole captcha; leave the tile blank and the
  // player can still pick a different one.
  try {
    let canvas = new Canvas(canvasEl, CaptchaModal.TILE_PX, CaptchaModal.TILE_PX);
    canvas.clear();
    if (spriteType === CaptchaModal.SPRITE_ITEM) {
      // Item rendering — drawItemAsCreature renders a static item
      // sprite into the canvas at the given tile-position + size.
      // Position(1, 1) centers the sprite the same way the outfit
      // modal does at 64-size + 0.25 scale (effective 32x32).
      canvas.drawItemAsCreature(spriteId, new Position(1, 1), CaptchaModal.SPRITE_SIZE);
    } else {
      // Monster outfit rendering — full character composition with
      // spriteBuffer (no mount, south-facing, frame 0).
      let spriteBuffer = new SpriteBuffer(2);
      let spriteBufferMount = new SpriteBuffer(2);
      let outfit = new Outfit({
        id: spriteId,
        // Real outfit colors from the server (Victor 2026-07-17: colorizable
        // humanoids rendered ALL-WHITE with zeroed details, poisoning the
        // odd-one-out). Zeros still arrive for fixed-sprite monsters/items.
        details: details || { head: 0, body: 0, legs: 0, feet: 0 },
        mount: 0,
        mounted: false,
        addonOne: false,
        addonTwo: false
      });
      let dataObject = outfit.getDataObject();
      if (dataObject) {
        let item = dataObject.getFrameGroup(0);
        if (item) {
          spriteBuffer.clear();
          canvas.__drawCharacter(
            spriteBuffer,
            spriteBufferMount,
            outfit,
            new Position(1, 1),
            item,
            null,
            0,
            0,
            CaptchaModal.FACE_DIRECTION,
            0,
            CaptchaModal.SPRITE_SIZE,
            CaptchaModal.SPRITE_SCALE
          );
        }
      }
    }
  } catch (e) {
    // Leave blank — player can still click a different tile
  }

  return { wrapper: wrapper, canvasEl: canvasEl };
};


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/modals/modal-character-select.js ===== */

const CharacterSelectModal = function(element) {

  /*
   * Class CharacterSelectModal
   * Modal for selecting a character from the account's character list
   */

  // Inherit from modal
  Modal.call(this, element);

  // State
  this.__selectedElement = null;
  this.__selectedCharacter = null;
  this.__sessionToken = null;
  this.__host = null;
  this.__characters = null;
  this.__hasEmail = false;

  // Debounce timer for name availability check
  this.__nameCheckTimer = null;

  // Wire up buttons
  document.getElementById("char-select-enter").addEventListener("click", this.__handleEnterGame.bind(this));
  document.getElementById("char-select-new").addEventListener("click", this.__handleNewCharacter.bind(this));
  document.getElementById("char-create-confirm").addEventListener("click", this.__handleCreateConfirm.bind(this));
  document.getElementById("char-create-cancel").addEventListener("click", this.__handleCreateCancel.bind(this));

  // Real-time validation on name input
  let self = this;
  document.getElementById("new-char-name").addEventListener("input", function() {
    self.__validateNameField(this);
  });

  // Arrow-key navigation of the character list. Active only while THIS modal is
  // the open one and the list view (not the create form) is showing.
  document.addEventListener("keydown", function(event) {
    let mgr = (typeof gameClient !== "undefined" && gameClient && gameClient.interface) ? gameClient.interface.modalManager : null;
    if (!mgr || !mgr.isOpened() || mgr.__openedModal !== self) return;
    let createView = document.getElementById("character-create-view");
    if (createView && createView.style.display !== "none") return;   // typing a new name
    if (event.key === "ArrowDown" || event.key === "ArrowUp") {
      event.preventDefault();
      self.__moveSelection(event.key === "ArrowDown" ? 1 : -1);
    }
  });

}

CharacterSelectModal.prototype = Object.create(Modal.prototype);
CharacterSelectModal.constructor = CharacterSelectModal;

// Indexed by character.vocation — character-select list labels. Base
// vocations stay spelled out; only the longer promoted names are
// shortened (Elite Knight = EK, Royal Paladin = RP, etc.).
CharacterSelectModal.prototype.VOCATION_LABELS = [
  "None",     // 0  no vocation
  "Knight",   // 1
  "Paladin",  // 2
  "Sorcerer", // 3
  "Druid",    // 4
  "EK",       // 5  Elite Knight
  "RP",       // 6  Royal Paladin
  "MS",       // 7  Master Sorcerer
  "ED"        // 8  Elder Druid
];

CharacterSelectModal.prototype.handleOpen = function(options) {

  /*
   * Function CharacterSelectModal.handleOpen
   * Callback fired when the modal is opened with character list data
   */

  // Drop focus from whatever submitted the login (password input / login
  // button keep focus after submit). A focused login control would re-run
  // enterGame() on the next Enter press — its own keydown listener and the
  // browser's native Enter-activates-focused-button both bypass this modal.
  if (document.activeElement && document.activeElement !== document.body) {
    document.activeElement.blur();
  }

  this.__sessionToken = options.sessionToken;
  this.__host = options.host;
  this.__characters = options.characters;
  this.__worlds = options.worlds || null;   // multi-world: {id:{name,pvp,online}}
  this.__premiumUntil = options.premiumUntil || null;
  this.__hasEmail = !!options.hasEmail;

  // Stash the full payload so a graceful LOGOUT can return here (owner
  // 2026-07-11: logout -> character screen, not the login form). Single
  // chokepoint: every open of this modal carries the freshest list (login,
  // OAuth, reconnect fallback), so the stash never goes staler than the
  // last time the modal was shown. Session tokens are multi-use with an
  // 8h TTL, so re-entering from the stash stays valid.
  if (gameClient.networkManager) {
    gameClient.networkManager.__lastCharSelectPayload = options;
  }

  // Show or hide the email reminder
  let emailReminder = document.getElementById("email-reminder");
  if (emailReminder) {
    emailReminder.style.display = this.__hasEmail ? "none" : "";
  }

  // Always show the character list view, hide the create view
  this.__showListView();
  this.__renderCharacterList();

}

CharacterSelectModal.prototype.handleConfirm = function() {

  /*
   * Function CharacterSelectModal.handleConfirm
   * Enter key with this modal open (ModalManager.handleConfirm). Without
   * this override the base Modal.handleConfirm returns TRUE and the
   * manager closes the modal — Enter silently dumped the player back to
   * the login screen. Returns false so the manager never auto-closes:
   * this modal only leaves the screen through its own flows
   * (selectCharacter swaps to floater-connecting; Back is action=cancel).
   */

  // Create-character view open: Enter submits the create form instead
  if (document.getElementById("character-create-view").style.display !== "none") {
    if (!document.getElementById("char-create-confirm").disabled) {
      this.__handleCreateConfirm();
    }
    return false;
  }

  // Enter the game with the selected character. The disabled check
  // swallows Enter repeats while a selection is already loading.
  if (!document.getElementById("char-select-enter").disabled) {
    this.__handleEnterGame();
  }
  return false;

}

CharacterSelectModal.prototype.__showListView = function() {

  /*
   * Function CharacterSelectModal.__showListView
   * Shows the character list view and hides the create view
   */

  document.getElementById("character-select-view").style.display = "";
  document.getElementById("character-create-view").style.display = "none";

}

CharacterSelectModal.prototype.__showCreateView = function() {

  /*
   * Function CharacterSelectModal.__showCreateView
   * Shows the create character view and hides the list view
   */

  document.getElementById("character-select-view").style.display = "none";
  document.getElementById("character-create-view").style.display = "";
  document.getElementById("new-char-name").value = "";
  document.getElementById("new-char-name").style.border = "";
  document.getElementById("new-char-name").classList.remove("field-valid", "field-invalid");
  document.getElementById("new-char-sex").value = "";
  let hint = document.getElementById("new-char-name-hint");
  if (hint) { hint.textContent = ""; hint.className = "field-hint"; }
  document.getElementById("char-create-error").style.display = "none";
  document.getElementById("char-create-confirm").disabled = false;
  document.getElementById("char-create-confirm").textContent = "Create Character";

}

CharacterSelectModal.prototype.__renderCharacterList = function() {

  /*
   * Function CharacterSelectModal.__renderCharacterList
   * Renders the list of characters in the modal
   */

  // Clear previous selection
  this.__selectedElement = null;
  this.__selectedCharacter = null;

  // Reset button states
  let enterBtn = document.getElementById("char-select-enter");
  enterBtn.disabled = false;
  enterBtn.textContent = "Enter Game";
  let newBtn = document.getElementById("char-select-new");
  newBtn.disabled = false;
  newBtn.style.opacity = "1";

  let container = document.getElementById("character-select-list");
  container.innerHTML = "";

  if (!this.__characters || this.__characters.length === 0) {
    container.innerHTML = "<div style='padding:8px;text-align:center;'>No characters. Create one below.</div>";
    return;
  }

  // Create a row for each character
  this.__characters.forEach(function(character) {

    let row = document.createElement("div");
    row.className = "character-select-row";

    let nameSpan = document.createElement("span");
    nameSpan.className = "character-select-name";
    nameSpan.textContent = character.name;

    let infoSpan = document.createElement("span");
    infoSpan.className = "character-select-info";
    let vocationLabel = this.VOCATION_LABELS[character.vocation] || "None";
    infoSpan.textContent = "Lvl %s - %s".format(character.level, vocationLabel);

    row.appendChild(nameSpan);

    // Multi-world: compact world PILL between name and level once more
    // than one world is enabled — single-world accounts see no change.
    // The row is a 3-column flex (name ellipsizes, pill + level never
    // shrink), so long names can't collide with the level column on any
    // width/orientation. Pill text color = status light: GREEN online,
    // RED offline (owner spec — no "(Offline)" suffix); neutral gold
    // when liveness is unknown (old server reply).
    if (this.__worlds && Object.keys(this.__worlds).length > 1) {
      let w = this.__worlds[character.world || "main"];
      let worldSpan = document.createElement("span");
      worldSpan.className = "character-select-world";
      worldSpan.style.color = "#e5c46a";
      let label = w ? w.name : (character.world || "main");
      if (w && typeof w.online === "boolean") {
        worldSpan.style.color = w.online ? "#5cb85c" : "#e06c5a";
      }
      worldSpan.textContent = label;
      row.appendChild(worldSpan);
    }

    row.appendChild(infoSpan);

    row.addEventListener("click", this.__handleSelectCharacter.bind(this, row, character.name));

    // Double-click to enter game immediately
    row.addEventListener("dblclick", this.__handleEnterGame.bind(this));

    container.appendChild(row);

  }.bind(this));

  // Auto-select the first character
  if (this.__characters.length > 0) {
    let firstRow = container.querySelector(".character-select-row");
    if (firstRow) {
      this.__handleSelectCharacter(firstRow, this.__characters[0].name);
    }
  }

  // Show premium account status
  let premiumEl = document.getElementById("character-select-premium");

  if (premiumEl) {
    if (this.__premiumUntil && new Date(this.__premiumUntil + "Z") > new Date()) {
      let expDate = new Date(this.__premiumUntil + "Z");
      let days = Math.ceil((expDate - new Date()) / (1000 * 60 * 60 * 24));
      premiumEl.textContent = "Premium Account (" + days + " day" + (days !== 1 ? "s" : "") + " remaining)";
      premiumEl.style.color = "#55ff55";
    } else {
      premiumEl.textContent = "Free Account";
      premiumEl.style.color = "#aaaaaa";
    }
    premiumEl.style.display = "";
  }

}

CharacterSelectModal.prototype.__moveSelection = function(delta) {

  /*
   * Function CharacterSelectModal.__moveSelection
   * Moves the highlighted character up/down (arrow keys), wrapping at the ends,
   * and scrolls it into view. Row order matches this.__characters.
   */

  let rows = document.querySelectorAll("#character-select-list .character-select-row");
  if (!rows.length) return;
  let idx = -1;
  for (let i = 0; i < rows.length; i++) { if (rows[i] === this.__selectedElement) { idx = i; break; } }
  let next = (idx === -1) ? 0 : ((idx + delta) % rows.length + rows.length) % rows.length;
  let character = this.__characters && this.__characters[next];
  if (rows[next] && character) {
    this.__handleSelectCharacter(rows[next], character.name);
    try { rows[next].scrollIntoView({ block: "nearest" }); } catch (e) {}
  }

};

CharacterSelectModal.prototype.__handleSelectCharacter = function(element, characterName) {

  /*
   * Function CharacterSelectModal.__handleSelectCharacter
   * Handles clicking a character row to select it
   */

  // Deselect previous
  if (this.__selectedElement !== null) {
    this.__selectedElement.className = "character-select-row";
  }

  // Select new
  this.__selectedElement = element;
  this.__selectedCharacter = characterName;
  element.className = "character-select-row selected";

}

CharacterSelectModal.prototype.__handleEnterGame = function() {

  /*
   * Function CharacterSelectModal.__handleEnterGame
   * Sends the character selection to the server to get an HMAC token
   */

  if (this.__selectedCharacter === null) {
    return;
  }

  // Show loading feedback on the Enter Game button
  let enterBtn = document.getElementById("char-select-enter");
  enterBtn.disabled = true;
  enterBtn.textContent = "Loading..";

  // Grey out Create Character while loading
  let newBtn = document.getElementById("char-select-new");
  newBtn.disabled = true;
  newBtn.style.opacity = "0.5";

  // Activate keep-alive audio now (user gesture) — browser autoplay policy
  // requires a user interaction before audio can play
  gameClient.interface.soundManager.activateAntiConnectionLoss();

  // Store premium status on gameClient so settings UI can check it
  gameClient.__premiumUntil = this.__premiumUntil;

  // Store this character's creation date so the Hub can grey out the games age-gate.
  let __sel = (this.__characters || []).find(function (c) { return c && c.name === this.__selectedCharacter; }.bind(this));
  gameClient.__accountCreatedAt = (__sel && __sel.createdAt) ? __sel.createdAt : null;

  gameClient.networkManager.selectCharacter(this.__sessionToken, this.__selectedCharacter, this.__host);

}

CharacterSelectModal.prototype.__handleNewCharacter = function() {

  /*
   * Function CharacterSelectModal.__handleNewCharacter
   * Switches to the create character view
   */

  if (this.__characters && this.__characters.length >= 6) {
    gameClient.interface.modalManager.open("floater-connecting", "You can have a maximum of 6 characters per account.");
    return;
  }

  this.__showCreateView();

}

CharacterSelectModal.prototype.__handleCreateConfirm = function() {

  /*
   * Function CharacterSelectModal.__handleCreateConfirm
   * Handles clicking the Create Character button
   */

  let name = document.getElementById("new-char-name").value.trim().toLowerCase();
  let sex = document.getElementById("new-char-sex").value;
  let errorEl = document.getElementById("char-create-error");

  // Validate: must be lowercase letters with single spaces, 3-20 chars
  if (name.length < 3 || name.length > 20) {
    errorEl.textContent = "Character name must be 3-20 characters.";
    errorEl.style.display = "";
    return;
  }

  if (!/^[a-z]+(?: [a-z]+)*$/.test(name)) {
    errorEl.textContent = "Use only letters with single spaces between words.";
    errorEl.style.display = "";
    return;
  }

  if (sex !== "male" && sex !== "female") {
    errorEl.textContent = "Please choose a sex.";
    errorEl.style.display = "";
    return;
  }

  // Hide any previous error and show loading feedback
  errorEl.style.display = "none";
  let createBtn = document.getElementById("char-create-confirm");
  createBtn.disabled = true;
  createBtn.textContent = "Creating...";

  gameClient.networkManager.createCharacterOnAccount(this.__sessionToken, name, sex, function(error, characters, premiumUntil) {

    createBtn.disabled = false;
    createBtn.textContent = "Create Character";

    if (error) {
      errorEl.textContent = error;
      errorEl.style.display = "";
      return;
    }

    // Update the character list, switch back to list view
    this.__characters = characters;
    if (premiumUntil !== undefined) {
      this.__premiumUntil = premiumUntil;
    }
    this.__showListView();
    this.__renderCharacterList();

  }.bind(this));

}

CharacterSelectModal.prototype.__handleCreateCancel = function() {

  /*
   * Function CharacterSelectModal.__handleCreateCancel
   * Switches back to the character list view
   */

  this.__showListView();

}



CharacterSelectModal.prototype.__validateNameField = function(field) {

  /*
   * Function CharacterSelectModal.__validateNameField
   * Real-time validation for the character name field with availability check
   */

  let hint = document.getElementById("new-char-name-hint");
  let val = field.value.toLowerCase().trim();

  if (val.length === 0) {
    field.classList.remove("field-valid", "field-invalid");
    if (hint) { hint.textContent = ""; hint.className = "field-hint"; }
    return;
  }

  if (val.length < 3) {
    field.classList.remove("field-valid");
    field.classList.add("field-invalid");
    if (hint) { hint.textContent = "Too short (min 3 characters)"; hint.className = "field-hint error"; }
    return;
  }

  if (!/^[a-z]+(?: [a-z]+)*$/.test(val)) {
    field.classList.remove("field-valid");
    field.classList.add("field-invalid");
    if (hint) { hint.textContent = "Only letters with single spaces"; hint.className = "field-hint error"; }
    return;
  }

  // Debounce the server check
  let self = this;
  clearTimeout(this.__nameCheckTimer);
  field.classList.remove("field-valid", "field-invalid");
  if (hint) { hint.textContent = "Checking..."; hint.className = "field-hint"; }

  this.__nameCheckTimer = setTimeout(function() {
    fetch("/api/login/check-name", {
      "method": "POST",
      "headers": { "Content-Type": "application/json" },
      "body": JSON.stringify({ "name": val })
    }).then(function(response) {
      return response.json();
    }).then(function(data) {
      if (field.value.toLowerCase().trim() !== val) return;
      if (data.available) {
        field.classList.remove("field-invalid");
        field.classList.add("field-valid");
        if (hint) { hint.textContent = "Name available"; hint.className = "field-hint success"; }
      } else {
        field.classList.remove("field-valid");
        field.classList.add("field-invalid");
        if (hint) { hint.textContent = "Name already taken"; hint.className = "field-hint error"; }
      }
    }).catch(function() {
      field.classList.remove("field-valid", "field-invalid");
      if (hint) { hint.textContent = ""; hint.className = "field-hint"; }
    });
  }, 400);

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/modals/modal-character.js ===== */

"use strict";

const CharacterModal = function (id) {

  /*
   * Class CharacterModal
   * Hub → Character: one window, journal-style TABS (Frags | Blessings |
   * Outfit). Frags/Blessings render from the CHARACTER_INFO payload that
   * arrives when the window opens (cached for tab switches and the outfit
   * dialog's back button — no extra round-trips). The Outfit tab is a
   * launcher: it opens the outfit dialog with a dynamic back target so its
   * standard ‹ button returns here. Chrome (‹ / ◐) comes from the
   * modal-manager framework — never hand-rolled.
   */

  Modal.call(this, id);

  this.__lastInfo = null;
  this.__activeTab = "skills";

  this.__tabButtons = Array.from(this.element.querySelectorAll(".char-tab"));
  this.__tabContents = {
    "skills": document.getElementById("char-tab-skills"),
    "frags": document.getElementById("char-tab-frags"),
    "blessings": document.getElementById("char-tab-blessings")
  };

  let self = this;
  this.__tabButtons.forEach(function (btn) {
    btn.addEventListener("click", function () {
      let tab = btn.dataset.tab;
      if (tab === "outfit") {
        // Launcher tab: the outfit dialog is its own window (canvas preview,
        // color picker). Standard ‹ returns here; HUD-opened dialogs never
        // get one (target cleared in OutfitModal.handleClose).
        let mgr = gameClient.interface.modalManager;
        let outfit = mgr.get("outfit-modal");
        if (outfit) outfit.__backTarget = "character-modal";
        return mgr.open("outfit-modal");
      }
      self.__switchTab(tab);
    });
  });

};

CharacterModal.prototype = Object.create(Modal.prototype);
CharacterModal.constructor = CharacterModal;

CharacterModal.prototype.handleOpen = function (info) {

  // Reopened without fresh data (outfit back button) → render the cache.
  if (info) this.__lastInfo = info;
  info = this.__lastInfo;
  if (!info) return;

  let nameEl = document.getElementById("character-header");
  if (nameEl && gameClient.player) {
    let name = gameClient.player.name || "";
    let level = (gameClient.player.skills && gameClient.player.skills.level) || "";
    nameEl.textContent = name + (level ? " — Level " + level : "");
  }

  this.__renderSkills();
  this.__renderFrags(info.frags || {});
  this.__renderBlessings(info.blessings || {});
  this.__switchTab(this.__activeTab === "outfit" ? "skills" : this.__activeTab);

};

CharacterModal.prototype.__switchTab = function (tab) {

  this.__activeTab = tab;

  // Stats move constantly (XP, HP, soul) — refresh on every visit so the
  // tab never shows open-time values after a long session.
  if (tab === "skills") this.__renderSkills();

  this.__tabButtons.forEach(function (btn) {
    btn.classList.toggle("active", btn.dataset.tab === tab);
  });

  Object.keys(this.__tabContents).forEach(function (name) {
    let el = this.__tabContents[name];
    if (el) el.style.display = (name === tab) ? "" : "none";
  }.bind(this));

};

CharacterModal.prototype.__renderSkills = function () {

  /*
   * Function CharacterModal.__renderSkills
   * Basic character stats (owner 2026-07-20: level, experience, soul
   * points notably) — rendered entirely from CLIENT state, no payload.
   * XP-to-next uses the same 7.6 experience formula as entities/skills.js
   * (table[i] = f(i+1), so xp needed to REACH level L is f(L)).
   */

  let el = this.__tabContents.skills;
  if (!el || !gameClient.player) return;
  let p = gameClient.player;
  let skills = p.skills || {};
  let raw = skills.__skills || {};
  let level = skills.level || 1;
  let xp = raw.experience || 0;
  let expAt = function (x) { return Math.round((50 / 3) * (Math.pow(x, 3) - 6 * Math.pow(x, 2) + 17 * x - 12)); };
  let curBase = expAt(level);
  let next = expAt(level + 1);
  let pct = next > curBase ? Math.max(0, Math.min(100, ((xp - curBase) / (next - curBase)) * 100)) : 0;
  let toNext = Math.max(0, next - xp);
  let fmtNum = function (n) { return String(n).replace(/\B(?=(\d{3})+(?!\d))/g, ","); };

  let html = this.__row("Level", level, pct > 0 ? pct.toFixed(1) + "% towards " + (level + 1) : null);
  html += this.__row("Experience", fmtNum(xp), fmtNum(toNext) + " to go");
  if (typeof p.state.soul === "number") {
    html += this.__row("Soul Points", p.state.soul, null, "#9cf");
  }
  let magicPts = raw.magic || 0;
  let ml = (typeof skills.__getSkillLevel === "function") ? skills.__getSkillLevel("magic", magicPts) : 0;
  html += this.__row("Magic Level", ml, null);
  // Food timer: the skills window owns the live countdown — read its
  // current seconds (this tab re-renders on every visit, so the value is
  // fresh each time you open it). Owner 2026-07-20: HP/mana/capacity
  // dropped (visible elsewhere), food added.
  let foodSec = 0;
  try {
    let sw = gameClient.interface.windowManager.getWindow("skill-window");
    foodSec = (sw && sw.__foodTimerSeconds) ? sw.__foodTimerSeconds : 0;
  } catch (e) { /* no skills window — show empty */ }
  let foodStr = Math.floor(foodSec / 60) + ":" + String(foodSec % 60).padStart(2, "0");
  html += this.__row("Food", foodSec > 0 ? foodStr : "None", null, foodSec > 0 ? "#8c8" : "#888");
  html += this.__row("Speed", p.state.speed || 0, null);
  el.innerHTML = html;

};

// ---- render helpers (Hunt Analyzer row language) ----

CharacterModal.prototype.__esc = function (str) {
  return String(str).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
};

CharacterModal.prototype.__row = function (label, value, sub, valueColor) {
  return "<div style=\"display:flex;justify-content:space-between;align-items:baseline;gap:12px;padding:5px 0;border-bottom:1px solid rgba(255,255,255,0.06);\">"
    + "<span style=\"color:#bbb;white-space:nowrap;\">" + this.__esc(label) + "</span>"
    + "<span style=\"text-align:right;\"><b style=\"color:" + (valueColor || "#eee") + "\">" + this.__esc(value) + "</b>"
    + (sub ? "<span style=\"color:#888;font-size:11px;margin-left:8px;\">" + this.__esc(sub) + "</span>" : "")
    + "</span></div>";
};

CharacterModal.prototype.__renderFrags = function (f) {

  let el = this.__tabContents.frags;
  if (!el) return;
  let self = this;
  let fmt = this.__formatDuration;
  let fragRow = function (label, count, cap, dropMs) {
    let sub = (dropMs !== null && dropMs !== undefined && count > 0)
      ? "drops in " + fmt(dropMs) : null;
    let color = count >= cap && cap > 0 ? "#e66" : "#eee";
    return self.__row(label, count + " / " + cap, sub, color);
  };
  let skullColors = { "None": "#8c8", "White": "#eee", "Red": "#e66", "Black": "#e66", "Pink (cheater)": "#e6a" };
  el.innerHTML = fragRow("Daily", f.daily || 0, f.dailyCap || 0, f.dailyDropMs)
    + fragRow("Weekly", f.weekly || 0, f.weeklyCap || 0, f.weeklyDropMs)
    + fragRow("Monthly", f.monthly || 0, f.monthlyCap || 0, f.monthlyDropMs)
    + this.__row("Skull", f.skull || "None", f.skullExpiresMs ? "expires in " + fmt(f.skullExpiresMs) : null,
        skullColors[f.skull] || "#eee");

};

CharacterModal.prototype.__renderBlessings = function (b) {

  let el = this.__tabContents.blessings;
  if (!el) return;
  let esc = this.__esc;
  let names = b.pilgrimage || [];
  let html = this.__row("Pilgrimage", names.length + " / 5", null, names.length === 5 ? "#8c8" : "#eee");
  if (names.length > 0) {
    html += "<div style=\"padding:4px 0 2px;\">" + names.map(function (n) {
      return "<div style=\"color:#9c9;font-size:12px;padding:1px 0 1px 10px;\">✦ " + esc(n) + "</div>";
    }).join("") + "</div>";
  }
  html += this.__row("Temple blessing", b.temple ? (names.length === 5 ? "Held in reserve" : "Active") : "None",
    null, b.temple ? "#8c8" : "#888");
  if (b.halfSpark) {
    let otherNpc = b.halfSpark === "Earth" ? "Pydar (Fire half)" : "Kawill (Earth half)";
    html += this.__row("Half Spark", b.halfSpark + " half held", "visit " + otherNpc, "#fc6");
  }
  if (typeof b.lossPct === "number") {
    html += this.__row("On death", b.lossPct + "% XP/skill loss",
      b.itemsProtected ? "items protected" : "items drop without AoL",
      b.lossPct === 0 ? "#8c8" : "#e96");
  }
  if (b.consumeNote) {
    html += "<div style=\"color:#888;font-size:11px;margin-top:6px;\">" + esc(b.consumeNote) + "</div>";
  }
  el.innerHTML = html;

};

CharacterModal.prototype.__formatDuration = function (ms) {

  /*
   * Function CharacterModal.__formatDuration
   * Compact duration: "2d 5h", "5h 12m", "12m", "45s".
   */

  let s = Math.max(0, Math.floor(ms / 1000));
  let d = Math.floor(s / 86400);
  let h = Math.floor((s % 86400) / 3600);
  let m = Math.floor((s % 3600) / 60);
  if (d > 0) return d + "d " + h + "h";
  if (h > 0) return h + "h " + m + "m";
  if (m > 0) return m + "m";
  return (s % 60) + "s";

};


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/modals/modal-chat.js ===== */

"use strict";

const ChatModal = function(element) {

  /*
   * Class ChatModal
   * Wrapper for the modal that can open chat windows
   */

  // Inherit from modal
  Modal.call(this, element);

  // Event listeners
  document.getElementById("open-private-channel-input").addEventListener("focus", this.__handleFocus.bind(this));

  // Bind click and double-click on channel list items
  let self = this;
  let list = document.getElementById("channel-select");

  list.addEventListener("click", function(event) {
    let item = event.target.closest(".channel-select-item");
    if (!item) return;
    // Deselect all, select clicked
    let items = list.querySelectorAll(".channel-select-item");
    for (let i = 0; i < items.length; i++) {
      items[i].classList.remove("selected");
    }
    item.classList.add("selected");
  });

  // Trade Offer row (owner 2026-07-17): opens the /trade broadcast module
  // instead of joining a channel. Server answers with TradeInfoPacket,
  // which opens trade-modal; MODAL_PARENT brings the back button here.
  let tradeRow = document.getElementById("open-trade-module");
  if (tradeRow) {
    tradeRow.addEventListener("click", function(event) {
      event.stopPropagation();
      gameClient.interface.channelManager.sendMessageText("/trade", undefined, true);
    });
  }

  list.addEventListener("dblclick", function(event) {
    let item = event.target.closest(".channel-select-item");
    if (!item) return;
    self.__buttonClick({"target": self.element.querySelector("button[action='confirm']")});
  });

}

ChatModal.prototype = Object.create(Modal.prototype);
ChatModal.constructor = ChatModal;

ChatModal.prototype.handleOpen = function() {

  /*
   * Function ChatModal.handleOpen
   * Wire the "open private channel" name field to the in-game VirtualKeyboard
   * so it's typeable on mobile — the client suppresses the native keyboard, so
   * an un-wired input is dead on phones (HARD RULE: every modal text input must
   * use VirtualKeyboard). Idempotent; safe to call on every open.
   */

  let input = document.getElementById("open-private-channel-input");
  if (input && typeof this.wireVirtualKeyboard === "function") {
    let self = this;
    this.wireVirtualKeyboard(input, function() {
      self.__handleOpenPrivateChannel();
      gameClient.interface.modalManager.close();
    }, /[a-z ]/i);
  }

};

ChatModal.prototype.handleConfirm = function() {

  /*
   * Function ChatModal.handleConfirm
   * Callback fired when confirm action is pressed
   */

  // Get the selected channel item
  let selected = document.querySelector("#channel-select .channel-select-item.selected");

  // When none are selected: try opening a private channel
  if (!selected) {
    return this.__handleOpenPrivateChannel();
  }

  // Get attributes from the selected row
  let type = selected.getAttribute("channelType");
  let id = selected.getAttribute("channelId");

  // Either open a local or global channel (global channels require informing the server)
  if(type === "local") {
    gameClient.interface.channelManager.addLocalChannel(id);
  } else {
    gameClient.interface.channelManager.joinChannel(Number(id), selected.textContent);
  }

  // Close the modal
  return true;

}

ChatModal.prototype.__handleOpenPrivateChannel = function() {

  /*
   * Function ChatModal.__handleOpenPrivateChannel
   * Handles opening of a private channel with another character
   */

  // Read the requested player name from the DOM
  let playerName = document.getElementById("open-private-channel-input").value.trim();

  // Add the private channel
  gameClient.interface.channelManager.addPrivateChannel(playerName);

  // Close the modal
  return true;

}

ChatModal.prototype.__handleFocus = function() {

  /*
   * Function ChatModal.__handleFocus
   * Handles focus event by deselecting channels when typing a private name
   */

  let items = document.querySelectorAll("#channel-select .channel-select-item");
  for (let i = 0; i < items.length; i++) {
    items[i].classList.remove("selected");
  }

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/modals/modal-chess.js ===== */

const ChessModal = function (id) {

  /*
   * Class ChessModal
   * Two views in one modal:
   *  - LOBBY: challenge a player by name + accept/decline pending challenges.
   *  - BOARD: an 8x8 canvas chess board (tap/click a piece then a destination),
   *    clock, resign. Server-authoritative — the board renders CHESS_STATE and
   *    moves are validated server-side; illegal taps just re-sync.
   * Server actions are driven through the existing chat commands (like the house
   * buttons): /chess <name>, /chessaccept <name>, /chessdecline <name>, /resign.
   */

  Modal.call(this, id);

  this.__lobbyView = document.getElementById("chess-lobby-view");
  this.__boardView = document.getElementById("chess-board-view");
  this.__incomingEl = document.getElementById("chess-incoming");
  this.__infoEl = document.getElementById("chess-info");
  this.__clockEl = document.getElementById("chess-clock");
  this.__titleEl = document.getElementById("chess-title");

  this.__canvas = (typeof Canvas !== "undefined") ? new Canvas("chess-canvas", 360, 360) : null;
  this.__SIZE = 360;
  this.__CELL = 360 / 8;

  this.__state = null;       // last CHESS_STATE payload
  this.__selected = null;    // selected from-square index, or null
  this.__clockTimer = null;  // 1s display countdown
  this.__clockLeft = 0;

  let self = this;

  let chBtn = document.getElementById("chess-challenge-btn");
  let chName = document.getElementById("chess-challenge-name");
  if (chBtn) chBtn.addEventListener("click", function () { self.__sendChallenge(); });
  if (chName) chName.addEventListener("keydown", function (e) { if (e.key === "Enter") { e.preventDefault(); self.__sendChallenge(); } });

  // Wager presets (None/1k/10k/100k): pick a stake (None default), then Challenge.
  this.__selectedStake = 0;
  this.__wirePresets();

  let resign = document.getElementById("chess-resign-btn");
  if (resign) resign.addEventListener("click", function () {
    self.__cmd("/resign");
  });

  let back = document.getElementById("chess-back-btn");
  if (back) back.addEventListener("click", function () {
    gameClient.interface.modalManager.open("games-modal");
  });

  if (this.__canvas) {
    this.__canvas.canvas.addEventListener("click", this.__onBoardClick.bind(this));
    this.__canvas.canvas.addEventListener("touchend", this.__onBoardTouch.bind(this), { passive: false });
  }

};

ChessModal.prototype = Object.create(Modal.prototype);
ChessModal.prototype.constructor = ChessModal;

// ︎ = VARIATION SELECTOR-15 (text presentation). U+265F ♟ defaults to
// EMOJI presentation (Unicode 11) — Windows/Android canvas then draws the
// color-emoji bitmap and IGNORES fillStyle, so WHITE pawns rendered black
// (Konfa 2026-07-04). The other five glyphs have no emoji mapping but get
// the selector too for uniformity. Same fix as the D-pad arrows.
ChessModal.prototype.GLYPH = { k: "♚︎", q: "♛︎", r: "♜︎", b: "♝︎", n: "♞︎", p: "♟︎" };

ChessModal.prototype.__cmd = function (text) {
  let cm = gameClient.interface && gameClient.interface.channelManager;
  if (cm && typeof cm.sendMessageText === "function") cm.sendMessageText(text);
};

ChessModal.prototype.__sendChallenge = function () {
  let inp = document.getElementById("chess-challenge-name");
  let name = inp ? (inp.value || "").trim() : "";
  if (!name) return;
  let self = this;
  let amount = this.__selectedStake || 0;
  let doSend = function () { self.__cmd("/chess " + name + (amount > 0 ? (" " + amount) : "")); if (inp) inp.value = ""; };
  if (amount > 0) this.wagerConfirm(document.getElementById("chess-wager-confirm"), amount, doSend); else doSend();
};

ChessModal.prototype.handleOpen = function () {
  // Mobile virtual keyboard for the challenge-name box (idempotent).
  this.wireVirtualKeyboard(document.getElementById("chess-challenge-name"), this.__sendChallenge.bind(this), /[a-z ]/i);
  // Ask the server for our lobby (+ board if we're mid-game). Default to lobby
  // view until a CHESS_STATE arrives.
  this.__showLobby();
  this.__cmd("/chess");
};

ChessModal.prototype.handleClose = function () {
  this.__stopClock();
  this.__testMode = false;
  if (this.__endCloseTimer) { clearTimeout(this.__endCloseTimer); this.__endCloseTimer = null; }
};

/*
 * Function ChessModal.showTestBoard
 * Dev/QA: render a fake initial board (no real match) so the board UI can be
 * eyeballed on any device. Moves won't do anything (server has no match).
 */
ChessModal.prototype.showTestBoard = function () {
  this.__testMode = true;
  let board = "RNBQKBNR" + "PPPPPPPP" + ".".repeat(32) + "pppppppp" + "rnbqkbnr";
  let legal = [];
  for (let i = 8; i <= 15; i++) { legal.push({ f: i, t: i + 8 }); legal.push({ f: i, t: i + 16 }); }
  this.onState({
    id: 0, white: (gameClient.player && gameClient.player.name) || "You", black: "Test Bot",
    board: board, turn: "w", youAre: "w", status: "active", result: null,
    check: false, lastMove: { from: 12, to: 28 }, turnLimitSec: 60, secondsLeft: 60, legal: legal
  });
};

ChessModal.prototype.__showLobby = function () {
  if (this.__lobbyView) this.__lobbyView.style.display = "";
  if (this.__boardView) this.__boardView.style.display = "none";
  if (this.__titleEl) this.__titleEl.textContent = "Chess";
  this.__stopClock();
};

ChessModal.prototype.__showBoard = function () {
  if (this.__lobbyView) this.__lobbyView.style.display = "none";
  if (this.__boardView) this.__boardView.style.display = "";
};

/* ---- lobby ---- */

ChessModal.prototype.onLobby = function (info) {
  // /testgamechess shows a fake board with no real match — ignore the lobby
  // push the open triggers so it doesn't flip the view back.
  if (this.__testMode) return;
  let bal = document.getElementById("chess-balance");
  if (bal) bal.textContent = this.__gameBalanceText(info);
  this.__applyWagerVisibility(info);   // hide stake presets when real-gold staking is off
  this.__applyBusyNotice(info);        // in-modal "already in another game" banner
  this.__renderIncoming(info.incoming || []);
  // Only flip to the lobby view when we're not in a live game (the board view
  // is driven by CHESS_STATE).
  if (!info.inMatch) this.__showLobby();
};

ChessModal.prototype.__renderIncoming = function (list) {
  if (!this.__incomingEl) return;
  if (!list.length) {
    this.__incomingEl.innerHTML = '<div class="chess-empty">No pending challenges.</div>';
    return;
  }
  let self = this;
  this.__incomingEl.innerHTML = "";
  list.forEach(function (c) {
    let nm = String(c.from == null ? "" : c.from);
    let row = document.createElement("div");
    row.className = "chess-incoming-row";
    let label = document.createElement("span");
    label.className = "chess-incoming-name";
    label.textContent = nm + "  (" + (c.secs || 0) + "s)" + (c.wager > 0 ? "  💰" + c.wager : "");
    let acc = document.createElement("button");
    acc.className = "chess-btn chess-accept";
    acc.textContent = "Accept";
    let w = c.wager || 0;
    acc.addEventListener("click", function () {
      if (w > 0) self.wagerConfirm(document.getElementById("chess-wager-confirm"), w, function () { self.__cmd("/chessaccept " + nm); });
      else self.__cmd("/chessaccept " + nm);
    });
    let dec = document.createElement("button");
    dec.className = "chess-btn chess-decline";
    dec.textContent = "Deny";
    dec.addEventListener("click", function () { self.__cmd("/chessdecline " + nm); });
    row.appendChild(label);
    row.appendChild(acc);
    row.appendChild(dec);
    self.__incomingEl.appendChild(row);
  });
};

/* ---- board ---- */

ChessModal.prototype.onState = function (info) {
  this.__state = info;
  this.__selected = null;
  this.__showBoard();

  // Title + info line.
  let opp = info.youAre === "w" ? info.black : info.white;
  if (this.__titleEl) this.__titleEl.textContent = "Chess vs " + opp;

  let line;
  if (info.status !== "active") {
    if (info.result && info.result.reason === "checkmate") {
      line = (info.result.winner === this.__myName() ? "Checkmate — you win!" : "Checkmate — you lose.");
    } else if (info.result && (info.result.reason === "stalemate" || info.result.reason === "draw50")) {
      line = "Draw (" + info.result.reason + ").";
    } else if (info.result && info.result.reason === "resign") {
      line = (info.result.winner === this.__myName() ? "Opponent resigned — you win!" : "You resigned.");
    } else if (info.result && info.result.reason === "timeout") {
      line = (info.result.winner === this.__myName() ? "Opponent ran out of time — you win!" : "You ran out of time.");
    } else {
      line = "Game over.";
    }
    this.__stopClock();
    // Hide Resign once the game is over (you can't resign a finished game) — it
    // otherwise lingered for the few seconds before the board auto-closes.
    let rbOver = document.getElementById("chess-resign-btn");
    if (rbOver) rbOver.style.display = "none";
    // Game over → close the board shortly after the result shows, so resigning
    // (and any other ending) auto-closes the module.
    let self = this;
    if (this.__endCloseTimer) clearTimeout(this.__endCloseTimer);
    this.__endCloseTimer = setTimeout(function () {
      let mgr = gameClient.interface.modalManager;
      if (mgr.isOpened() && mgr.__openedModal === self) mgr.close();
    }, 3500);
  } else {
    let myTurn = info.turn === info.youAre;
    line = myTurn ? "Your move." : "Waiting for opponent…";
    if (info.check) line = "Check! " + line;
    this.__startClock(info.secondsLeft || 0, myTurn);
  }
  if (this.__infoEl) this.__infoEl.textContent = line + "  (You: " + (info.youAre === "w" ? "White" : "Black") + ")";

  this.__draw();
};

ChessModal.prototype.__myName = function () {
  return (gameClient.player && gameClient.player.name) ? gameClient.player.name : null;
};

ChessModal.prototype.__startClock = function (secs, myTurn) {
  this.__stopClock();
  this.__clockLeft = secs;
  this.__renderClock(myTurn);
  let self = this;
  this.__clockTimer = setInterval(function () {
    self.__clockLeft = Math.max(0, self.__clockLeft - 1);
    self.__renderClock(myTurn);
    if (self.__clockLeft <= 0) self.__stopClock();
  }, 1000);
};

ChessModal.prototype.__stopClock = function () {
  if (this.__clockTimer) { clearInterval(this.__clockTimer); this.__clockTimer = null; }
};

ChessModal.prototype.__renderClock = function (myTurn) {
  if (!this.__clockEl) return;
  this.__clockEl.textContent = (myTurn ? "Your turn: " : "Their turn: ") + this.__clockLeft + "s";
  this.__clockEl.style.color = (myTurn && this.__clockLeft <= 15) ? "#e06060" : "#cccccc";
};

// Board orientation: white player sees white at the bottom, black sees black.
ChessModal.prototype.__idxToScreen = function (index) {
  let file = index % 8, rank = (index / 8) | 0;
  let black = this.__state && this.__state.youAre === "b";
  let col = black ? (7 - file) : file;
  let row = black ? rank : (7 - rank);
  return { col: col, row: row };
};
ChessModal.prototype.__screenToIdx = function (col, row) {
  let black = this.__state && this.__state.youAre === "b";
  let file = black ? (7 - col) : col;
  let rank = black ? row : (7 - row);
  return rank * 8 + file;
};

ChessModal.prototype.__draw = function () {
  if (!this.__canvas || !this.__state) return;
  let ctx = this.__canvas.context;
  let CELL = this.__CELL;
  let board = this.__state.board || "";
  let legalTo = {};
  if (this.__selected !== null && this.__state.legal) {
    for (let i = 0; i < this.__state.legal.length; i++) {
      if (this.__state.legal[i].f === this.__selected) legalTo[this.__state.legal[i].t] = true;
    }
  }

  for (let index = 0; index < 64; index++) {
    let s = this.__idxToScreen(index);
    let x = s.col * CELL, y = s.row * CELL;
    let light = ((s.col + s.row) % 2 === 0);
    ctx.fillStyle = light ? "#e8d3a8" : "#9d6b3f";
    ctx.fillRect(x, y, CELL, CELL);

    // Last-move highlight.
    let lm = this.__state.lastMove;
    if (lm && (index === lm.from || index === lm.to)) {
      ctx.fillStyle = "rgba(255,235,90,0.35)";
      ctx.fillRect(x, y, CELL, CELL);
    }
    // Selected square.
    if (index === this.__selected) {
      ctx.fillStyle = "rgba(120,200,120,0.55)";
      ctx.fillRect(x, y, CELL, CELL);
    }

    // Piece.
    let p = board.charAt(index);
    if (p && p !== ".") {
      let g = this.GLYPH[p.toLowerCase()];
      if (g) {
        let isWhite = (p === p.toUpperCase());
        ctx.font = "bold " + Math.floor(CELL * 0.78) + "px serif";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.lineWidth = 2;
        ctx.strokeStyle = isWhite ? "#222" : "#000";
        ctx.fillStyle = isWhite ? "#f7f7f7" : "#1c1c1c";
        let cx = x + CELL / 2, cy = y + CELL / 2 + 1;
        ctx.strokeText(g, cx, cy);
        ctx.fillText(g, cx, cy);
      }
    }

    // Legal destination dot.
    if (legalTo[index]) {
      ctx.beginPath();
      ctx.fillStyle = "rgba(40,90,40,0.55)";
      ctx.arc(x + CELL / 2, y + CELL / 2, CELL * 0.16, 0, 2 * Math.PI);
      ctx.fill();
    }
  }
};

ChessModal.prototype.__cellFromEvent = function (clientX, clientY) {
  let rect = this.__canvas.canvas.getBoundingClientRect();
  if (!rect.width || !rect.height) return null;
  let col = Math.floor((clientX - rect.left) / (rect.width / 8));
  let row = Math.floor((clientY - rect.top) / (rect.height / 8));
  if (col < 0 || col > 7 || row < 0 || row > 7) return null;
  return this.__screenToIdx(col, row);
};

ChessModal.prototype.__onBoardClick = function (event) {
  this.__handleSquare(this.__cellFromEvent(event.clientX, event.clientY));
};

ChessModal.prototype.__onBoardTouch = function (event) {
  event.preventDefault();
  let t = event.changedTouches && event.changedTouches[0];
  if (!t) return;
  this.__handleSquare(this.__cellFromEvent(t.clientX, t.clientY));
};

ChessModal.prototype.__handleSquare = function (index) {
  if (index === null || !this.__state) return;
  let st = this.__state;
  if (st.status !== "active" || st.turn !== st.youAre) return; // not your move

  // If a square is selected and this is a legal destination → move.
  if (this.__selected !== null && st.legal) {
    for (let i = 0; i < st.legal.length; i++) {
      if (st.legal[i].f === this.__selected && st.legal[i].t === index) {
        let promoCode = st.legal[i].p ? ({ q: 1, r: 2, b: 3, n: 4 })[st.legal[i].p] : 0;
        if (typeof ChessMovePacket !== "undefined") gameClient.send(new ChessMovePacket(this.__selected, index, promoCode));
        this.__selected = null;
        return; // server will push the new state
      }
    }
  }

  // Otherwise (re)select if this square has one of my pieces with legal moves.
  let hasMove = false;
  if (st.legal) for (let i = 0; i < st.legal.length; i++) { if (st.legal[i].f === index) { hasMove = true; break; } }
  this.__selected = hasMove ? index : null;
  this.__draw();
};


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/modals/modal-confirm.js ===== */

const ConfirmModal = function(element) {

  /*
   * Class ConfirmModal
   * Modal that pops up to ask for a confirmation and apply a callback if succesful
   */

  // Inherit from modal
  Modal.call(this, element);

  this.__confirmCallback = Function.prototype;

}

ConfirmModal.prototype = Object.create(Modal.prototype);
ConfirmModal.constructor = ConfirmModal;

ConfirmModal.prototype.handleOpen = function(callback) {

  /*
   * Function ConfirmModal.handleOpen
   * Resets title/body to defaults and sets the confirm callback
   */

  // Reset title and body to defaults so previous customizations don't leak
  this.setTitle("Confirm");
  this.element.querySelector(".modal-body > div").innerHTML = "Are you sure?";

  // Sets the callback
  this.__confirmCallback = callback;

}

ConfirmModal.prototype.handleConfirm = function() {

  /*
   * Function ConfirmModal.handleConfirm
   * Callback fired when confirm action is pressed
   */

  // Apply and reset the callback
  this.__confirmCallback(name);
  this.__confirmCallback = Function.prototype;

  return true;

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/ui/modals/modal-create-account.js ===== */

const CreateAccountModal = function(element) {

  /*
   * Class CreateAccountModal
   * Modal for creating a new account with validation and auto-login on success
   */

  // Inherit from modal
  Modal.call(this, element);

  // Debounce timers for availability checks
  this.__nameCheckTimer = null;
  this.__accountCheckTimer = null;

  // Attach real-time validation listeners
  let self = this;

  document.getElementById("create-name").addEventListener("input", function() {
    self.__validateNameField(this);
  });

  document.getElementById("create-username").addEventListener("input", function() {
    self.__validateAccountField(this);
  });

  document.getElementById("create-password").addEventListener("input", function() {
    self.__validatePasswordField(this);
  });

}

CreateAccountModal.prototype = Object.create(Modal.prototype);
CreateAccountModal.constructor = CreateAccountModal;

CreateAccountModal.prototype.__setHint = function(id, text, type) {

  /*
   * Function CreateAccountModal.__setHint
   * Sets the hint text and style for a field
   */

  let hint = document.getElementById(id);
  if (!hint) return;
  hint.textContent = text;
  hint.className = "field-hint" + (type ? " " + type : "");

}

CreateAccountModal.prototype.__setFieldState = function(field, valid) {

  /*
   * Function CreateAccountModal.__setFieldState
   * Adds valid/invalid CSS class to an input field
   */

  field.classList.remove("field-valid", "field-invalid");
  if (valid === true) field.classList.add("field-valid");
  else if (valid === false) field.classList.add("field-invalid");

}

CreateAccountModal.prototype.__validateNameField = function(field) {

  /*
   * Function CreateAccountModal.__validateNameField
   * Real-time validation for the character name field with availability check
   */

  let val = field.value.toLowerCase().trim();

  if (val.length === 0) {
    this.__setFieldState(field, null);
    this.__setHint("create-name-hint", "", "");
    return;
  }

  if (val.length < 3) {
    this.__setFieldState(field, false);
    this.__setHint("create-name-hint", "Too short (min 3 characters)", "error");
    return;
  }

  if (!/^[a-z]+(?: [a-z]+)*$/.test(val)) {
    this.__setFieldState(field, false);
    this.__setHint("create-name-hint", "Only letters with single spaces", "error");
    return;
  }

  // Debounce the server check
  let self = this;
  clearTimeout(this.__nameCheckTimer);
  this.__setHint("create-name-hint", "Checking...", "");
  this.__setFieldState(field, null);

  this.__nameCheckTimer = setTimeout(function() {
    fetch("/api/login/check-name", {
      "method": "POST",
      "headers": { "Content-Type": "application/json" },
      "body": JSON.stringify({ "name": val })
    }).then(function(response) {
      return response.json();
    }).then(function(data) {
      // Only update if value hasn't changed
      if (field.value.toLowerCase().trim() !== val) return;
      if (data.available) {
        self.__setFieldState(field, true);
        self.__setHint("create-name-hint", "Name available", "success");
      } else {
        self.__setFieldState(field, false);
        self.__setHint("create-name-hint", "Name already taken", "error");
      }
    }).catch(function() {
      self.__setHint("create-name-hint", "", "");
      self.__setFieldState(field, null);
    });
  }, 400);

}

CreateAccountModal.prototype.__validateAccountField = function(field) {

  /*
   * Function CreateAccountModal.__validateAccountField
   * Length-only validation for the account name. We deliberately don't
   * call any availability-check endpoint — server-side that endpoint
   * was the username-enumeration oracle, so it was removed. If the name
   * is taken, /create returns 409 on submit and the form surfaces that.
   */

  let val = field.value.trim();

  if (val.length === 0) {
    this.__setFieldState(field, null);
    this.__setHint("create-username-hint", "", "");
    return;
  }

  if (val.length < 3) {
    this.__setFieldState(field, false);
    this.__setHint("create-username-hint", "Too short (min 3 characters)", "error");
    return;
  }

  if (val.length > 20) {
    this.__setFieldState(field, false);
    this.__setHint("create-username-hint", "Too long (max 20 characters)", "error");
    return;
  }

  this.__setFieldState(field, null);
  this.__setHint("create-username-hint", "", "");

}

CreateAccountModal.prototype.__validatePasswordField = function(field) {

  /*
   * Function CreateAccountModal.__validatePasswordField
   * Real-time validation for the password field
   */

  let val = field.value;

  if (val.length === 0) {
    this.__setFieldState(field, null);
    this.__setHint("create-password-hint", "", "");
    return;
  }

  if (val.length < 8 || !/[A-Z]/.test(val) || !/[0-9]/.test(val) || !/[^A-Za-z0-9]/.test(val)) {
    this.__setFieldState(field, false);
    this.__setHint("create-password-hint", "Min 8 chars: a capital, a number, and a special character", "error");
  } else {
    this.__setFieldState(field, true);
    this.__setHint("create-password-hint", "", "");
  }

}

CreateAccountModal.prototype.__isValidSubmission = function(options) {

  /*
   * Function CreateAccountModal.__isValidSubmission
   * Returns true if the submission is valid
   */

  document.getElementById("create-username").style.border = null;
  document.getElementById("create-password").style.border = null;
  document.getElementById("create-name").style.border = null;
  document.getElementById("create-sex").style.border = null;

  let errorEl = document.getElementById("create-error");
  if (errorEl) { errorEl.style.display = "none"; errorEl.textContent = ""; }

  function showError(fieldId, msg) {
    document.getElementById(fieldId).style.border = "1px solid red";
    if (errorEl) { errorEl.textContent = msg; errorEl.style.display = "block"; }
  }

  if(options.name === "") {
    showError("create-name", "Please enter a character name.");
    return false;
  }

  if(options.sex !== "male" && options.sex !== "female") {
    showError("create-sex", "Please choose a sex.");
    return false;
  }

  if(options.account === "") {
    showError("create-username", "Please enter an account name.");
    return false;
  }

  if(options.password === "") {
    showError("create-password", "Please enter a password.");
    return false;
  }

  if(options.name.length < 3 || options.name.length > 20) {
    showError("create-name", "Character name must be 3-20 characters.");
    return false;
  }

  if(!/^[a-z]+(?: [a-z]+)*$/.test(options.name)) {
    showError("create-name", "Only lowercase letters with single spaces.");
    return false;
  }

  if(options.account.length < 3 || options.account.length > 20) {
    showError("create-username", "Account name must be 3-20 characters.");
    return false;
  }

  if(options.password.length < 8 || options.password.length > 32
      || !/[A-Z]/.test(options.password) || !/[0-9]/.test(options.password) || !/[^A-Za-z0-9]/.test(options.password)) {
    showError("create-password", "Password must be 8-32 characters and include an uppercase letter, a number, and a special character.");
    return false;
  }

  return true;

}

CreateAccountModal.prototype.handleOpen = function() {

  /*
   * Function CreateAccountModal.handleOpen
   * Resets the confirm button state when the modal is opened
   */

  let confirmBtn = this.element.querySelector("button[action='confirm']");
  if (confirmBtn) {
    confirmBtn.disabled = false;
    confirmBtn.textContent = "Create Account";
  }

}

CreateAccountModal.prototype.handleCancel = function() {

  /*
   * Function CreateAccountModal.handleCancel
   * Handles the Cancel button click — closes modal and returns to login form
   */

  gameClient.interface.modalManager.close();
  gameClient.interface.modalManager.open("floater-enter");

  return false;

}

CreateAccountModal.prototype.handleConfirm = function() {

  /*
   * Function CreateAccountModal.handleConfirm
   * Validates and submits account creation, then auto-logs in on success
   */

  let referralVal = document.getElementById("create-referral");
  let options = new Object({
    "account": document.getElementById("create-username").value.trim(),
    "password": document.getElementById("create-password").value,
    "name": document.getElementById("create-name").value.toLowerCase().trim(),
    "sex": document.getElementById("create-sex").value,
    "referral": referralVal ? referralVal.value.trim().toUpperCase() : ""
  });

  if(!this.__isValidSubmission(options)) {
    return false;
  }

  // Show loading state on the confirm button
  let confirmBtn = this.element.querySelector("button[action='confirm']");
  if (confirmBtn) {
    confirmBtn.disabled = true;
    confirmBtn.textContent = "Creating Account...";
  }

  // Store credentials for auto-login
  this.__pendingAccount = options.account;
  this.__pendingPassword = options.password;

  gameClient.networkManager.createAccount(options);
  return false;

}


