const WordSuggestions = function (virtualKeyboard) {

  /*
   * Class WordSuggestions
   * Renders a strip of up to three predicted completions above the mobile
   * virtual keyboard. Uses a trie built from a small bundled dictionary plus
   * game-specific words (spell incantations). Per-player usage frequencies
   * are persisted to localStorage so frequently used words bubble up.
   *
   * Toggled via Settings.isWordSuggestionsEnabled() — the strip and all
   * computation are short-circuited when disabled.
   */

  this.__vk = virtualKeyboard;
  this.__trie = new SuggestionTrie();
  this.__usage = this.__loadUsage();
  this.__active = new Array();    // Currently rendered suggestion strings
  this.__currentWord = "";        // In-progress word prefix

  this.__buildStrip();
  this.__seedDictionary();

}

