"use strict";

const ChannelManager = function() {

  /*
   * Class ChannelManager
   * Container that manages all the incoming chat channels and messages
   *
   * API:
   *
   * ChannelManager.handleMessageSend() - Writes whatever is in the chat input box to the server
   *
   */

  // Collection for all the available channels
  this.channels = new Array();

  // The index of the active channel that is currently being written to
  this.__activeIndex = 0;
  this.__disabled = true;
  this.__currentDragElement = null;

  // Shell-style send-history for Shift+Up / Shift+Down recall.
  // Capped at __SEND_HISTORY_MAX entries (oldest dropped on overflow).
  // Cursor: -1 = "no history active, show whatever the user typed";
  // 0 = newest entry, length-1 = oldest. Reset to -1 on send / channel
  // switch / explicit clear.
  this.__sendHistory = [];
  this.__historyCursor = -1;

  // Element for the text input (contenteditable div)
  this.__inputElement = document.getElementById("chat-input");
  this.__headerElement = document.getElementById("cheader");

  // Bound refocus handler for chat-always-unlocked mode
  let self = this;
  this.__isDragging = false;
  this.__headerMouseDown = false;

  this.__shouldSuppressRefocus = function () {
    // Don't refocus during hotbar rebind mode or when any modal is open (text inputs need focus)
    if (gameClient.interface.hotbarManager && gameClient.interface.hotbarManager.__rebindSlot !== null) return true;
    if (gameClient.interface.modalManager && gameClient.interface.modalManager.isOpened()) return true;
    // Don't refocus while dragging or initiating a drag on a window header
    if (self.__isDragging || self.__headerMouseDown) return true;
    // Don't refocus while dragging items between containers/slots (custom mouse tracking)
    if (gameClient.mouse && gameClient.mouse.__mouseDownObject) return true;
    return false;
  };

  this.__refocusBound = function () {
    if (!self.__disabled && gameClient.interface && gameClient.interface.settings.isChatAlwaysUnlocked()) {
      if (self.__shouldSuppressRefocus()) return;
      self.__inputElement.focus();
    }
  };

  // Track drag state to suppress refocus during window dragging
  document.addEventListener("dragstart", function () { self.__isDragging = true; });
  document.addEventListener("dragend", function () {
    self.__isDragging = false;
    self.__headerMouseDown = false;
    // Refocus chat after drag completes
    if (!self.__disabled && gameClient.interface && gameClient.interface.settings.isChatAlwaysUnlocked()) {
      self.__inputElement.focus();
    }
  });
  document.addEventListener("mouseup", function () { self.__headerMouseDown = false; });

  // Prevent clicks on canvas/body from stealing focus when chat is unlocked
  document.body.addEventListener("mousedown", function (e) {
    if (!self.__disabled) {
      if (e.target !== self.__inputElement && e.target.id !== "chat-input") {
        // Allow interaction with modals and form elements
        if (gameClient.interface.modalManager && gameClient.interface.modalManager.isOpened()) return;
        if (e.target.tagName === "INPUT" || e.target.tagName === "SELECT" || e.target.tagName === "TEXTAREA") return;
        // Allow draggable window headers
        if (e.target.className === "header" && e.target.parentElement && e.target.parentElement.draggable) {
          self.__headerMouseDown = true;
          return;
        }
        // Prevent browser from moving focus away from chat input
        e.preventDefault();
      }
    }
  });

  // Prevent focus when chat is locked
  this.__inputElement.addEventListener("mousedown", function(e) {
    if (self.__disabled) {
      e.preventDefault();
    }
  });

  // Prevent line breaks in contenteditable
  this.__inputElement.addEventListener("keydown", function(e) {
    if (e.key === "Enter") {
      e.preventDefault();
    }
  });

  // Auto-lock chat when it loses focus (only in "always unlocked" mode)
  // Normal Enter-toggle mode locks only via Enter key, not on blur
  this.__inputElement.addEventListener("blur", function() {
    if (!self.__disabled && gameClient.interface && gameClient.interface.settings.isChatAlwaysUnlocked()) {
      // Small delay to allow click-to-send button to fire before locking
      setTimeout(function() {
        if (document.activeElement !== self.__inputElement && !self.__disabled) {
          if (self.__shouldSuppressRefocus()) return;
          self.__inputElement.focus();
        }
      }, 100);
    }
  });

  // Typing pulse: add class on input, remove after 1s of inactivity
  this.__typingTimeout = null;
  this.__inputElement.addEventListener("input", function() {
    this.classList.add("chat-typing");
    clearTimeout(self.__typingTimeout);
    self.__typingTimeout = setTimeout(function() {
      self.__inputElement.classList.remove("chat-typing");
    }, 1000);
  });

  // Shake on blocked keypress: printable key while chat is locked
  this.__shakeThrottled = false;
  document.addEventListener("keydown", function(e) {
    if (!self.__disabled) return;
    if (!e.key || e.key.length !== 1 || e.ctrlKey || e.metaKey || e.altKey) return;
    var k = e.key.toLowerCase();
    if (k === "w" || k === "a" || k === "s" || k === "d") return;
    // Q/E/Z/C are diagonal movement keys when QEZC Diagonal is on — they
    // walk, they don't type, so they must not trip the locked-chat shake.
    if ((k === "q" || k === "e" || k === "z" || k === "c")
        && gameClient.interface && gameClient.interface.settings
        && gameClient.interface.settings.isQezcDiagonalEnabled
        && gameClient.interface.settings.isQezcDiagonalEnabled()) {
      return;
    }
    if (self.__shakeThrottled) return;
    self.__shakeThrottled = true;
    self.__inputElement.classList.add("chat-shake");
    self.__inputElement.addEventListener("animationend", function handler() {
      self.__inputElement.classList.remove("chat-shake");
      self.__shakeThrottled = false;
      self.__inputElement.removeEventListener("animationend", handler);
    });
  });

  // Enforce 120 character limit on chat input
  this.__inputElement.addEventListener("input", function() {
    if (this.textContent.length > 120) {
      this.textContent = this.textContent.substring(0, 120);
      // Move cursor to end after truncation
      let range = document.createRange();
      let sel = window.getSelection();
      range.selectNodeContents(this);
      range.collapse(false);
      sel.removeAllRanges();
      sel.addRange(range);
    }
  });

  // Intercept paste to strip formatting and enforce 120 character limit
  this.__inputElement.addEventListener("paste", function(event) {
    event.preventDefault();
    let text = (event.clipboardData || window.clipboardData).getData("text/plain").replace(/[\r\n]+/g, " ").trim();
    let current = this.textContent.replace(/[\r\n]+/g, "").trim();
    this.textContent = (current + (current ? " " : "") + text).substring(0, 120);
    // Move cursor to end
    let range = document.createRange();
    let sel = window.getSelection();
    range.selectNodeContents(this);
    range.collapse(false);
    sel.removeAllRanges();
    sel.addRange(range);
  });

  // Always add these channels — Loot is a Console-style local channel
  // that mirrors only "Loot of X: ..." lines so players can keep a clean
  // drop log without it being scrolled away by other server messages.
  this.addChannel(0x00, "Default");
  this.addLocalChannel("Console");
  this.addLocalChannel("Loot");

  // Add listeners to left and right buttons for the channels
  document.getElementById("left-channel").addEventListener("click", this.handleChannelIncrement.bind(this, -1));
  document.getElementById("right-channel").addEventListener("click", this.handleChannelIncrement.bind(this, 1));

  // Add listener to send button
  document.getElementById("send-chat-message").addEventListener("click", this.handleMessageSend.bind(this));

  // Attach a listener to the header for dragged channels
  document.getElementById("cheader").addEventListener("dragover", this.__handleChannelDrop.bind(this));
  
  // Focus on the main default channel
  this.setActiveChannel(0);

  document.getElementById("chat-say-loudness").addEventListener("click", this.__changeLoudness);

  // Prevent loudness button from stealing focus (which would lock the chat)
  document.getElementById("chat-say-loudness").addEventListener("mousedown", function(e) {
    e.preventDefault();
  });

}

ChannelManager.prototype.LOUDNESS = new Object({
  "WHISPER": 0,
  "SAY": 1,
  "YELL": 2
});

ChannelManager.prototype.getLoudness = function() {

  /*
   * Function ChannelManager.getLoudness
   * Gets the loudness of what is being said
   */

  switch(document.getElementById("chat-say-loudness").innerHTML) {
    case ")": return this.LOUDNESS.WHISPER;
    case "))": return this.LOUDNESS.SAY;
    case ")))": return this.LOUDNESS.YELL;
  }

}

ChannelManager.prototype.__changeLoudness = function() {

  /*
   * Function ChannelManager.__changeLoudness
   * Changes the loudness of what is being said (e.g., whisper, normal, yell)
   */

  // Go in a circle
  switch(this.innerHTML) {
    case ")": return this.innerHTML = "))";
    case "))": return this.innerHTML = ")))";
    case ")))": return this.innerHTML = ")";
  }

}

ChannelManager.prototype.isDisabled = function() {

  return this.__disabled;

}

ChannelManager.prototype.toggleInputLock = function() {

  /*
   * Function ChannelManager.toggleInputLock
   * Handles toggling of the chat input box where messages can be written
   */

  // If chat-always-unlocked is enabled, prevent locking (only allow unlock)
  if (!this.__disabled && gameClient.interface && gameClient.interface.settings.isChatAlwaysUnlocked()) {
    return;
  }

  // Toggle disabled
  this.__disabled = !this.__disabled;

  // Update the DOM — use contentEditable and CSS class instead of disabled attribute
  this.__inputElement.contentEditable = this.__disabled ? "false" : "true";
  this.__inputElement.classList.toggle("chat-disabled", this.__disabled);

  if(this.__disabled) {
    this.__inputElement.setAttribute("data-placeholder", "\uD83D\uDD12 Press Enter to unlock.");
    this.__inputElement.textContent = "";
    this.__inputElement.removeEventListener("blur", this.__refocusBound);
    document.activeElement.blur();
  } else {
    // Mobile/tablet: simpler placeholder since there's no lock/unlock concept
    // has-keyboard (tablet with physical keyboard) opts back into desktop-
    // style chat behavior so Enter both unlocks AND auto-focuses the input.
    // Without this, force-tablet has isMobileMode=true so Enter unlocked
    // but skipped focus, and typing went nowhere.
    let hasKeyboard = document.body.classList.contains("has-keyboard");
    let isMobile = gameClient.touch && gameClient.touch.isMobileMode && !hasKeyboard;
    let alwaysUnlocked = gameClient.interface && gameClient.interface.settings.isChatAlwaysUnlocked();
    this.__inputElement.setAttribute("data-placeholder", isMobile ? "Type here..." : (alwaysUnlocked ? "Type here..." : "\uD83D\uDD13 Press Enter to lock."));
    // Only auto-focus on desktop — on mobile the user taps the input to open keyboard
    if (!isMobile) {
      this.__inputElement.focus();
    }
    // Keep focus on chat input when always-unlocked is enabled
    if (alwaysUnlocked) {
      this.__inputElement.addEventListener("blur", this.__refocusBound);
    }
  }

  // Brief glow effect on toggle
  this.__inputElement.classList.add("chat-glow");
  let inputEl = this.__inputElement;
  setTimeout(function() { inputEl.classList.remove("chat-glow"); }, 600);

}

ChannelManager.prototype.__handleChannelDrop = function(event) {

  /*
   * Function WindowManager.__handleChannelDrop
   * Handles drop of a channel in the channel header
   */

  if(this.__currentDragElement === null) {
    return;
  }

  // Get the target of the element being dropped on
  let element = event.target;

  // Append
  if(element === document.getElementById("cheader")) {
    return element.appendChild(this.__currentDragElement);
  }

  if(element.parentElement.className === "channel-header") {
    return document.getElementById("cheader").insertBefore(this.__currentDragElement, element.parentElement);
  }

}

ChannelManager.prototype.dragElement = function(elmnt) {

  /*
   * Function ChannelManager.dragElement
   * Returns the window for a particular name
   */

  // Add callback to the drag element
  elmnt.element.addEventListener("dragstart", this.__handleDragStart.bind(this));
  elmnt.element.addEventListener("dragend", this.__handleDragEnd.bind(this));

}

ChannelManager.prototype.__handleDragEnd = function(event) {

  /*
   * Function WindowManager.handleDragEnd
   * Returns the window for a particular name
   */

  // Reset the opacity and current element
  this.__currentDragElement = null;

  event.target.style.opacity = 1;

}


ChannelManager.prototype.__handleDragStart = function(event) {

  /*
   * Function Window.__handleDragStart
   * Callback fired when the dragging is started
   */

  // Set the currently dragged element and opacity
  this.__currentDragElement = event.target.parentElement;

  // Drop the opacity to show being dragged
  event.target.style.opacity = 0.25;

}

ChannelManager.prototype.joinChannel = function(id, name) {

  /*
   * Function ChannelManager.joinChannel
   * Handles the joining of public channel
   */

  // Write the join request to the gameserver
  gameClient.send(new ChannelJoinPacket(id));

}

ChannelManager.prototype.handleOpenChannel = function(channel) {

  /*
   * Function ChannelManager.handleOpenChannel
   * Handles the opening of a channel without switching active channel
   */

  this.addChannel(channel.id, channel.name, false);

}

// Global channels the SERVER already auto-opens/manages on login, so they are
// NOT persisted/restored here — mirrors gamesocket.js login auto-joins
// (World 1 / Trade 2 / Help 3 / Team 6) + Guild 4 (in-guild) + Party 12 (auto).
// Everything else a player opened (Rook 5, Minigames 7, language channels 8-11)
// is remembered in localStorage and reopened next login.
ChannelManager.prototype.__CHANNEL_PERSIST_SKIP = { 0: 1, 1: 1, 2: 1, 3: 1, 4: 1, 6: 1, 12: 1 };

ChannelManager.prototype.__openChannelsKey = function() {
  /*
   * Function ChannelManager.__openChannelsKey
   * PER-CHARACTER localStorage key for the remembered channel set. The old
   * single global "open-channels" key made characters CLOBBER each other:
   * playing a Rookgaard/Starfish alt (where you close mainland channels, or
   * never open any) overwrote the set your main had saved — the main then
   * restored nothing (player report 2026-07-09). Returns null when no player
   * is available (teardown/reset) so callers skip rather than write a
   * cross-character key.
   */
  try {
    let name = gameClient && gameClient.player && gameClient.player.name;
    return name ? ("open-channels:" + name) : null;
  } catch (e) { return null; }
};

ChannelManager.prototype.__saveOpenChannels = function() {
  /*
   * Function ChannelManager.__saveOpenChannels
   * Persists the player's currently-open OPTIONAL global channels to
   * localStorage so they reopen on the next login. Called whenever a channel is
   * added or closed (infrequent — not a hot path). Keyed per character; skips
   * silently when no player is live (a teardown-time save must never clobber).
   */
  try {
    let key = this.__openChannelsKey();
    if (!key) return;
    let ids = [];
    for (let i = 0; i < this.channels.length; i++) {
      let id = this.channels[i].id;
      if (typeof id === "number" && id > 0 && !this.__CHANNEL_PERSIST_SKIP[id]) ids.push(id);
    }
    localStorage.setItem(key, JSON.stringify(ids));
  } catch (e) { /* private mode / quota — non-fatal */ }
};

ChannelManager.prototype.__restoreOpenChannels = function() {
  /*
   * Function ChannelManager.__restoreOpenChannels
   * Re-opens the optional global channels THIS CHARACTER had open last
   * session. Called synchronously during handleAcceptLogin — BEFORE the
   * server's auto-open packets arrive — so it reads the saved set before any
   * __saveOpenChannels() overwrites it. Each id is requested from the server
   * (which replies with a ChannelJoinPacket); already-open ones are skipped.
   * Falls back to the legacy global "open-channels" key the first time a
   * character has no per-character entry yet (one-time migration read).
   */
  let ids = null;
  try {
    let key = this.__openChannelsKey();
    let raw = key ? localStorage.getItem(key) : null;
    if (raw === null) raw = localStorage.getItem("open-channels");   // legacy migration
    ids = JSON.parse(raw || "[]");
  } catch (e) { return; }
  if (!Array.isArray(ids)) return;
  for (let i = 0; i < ids.length; i++) {
    let id = ids[i];
    if (typeof id !== "number" || id <= 0 || this.__CHANNEL_PERSIST_SKIP[id]) continue;
    if (this.getChannelById(id)) continue;   // already open
    this.joinChannel(id);                     // ask the server to open it
  }
};

ChannelManager.prototype.closeCurrentChannel = function() {

  /*
   * Function ChannelManager.closeCurrentChannel
   * Closes the currently opened channel
   */

  this.closeChannel(this.getActiveChannel());

}

ChannelManager.prototype.closeChannel = function(channel, skipServerNotify) {

  /*
   * Function ChannelManager.closeChannel
   * Deletes a channel by channel reference. `skipServerNotify` suppresses the
   * ChannelLeavePacket sent back to the server — used when the close was itself
   * server-initiated (the party channel CHANNEL_CLOSE), so it doesn't echo a
   * leave that would loop back as another close.
   */

  // Get the index of the channel
  let index = this.channels.indexOf(channel);

  // The channel does not exist
  if(index === -1) {
    return;
  }

  // Prevent closure of Default channel
  if(this.channels[index].id === 0) {
    return gameClient.interface.setCancelMessage("The Default channel cannot be closed.");
  }

  // Set previous channel as the new active channel
  this.setActiveChannel((index - 1).clamp(0, +Infinity));

  // Splice the channel
  this.channels.splice(index, 1);

  // Remove from the DOM
  channel.element.parentNode.remove();

  // Remember the open set so a closed channel stays closed next login.
  this.__saveOpenChannels();

  // Do nothing for private and local channels
  if(channel.constructor === PrivateChannel || channel.constructor === LocalChannel) {
    return;
  }

  // Server-initiated closes (party CHANNEL_CLOSE) must not echo a leave back.
  if(!skipServerNotify) {
    gameClient.send(new ChannelLeavePacket(channel.id));
  }

}

ChannelManager.prototype.handleChannelIncrement = function(increment) {

  /*
   * Function ChannelManager.handleChannelIncrement
   * Increments or decrements the active channel
   */

  // Make sure to wrap around in both directions
  this.setActiveChannel((this.channels.length + this.__activeIndex + increment) % this.channels.length);

}

ChannelManager.prototype.getActiveChannel = function() {

  /*
   * Function ChannelManager.getActiveChannel
   * Returns a reference to the currently active channel
   */

  return this.channels[this.__activeIndex];

}

ChannelManager.prototype.isActive = function(channel) {

  /*
   * Function ChannelManager.isActive
   * Returns true when the passed channel reference is active
   */

  return this.getActiveChannel() === channel;

}

ChannelManager.prototype.SEND_HISTORY_MAX = 4;

ChannelManager.prototype.__pushSendHistory = function(message) {

  /*
   * Function ChannelManager.__pushSendHistory
   * Records a sent message at the top of the history. Drops the oldest if
   * we're at the cap. Resets the recall cursor so the next Shift+Up
   * starts at the newest entry. De-dupes consecutive identical sends so
   * a stutter-typed message doesn't fill all 4 slots.
   */

  if (!message) return;
  if (this.__sendHistory[0] === message) {
    this.__historyCursor = -1;
    return;
  }
  this.__sendHistory.unshift(message);
  if (this.__sendHistory.length > this.SEND_HISTORY_MAX) {
    this.__sendHistory.length = this.SEND_HISTORY_MAX;
  }
  this.__historyCursor = -1;

}

ChannelManager.prototype.suggestPrevious = function() {

  /*
   * Function ChannelManager.suggestPrevious
   * Shift+Up: walk one step further back in send history. At the oldest
   * entry, further presses are no-ops.
   */

  if (this.__sendHistory.length === 0) return;

  let next = this.__historyCursor + 1;
  if (next >= this.__sendHistory.length) next = this.__sendHistory.length - 1;
  this.__historyCursor = next;

  this.__inputElement.textContent = this.__sendHistory[next];
  this.__moveCursorToEnd();

}

ChannelManager.prototype.suggestNext = function() {

  /*
   * Function ChannelManager.suggestNext
   * Shift+Down: walk one step forward (toward newer). Past the newest
   * entry the input clears, mirroring how a shell behaves.
   */

  if (this.__historyCursor < 0) return;

  this.__historyCursor -= 1;
  if (this.__historyCursor < 0) {
    this.__inputElement.textContent = "";
    return;
  }

  this.__inputElement.textContent = this.__sendHistory[this.__historyCursor];
  this.__moveCursorToEnd();

}

ChannelManager.prototype.__moveCursorToEnd = function() {
  // contenteditable input: place caret after the recalled text so the
  // user can immediately edit/append instead of overwriting from the start.
  try {
    let range = document.createRange();
    let sel = window.getSelection();
    range.selectNodeContents(this.__inputElement);
    range.collapse(false);
    sel.removeAllRanges();
    sel.addRange(range);
  } catch (e) { /* ignore */ }
}

ChannelManager.prototype.isInputActive = function() {

  /*
   * Function ChannelManager.isInputActive
   * Returns true if the input element is actively focused
   */

  return this.__inputElement === document.activeElement;

}

ChannelManager.prototype.addConsoleMessage = function(message, color) {

  /*
   * Function ChannelManager.addConsoleMessage
   * Wrapper function to add a console message
   */

  let console = this.getChannel("Console");

  // Exists
  if(console !== null) {
    console.addConsoleMessage(message, color);
  }

}

ChannelManager.prototype.addLootMessage = function(message, color) {

  /*
   * Function ChannelManager.addLootMessage
   * Mirrors loot lines into the dedicated Loot local channel.
   * Filtered by the "Loot of " prefix in PacketHandler.handleServerMessage.
   */

  let loot = this.getChannel("Loot");

  if(loot !== null) {
    loot.addConsoleMessage(message, color);
  }

}

ChannelManager.prototype.getChannelById = function(id) {

  /*
   * Function ChannelManager.getChannel
   * Returns the private channel with another player
   */

  // Linear search over all opened channels
  for(let i = 0; i < this.channels.length; i++) {
    if(this.channels[i].id === id) {
      return this.channels[i];
    }
  }

  return null;

}

ChannelManager.prototype.getChannel = function(name) {

  /*
   * Function ChannelManager.getChannel
   * Returns the private channel with another player. Case-insensitive
   * match — a user can open a private chat with "PRIME" / "prime" /
   * "Prime" and the reply (which comes back with the server's canonical
   * "Prime" casing) still lands on the correct tab. Was case-sensitive
   * before, which routed Prime's reply to default channel.
   */

  if (name === null || name === undefined) {
    return null;
  }

  let target = String(name).toLowerCase();

  // Linear search over all opened channels
  for(let i = 0; i < this.channels.length; i++) {
    let chName = this.channels[i].name;
    if (chName !== null && chName !== undefined && String(chName).toLowerCase() === target) {
      return this.channels[i];
    }
  }

  return null;

}

ChannelManager.prototype.addLocalChannel = function(name) {

  /*
   * Function ChannelManager.addLocalChannel
   * Adds a new local channel to the gameclient
   */

  // Check for existing channels
  let existingChannel = this.getChannel(name);

  if(existingChannel !== null) {
    return this.setActiveChannelElement(existingChannel);
  }

  this.__addChannel(new LocalChannel(name));

}

ChannelManager.prototype.addPrivateChannel = function(name) {

  /*
   * Function ChannelManager.addChannel
   * Adds a new private channel after server validates the name. The
   * actual channel is created in handleNameLookupResult once the
   * server replies — this prevents tabs from being opened for
   * non-existent / offline / gibberish names.
   */

  if (typeof name !== "string") return;
  name = name.trim();
  if (name.length === 0) return;

  // Capitalize each word (Tibia names always display with proper capitalization)
  name = name.replace(/\b\w/g, function(c) { return c.toUpperCase(); });

  // Check for existing channels — already-open tabs activate immediately,
  // no server round-trip needed.
  let existingChannel = this.getChannel(name);

  if(existingChannel !== null) {
    return this.setActiveChannelElement(existingChannel);
  }

  // Cannot open with yourself
  if(gameClient && gameClient.player.name.toLowerCase() === name.toLowerCase()) {
    return gameClient.interface.setCancelMessage("Cannot open a chat window yourself.");
  }

  // Defer channel creation until the server confirms the name resolves
  // to an online player. Pending lookups are keyed by capitalized name
  // so the response handler can match.
  if (!this.__pendingNameLookups) this.__pendingNameLookups = new Map();
  if (this.__pendingNameLookups.has(name)) return; // already probing
  this.__pendingNameLookups.set(name, true);
  gameClient.send(new NameLookupPacket(name));

}

ChannelManager.prototype.handleNameLookupResult = function(name, valid) {

  /*
   * Function ChannelManager.handleNameLookupResult
   * Server replied to our NAME_LOOKUP probe — open the channel if the
   * name is valid, otherwise show an error. Name comes back capitalized
   * from the server's echo of what we sent.
   */

  if (!this.__pendingNameLookups) return;
  if (!this.__pendingNameLookups.has(name)) return;
  this.__pendingNameLookups.delete(name);

  if (!valid) {
    return gameClient.interface.setCancelMessage("A player with that name is not online.");
  }

  // Avoid double-open if another path created the channel during the
  // round-trip.
  let existingChannel = this.getChannel(name);
  if (existingChannel !== null) {
    return this.setActiveChannelElement(existingChannel);
  }

  this.__addChannel(new PrivateChannel(name));

  // Mobile auto-focus: the DM input flow in mobile-chat called
  // openPrivateChat synchronously which used to find the channel
  // immediately. Now that creation is async, mirror the focus side
  // effect here so the DM tab actually surfaces on mobile.
  if (gameClient.touch && gameClient.touch.mobileChat
      && typeof gameClient.touch.mobileChat.openPrivateChat === "function") {
    gameClient.touch.mobileChat.openPrivateChat(name);
  }

}

ChannelManager.prototype.addChannel = function(id, name, activate) {

  /*
   * Function ChannelManager.addChannel
   * Adds a new channel. If activate is false, the channel is added without switching to it.
   */

  // Check for existing channels
  let existingChannel = this.getChannel(name);

  if(existingChannel !== null) {
    if(activate !== false) {
      this.setActiveChannelElement(existingChannel);
    }
    return;
  }

  this.__addChannel(new Channel(name, id), activate);

}

ChannelManager.prototype.__addChannel = function(channel, activate) {

  /*
   * Function ChannelManager.__addChannel
   * Adds the new channel to the DOM
   */

  this.channels.push(channel);

  if(activate !== false) {
    this.setActiveChannelElement(channel);
  }

  // Enable dragging
  this.dragElement(channel);

  // Remember the open set so it reopens next login.
  this.__saveOpenChannels();

}

ChannelManager.prototype.setActiveChannelElement = function(channel) {

  /*
   * Function ChannelManager.setActiveChannelElement
   * Sets an active channel by its reference
   */

  let index = this.channels.indexOf(channel);

  if(index === -1) {
    return;
  }

  this.setActiveChannel(index);

}

ChannelManager.prototype.setHeaderOffset = function(element) {

  /*
   * Function ChannelManager.setHeaderOffset
   * Sets the proper header offset after selecting a new channel
   */

  let parentOffset = element.parentNode.parentNode.offsetLeft;
  let selfOffset = element.parentNode.offsetLeft;

  // Update the scroll of the header
  this.__headerElement.scrollLeft = (selfOffset - parentOffset);

}

ChannelManager.prototype.__handlePrivateMessageSend = function(channel, message) {

  /*
   * Function ChannelManager.__handlePrivateMessageSend
   * Handles writing of private chat message to server
   */

  // Client side add message to channel. Pass our own level so the local echo
  // matches how the RECIPIENT sees it ("Name [level]:") — the server never
  // echoes an outgoing PM back, so without this your own messages showed no
  // level (player report 2026-07-09).
  channel.__addMessage(
    new CharacterMessage(
      message,
      0,
      gameClient.player.name,
      gameClient.interface.COLORS.MAYABLUE,
      undefined,
      gameClient.player.level
    )
  );

  gameClient.send(new ChannelPrivatePacket(channel.name, message));

}

ChannelManager.prototype.handleMessageSend = function() {

  /*
   * Function ChannelManager.handleMessageSend
   * Handles writing of chat message to server (reads from desktop #chat-input)
   */

  // Read the input from the DOM and eliminate white spaces
  let message = this.__inputElement.textContent.trim();

  // Reset the value to nothing
  this.__inputElement.textContent = "";

  // String length is empty, nothing to do!
  if(message.length === 0) {
    return;
  }

  // History is pushed by sendMessageText so both desktop and mobile
  // (which calls sendMessageText directly, bypassing this method)
  // populate the recall buffer.
  this.sendMessageText(message);

}

// Links to these domains (and their subdomains) are allowed in chat; every
// OTHER link is blocked. Keep in sync with the server gate in
// src/network/packet-handler.js.
ChannelManager.prototype.ALLOWED_LINK_DOMAINS = ["minibia.com"];

// Explicit-scheme links — capture the host right after the scheme (any TLD).
ChannelManager.prototype.__SCHEME_LINK_REGEX = /(?:https?|ftp):\/\/([a-z0-9.-]+)/gi;
// Bare hostnames / www. links — one-or-more labels ending in a common real
// TLD. The leading domain-label requirement keeps "3.5k", "Mr.Smith",
// "lvl 8.1" from matching (no real TLD after the dot).
ChannelManager.prototype.__HOST_LINK_REGEX = /((?:[a-z0-9][a-z0-9-]*\.)+(?:com|net|org|io|gg|me|tv|co|uk|us|eu|de|nl|ru|br|pl|xyz|info|biz|online|site|live|app|link|click|shop|store|fun|top|vip|cc|tk|ml|ga|cf|gq|gl|ly|to|pw|su|dev|gd|st))(?![a-z0-9-])/gi;

ChannelManager.prototype.__isAllowedLinkHost = function(host) {

  /*
   * Function ChannelManager.__isAllowedLinkHost
   * True if the host is a whitelisted domain or one of its subdomains. The
   * leading-dot check ("." + d) is what stops look-alikes: "notminibia.com"
   * and "minibia.com.evil.com" both fail it.
   */

  for (let i = 0; i < this.ALLOWED_LINK_DOMAINS.length; i++) {
    let d = this.ALLOWED_LINK_DOMAINS[i];
    if (host === d || host.endsWith("." + d)) return true;
  }
  return false;

}

ChannelManager.prototype.__containsBlockedLink = function(message) {

  /*
   * Function ChannelManager.__containsBlockedLink
   * True when the message carries a web link (URL, www.host, or bare
   * domain.tld) to anything OTHER than a whitelisted domain. Used to block
   * non-minibia links in player chat client-side. Catches the common/casual
   * cases; deliberate obfuscation ("site dot com") is intentionally NOT
   * covered here — the server-side gate is the real enforcement.
   */

  let text = String(message || "").toLowerCase();
  let m;
  this.__SCHEME_LINK_REGEX.lastIndex = 0;
  while ((m = this.__SCHEME_LINK_REGEX.exec(text)) !== null) {
    if (!this.__isAllowedLinkHost(m[1])) return true;
  }
  this.__HOST_LINK_REGEX.lastIndex = 0;
  while ((m = this.__HOST_LINK_REGEX.exec(text)) !== null) {
    if (!this.__isAllowedLinkHost(m[1])) return true;
  }
  return false;

}

ChannelManager.prototype.sendMessageText = function(text, channelIndex, noHistory) {

  /*
   * Function ChannelManager.sendMessageText
   * Sends a message from arbitrary text input (mobile chat or desktop)
   * Optionally accepts a channelIndex to target a specific channel.
   * noHistory: true for AUTOMATION-origin sends (auto /bagnames, context-
   * menu /namebag) — Shift+Up recall must only surface what the player
   * actually TYPED (owner report 2026-07-04: '/bagnames was suddenly in
   * my shift up chat history').
   */

  let message = text.trim().substring(0, 120);

  if(message.length === 0) {
    return;
  }

  // Push to send-history so the Shift+Up / mobile history button can
  // recall this message later. Single push site covers desktop and
  // mobile (mobile bypasses handleMessageSend). Consecutive duplicates
  // are deduped inside __pushSendHistory.
  if (noHistory !== true) this.__pushSendHistory(message);

  // /report confirm interception (owner request): typed reports get the
  // same small confirm dialog as the context-menu path. sendMessageText is
  // the single funnel for desktop AND mobile chat, so both are covered.
  // The confirmed send re-enters with the bypass flag set so this block
  // is skipped exactly once. Free-typed text goes into innerHTML, so the
  // shown name is stripped of HTML-meaningful chars (the server validates
  // the real name independently).
  if (!this.__reportConfirmBypass && /^\/report\s+\S/.test(message)) {
    let self = this;
    let shownName = message.substring(8).trim().replace(/[<>&"]/g, "");
    let modal = gameClient.interface.modalManager.open("confirm-modal", function () {
      self.__reportConfirmBypass = true;
      try { self.sendMessageText(message, channelIndex); } finally { self.__reportConfirmBypass = false; }
    });
    if (modal) {
      modal.setTitle("Report Player");
      modal.element.querySelector(".modal-body > div").innerHTML =
        "You are about to report <b>" + shownName + "</b> for using unofficial software.<br>Continue?";
    }
    return;
  }

  // Client-side /rename command — changes your display name locally (for screenshots, etc.)
  if(message.indexOf("/rename ") === 0) {
    let newName = message.substring(8).trim();
    if(newName.length > 0 && gameClient.player) {
      gameClient.player.name = newName;
      gameClient.player.characterElement.setName(newName);
      gameClient.interface.setCancelMessage("Display name changed to " + newName + ".");
    }
    return;
  }

  // Client-side /resethotkeys command — wipes the current hotbar preset (all
  // slots + key bindings) back to default after a yes/no confirm. The hotbar
  // lives entirely in localStorage, so this is purely local — nothing is sent
  // to the server. (owner request 2026-06-13)
  if(message.toLowerCase() === "/resethotkeys") {
    if(gameClient.interface && gameClient.interface.modalManager) {
      let modal = gameClient.interface.modalManager.open("confirm-modal", function () {
        if (gameClient.interface && gameClient.interface.hotbarManager) {
          gameClient.interface.hotbarManager.resetToDefault();
        }
      });
      if (modal) {
        modal.setTitle("Reset Hotkeys");
        modal.element.querySelector(".modal-body > div").innerHTML =
          "This will clear all your hotbar slots and key bindings and restore the defaults.<br>Continue?";
      }
    }
    return;
  }

  // Client-side /exporthotkeys — downloads the current hotbar setup (all presets,
  // both banks incl. Shift+F, plus key bindings) as a JSON file on the player's
  // machine. /importhotkeys loads such a file back. Purely local — nothing is
  // sent to the server, so no protocol/flood risk. Never forwarded as chat.
  if(message.toLowerCase() === "/exporthotkeys") {
    if(gameClient.interface && gameClient.interface.hotbarManager) {
      gameClient.interface.hotbarManager.exportToFile();
    }
    return;
  }

  // Client-side /importhotkeys — opens a file picker and applies a hotkeys file
  // exported with /exporthotkeys. Local-only; re-applies the hotbar immediately.
  if(message.toLowerCase() === "/importhotkeys") {
    if(gameClient.interface && gameClient.interface.hotbarManager) {
      gameClient.interface.hotbarManager.importFromFile();
    }
    return;
  }

  // Client-side /record — local gameplay recording (canvas capture → a video
  // file downloaded to the player's machine). Subcommands: "/record start" and
  // "/record stop"; bare "/record" prints usage. Purely local — nothing is sent
  // to the server. Lazily creates one ScreenRecorder per session.
  if(message.toLowerCase() === "/record" || message.toLowerCase().indexOf("/record ") === 0) {
    let recArg = message.slice(7).trim().toLowerCase();
    if(typeof ScreenRecorder !== "undefined") {
      if(!gameClient.__screenRecorder) {
        gameClient.__screenRecorder = new ScreenRecorder();
      }
      let rec = gameClient.__screenRecorder;
      if(recArg === "start") {
        rec.start();
      } else if(recArg === "stop") {
        rec.stop();
      } else {
        gameClient.interface.setCancelMessage("Recording: /record start (then pick the game tab to share), /record stop to save. Captures everything on screen — names, bars, UI — to a video saved on your device; nothing is uploaded.");
      }
    }
    return;
  }

  // Client-side /channels command — opens the channel-selection modal. On
  // mobile the desktop chat header (which holds the #open-chat-modal button)
  // lives inside .lower, which is display:none on phones, so this is the only
  // way to reach the channel picker there; on desktop it's just a shortcut.
  // Purely local — nothing is sent to the server; the modal's own confirm
  // handler joins whichever channel is picked.
  if(message.toLowerCase() === "/channels" || message.toLowerCase() === "/channel") {
    if(gameClient.interface && gameClient.interface.modalManager) {
      gameClient.interface.modalManager.open("chat-modal");
    }
    return;
  }

  // Client-side /testgame<name> — DEV/QA: open a game module with a fake board
  // (no real match/opponent) to eyeball the UI across devices. Extensible:
  // /testgamechess today; future games add a case. Purely local.
  if(message.toLowerCase().indexOf("/testgame") === 0) {
    let game = message.toLowerCase().slice(9).trim();
    let mgr = gameClient.interface && gameClient.interface.modalManager;
    if(game === "chess") {
      let m = mgr && mgr.get("chess-modal");
      if(m) { mgr.open("chess-modal"); if(typeof m.showTestBoard === "function") m.showTestBoard(); }
      else if(gameClient.interface) gameClient.interface.setCancelMessage("Chess module not available.");
    } else if(gameClient.interface) {
      gameClient.interface.setCancelMessage("Unknown test game: '" + game + "'. Try /testgamechess.");
    }
    return;
  }

  // Block links in player-visible chat (public channels, private channels,
  // and inline/explicit PMs). Slash-prefixed text is a command routed to the
  // server's command handler — never broadcast as chat — so it is exempt.
  // CLIENT-SIDE guard only: instant feedback that stops the casual case, but
  // NOT a security boundary (a crafted packet / userscript bypasses it). The
  // server-side check in the channel-message handler is the real enforcement.
  if (message.charAt(0) !== "/" && this.__containsBlockedLink(message)) {
    return gameClient.interface.setCancelMessage("Only minibia.com links are allowed in chat.");
  }

  // Inline PM: "*Name* hello" sends a private message to Name without
  // first opening a PM tab. Parsed before channel resolution so it
  // short-circuits whichever channel is currently active.
  //
  // Slash-prefixed bodies (e.g. "*Foo* /heal") are REJECTED with a
  // cancel message. Reason: the project routes any message starting
  // with "/" to the command handler precisely to stop slash commands
  // leaking out as chat text. Allowing the *Name* prefix to bypass
  // that gate would reintroduce the exact accident the slash-redirect
  // was built to prevent — only this time leaking as a PM to a real
  // person instead of into a public channel.
  let pmMatch = message.match(/^\*([^*]+)\*\s+(.+)$/);
  if (pmMatch) {
    let pmName = pmMatch[1].trim();
    let pmText = pmMatch[2].trim();
    if (pmName.length > 0 && pmText.length > 0) {
      if (pmText.charAt(0) === "/") {
        return gameClient.interface.setCancelMessage("Slash commands cannot be sent as a private message. Type the command directly.");
      }
      if (gameClient.player && gameClient.player.name.toLowerCase() === pmName.toLowerCase()) {
        return gameClient.interface.setCancelMessage("Cannot send a message to yourself.");
      }
      // Capitalize to match how PM channel names are stored elsewhere
      pmName = pmName.replace(/\b\w/g, function(c) { return c.toUpperCase(); });
      // Local echo only when a PM tab for this name is already open —
      // otherwise just fire the packet. Auto-opening a tab on every
      // inline PM would clutter the channel bar.
      let existing = this.getChannel(pmName);
      if (existing && existing.constructor === PrivateChannel) {
        existing.__addMessage(
          new CharacterMessage(
            pmText,
            0,
            gameClient.player.name,
            gameClient.interface.COLORS.MAYABLUE,
            undefined,
            gameClient.player.level
          )
        );
      }
      gameClient.send(new ChannelPrivatePacket(pmName, pmText));
      return;
    }
  }

  // Get the target channel
  let channel = (channelIndex !== undefined) ? this.channels[channelIndex] : this.getActiveChannel();

  if(!channel) {
    return;
  }

  // Slash commands ALWAYS go to the Default channel regardless of which
  // channel is active. Players were accidentally typing /blessings, /frags,
  // /hunt, /lootlist etc. into Trade or World chat, broadcasting them as
  // plain text and spamming the channel. Default routes them through the
  // command handler instead. Applies even when the active channel is
  // private — a slash command in a PM still belongs to the command system.
  if(message.charAt(0) === "/") {
    // /dev — client-only command, toggles the FULL debug HUD as a
    // session-only override. Independent of the persistent "Show
    // Performance" checkbox: never sent to the server, never saved
    // anywhere, resets to off on reload.
    //
    // Side effect when turning ON: unchecks the Show Performance
    // checkbox (and persists THAT, since the checkbox is the persistent
    // setting) — dev overrules minimal, so leaving the checkbox ticked
    // would be misleading. Turning OFF dev does not auto-recheck; the
    // player explicitly re-enables minimal if they want it back.
    let trimmed = message.trim().toLowerCase();
    if (trimmed === "/dev" || trimmed === "/dev on" || trimmed === "/dev off") {
      let dbg = gameClient.renderer.debugger;
      let next;
      if (trimmed === "/dev on") next = true;
      else if (trimmed === "/dev off") next = false;
      else next = !dbg.__devOverride;

      dbg.setDevOverride(next);

      if (next) {
        let s = gameClient.interface.settings;
        if (s.__state["show-performance"] === true) {
          s.__state["show-performance"] = false;
          s.saveState();
          let perfCheckbox = document.getElementById("show-performance");
          if (perfCheckbox) perfCheckbox.checked = false;
          dbg.setHudEnabled(false);
        }
      }
      return;
    }
    // /fullscreen [on|off] — client-only: toggle browser fullscreen. This runs in
    // the keypress that sent the message (synchronous from the chat-send path), so
    // the Fullscreen API's required user activation is still live — a server
    // round-trip would lose it and the browser would block the request. Never sent
    // to the server. Falls back to a cancel message if the browser blocks it.
    if (trimmed === "/fullscreen" || trimmed === "/fullscreen on" || trimmed === "/fullscreen off") {
      let fsEl = document.fullscreenElement || document.webkitFullscreenElement;
      let wantOff = (trimmed === "/fullscreen off") || (trimmed === "/fullscreen" && fsEl);
      if (wantOff) {
        let exit = document.exitFullscreen || document.webkitExitFullscreen || document.mozCancelFullScreen || document.msExitFullscreen;
        if (exit) { try { exit.call(document); } catch (e) {} }
      } else {
        let el = document.documentElement;
        let req = el.requestFullscreen || el.webkitRequestFullscreen || el.mozRequestFullScreen || el.msRequestFullscreen;
        if (req) {
          try {
            let p = req.call(el);
            if (p && p.catch) p.catch(function () {
              if (gameClient.interface) gameClient.interface.setCancelMessage("Couldn't enter fullscreen — your browser blocked it. Type /fullscreen again.");
            });
          } catch (e) {
            if (gameClient.interface) gameClient.interface.setCancelMessage("Fullscreen isn't available in this browser.");
          }
        } else if (gameClient.interface) {
          gameClient.interface.setCancelMessage("Fullscreen isn't supported in this browser.");
        }
      }
      return;
    }
    let def = this.getChannelById(0);
    if(def) channel = def;
  }

  // Redirect local channel messages (e.g. Console) to Default channel
  if(channel.constructor === LocalChannel) {
    channel = this.getChannelById(0);
    if(!channel) {
      return;
    }
  }

  // Writing in a private channel
  if(channel.constructor === PrivateChannel) {
    return this.__handlePrivateMessageSend(channel, message);
  }

  let loudness = this.getLoudness();

  // Spell glow: check if the message matches known spell words
  if (gameClient.player && gameClient.interface.SPELLS) {
    let msgLower = message.toLowerCase().trim();
    let matchedSpell = false;
    gameClient.interface.SPELLS.forEach(function(spell) {
      if (!matchedSpell && spell.words && spell.words.toLowerCase() === msgLower) {
        matchedSpell = true;
      }
    });
    if (matchedSpell) {
      let glowColor = HotbarManager.prototype.__getSpellGlowColor(message);
      gameClient.player.__spellGlow = { start: performance.now(), color: glowColor };
    }
  }

  // Arm the spectate expectation window: SPECTATE_MODE 1/2 is only honoured
  // shortly after the client ITSELF asked to spectate (/watch here, or the
  // cam boot). See handleSpectateMode's gate — a misparsed byte stream must
  // never be able to mute a playing client (live incident 2026-06-11:
  // 'Watching (GM)' banner with an EMPTY label on a regular player, who
  // then couldn't move).
  if (typeof message === "string" && message.trim().toLowerCase().indexOf("/watch") === 0) {
    gameClient.__spectateExpectedAt = Date.now();
  }

  gameClient.send(new ChannelMessagePacket(channel.id, loudness, message));

  // Yell / whisper is a PER-MESSAGE mode: after sending one, snap the loudness
  // button back to normal "say" so the next line isn't accidentally yelled or
  // whispered (you re-pick it each time, like authentic Tibia). "))" == SAY.
  let lb = document.getElementById("chat-say-loudness");
  if (lb && lb.innerHTML !== "))") lb.innerHTML = "))";

}

