const Channel = function(name, id) {

  /*
   * Class Channel
   * Container for all channels that go to the DOM
   *
   * API:
   *
   *
   */

  // All channels have a new
  this.name = name;
  this.id = id;

  // Contents contain all the messages in the channel
  this.__contents = new Array();

  // Save a reference to the element
  this.element = this.__createElement(name);

}

Channel.prototype.MAX_MESSAGE_COUNT = 100;

Channel.prototype.close = function() {

  /*
   * Function Channel.close
   * Closes the channel by delegating to the interface channel manager
   */

  gameClient.interface.channelManager.closeChannel(this);

}

Channel.prototype.addPrivateMessage = function(message, name, level) {

  /*
   * Function Channel.addPrivateMessage
   * Adds a private message to the channel
   */

  // Private messages are colored skyblue
  this.addMessage(message, 0, name, gameClient.interface.COLORS.SKYBLUE, undefined, level);

}

Channel.prototype.addMessage = function(message, type, name, color, loudness, level) {

  /*
   * Function Channel.addMessage
   * Adds a message to the channel
   */

  // Add to the contents
  this.__addMessage(new CharacterMessage(message, type, name, color, loudness, level));

}

Channel.prototype.blink = function() {

  /*
   * Function Channel.blink
   * Sets the message header color back to white to signifiy a new message
   */

  this.element.style.color = "orange";

}

Channel.prototype.lastMessageSelf = function() {

  /*
   * Function Channel.lastMessageSelf
   * Returns the last message said by the player
   */

  if(this.isEmpty()) {
    return null;
  }

  let selfMessages = this.__contents.filter(x => gameClient.player.name === x.name);

  if (selfMessages.length === 0) {
    return null;
  }

  return selfMessages.last().message;

}

Channel.prototype.lastMessage = function() {

  /*
   * Function Channel.lastMessage
   * Returns the last message said by the player
   */

  if(this.isEmpty()) {
    return null;
  }

  return this.__contents.last().message;

}

Channel.prototype.isEmpty = function() {

  /*
   * Function Channel.isEmpty
   * Returns true if the channel has no messages and is empty
   */

  return this.__contents.length === 0;

}

// Scroll-up hold expiry — after this long, the next incoming live message
// snaps the chat back to the latest line (see render)
Channel.prototype.SCROLL_HOLD_MS = 60000;

Channel.prototype.__isScrolledDown = function(chatbox) {

  /*
   * Function Channel.__isScrolledDown
   * Returns true when the chatbox is fully scrolled down
   */

  return (chatbox.scrollHeight - chatbox.offsetHeight) - chatbox.scrollTop <= 5;

}

Channel.prototype.render = function(preserveScroll) {

  /*
   * Function Channel.render
   * Renders channel contents to the chat area box.
   *
   * preserveScroll (default false): when a live message arrives on the active
   * channel (__addMessage), keep the user's scroll position if they have
   * scrolled up to read/copy an older line instead of snapping to the bottom.
   * Selecting / clearing a channel passes no flag and jumps to the latest.
   * Mirrors the mobile chat fix (player report 2026-05-31).
   */

  // Get the chatbox element from the DOM
  let chatbox = document.getElementById("chat-text-area");

  // Track when the user scrolled away from the bottom (lazy one-time hook).
  // The scroll-up hold keeps incoming messages from yanking the view while
  // reading/copying, but it EXPIRES: after SCROLL_HOLD_MS the next live
  // message snaps back to the latest (owner request 2026-07-02) — the hold
  // is a reading aid, not a permanent detach. Scrolling back to the bottom
  // (by hand or programmatically) clears the stamp.
  if(!chatbox.__scrollHoldHooked) {
    chatbox.__scrollHoldHooked = true;
    chatbox.addEventListener("scroll", function() {
      if((chatbox.scrollHeight - chatbox.offsetHeight) - chatbox.scrollTop <= 5) {
        chatbox.__scrolledUpAt = 0;
      } else if(!chatbox.__scrolledUpAt) {
        chatbox.__scrolledUpAt = Date.now();
      }
    }, { "passive": true });
  }

  // Measure scroll intent BEFORE wiping. Stick to the bottom only when the
  // user is already there (__isScrolledDown); otherwise remember the offset
  // and restore it after the rebuild so an incoming message does not yank
  // them away from the line they are reading.
  let stickToBottom = true;
  let prevScrollTop = 0;
  if(preserveScroll && chatbox.childNodes.length > 0) {
    prevScrollTop = chatbox.scrollTop;
    stickToBottom = this.__isScrolledDown(chatbox);

    // Hold expired: resume following the conversation
    if(!stickToBottom && chatbox.__scrolledUpAt &&
       (Date.now() - chatbox.__scrolledUpAt > Channel.prototype.SCROLL_HOLD_MS)) {
      stickToBottom = true;
      chatbox.__scrolledUpAt = 0;
    }
  }

  chatbox.innerHTML = "";

  // The channel is empty
  if(this.isEmpty()) {
    return chatbox.innerHTML = this.__getEmptyMessage();
  }

  // Add all the content to the element
  this.__contents.forEach(function(message) {
    chatbox.appendChild(message.createNode());
  }, this);

  // After the browser completes layout: stick to the latest message, or hold
  // the user's position if they had scrolled up to read history.
  requestAnimationFrame(function() {
    if(stickToBottom) {
      chatbox.scrollTop = chatbox.scrollHeight;
    } else {
      chatbox.scrollTop = prevScrollTop;
    }
  });

}

Channel.prototype.click = function(event) {

  /*
   * Function Channel.click
   * Click event when the tab handler is clicked: set this as active
   */

  // Set the active index
  gameClient.interface.channelManager.setActiveChannelElement(this);

}

Channel.prototype.select = function(message) {

  /*
   * Function Channel.select
   * Selects a channel and updates settings to make it active
   */

  this.element.className = "chat-title selected";
  this.render();
  this.element.style.color = null;

}

Channel.prototype.clear = function() {

  /*
   * Function Channel.clear
   * Clear all messages in the channel
   */

  this.__contents = new Array();
  this.render();

  return true;

}

Channel.prototype.addConsoleMessage = function(message, color) {

  /*
   * Function Channel.addConsoleMessage
   * Adds a console message to the channel.
   */

  this.__addMessage(new Message(message, color), true);

}

Channel.prototype.__addMessage = function(message, isConsole) {

  /*
   * Function Channel.__addMessage
   * Adds a message to a channel
   */

  // Push the message to the contents and slice to the allowed count
  this.__contents.push(message);
  this.__contents = this.__contents.slice(-this.MAX_MESSAGE_COUNT);

  // Notify mobile of new message for unread badge and live log updates
  if(gameClient.touch && gameClient.touch.isMobileMode) {
    gameClient.touch.notifyNewMessage(this, isConsole);
  }

  // If this channel is currently active: render it. Preserve the user's
  // scroll position so a live message does not snap them to the bottom while
  // they read/copy an older line (only sticks if already at the bottom).
  if(gameClient.interface.channelManager.isActive(this)) {
    return this.render(true);
  }

  // Set text color to indicate a new message has appeared in an inactive channel
  this.blink();

}

Channel.prototype.__getEmptyMessage = function() {

  /*
   * Function Channel.__getEmptyMessage
   * Returns the empty message span element
   */

  return "<span class=\"channel-empty\">No messages in channel %s.</span>".format(this.name);

}

Channel.prototype.__createElement = function(name) {

  /*
   * Function Channel.__createElement
   * Creates the DOM element for the channel
   */

  // Create tab handle DOM element
  let div = document.createElement("div");
  div.className = "channel-header";

  // Name and stuff
  let tab = document.createElement("div");
  tab.draggable = true;
  tab.className = "chat-title";
  tab.innerHTML = "<span>%s</span>".format(name);
  tab.addEventListener("click", this.click.bind(this));
  
  div.appendChild(tab);

  // Append the tab to the header
  document.getElementById("cheader").appendChild(div);

  return tab;

}


