/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/utils/message-character.js ===== */

const CharacterMessage = function(message, type, name, color, loudness, level) {

  /*
   * Class CharacterMessage
   * Container for a message that belongs to a character
   */

  // Inherit from message
  Message.call(this, message);

  // Has a name and color
  this.name = name;
  this.type = type;
  this.color = gameClient.interface.getHexColor(color);
  // Loudness: 0=whisper, 1=say, 2=yell
  this.loudness = loudness !== undefined ? loudness : 1;
  // Sender level (0/undefined = unknown/system). Shown after the name as
  // "Name [level]:" when the "Show level in chat" setting is on. Kept separate
  // from this.name so the right-click context menu / copy still use the clean
  // name.
  this.level = level;

}

CharacterMessage.prototype = Object.create(Message.prototype);
CharacterMessage.prototype.constructor = CharacterMessage;

CharacterMessage.prototype.format = function() {

  /*
   * Function CharacterMessage.format
   * Implements the format API to format a message in a particular way
   */

  let verb = " says:";
  if (this.loudness === 0) verb = " whispers:";
  else if (this.loudness === 2) verb = " YELLS:";

  // Build the full line first (prefix + message), then wrap so every
  // visual row stays under ~80 chars regardless of how long the prefix
  // (timestamp + name + verb) eats. Two passes:
  //   1. Insert a space after every 70 unbroken non-space chars to
  //      defuse pathological tokens (URLs, glyph runs, malformed text).
  //   2. Insert a newline at the next space past every 80 chars so
  //      long NPC greets split across multiple rows instead of pushing
  //      the chat box past its container width.
  // CSS already has white-space: pre-wrap so the inserted \n renders.
  // Optionally show the sender level after the name ("Name [100] says:").
  // Display-only — this.name stays clean for the context menu / copy.
  let displayName = this.name;
  try {
    if (this.level
        && gameClient.interface.settings
        && gameClient.interface.settings.isShowChatLevelEnabled()) {
      displayName = this.name + " [" + this.level + "]";
    }
  } catch (e) { /* setting unavailable — show the plain name */ }

  let line = "%s %s%s %s".format(this.__formatTime(), displayName, verb, this.message);
  return line
    .replace(/(\S{70})(?=\S)/g, "$1 ")
    .replace(/(.{80,}?)\s/g, "$1\n");

}

CharacterMessage.prototype.createNode = function() {

  /*
   * Function Message.createNode
   * Formats the internal messages to the DOM
   */

  // Format the time the message was sent
  let span = document.createElement("span");
  span.className = "chat-message";
  span.style.color = this.color;

  // Call to format the message string
  span.innerHTML = this.format();

  // Always set the speaker name on the span so right-click → context
  // menu works for any character message (player AND NPC). The
  // `type === 0` gate previously restricted this to private channels
  // and silently broke "copy message" on regular say/whisper/yell.
  // MessageMenu.open hides irrelevant buttons (Message/Whisper/Add
  // Friend) when the right-clicked entry isn't a real player.
  span.setAttribute("name", this.name);

  // Stamp the raw body so "copy message" copies JUST the text — no
  // "<time> <name> says:" prefix and no format() wrap artifacts — so re-pasting
  // into chat (almost always the Trade channel) doesn't blow the short character
  // limit and truncate the message. See MessageMenu.copyMessage.
  span.setAttribute("data-message", this.message);

  return span;

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/utils/message.js ===== */

const Message = function(message, color) {

  /*
   * Class Message
   * Container for messages that were sent to the client
   *
   * API:
   *
   * Message.format - formats the message as text
   * Message.createNode - creates the DOM node for the message to be added to the textbox
   *
   */

  // Save the message and color
  this.message = message;
  this.color = gameClient.interface.getHexColor(color);

  // Time the message was received
  this.__time = new Date();

}

Message.prototype.format = function() {

  /*
   * Function Message.format
   * Implements the format API for displaying a messsage
   */

  return "%s: %s".format(this.__formatTime(), this.message);
 
}

Message.prototype.createNode = function() {

  /*
   * Function Message.createNode
   * Formats the internal messages to the DOM
   */

  // Format the time the message was sent
  let span = document.createElement("span");
  span.className = "chat-message";
  span.style.color = this.color;

  // Call to format the message string
  span.innerHTML = this.format();

  // Stamp the raw body so "copy message" can grab JUST the text — no "<time>:"
  // prefix and none of format()'s line-wrap artifacts. The CLIENT-injected
  // colour spans (loot {auto}/{valuable}/{eat}/{listed} markers converted to
  // <span style="color:#…"> in handleServerMessage) are stripped here so
  // copying a loot line yields plain text, not raw HTML (player report
  // 2026-07-02: copied "Loot of giant spider" showed the span markup).
  // Player-typed text is HTML-escaped server-side, so a literal "<span" typed
  // by a player arrives as "&lt;span" and can never match the strip. See
  // MessageMenu.copyMessage.
  // [^"]* after the hex: {listed}/{retro} spans carry ;font-weight:bold in
  // the same style attribute — the strict hex-then-quote form left their
  // HTML in copied text (same class of bug as the 2026-07-02 report).
  span.setAttribute("data-message",
    String(this.message).replace(/<span style="color:#[0-9A-Fa-f]{3,8}[^"]*">([\s\S]*?)<\/span>/g, "$1"));

  return span;

}

Message.prototype.__formatMinute = function() {

  /*
   * Function Message.__formatMinute
   * Formats the current timestamp minute
   */

  return (("00") + this.__time.getMinutes()).slice(-2);

}

Message.prototype.__formatHour = function() {

  /*
   * Function Message.__formatHour
   * Formats the current timestamp hour
   */

  return ("0" + this.__time.getHours()).slice(-2);

}

Message.prototype.__formatTime = function() {

  /*
   * Function Message.__formatTime
   * Formats the current timestamp hour
   */

  return this.__formatHour() + ":" + this.__formatMinute();

}


