      let frameGroup = new FrameGroup();

      frameGroup.type = this.__hasFrameGroups(id) ? packet.readUInt8() : 0;

      // Read sprite parameters: this defines the width and height (e.g. 64x64 pillar/wall)
      let width = packet.readUInt8();
