ObjectBuffer.prototype.__mapVersionFlag = function (flag) {

  /*
   * Function ObjectBuffer.__mapVersionFlag
   * Conversion to map the right flag in the right Tibia.dat versions (taken from RME/EDUBART)
   */

  // This always means the final flag regardless of the version
  if (flag === this.attributes.ThingAttrLast) {
    return flag;
  }

  // Specific .dat version handling
  if (this.__version >= 1000) {

    if (flag === 16) {
      return this.attributes.ThingAttrNoMoveAnimation;
    } else if (flag > 16) {
      return flag - 1;
    }

  } else if (this.__version >= 755) {

    if (flag == 23) {
      return this.attributes.ThingAttrFloorChange;
    }

  } else if (this.__version >= 740) {

    // Increment flags 1 to 15
    if (flag > 0 && flag <= 15) {
      if (flag === 5) return this.attributes.ThingAttrMultiUse;
      if (flag === 6) return this.attributes.ThingAttrForceUse;
      return flag + 1;
    } else {

      // Switch around some flags
      switch (flag) {
        case 16: return this.attributes.ThingAttrLight;
        case 17: return this.attributes.ThingAttrFloorChange;
        case 18: return this.attributes.ThingAttrFullGround;
        case 19: return this.attributes.ThingAttrElevation;
        case 20: return this.attributes.ThingAttrDisplacement;
        case 22: return this.attributes.ThingAttrMinimapColor;
        case 23: return this.attributes.ThingAttrRotateable;
        case 24: return this.attributes.ThingAttrLyingCorpse;
        case 25: return this.attributes.ThingAttrHangable;
        case 26: return this.attributes.ThingAttrHookSouth;
        case 27: return this.attributes.ThingAttrHookEast;
        case 28: return this.attributes.ThingAttrAnimateAlways;
      }
    }

  }

  return flag;

}

ObjectBuffer.prototype.__readFlags = function (packet) {

  /*
   * Function ObjectBuffer.__readFlags
   * Reads specific flags of that are configured for the data object
   */

  let flags = new PropBitFlag();
  let properties = new Object();

  // Read all the data file flags
  while (true) {

    let flag = this.__mapVersionFlag(packet.readUInt8());

    switch (flag) {

      // End byte: we are finished reading the data flags
      case this.attributes.ThingAttrLast: {
        return new Object({ flags, properties });
      }

      case this.attributes.ThingAttrGround: {
        flags.set(PropBitFlag.prototype.flags.DatFlagGround);
        properties.speed = packet.readUInt16();
        break;
      }

      case this.attributes.ThingAttrGroundBorder: {
        flags.set(PropBitFlag.prototype.flags.DatFlagGroundBorder);
        break;
      }

      case this.attributes.ThingAttrOnBottom: {
        flags.set(PropBitFlag.prototype.flags.DatFlagOnBottom);
        break;
      }

      case this.attributes.ThingAttrOnTop: {
        flags.set(PropBitFlag.prototype.flags.DatFlagOnTop);
        break;
      }

      case this.attributes.ThingAttrContainer: {
        flags.set(PropBitFlag.prototype.flags.DatFlagContainer);
        break;
      }

      case this.attributes.ThingAttrStackable: {
        flags.set(PropBitFlag.prototype.flags.DatFlagStackable);
        break;
      }

      case this.attributes.ThingAttrForceUse: {
        flags.set(PropBitFlag.prototype.flags.DatFlagForceUse);
        break;
      }

      case this.attributes.ThingAttrMultiUse: {
        flags.set(PropBitFlag.prototype.flags.DatFlagMultiUse);
        break;
      }

      case this.attributes.ThingAttrWritable: {
        flags.set(PropBitFlag.prototype.flags.DatFlagWritable);
        let length = packet.readUInt16();
        break;
      }

      case this.attributes.ThingAttrWritableOnce: {
        flags.set(PropBitFlag.prototype.flags.DatFlagWritableOnce);
        let length = packet.readUInt16();
        break;
      }

      case this.attributes.ThingAttrFluidContainer: {
        flags.set(PropBitFlag.prototype.flags.DatFlagFluidContainer);
        break;
      }

      case this.attributes.ThingAttrSplash: {
        flags.set(PropBitFlag.prototype.flags.DatFlagSplash);
        break;
      }

      case this.attributes.ThingAttrNotWalkable: {
        flags.set(PropBitFlag.prototype.flags.DatFlagNotWalkable);
        break;
      }

      case this.attributes.ThingAttrNotMoveable: {
        flags.set(PropBitFlag.prototype.flags.DatFlagNotMoveable);
        break;
      }

      case this.attributes.ThingAttrBlockProjectile: {
        flags.set(PropBitFlag.prototype.flags.DatFlagBlockProjectile);
        break;
      }

      case this.attributes.ThingAttrNotPathable: {
        flags.set(PropBitFlag.prototype.flags.DatFlagNotPathable);
        break;
      }

      case this.attributes.ThingAttrPickupable: {
        flags.set(PropBitFlag.prototype.flags.DatFlagPickupable);
        break;
      }

      case this.attributes.ThingAttrHangable: {
        flags.set(PropBitFlag.prototype.flags.DatFlagHangable);
        break;
      }

      case this.attributes.ThingAttrHookSouth: {
        flags.set(PropBitFlag.prototype.flags.DatFlagHookSouth);
        break;
      }

      case this.attributes.ThingAttrHookEast: {
        flags.set(PropBitFlag.prototype.flags.DatFlagHookEast);
        break;
      }

      case this.attributes.ThingAttrRotateable: {
        flags.set(PropBitFlag.prototype.flags.DatFlagRotateable);
        break;
      }

      case this.attributes.ThingAttrLight: {
        flags.set(PropBitFlag.prototype.flags.DatFlagLight);
        properties.light = packet.readLight();
        break;
      }

      case this.attributes.ThingAttrDontHide: {
        flags.set(PropBitFlag.prototype.flags.DatFlagDontHide);
        break;
      }

      case this.attributes.ThingAttrTranslucent: {
        flags.set(PropBitFlag.prototype.flags.DatFlagTranslucent);
        break;
      }

      case this.attributes.ThingAttrDisplacement: {
        flags.set(PropBitFlag.prototype.flags.DatFlagDisplacement);
        if (this.__version >= 755) {
          packet.readLight();
        }
        break;
      }

      case this.attributes.ThingAttrElevation: {
        flags.set(PropBitFlag.prototype.flags.DatFlagElevation);
        properties.elevation = packet.readUInt16();
        break;
      }

      case this.attributes.ThingAttrLyingCorpse: {
        flags.set(PropBitFlag.prototype.flags.DatFlagLyingCorpse);
        break;
      }

      case this.attributes.ThingAttrAnimateAlways: {
        flags.set(PropBitFlag.prototype.flags.DatFlagAnimateAlways);
        break;
      }

      case this.attributes.ThingAttrMinimapColor: {
        flags.set(PropBitFlag.prototype.flags.DatFlagMinimapColor);
        properties.minimapColor = packet.readUInt16();
        break;
      }

      case this.attributes.ThingAttrLensHelp: {
        flags.set(PropBitFlag.prototype.flags.DatFlagLensHelp);
        packet.readUInt16();
        break;
      }

      // Not implemented
      case this.attributes.ThingAttrFullGround: {
        break;
      }

      case this.attributes.ThingAttrLook: {
        break;
      }

      case this.attributes.ThingAttrCloth: {
        packet.readUInt16();
        break;
      }

      case this.attributes.ThingAttrMarket: {
        packet.skip(6);
        packet.readString();
        packet.skip(4);
        break;
      }

      case this.attributes.ThingAttrUsable: {
        packet.readUInt16();
        break;
      }

      case this.attributes.ThingAttrWrapable: {
        break;
      }

      case this.attributes.ThingAttrUnwrapable: {
        break;
      }

      case this.attributes.ThingAttrTopEffect: {
        break;
      }

      case this.attributes.ThingAttrOpacity: {
        break;
      }

      case this.attributes.ThingAttrNotPreWalkable: {
        break;
      }

      case this.attributes.ThingAttrFloorChange: {
        // Floor-change items (stairs, holes) should block pathfinding
        flags.set(PropBitFlag.prototype.flags.DatFlagNotPathable);
        break;
      }

      case this.attributes.ThingAttrNoMoveAnimation: {
        break;
      }

      case this.attributes.ThingAttrChargeable: {
        break;
      }

      default: {
        throw ("Could not parse flag " + flag.toString(16) + " of Tibia.dat");
      }

    }

  }

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/utils/position.js ===== */

const Position = function (x, y, z) {

  /*
   * Class Position
   * Wrapper for a generic 3D vector that represents a position or coordinates
   *
   * API:
   *
   * subtract(position) - subtracts the passed position from the current position
   * add(position) - adds the passed position to the current position
   * besides(position) - returns true if the passed position is besides (or equal to) the current position
   *
   *
   */

  this.x = x;
  this.y = y;
  this.z = z;

}

Position.prototype.NULL = new Position(0, 0, 0);

Position.prototype.subtract = function (position) {

  /*
   * Function Position.subtract
   * Subtracts a position vector from this vector
   */

  return new this.constructor(
    this.x - position.x,
    this.y - position.y,
    this.z - position.z
  );

}

Position.prototype.add = function (position) {

  /*
   * Function Position.add
   * Adds a position vector to this vector
   */

  return new this.constructor(
    this.x + position.x,
    this.y + position.y,
    this.z + position.z
  );

}

Position.prototype.above = function () {

  /*
   * Function Position.above
   * Returns the position above the current position vector
   */

  return new this.constructor(
    this.x,
    this.y,
    this.z - 1
  );

}

Position.prototype.unprojected = function () {

  /*
   * Function Position.unprojected
   * Unprojects the current chunk position to 3D space
   */

  // Bind to sector height
  let z = this.z % 8;

  return new this.constructor(
    this.x - z,
    this.y - z,
    z
  );

}

Position.prototype.projected = function () {

  /*
   * Function Position.projected
   * Projects the current world position on a flat surface
   */

  // Bind to sector height
  let z = this.z % 8;

  return new this.constructor(
    this.x + z,
    this.y + z,
    z
  );

}

Position.prototype.fromOpcode = function (opcode) {

  /*
   * Function Position.fromOpcode
   * Maps the byte opcode to a direction
   */

  switch (opcode) {
    case CONST.DIRECTION.NORTH:
      return this.north();
    case CONST.DIRECTION.EAST:
      return this.east();
    case CONST.DIRECTION.SOUTH:
      return this.south();
    case CONST.DIRECTION.WEST:
      return this.west();
    case CONST.DIRECTION.NORTH_EAST:
      return this.northeast();
    case CONST.DIRECTION.SOUTH_EAST:
      return this.southeast();
    case CONST.DIRECTION.SOUTH_WEST:
      return this.southwest();
    case CONST.DIRECTION.NORTH_WEST:
      return this.northwest();
  }

}

Position.prototype.copy = function () {

  /*
   * Function Position.copy
   * Makes a memory copy of the position
   */

  return new Position(this.x, this.y, this.z);

}

Position.prototype.west = function () {

  /*
   * Function Position.west
   * Returns the position currently west of the current position
   */

  return new this.constructor(this.x - 1, this.y, this.z);

}

Position.prototype.north = function () {

  /*
   * Function Position.north
   * Returns the position currently north of the current position
   */

  return new this.constructor(this.x, this.y - 1, this.z);

}

Position.prototype.east = function () {

  /*
   * Function Position.east
   * Returns the position currently east of the current position
   */

  return new this.constructor(this.x + 1, this.y, this.z);

}

Position.prototype.south = function () {

  /*
   * Function Position.south
   * Returns the position currently south of the current position
   */

  return new this.constructor(this.x, this.y + 1, this.z);

}

Position.prototype.northwest = function () {

  /*
   * Function Position.northwest
   * Returns the position north west the current position
   */

  return new this.constructor(this.x - 1, this.y - 1, this.z);

}

Position.prototype.northeast = function () {

  /*
   * Function Position.northeast
   * Returns the position north east of the current position
   */

  return new this.constructor(this.x + 1, this.y - 1, this.z);

}

Position.prototype.southeast = function () {

  /*
   * Function Position.southeast
   * Returns the position south east of the current position
   */

  return new this.constructor(this.x + 1, this.y + 1, this.z);

}

Position.prototype.southwest = function () {

  /*
   * Function Position.southeast
   * Returns the position south west of the current position
   */

  return new this.constructor(this.x - 1, this.y + 1, this.z);

}

Position.prototype.up = function () {

  /*
   * Function Position.up
   * Returns the position above the current position
   */

  return new this.constructor(this.x, this.y, this.z - 1);

}

Position.prototype.down = function () {

  /*
   * Function Position.down
   * Returns the position below the current position
   */

  return new this.constructor(this.x, this.y, this.z + 1);

}

Position.prototype.random = function () {

  /*
   * Function Position.random
   * Returns a random position around the current only (NESW)
   */

  let random = Math.floor(Math.random() * Math.floor(4));

  switch (random) {
    case 0:
      return this.west();
    case 1:
      return this.north();
    case 2:
      return this.east();
    case 3:
      return this.south();
  }

}

Position.prototype.getLookDirection = function (position) {

  /*
   * Function Position.getLookDirection
   * Returns the look direction towards another direction
   */

  if (this.z !== position.z) {
    return null;
  }

  let diff = position.subtract(this);

  if (diff.x === 0) {
    switch (diff.y) {
      case -1:
        return CONST.DIRECTION.NORTH;
      case 0:
        return null;
      case 1:
        return CONST.DIRECTION.SOUTH;
    }
  }

  if (diff.x === -1) {
    switch (diff.y) {
      case -1:
        return CONST.DIRECTION.NORTH_WEST;
      case 0:
        return CONST.DIRECTION.WEST;
      case 1:
        return CONST.DIRECTION.SOUTH_WEST;
    }
  }

  if (diff.x === 1) {
    switch (diff.y) {
      case -1:
        return CONST.DIRECTION.NORTH_EAST;
      case 0:
        return CONST.DIRECTION.EAST;
      case 1:
        return CONST.DIRECTION.SOUTH_EAST;
    }
  }

  return null;

}

Position.prototype.isDiagonal = function (position) {

  /*
   * Function Position.isDiagonal
   * Returns true when a position is diagonal to another position
   */

  return (Math.abs(this.x - position.x) & Math.abs(this.y - position.y)) === 1;

}

Position.prototype.toString = function () {

  /*
   * Function Position.toString
   * Returns the position as a comma delimited string
   */

  return this.x + ", " + this.y + ", " + this.z;

}

Position.prototype.serialize = function () {

  /*
   * Function Position.serialize
   * Serializes the position as a buffer
   */

  return {
    "x": this.x,
    "y": this.y,
    "z": this.z
  }

}

Position.prototype.equals = function (position) {

  /*
   * Function Position.equals
   * Returns true if two positions are equal
   */

  return this.x === position.x &&
    this.y === position.y &&
    this.z === position.z;

}

Position.prototype.inRange = function (position, range) {

  /*
   * Function Position.inRange
   * Returns true if a position is in range of another position
   */

  // Must be on same floor
  return this.z === position.z &&
    (Math.sqrt(Math.pow((this.x - position.x), 2) + Math.pow((this.y - position.y), 2)) | 0) < range

}

Position.prototype.besides = function (position) {

  /*
   * Function WorldPosition.besides
   * Returns true if position is besides another position
   */

  // Not same floor
  if (this.z !== position.z) {
    return false;
  }

  // Check the difference is one
  return Math.max(Math.abs(this.x - position.x), Math.abs(this.y - position.y)) <= 1;

}


/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/utils/private-channel.js ===== */

const PrivateChannel = function(name) {

  /*
   * Class PrivateChannel
   * Wrapper for channels from one character to another
   */

  // Inherits from channel
  Channel.call(this, name, null);

}

PrivateChannel.prototype = Object.create(Channel.prototype);
PrivateChannel.prototype.constructor = PrivateChannel;

PrivateChannel.prototype.__getEmptyMessage = function() {

  /*
   * Function PrivateChannel.__getEmptyMessage
   * Returns the string to display when the channel is empty
   */

  return "<div class=\"channel-empty\">No messages in channel with " + this.name + ".</div>";

}

/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/utils/replay-manager.js ===== */

const ReplayManager = function() {

  /*
   * Classs ReplayManager
   * Container for a packet replayer (playback) for recorded packets
   * This is a feature similar to what TibiaCam provided
   */

  this.__recording = false;
  this.__replaying = false;
  this.__aborted = false;
  this.__forward = false;

  this.__recordedPackets = new Array();
  this.__encodedLength = 0;

}

ReplayManager.prototype.abort = function(callback) {

  this.__replaying = false;
  this.__aborted = true;
  this.abortCallback = callback;

}

ReplayManager.prototype.record = function() {

  /*
   * Function ReplayManager.record
   * Starts a recording of the game packets by setting the recording state (picked up by network manager on recv)
   */

  document.getElementById("recording-span").innerHTML = "<button onclick='downloadSafe()'>&#128308</button> Recording..";
  this.__recording = true;
  this.start = Date.now();

}

ReplayManager.prototype.abortCallback = Function.prototype;

ReplayManager.prototype.replay = function(data) {

  /*
   * Function ReplayManager.replay
   * Replays all packets as sent by the server
   */

  // If already replaying: abort the current replay
  if(this.__replaying) {
    this.abort(this.replay.bind(this, data));
    return;
  }

  this.__replaying = true;
  this.__aborted = false;

  // Hide the login modal
  document.getElementById("asset-modal").style.display = "none";
  document.getElementById("skip").style.display = "block";

  // Parse the input data file
  this.data = JSON.parse(data);
  this.packets = this.data.packets;

  this.length = this.data.end - this.data.start;

  gameClient.interface.reset();
  gameClient.setServerData(this.data.metadata);

  // State for the replay
  this.replayStart = this.packets[0].timestamp;
  this.now = Date.now();
  this.replayIndex = 0;

  // Begin replaying the 
  this.playback();

}

ReplayManager.prototype.isReplayForwarding = function() {

  return this.__forward;

}

ReplayManager.prototype.setFraction = function(fraction) {

  /*
   * Function ReplayManager.setFraction
   * Sets the replay to the number of elapsed seconds by replaying everything
   */

  if(this.__replaying) {
    this.abort(this.setFraction.bind(this, fraction));
    return;
  }

  gameClient.interface.reset();
  gameClient.setServerData(this.data.metadata);

  this.__replaying = true;
  this.__aborted = false;


  this.replayIndex = 0;

  let seconds = (fraction * this.length) | 0;
  let elapsed = this.replayStart + seconds;
  this.now = Date.now() - seconds;

  // Set forwarding state and catch up to current situation
  this.__forward = true;
  this.catchup(elapsed);
  this.__forward = false;

}

ReplayManager.prototype.finish = function() {

  /*
   * Function ReplayManager.finish
   * Finishes the replay of the server
   */

  this.__replaying = false;
  this.__aborted = false;
  this.abortCallback = Function.prototype;
  this.__encodedLength = 0;
  gameClient.networkManager.__connected = false;
  gameClient.renderer.screen.clear();
  this.updateStatistics(this.replayStart + this.length, 100);


}

ReplayManager.prototype.catchup = function(elapsed) {

  /*
   * Function ReplayManager.catchup
   * Catches up to the elapsed time
   */

  if(this.replayIndex >= this.packets.length) {
    return this.finish();
  }

  while(elapsed >= this.packets[this.replayIndex].timestamp) {

    gameClient.networkManager.handleMessage({
      "data": this.decode64(this.packets[this.replayIndex++].buffer)
    });

    if(this.replayIndex >= this.packets.length) {
      return this.finish();
    }

  }

}

ReplayManager.prototype.updateStatistics = function(elapsed, percent) {

  document.getElementById("recording-span-text").innerHTML = new Date(elapsed).toISOString();
  document.getElementById("skip").firstElementChild.style.width = percent.toFixed(0) + "%";
  document.getElementById("skip").lastElementChild.innerHTML = percent.toFixed(0) + "%";

}

ReplayManager.prototype.playback = function() {

  /*
   * Function ReplayManager.playback
   * Replay loop to handle all virtual packets from the server
   */

  // Percentage completed
  let elapsed = this.replayStart + (Date.now() - this.now);
  let percent = 100 * ((Date.now() - this.now) / this.length);

  this.updateStatistics(elapsed, percent);
  this.catchup(elapsed);

}

ReplayManager.prototype.download = function(filename) {

  /*
   * Function ReplayManager.download
   * Downloads the recorded packets to a JSON file
   */

  // Not recording or no packets: nothing to download
  if(!this.__recording || this.__recordedPackets.length === 0) {
    return;
  }

  // Create the payload
  let data = JSON.stringify({
    "packets": this.__recordedPackets,
    "end": Date.now(),
    "start": this.start,
    "clientVersion": gameClient.clientVersion,
    "metadata": {
      "tick": gameClient.getTickInterval(),
      "version": gameClient.serverVersion,
      "width": gameClient.world.width,
      "height": gameClient.world.height,
      "depth": gameClient.world.depth
    }
  });

  let file = new Blob([data], {"type": "application/json"});
  let a = document.createElement("a");
  let url = URL.createObjectURL(file);

  // Some hackery to download a file
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();

}

ReplayManager.prototype.encode64 = function(buffer) {

  /*
   * Function ReplayManager.encode64
   * Encodes the received packet buffers to base 64
   */

  return btoa(String.fromCharCode.apply(null, buffer));

}

ReplayManager.prototype.decode64 = function(string) {

  /*
   * Function ReplayManager.decode64
   * Encodes the received packet buffers from base64 to something that can be replayed
   */

  return atob(string).split("").map(function(x) {
    return x.charCodeAt(0);
  });

}

ReplayManager.prototype.recordPacket = function(buffer) {

  /*
   * Function ReplayManager.recordPacket
   * Records an incoming packet from the server including the timestamp
   */

  let encoded = this.encode64(buffer);

  this.__encodedLength += encoded.length;

  this.__recordedPackets.push({
    "timestamp": Date.now(),
    "buffer": encoded
  });

}

/* ===== FILE: https://minibia.com/b/2026-07-20-2053/src/utils/rgba.js ===== */

const RGBA = function(r, g, b, a) {

  /*
   * Class RGBA
   * Container for colors
   */

  // Four components (0x00 to 0xFF)
  this.r = r;
  this.g = g;
  this.b = b;
  this.a = a;

}

RGBA.prototype.copy = function() {

  /*
   * Function RGBA.copy
   * Returns a copy (new memory) of the current RGBA instance
   */

  return new RGBA(this.r, this.g, this.b, this.a);

}

RGBA.prototype.toString = function() {

  /*
   * Function RGBA.toString
   * Returns HTML/CSS string representation of the color
   */

  // Return and scale the alpha channel between [0, 1]
  return "rgba(" + this.r + ", " + this.g + ", " + this.b + ", " + (this.a / 0xFF) + ")";

}

RGBA.prototype.interpolate = function(color, fraction) {

  /*
   * Function RGBA.interpolate
   * Inpolates self to the requested color by a fraction
   */

  return new RGBA(
    Math.round(this.r + fraction * (color.r - this.r)),
    Math.round(this.g + fraction * (color.g - this.g)),
    Math.round(this.b + fraction * (color.b - this.b)),
    Math.round(this.a + fraction * (color.a - this.a))
  );

}
